INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9be001ea0e9c6def','А может быть ворона...','(Песня из мультфильма «Пластилиновая ворона»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Эдуард Успенский, музыка: Григорий Гладков) | Песни для детей | https://pesni.retroportal.ru/deti/a_mozhet_byt_vorona.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Пластилиновая ворона») | merged_versions: 1','Одну простую сказку,
А может, и не сказку,
А может, не простую,
Хотим вам рассказать.
Её мы помним с детства,
А может, и не с детства,
А может, и не помним,
Но будем вспоминать.
Нам помнится вороне,
А может быть, собаке,
А может быть, корове,
Однажды повезло.
Послал ей кто-то сыра,
Грамм, думается двести,
А может быть, и триста,
А может, полкило.
На ель она взлетела,
А может, не взлетела,
А может быть, на пальму
С разбега взобралась.
И там она позавтракать,
А может, пообедать,
А может быть, поужинать
Спокойно собралась.
Но тут лиса бежала,
А может, не бежала,
А может, это стаус злой,
А может, и не злой.
А может, это дворник был.
Он шёл по сельской местности
К ближайшему орешнику
За новою метлой.
- Послушайте, ворона,
А может быть, собака,
А может быть, корова,
Но тоже хороша!
У вас такие перья,
У вас рога такие,
Копыта очень стройные
И добрая душа.
А если вы споёте,
А может быть, залаете,
А может, замычите -
Коровы ведь мычат, -
То вам седло большое,
Ковёр и телевизор
В подарок сразу вручат,
А может быть, вручат.
И глупая ворона,
А может быть, собака,
А может быть, корова,
Как что-то запоёт!
И от такого пения,
А может быть не пения
Упал, немедля, в обморок
От смеха весь народ.
А сыр у той вороны,
А может быть, собаки
А может быть, коровы,
Конечно же, упал.
И прямо на лисицу,
А может быть, на страуса,
А может быть, на дворника
Немедленно попал.
Идею этой сказки,
А может, и не сказки,
Поймёт не только взрослый,
Но даже карапуз,&nbsp;-
Не стойте и не прыгайте,
Не пойте не пляшите
Там, где идёт строительство
Или подвешен груз!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Пластилиновая ворона»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9be001ea0e9c6def'), datetime('now')),datetime('now'));
