INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_252066f678926daf','А мы масленицу прокатали',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/a_my_maslenicu_prokatali.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','А мы масленицу прокатали ,
Прокатали, душа, прокатали.
На каталищах не бывали,
Не бывали, душа, не бывали.
Наша масленица  обманила,
Обманила, душа, обманила.
На велик пост посадила,
Посадила, душа, посадила.
Наша масленица дорогая ,
Дорогая, душа, дорогая.
Да ты,  масленица , протянися,
Протянися, душа, протянися,
Один день за семь недель,
Соловея, соловея, душа, соловея.
Со  Христова дня , до  Петрова дня ,
Соловея,  соловея , душа, соловея.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_252066f678926daf'), datetime('now')),datetime('now'));
