INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_72bcca58dab6ca90','А ну-ка, девушки! А ну, красавицы!..','(«Марш женских бригад»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/a_nu-ka_devushki_marsh_zhenskih_brigad.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Марш женских бригад») | merged_versions: 1','Идём, идём, весёлые подруги,
Страна, как мать, зовёт и любит нас!
Везде нужны заботливые руки
И наш хозяйский, тёплый женский глаз.
Припев:
А ну-ка, девушки! А ну, красавицы!
Пускай поёт о нас страна!
И звонкой песнею пускай прославятся
Среди героев наши имена!
Для нас пути открыты все на свете,
И свой поклон приносит нам земля.
Растут цветы, и радуются дети,
И колосятся тучные поля!
Припев
Сады, леса, и фабрики, и пашни&nbsp;-
Всё это наш родной и милый дом.
Пусть новый день обгонит день вчерашний
Своим весёлым, радостным трудом!
Припев
Расти, страна, где волею единой
Народы все слились в один народ!
Цвети, страна, где женщина с мужчиной
В одних рядах, свободная, идёт!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Марш женских бригад»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_72bcca58dab6ca90'), datetime('now')),datetime('now'));
