INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e4d574bb448dc873','А у нас во дворе','(«А у нас во дворе есть девчонка одна»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лев Ошанин, музыка: Аркадий Островский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/a_u_nas_vo_dvore.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («А у нас во дворе есть девчонка одна») | merged_versions: 1','А у нас во дворе есть девчонка одна,
Между шумных подруг неприметна она.
Никому из ребят неприметна она...
Припев:
Я гляжу ей вслед:
Ничего в ней нет,
А я всё гляжу,
Глаз не отвожу...
Есть дружок у меня, я с ним с детства знаком&nbsp;-
Но о ней я молчу даже с лучшим дружком.
Почему-то молчу даже с лучшим дружком.
Припев
Не боюсь я, ребята, ни ночи, ни дня,
Ни крутых кулаков, ни воды, ни огня,
А при ней словно вдруг подменяют меня.
Припев
Вот опять вечерком я стою у ворот,
Она мимо из булочной с сумкой идёт...
Я стою и молчу, и обида берёт.
Припев
Или утром стучит каблучками она&nbsp;—
Обо всём позабыв, я слежу из окна
И не знаю, зачем мне она так нужна.
Припев
Текст песни Льва Ошанина  &laquo;И опять во дворе нам пластинка поёт...&raquo;  на музыку Аркадия Островского.
Слушать песню &laquo;А у нас во дворе&raquo; композитора Аркадия Островского на стихи Льва Ошанина в исполнении  Иосифа Кобзона .','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«А у нас во дворе есть девчонка одна»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e4d574bb448dc873'), datetime('now')),datetime('now'));
