INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d64e942cc4bd741e','Амурские волны','(«Плавно Амур свои волны несёт...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Константин Васильев и Серафим Попов, музыка: Макс Кюсс) | Патриотические песни | https://pesni.retroportal.ru/rodina/amurskie_volny.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Плавно Амур свои волны несёт...») | merged_versions: 1','Плавно Амур свои волны несёт,
Ветер сибирский им песни поёт.
Тихо шумит над Амуром тайга,
Ходит пенная волна
Пенная волна плещет,
Величава и вольна.
Там, где багряное солнце встаёт,
Песню матрос об Амуре поёт.
Песня летит над широкой рекой,
Льётся песня широко
Песня широко льётся,
И несётся далеко.
Красоты и силы полны,
Хороши Амура волны.
Серебрятся волны
Серебрятся волны,
Славой Родины горды.
Плещут, плещут, силы полны,
И стремятся к морю волны.
Серебрятся волны
Серебрятся волны,
Славой русскою горды.
Красива Амура волна,
И вольностью дышит она.
Знает волна&nbsp;-
Стерегут её покой.
Спокойны реки берега,
Шумит золотая тайга.
Дышит волна
Её чудной красотой.
Величав Амур седой,
Мы храним его покой.
Корабли вперёд плывут,
Волны бегут и бегут:
Ты шуми, Амур родной.
Ты шуми седой волной,
В грозном беге прославляй
Наш советский вольный край.
Плавно Амур свои волны несёт,
Ветер сибирский им песни поёт.
Тихо шумит над Амуром тайга,
Ходит пенная волна
Пенная волна плещет,
Величава и вольна.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Плавно Амур свои волны несёт...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d64e942cc4bd741e'), datetime('now')),datetime('now'));
