INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5fdbf5ab0c5e3ee9','Армия, вперёд!','(«Идут полки со славою за наше дело правое...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Владимир Замятин, музыка: Леонид Бакалов) | Песни военных лет | https://pesni.retroportal.ru/vov/armiya_vpered.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Идут полки со славою за наше дело правое...») | merged_versions: 1','За наше счастье в грозный бой
Идут уверенно полки.
Готов на фронт идти любой -
Сейчас мы все фронтовики!
Припев:
Идут полки со славою
За наше дело правое,
За наш народ, за наш народ.
За Родину любимую,
За нашу жизнь счастливую&nbsp;-
Армия, вперёд!
Смотри, над Родиной висят
Пороховые облака,
Отчизну нашу хочет взять
Фашизма чёрная рука.
Припев
Врага раздавим мы в боях
Победным натиском полков,
Чтоб вечно Родина моя
Дышала радостно, легко!
Припев
Туда, где воздух грозовой,
В поход решительный идём.
Вперёд, друзья, смелее в бой,
Фашистской банде смерть несём!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Идут полки со славою за наше дело правое...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5fdbf5ab0c5e3ee9'), datetime('now')),datetime('now'));
