INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f2c993f65c02cdfd','Астры осенние',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: С.Грей, музыка: Николай Харито) | Старинные романсы | https://pesni.retroportal.ru/sr1/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Астры осенние, грусти цветы,
Тихи, задумчивы ваши кусты;
Тихо качаетесь, грустно склоняетесь
Осенью поздней к земле...
Солнышко яркое вас не пригреет,
Осень печальная – ваша весна,
Глядя на вас, моё сердце сжимается,
Грустью объята душа.
Сад весь осыпался, всё отцвело...
Листья увядшие вдаль разнесло...
Лишь одинокие астры осенние
Ждут понапрасну весны.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f2c993f65c02cdfd'), datetime('now')),datetime('now'));
