INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bd2c64665bd77407','Ах вы, сени мои, сени',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах вы, сени мои, сени,
Сени новые мои,
Сени новые кленовые,
Решетчатые!
Как и мне по вам, по сеничкам,
Не хаживати,
Мне мила друга за рученьку
Не важивати!
Выходила молода
За новые ворота,
Выпускала сокола
Из правого рукава.
На полетике соколику
Наказывала:
&laquo;Ты лети, лети, соколик,
Высоко и далеко,
И высоко и далёко,
На родиму сторону;
На родимой на сторонке
Грозен батюшка живёт.
Он грозен, сударь, грозен,
Он не милостивой:
Не пускает молоду
Поздно вечером одну.
Я не слушала отца,
Спотешала молодца.
Я за то его спотешу,
Что один сын у отца.
Что один сын у отца,
Уродился в молодца, -
Зовут Ванюшкою –
Пивоварушкою&raquo;.
Пивовар пиво варил,
Зелено вино курил,
Зелено вино курил,
Красных девушек манил
&laquo;Вы пожалуйте, девицы,
На поварню на мою!
На моей ли на поварне
Пиво пьяно на ходу.
На моей ли на поварне
Пиво пьяно на ходу,
Пиво пьяно на ходу
И на сладком на меду&raquo;.
Ах вы, сени мои, сени,
Сени новые мои,
Сени новые, кленовые,
Решетчатые!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bd2c64665bd77407'), datetime('now')),datetime('now'));
