INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_cc00598533429e09','Ах ты Волга, Волга–матушка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/ah_ty_volga_matushka.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах ты Волга ,  Волга-матушка ,
Широко Волга разливалася
По лугам, лугам зелёным,
По цветочкам по лазоревым;
Что  по травушке, муравушке ,
Что под яблоней под кудрявою,
Что под грушею под зелёною,
Молодец девку журил, бранил,
Журил, бранил, всё добру учил.
Ах ты девка, девка красная,
Не ходи девка молода за муж,
Ты спроси девка отца, матери,
Отца, матери, роду, племени,
Накопи девка ума, разума,
Ума, разума, приданова.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_cc00598533429e09'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_cc00598533429e09','Ах ты Волга, Волга–матушка','Ах ты Волга ,  Волга-матушка ,
