INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8160b1b0fc0cb38f','Ах ты, ноченька',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах ты, ноченька, ночка тёмная,
Ночка тёмная, ах, ночь осенняя.
Что же ты, ноченька, да при... притуманилась,
Что ж, осенняя, ах, принахмурилась?
Что же ты, девица, притуманилась,
Что же ты, красная, ах, припечалилась?
&laquo;Как же мне, девице, да не... да не туманиться,
Как же мне, красной, да не печалиться?
Нет ни матушки, да нет, да нет ни батюшки,
Только есть у меня, ах, мил сердечный друг.
Да и тот со мной да не... да не в ладу живёт,
Не в ладу живёт, ах, не в согласии...&raquo;','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8160b1b0fc0cb38f'), datetime('now')),datetime('now'));
