INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_be7b4b7d7b1d6ffc','Ах! Когда б я прежде знала',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Иван Дмитриев, музыка: Михаил Глинка) | Старинные романсы | https://pesni.retroportal.ru/sr1/04.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ах! Когда б я прежде знала,
Что любовь творит беды,
Я б с весельем не встречала, не встречала б
Полуночныя звёзды, полуночныя звёзды.
Не лила б от всех украдкой
Золотого я кольца,
Не была б в надежде сладкой, надежде сладкой
Видеть милого льстеца, видеть милого льстеца.
Я б слила из воску яра
Лёгки крылышки себе
И на родину б вспорхнула
Мила друга, мила друга моего, мила друга моего.
Я на родину б вспорхнула
Мила друга моего,
Нежно, нежно я б взглянула, я б взглянула
Хоть однажды на него, хоть однажды на него.
А потом бы улетела
Со слезами и тоской,
Подгорюнившись бы, села
На дороге, на дороге на большой, на дороге на большой.
Возопила б, возрыдала:
&laquo;Люди добры, как мне быть?
Я неверного любила,
Научите, научите, как забыть, научите, как забыть&raquo;.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_be7b4b7d7b1d6ffc'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_be7b4b7d7b1d6ffc','Ах! Когда б я прежде знала','Ах! Когда б я прежде знала,
