INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_81ccb10b6dc3022b','Ах, зачем ты меня целовала',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Пётр Баторин) | Старинные романсы | https://pesni.retroportal.ru/sr1/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ах, зачем ты меня целовала,
Жар безумный в груди затая,
Ненаглядным меня называла
И клялась: &laquo;Я твоя, я твоя!&raquo;
В тихий час упоительной встречи
Только месяц в окошко сверкал,
Полон страсти, я дивные плечи
Без конца целовал, целовал.
А теперь беспредельные муки
Суждены мне злодейской судьбой.
И не слышны мне дивные звуки:
&laquo;Милый, как я счастлива с тобой!&raquo;
Ах, зачем ты меня целовала,
Жар безумный в груди затая,
Ненаглядным меня называла
И клялась: &laquo;Я твоя, я твоя!&raquo;','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_81ccb10b6dc3022b'), datetime('now')),datetime('now'));
