INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_759744924657e702','Ах, зачем эта ночь',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай фон Риттер, обработка: Николай Пашков, музыка: Николай Бакалейников) | Старинные романсы | https://pesni.retroportal.ru/sr1/03.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ах, зачем эта ночь
Так была хороша!
Не болела бы грудь,
Не страдала б душа.
Полюбил я её,
Полюбил горячо,
А она на любовь
Смотрит так холодно.
Не понравился ей
Моей жизни конец,
И с постылым назло
Мне пошла под венец.
Звуки вальса неслись,
Веселился весь дом,
Я в каморку свою
Пробирался с трудом.
И всю ночь напролёт
Я все думал о ней:
Каково будет ей
Без милого жить век?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_759744924657e702'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_759744924657e702','Ах, зачем эта ночь','Ах, зачем эта ночь
