INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e35d794a0627e0a3','Ах, как скучно мне одной',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/ah_kak_skuchno_mne_odnoj.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах,  как скучно мне одной ,
Где девался мой покой ;
Я любила завсегда,
Пасти стадо здесь одна.
Ныне стадо поди прочь,
День темняе, нежель ночь;
Стражду, рвуся, слёзы лью,
От чево, ах!  я люблю .
Злой пастух пленил меня ,
Где ты, плачу без тебя:
Он мне часто говорил,
Умились, люби твердил.
Я внимала ево речь,
Не стараяся пресечь,
От тово терплю напасть,
От тово  узнала страсть .
Вон он вижу за рекой,
Вон и  машет мне рукой ;
Овцы нужды мне в вас нет,
Коль пастух к себе зовет.
Ай, ау, мой свет, постой,
Я останусь там с тобой;
Нету силы огня скрыть,
Коль  вся кровь во мне кипит .','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e35d794a0627e0a3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e35d794a0627e0a3','Ах, как скучно мне одной','Ах,  как скучно мне одной ,
