INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e1ebf995eaaa0ac5','Ах, по морю, морю синему',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/ah_po_moryu_sinemu.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах,  по морю, морю синему ,
По синю морю по Хвалынскому ,
Что плывут тут  выплывают тридцать кораблей ;
Что один из них корабль братцы наперёд бежит,
Впереди бежит корабль,  как сокол летит .
Хорошо больно кораблик изукрашен был,
Паруса на корабле были тафтяные ,
А  тетивочки у корабля шемаханскова шёлку ,
А подзоры у кораблика  рытова бархату ,
На рулю сидел наш  батюшка православной Царь .
Что не золотая трубушка вострубила,
Да что взговорит наш батюшко  православной Царь ,
Ах! вы гой матрозы люди лёгкие,
Вы мечитеся на  мачты корабельные ,
Вы смотрите во  трубочки подзорные ,
Что долеко ли до  Стекольнова .','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e1ebf995eaaa0ac5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e1ebf995eaaa0ac5','Ах, по морю, морю синему','Ах,  по морю, морю синему ,
По синю морю по Хвалынскому ,
Что плывут тут  выплывают тридцать кораблей ;
