INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_fdc79e8e010205eb_d1ea89fd778160c1','rpp_fdc79e8e010205eb','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/04.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b0117846a87d48a9','Ах, ты зимушка, зима',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/ah_ty_zimushka_zima.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах, ты зимушка, зима ,
Холодна очень была,
Холодна очень была,
Заморозила меня ,
Заморозила меня,
Сержантика бравого .
Как на улице большой
Вот шла партия солдат;
Впереди солдат идёт,
Сам  сержантик молодой .
На все стороны сержант
Низко кланяется,
Низко кланяется,
С Машей здравствуется:
&laquo; Здравствуй, Маша , здравствуй, Маша,
Здравствуй, Машенька моя ,
Здравствуй, Машенька моя!
Дома ль маменька твоя?&raquo;
—&nbsp;Ни тятеньки, ни маменьки,&nbsp;—
Дома нету никого,
Дома нету никого,
Полезай, сударь, в окно.&nbsp;—
Сержант руки протянул,
Холоп плетью стёгнул:
&laquo;Не дворянска, сударь, честь
По ночам в окошко лезть .&raquo;
Вот сержантик догадался,
За карман скорей хватался:
—&nbsp;Вот тебе  целковый-рубль ,
Выпусти меня из рук;
Вот тебе и полтора,
Пусти меня со двора .','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b0117846a87d48a9'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b0117846a87d48a9','Ах, ты зимушка, зима','Ах, ты зимушка, зима ,
Холодна очень была,
Холодна очень была,
Заморозила меня ,
Заморозила меня,
Сержантика бравого .
Как на улице большой
Вот шла партия солдат;
Впереди солдат идёт,
Сам  сержантик молодой .
На все стороны сержант
Низко кланяется,
Низко кланяется,
С Машей здравствуется:
&laquo; Здравствуй, Маша , здравствуй, Маша,
Здравствуй, Машенька моя ,
Здравствуй, Машенька моя!
Дома ль маменька твоя?&raquo;
—&nbsp;Ни тятеньки, ни маменьки,&nbsp;—
Дома нету никого,
Дома нету никого,
Полезай, сударь, в окно.&nbsp;—
Сержант руки протянул,
Холоп плетью стёгнул:
&laquo;Не дворянска, сударь, честь
По ночам в окошко лезть .&raquo;
Вот сержантик догадался,
За карман скорей хватался:
—&nbsp;Вот тебе  целковый-рубль ,
Выпусти меня из рук;
Вот тебе и полтора,
Пусти меня со двора .');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b0117846a87d48a9_fd757a81c3c87762','rpp_b0117846a87d48a9','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/ah_ty_zimushka_zima.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3e7020eed2ec0da9','Ах, ты солнце, ты солнце красное',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/ah_ty_solnce_krasnoe.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах, ты солнце,  ты солнце красное ,
Ты к чему  рано за лес катишься .
У меня в глазах  мил сердечной друг ,
Не гостит он не жалует,
Всё домой снаряжается.
Провожу ли я друга милова ,
Через два поля чистые ,
Через три луга зелёные ,
Через  матушку каменну Москву ;
Я тут с другом расставалася,
И слезами обливалася ,
Во слезах ему слово молвила,
Коли лучше меня найдёшь, позабудешь,
Коли хуже меня найдёшь, воспомянешь.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3e7020eed2ec0da9'), datetime('now')),datetime('now'));
