INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4b774f5c2f6b8531','Ах, утушка моя луговая',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/ah_utushka_moya_lugovaya.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах, утушка моя луговая ,
Молодушка моя молодая .
Ой, люли, люли , люли, люли, молодая.
Ой, люли, люли, люли, люли, молодая.
Где ты была, была-побывала,
Где всю ночку ты да ночевала ?
Ой, люли, люли, люли, люли, ночевала.
Ой, люли, люли, люли, люли, ночевала.
Ночевала да я во лесочке
Под ракитовым да под кусточком .
Ой, люли, люли, люли, люли, под кусточком.
Ой, люли, люли, люли, люли, под кусточком.
Как шли-прошли парни молодые ,
Два молодчика , ой, да удалые,
Ой, люли, люли, люли, люли, удалые.
Ой, люли, люли, люли, люли, удалые.
Они срезали да по пруточку ,
Они сделали да по гудочку .
Ой, люли, люли, люли, люли, по гудочку.
Ой, люли, люли, люли, люли, по гудочку.
Вы, гудочки, ой, да не гудите,
Мово батюшку да не будите.
Ой, люли, люли, люли, люли, не будите.
Ой, люли, люли, люли, люли, не будите.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4b774f5c2f6b8531'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4b774f5c2f6b8531','Ах, утушка моя луговая','Ах, утушка моя луговая ,
