INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0c93748eb694103b','Ах, эта красная рябина',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Софронов, музыка: Семён Заславский) | Старинные романсы | https://pesni.retroportal.ru/sr1/05.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ах, эта красная рябина
Среди осенней желтизны.
Я на тебя смотрю, любимый,
Теперь уже со стороны.
Со стороны страданий прежних,
Со стороны ушедших лет,
Которым, словно зорям вешним,
Уже возврата больше нет.
Летят, как ласточки, листочки
С моей любовью по пути;
И только нет последней точки,
И слова нет ещё &laquo;прости&raquo;.
Ещё цепляется за память
Счастливых дней весенний гром,
Когда любовь бродила с нами,
Скрывая нас одним крылом.
Весною ласточки вернутся,
Оставив за морем любовь,
И над рябиной пронесутся,
И что-то мне напомнят вновь...
Ах, эта красная рябина
Среди осенней желтизны...
Я на тебя смотрю, любимый,
Из невозвратной стороны.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0c93748eb694103b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_0c93748eb694103b','Ах, эта красная рябина','Ах, эта красная рябина
