INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7f13a1229c6ab02b','Ах, я влюблён в глаза одни',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Татьяна Щепкина-Куперник, музыка: Александр Вилинский) | Старинные романсы | https://pesni.retroportal.ru/sr1/06.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ах, я влюблён в глаза одни,
Я увлекаюсь их игрою...
Как дивно хороши они,
Но чьи они, я не открою.
Едва в тени пустых ресниц
Блеснут опасными лучами,
И я упасть готов уж ниц
Перед волшебными очами.
В моей душе растёт гроза,
Растёт, тоскуя и ликуя.
Да, я влюблён в одни глаза,
Но чьи они, не назову я...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7f13a1229c6ab02b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7f13a1229c6ab02b','Ах, я влюблён в глаза одни','Ах, я влюблён в глаза одни,
