INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_251d260e93c5816c','Барыня, барыня, сударыня барыня!',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/barynya_sudarynya_barynya.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Барыня , барыня,  сударыня барыня !
Приехала барыня из деревни во Москву ;
Становилась  барыня во палатах каменных .
Мимо тех ли ведь палат шла дорожка хороша;
По той по дороженьке офицер часто ходил,
Офицер часто ходил, на окошечко глядел.
У барыни, барыни глаза разгорелися,
Глаза разгорелися, вся кровь воскипелася.
&laquo; Офицерик молодой , побывай ко мне, душа!&raquo;
У барыни, барыни, сударыни барыни,
Офицерик побывал, со барышней посидел,
У барыни посидел, с нею время препровел.
Чаем-кофием поила, в уста его целовала,
К нежну сердцу прижимала, таки речи говорила:
&laquo; Я счастлива бы была, кабы век с тобой жила !&raquo;','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_251d260e93c5816c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_251d260e93c5816c','Барыня, барыня, сударыня барыня!','Барыня , барыня,  сударыня барыня !
Приехала барыня из деревни во Москву ;
