INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6e683c879031e95f','«Белая акация» («Белой акации гроздья душистые»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Пугачёв, музыка неизвестного автора) | Старинные романсы | https://pesni.retroportal.ru/sr1/07.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Белой акации гроздья душистые
Веют восторгом весны.
Тихо разносится песнь соловьиная
В бледном сверканье, сверканье луны.
Помнишь ли – ночью средь белых акаций
Трели неслись соловья?
Нежно прильнув, ты шептала мне, томная:
&laquo;Верь, навсегда, навсегда я твоя!&raquo;
Время промчалось, и старость нещадную
Нам подослали года;
Но аромата пахучих акаций
Мне не забыть, не забыть никогда!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6e683c879031e95f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6e683c879031e95f','«Белая акация» («Белой акации гроздья душистые»)','Белой акации гроздья душистые
Веют восторгом весны.
Тихо разносится песнь соловьиная
В бледном сверканье, сверканье луны.
Помнишь ли – ночью средь белых акаций
Трели неслись соловья?
Нежно прильнув, ты шептала мне, томная:
&laquo;Верь, навсегда, навсегда я твоя!&raquo;
Время промчалось, и старость нещадную
Нам подослали года;
Но аромата пахучих акаций
Мне не забыть, не забыть никогда!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6e683c879031e95f_63b4a4f2f05f28ca','rpp_6e683c879031e95f','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/07.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_903dd9935819a0cc','Берёзовый сок','(Песня из фильма «Мировой парень»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Вениамин Баснер) | Патриотические песни | https://pesni.retroportal.ru/rodina/berezovy_sok.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из фильма «Мировой парень») | merged_versions: 1','Лишь только подснежник распустится в срок,
Лишь только приблизятся первые грозы,
На белых стволах появляется сок&nbsp;-
То плачут берёзы, то плачут берёзы.
Как часто, пьянея средь ясного дня,
Я брёл наугад по весенним протокам,
И Родина щедро поила меня
Берёзовым соком, берёзовым соком.
Заветную память храня обо всём,
Мы помним холмы и просёлки родные,
Мы трудную службу сегодня несём
Вдали от России, вдали от России.
Где эти туманы родной стороны
И ветви берёз, что над заводью гнутся,
Туда мы с тобой непременно должны
Однажды вернуться, однажды вернуться.
Открой нам, Отчизна, просторы свои,
Заветные чащи открой ненароком&nbsp;-
И так же, как прежде, меня напои
Берёзовым соком, берёзовым соком!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из фильма «Мировой парень»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_903dd9935819a0cc'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_903dd9935819a0cc','Берёзовый сок','Лишь только подснежник распустится в срок,
Лишь только приблизятся первые грозы,
На белых стволах появляется сок&nbsp;-
