INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e8a384ef1a5a247d','Боевая песня партизан','(«Поднимайтесь, воины народа, партизаны сёл и городов...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Михаил Голодный, музыка: Александр Александров) | Песни военных лет | https://pesni.retroportal.ru/vov/boevaya_pesnya_partizan.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Поднимайтесь, воины народа, партизаны сёл и городов...») | merged_versions: 1','Поднимайтесь, воины народа,
Партизаны сёл и городов!
Наша честь, и правда, и свобода
Голос свой слили в единый зов!
Родина взывает нас сиреной,
Вождь зовёт нас братьев и сестёр.
На войне, и правой, и священной,
Как один, врагу дадим отпор!
Отстоим родную землю грудью,
Мы не зря в боях её прошли.
Не хотим - так значит и не будет!
Не топтать врагу родной земли!
Все в ружьё! Сосед, зови соседа!
Нас связала общая борьба.
Если жертвы требует победа,
Лучше смерть в бою, чем жизнь раба!
Рейды в тыл, удары в лоб ночные!
Повторить их нам пора пришла.
Вспомним, братья, годы боевые,
Вспомним партизанские дела!
Выше звёзд сияет наша слава,
Не дрожит оружие в руках.
Встанем на мостах, на переправах,
На дорогах, в сёлах, городах.
Скоро, скоро враг нам поневоле
Возвратит родимые края!
Ждёт детей своих родное поле,
В бой идут отцы и сыновья.
Все в ружьё! Сосед, зови соседа!
Нас связала общая борьба.
Если жертвы требует победа,
Лучше смерть в бою, чем жизнь раба!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Поднимайтесь, воины народа, партизаны сёл и городов...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e8a384ef1a5a247d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e8a384ef1a5a247d','Боевая песня партизан','Поднимайтесь, воины народа,
Партизаны сёл и городов!
Наша честь, и правда, и свобода
