Русское &laquo;Ура!&raquo;');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_712346cd475777e0_4aacef16da2c67a6','rpp_712346cd475777e0','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/boevaya_polkovaya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f66beeaf153a31d3','Бородино','(«Скажи-ка, дядя, ведь недаром Москва, спалённая пожаром...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Михаил Лермонтов, музыка народная) | Песни военных лет | https://pesni.retroportal.ru/vov/borodino.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Скажи-ка, дядя, ведь недаром Москва, спалённая пожаром...») | merged_versions: 1','Скажи-ка, дядя, ведь недаром
Москва, спалённая пожаром,
Французу отдана?
Ведь были ж схватки боевые,
Да, говорят, ещё какие!
Недаром помнит вся Россия
Про день Бородина!
Мы долго молча отступали,
Досадно было, боя ждали,
Ворчали старики:
&laquo;Что ж мы? на зимние квартиры?
Не смеют, что ли, командиры
Чужие изорвать мундиры
О русские штыки?&raquo;
И вот нашли большое поле:
Есть разгуляться где на воле!
Построили редут.
У наших ушки на макушке!
Чуть утро осветило пушки
И леса синие верхушки&nbsp;-
Французы тут как тут.
Забил заряд я в пушку туго
И думал: угощу я друга!
Постой-ка, брат мусью:
Что тут хитрить, пожалуй к бою;
Уж мы пойдем ломить стеною,
Уж постоим мы головою
За родину свою!
И вот сказал, сверкнув очами:
&laquo;Ребята! не Москва ль за нами?
Умрёмте ж под Москвой,
Как наши братья умирали!&raquo;
И умереть мы обещали,
И клятву верности сдержали
Мы в Бородинский бой!
И клятву верности сдержали
Мы в Бородинский бой!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Скажи-ка, дядя, ведь недаром Москва, спалённая пожаром...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f66beeaf153a31d3'), datetime('now')),datetime('now'));
