INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_724c79198ee106d5','«Бубенцы» («Слышу звон бубенцов издалёка»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Кусиков, музыка: Владимир Бакалейников) | Старинные романсы | https://pesni.retroportal.ru/sr1/10.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Сердце будто проснулось пугливо,
Пережитого стало мне жаль;
Пусть же кони с распущенной гривой
С бубенцами умчат меня вдаль.
Слышу звон бубенцов издалёка –
Это тройки знакомый разбег,
А вокруг расстелился широко
Белым саваном искристый снег.
Пусть ямщик свою песню затянет,
Ветер будет ему подпевать;
Что прошло – никогда не настанет,
Так зачем же, зачем горевать!
Припев
Звон бубенчиков трепетно может
Воскресить позабытую тень,
Мою русскую душу встревожить
И встряхнуть мою русскую лень!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_724c79198ee106d5'), datetime('now')),datetime('now'));
