INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_64e10758dd1a603f','Будем драться до победы','(«Всенародной дружной силой вражью нечисть разобьём...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Семён Чернецкий) | Песни военных лет | https://pesni.retroportal.ru/vov/budem_dratsya_do_pobedy.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Всенародной дружной силой вражью нечисть разобьём...») | merged_versions: 1','На Отечество родное
Наглый враг напал, как вор.
Станем дружно всей страною
И дадим врагу отпор.
Припев:
Всенародной дружной силой
Вражью нечисть разобьём
И фашистам на могилу&nbsp;- дружно! -
Кол осиновый вобьём!
Много раз враги пытались
Нас согнуть в бараний рог.
С белым светом распрощались,
Не нашли домой дорог.
Припев
Наши прадеды и деды
Нам оставили завет:
Надо драться до победы,
Без победы жизни нет!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Всенародной дружной силой вражью нечисть разобьём...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_64e10758dd1a603f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_64e10758dd1a603f','Будем драться до победы','На Отечество родное
