INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7bb510d39d5fc941','Бывали дни весёлые...',NULL,'ru','russian_empire_1900_1917',NULL,'1901','pesni.retroportal.ru | (русская народная песня, в основе которой баллада Прохора Горохова « Изменница », сочинённая поэтом в 1901 году) | Народные песни | https://pesni.retroportal.ru/np1/byvali_dni_veselye.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Бывали дни весёлые &nbsp;—
Гулял я, молодец ,
Не знал тоски-кручинушки ,
Как вольный удалец .
Бывало, спашешь пашенку ,
Лошадок уберёшь,
А сам тропой знакомою
В заветный дом пойдёшь .
Иду, там дожидается
Красавица моя ,
Глаза полуоткрытые,
Румяна и бела.
Но вот однажды осенью
Пришёл любви конец ,
И к ней приезжий с ярмарки
Посватался купец .
Красавица-изменница
Забыла про меня,
Забыла мою хижину,
В хоромы жить пошла .
Живёт у чорта старого ,
Как в клетке золотой ,
Как куколка наряжена ,
С распущенной косой .
Не раз я чорта старого
Просил и умолял,
Не раз просил и кланялся,
Но он не уступал.
И идучи оттудова,
Я точно опьянел,
Всю тёмную я ноченьку
В раздумье просидел .
Напала мысль злодейская,
Впотьмах нашёл топор,
Простился с отцом, с матерью
И вышел через двор.
Иду, а ночка тёмная,
Вдали журчал ручей,
И дело совершилося ,
С тех пор я стал злодей...
В Сибирь меня, на каторгу ,
Погонят молодца,
За девку черноокую,
За чорта, за купца.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7bb510d39d5fc941'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7bb510d39d5fc941','Бывали дни весёлые...','Бывали дни весёлые &nbsp;—
