INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_7bb510d39d5fc941_416b2ae72b8730e9','rpp_7bb510d39d5fc941','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/byvali_dni_veselye.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3e08d7c7a322bd75','В городском саду','(«В городском саду играет духовой оркестр...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Матвей Блантер) | Эстрадные песни | https://pesni.retroportal.ru/estrada/v_gorodskom_sadu_igraet_duhovoj_orkestr.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («В городском саду играет духовой оркестр...») | merged_versions: 1','В городском саду играет
Духовой оркестр.
На скамейке, где сидишь ты,
Нет свободных мест.
От того ль, что пахнет липа
Иль роса блестит,
Мне от глаз твоих красивых
Взор не отвести.
Припев:
Прошёл чуть не полмира я&nbsp;-
С такой, как ты, не встретился.
И думать не додумался,
Что встречу я тебя.
Верь, такой, как ты, на свете
Нет наверняка,
Чтоб навеки покорила
Сердце моряка.
По морям, по океанам
Мне легко пройти,
Но к такой, как ты, желанной,
Видно, нет пути.
Припев
Вот рассвет весенний гасит
Звёздочки в пруду.
Но ничто не изменилось
В городском саду.
На скамейке, где сидишь ты,
Нет свободных мест...
В городском саду играет
Духовой оркестр.
Припев
Слушать  мелодию песни &laquo;В городском саду&raquo;  композитора Матвея Блантера. Народный духовой оркестр города Анапа. Дирижёр Валерий Степанов.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«В городском саду играет духовой оркестр...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3e08d7c7a322bd75'), datetime('now')),datetime('now'));
