INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_3e08d7c7a322bd75_69f5bfd2f376504f','rpp_3e08d7c7a322bd75','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/v_gorodskom_sadu_igraet_duhovoj_orkestr.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5115452ee65815e1','В деревне было Ольховке',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/05.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','В деревне было Ольховке.
Лапти, да лапти, да лапти мои,
Эх, лапти, да лапти, да лапти мои.
Эх, лапти мои, лапти липовые,
Вы не бойтесь, ходитё,
Тятька новые сплетё!
Эх, ну! Тьфу!
Там жил-был парень Андреяшка,
Припев
Полюбил Андреяшка Парашку.
Припев
Он носил ей дороги подарци:
Припев
Всё прянцы да баранцы.
Припев
Не велел ему тятька жениться...
Припев
Эх, заплакал тут наш Андреяшка,
Припев
А за ним заревела Парашка.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5115452ee65815e1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5115452ee65815e1','В деревне было Ольховке','В деревне было Ольховке.
Лапти, да лапти, да лапти мои,
Эх, лапти, да лапти, да лапти мои.
Эх, лапти мои, лапти липовые,
Вы не бойтесь, ходитё,
Тятька новые сплетё!
Эх, ну! Тьфу!
Там жил-был парень Андреяшка,
Припев
Полюбил Андреяшка Парашку.
Припев
Он носил ей дороги подарци:
Припев
Всё прянцы да баранцы.
Припев
Не велел ему тятька жениться...
Припев
Эх, заплакал тут наш Андреяшка,
Припев
А за ним заревела Парашка.
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_5115452ee65815e1_2d599912f4ef2a26','rpp_5115452ee65815e1','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/05.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_42b8e07a7dd5d75d','В защиту мира','(«Вновь богачи раздувают пожар...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Илья Френкель, музыка: Виктор Белый) | Патриотические песни | https://pesni.retroportal.ru/rodina/v_zashitu_mira.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Вновь богачи раздувают пожар...») | merged_versions: 1','Вновь богачи раздувают пожар&nbsp;-
Миру готовят смертельный удар.
Но против них миллионы людей:
Армия мира всех сильней!
Припев:
В зашиту мира вставайте люди!
Ряды тесней, страна к стране!
И пусть над миром сильней орудий
Гремит призыв наш: Не быть войне!
Новой войне мы пути преградим,
Не для войны сыновей мы растим,
Не для траншей зеленеют поля,
К миру стремится вся земля!
Припев
Вместе с народом советской страны
Армия мира сильнее войны.
Слушай и ты, гражданин, патриот:
Долг наш священный к борьбе зовет!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Вновь богачи раздувают пожар...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_42b8e07a7dd5d75d'), datetime('now')),datetime('now'));
