INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_79e52931c0235f07','В лесу родилась ёлочка','(Новогодняя песенка)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Раиса Кудашева, музыка: Леонид Бекман) | Песни для детей | https://pesni.retroportal.ru/deti/v_lesu_rodilas_elochka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Новогодняя песенка) | merged_versions: 1','В лесу родилась ёлочка,
В лесу она росла,
Зимой и летом стройная,
Зелёная была.
Метель ей пела песенку:
&laquo;Спи, ёлочка, бай-бай!&raquo;
Мороз снежком укутывал:
&laquo;Смотри, не замерзай!&raquo;
Трусишка-зайка серенький
Под ёлочкой скакал,
Порою волк, сердитый волк,
Рысцою пробегал.
Чу! Снег по лесу частому
Под полозом скрипит;
Лошадка мохноногая
Торопится, бежит.
Везёт лошадка дровенки,
А в дровнях - мужичок,
Срубил он нашу ёлочку
Под самый корешок.
Теперь она, нарядная,
На праздник к нам пришла
И много, много радости
Детишкам принесла.
На сайте &laquo;Retroportal.ru&raquo;   опубликован очерк   историка, журналиста, популяризатора литературы   Алексея Корнеева  , посвящённый авторам песенки &laquo;В лесу родилась ёлочка&raquo; (глава из книги А.В.&nbsp;Корнеева 2023 года &laquo;Страницы прошлого листая... Очерки о русских писателях&raquo;).','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Новогодняя песенка)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_79e52931c0235f07'), datetime('now')),datetime('now'));
