INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_67e56aa4f58faa59','В любимом Бухаресте','(«Вечно будем мы вместе май встречать в Бухаресте...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (русский текст: Яков Белинский, музыка: Михай Вескан) | Эстрадные песни | https://pesni.retroportal.ru/estrada/v_lyubimom_buhareste.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Вечно будем мы вместе май встречать в Бухаресте...») | merged_versions: 1','Солнечной майской порой
Цветут в Бухаресте сады.
В парке над синей рекой
Встретили май я и ты.
Плыл, затихая вдали,
Сверкающий, праздничный вальс.
За руки взявшись, мы шли,
И песня наша лилась!
Припев:
Вечно будем мы вместе
Май встречать в Бухаресте.
Полны света и счастья
Вольные наши края!
С каждым годом всё краше
Город юности нашей!
Счастье светлое наше
Строим мы с вами, друзья!
Годы летят чередой...
Опять распустились цветы...
Снова зелёной весной
Рядом идём я и ты.
Вижу в ночи голубой
Я блеск твоих радостных глаз.
Ярко горит в них любовь,
Она всё крепче у нас!
Припев
Светит нам счастья звезда!
Мы сделали былью мечты!
И неразлучны всегда
Будем, мой друг, я и ты!
Вечны любовь и весна!
Счастливей нас не найдёшь!
В майском наряде страна,
Поёт кругом молодёжь!','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Вечно будем мы вместе май встречать в Бухаресте...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_67e56aa4f58faa59'), datetime('now')),datetime('now'));
