INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d2713bb6e2bd388f','В ноль часов и ноль минут','(Новогодняя песенка)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Танич, музыка: Ян Френкель) | Песни для детей | https://pesni.retroportal.ru/deti/v_00_chasov_00_minut.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Новогодняя песенка) | merged_versions: 1','На часах двенадцать бьёт!
Кто же виноват,
Что приходит Новый год,
А ребята спят?
Припев:
Новый год,
Он раз в году!
Так что же он копается?
Девять&nbsp;- жду его!
Десять&nbsp;- жду!
А глаза слипаются.
Дед Мороза всюду ждут!
Он придёт пешком
В ноль часов и ноль минут
С голубым мешком.
Припев
Слышу&nbsp;- кружится земля!
На часы гляжу!
Ой до этого нуля
Я не досижу.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Новогодняя песенка)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d2713bb6e2bd388f'), datetime('now')),datetime('now'));
