INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f99e9f7d533e7a79','В отраду грусти и мученья...',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/v_otradu_grusti_i_muchenya.html','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','В отраду грусти и мученья ,
Что я, мой свет, тобой терплю ,
Инова нет мне утешенья
Как только что я слёзы лью ;
О ты сладчайшая утеха !
Что в свете есть тебя миляй?
А есть ли ты, ах! Без успеха,
Ты самой лютой смерти зляй.
Несносно как злодей терзает:
Но как ни зла сия напасть.
Боль вящу сердце ощущает,
Питая тщетно нежну страсть;
А то лютяе несказанно,
Что ты меня к любви взманя,
И множа жар мой непрестанно
Днесь оставляешь ты меня.
Уже на место ласки строгость
Являет твой прелестной взгляд ,
На место нежности суровость
Уста твои мне говорят .
Всё вижу я в тебе пременно
К смертельной горести моей.
О сердце толь ожесточенно
Доколе будешь в мысли сей!
Иль вечно мне тобой терзаться,
Всегда твою холодность зреть,
Грустить, и ах! Не утешаться,
В отчаяньи и умереть.
Увяну в самом лутчем цвете,
Когда угодно то судьбе;
А ты оставшися на свете
Ищи верняй меня себе.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f99e9f7d533e7a79'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f99e9f7d533e7a79','В отраду грусти и мученья...','В отраду грусти и мученья ,
