INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_527e0b6822951548','В поход','(«Долой фашизм! Удары мы утроим, сплотимся все в работе и бою...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Александр Прокофьев, музыка: Александр Александров) | Песни военных лет | https://pesni.retroportal.ru/vov/v_pohod.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Долой фашизм! Удары мы утроим, сплотимся все в работе и бою...») | merged_versions: 1','В поход! В поход! Зовёт Отчизна смелых.
В поход! В поход! Объявлена война.
На боевое воинское дело
Зовёт нас всех советская страна!
Долой фашизм! Удары мы утроим,
Сплотимся все в работе и бою.
И, как в былом, опять народ героев
Идёт на бой за Родину свою.
Мы в бой идём за жизнь и за свободу.
Страна отваги, Родина труда
Сказала Красной Армии, народу
&laquo;Враг должен быть разбит, разгромлен навсегда!&raquo;
Сегодня все стеной единой встали.
Пошли войска на подвиг боевой.
И нас ведёт к победам новым Сталин,
Великий вождь Отчизны дорогой.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Долой фашизм! Удары мы утроим, сплотимся все в работе и бою...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_527e0b6822951548'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_527e0b6822951548','В поход','В поход! В поход! Зовёт Отчизна смелых.
В поход! В поход! Объявлена война.
На боевое воинское дело
Зовёт нас всех советская страна!
Долой фашизм! Удары мы утроим,
Сплотимся все в работе и бою.
И, как в былом, опять народ героев
Идёт на бой за Родину свою.
Мы в бой идём за жизнь и за свободу.
Страна отваги, Родина труда
Сказала Красной Армии, народу
&laquo;Враг должен быть разбит, разгромлен навсегда!&raquo;
Сегодня все стеной единой встали.
Пошли войска на подвиг боевой.
И нас ведёт к победам новым Сталин,
Великий вождь Отчизны дорогой.');
