INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_08da955cef8b5557','В предгорьях Алтая','(«В предгорьях Алтая, в посёлке большом, среди зеленеющих гор...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Жаров, музыка: Леонид Бакалов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/v_predgoryah_altaya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («В предгорьях Алтая, в посёлке большом, среди зеленеющих гор...») | merged_versions: 1','В предгорьях Алтая, в посёлке большом,
Среди зеленеющих гор
Стоит у дороги бревенчатый дом,
Твой новый дом, шахтёр.
Кругом серебристого угля пласты,
А дальше долина озёр.
Лесного наряда такой красоты
Нигде не видал шахтёр.
В сиреневый садик заросший травой
Тропинка вплетает узор,
И счастье приходит с хорошей молвой
В твой новый дом, шахтёр.
Под вечер шахтёра встречает жена.
Спокойный и ласковый взор.
Жена - сибирячка, такой, как она
Нигде не видал шахтёр.
Вдали загорается звёздный алмаз,
Луна озаряет простор.
Сибирские дали, привольный Кузбасс
Твой новый дом, шахтёр.
В заливе за озером с той стороны
Мерцает рыбацкий костёр.
Такой синевы и такой тишины
Нигде не видал шахтёр.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«В предгорьях Алтая, в посёлке большом, среди зеленеющих гор...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_08da955cef8b5557'), datetime('now')),datetime('now'));
