INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_dafb81282e029c98','В рабочем посёлке','(«В рабочем посёлке всё тихо давно, стоят задремавшие ёлки...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Юрий Милютин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/v_rabochem_poselke.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («В рабочем посёлке всё тихо давно, стоят задремавшие ёлки...») | merged_versions: 1','В рабочем посёлке всё тихо давно,
Стоят задремавшие ёлки,
И светится только одно лишь окно
В уснувшем рабочем посёлке.
Там трое строителей, славных ребят,
Закончив часы трудовые,
Три друга хороших сегодня не спят,
Молчат и вздыхают впервые.
Был первый из них, безусловно, герой,
Да все они в славе, поверьте,
Но первый вздыхает, вздыхает второй,
А следом вздыхает и третий.
И как полагается верным друзьям
Они во вражде не бывали.
Но дело тут в том, что приехала к нам
Весёлая девушка Валя.
И вот загрустили они той порой,
Казалось им: солнце не светит.
Как первый вздохнет, так вздыхает второй,
А следом вздыхает и третий.
В рабочем посёлке всё тихо давно,
Стоят задремавшие ёлки,
И светится только одно лишь окно
В уснувшем рабочем посёлке.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«В рабочем посёлке всё тихо давно, стоят задремавшие ёлки...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_dafb81282e029c98'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_dafb81282e029c98','В рабочем посёлке','В рабочем посёлке всё тихо давно,
