INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5de7dfc862227445','В траве сидел кузнечик','(Песня из мультфильма «Приключения Незнайки и его друзей»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Носов, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/v_trave_sidel_kuznechik.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Приключения Незнайки и его друзей») | merged_versions: 1','В траве сидел кузнечик, в траве сидел кузнечик,
Совсем как огуречик, зелёненький он был.
Представьте себе, представьте себе,
Совсем как огуречик,
Представьте себе, представьте себе,
Зелёненький он был.
Он ел одну лишь травку, он ел одну лишь травку,
Не трогал и козявку, и с мухами дружил.
Представьте себе, представьте себе,
Не трогал и козявку
Представьте себе, представьте себе,
И с мухами дружил.
Но вот пришла лягушка, но вот пришла лягушка&nbsp;-
Прожорливое брюшко&nbsp;- и съела кузнеца.
Представьте себе, представьте себе,
Прожорливое брюшко,
Представьте себе, представьте себе,
И съела кузнеца.
Не думал, не гадал он, не думал, не гадал он,
Никак не ожидал он такого вот конца.
Представьте себе, представьте себе,
Никак не ожидал он
Представьте себе, представьте себе,
Такого вот конца.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Приключения Незнайки и его друзей»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5de7dfc862227445'), datetime('now')),datetime('now'));
