INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_80431afbe9afd92c','В час роковой',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Михаил Шишкин и Софус Гердаль) | Старинные романсы | https://pesni.retroportal.ru/sr1/11.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','В час роковой, когда встретил тебя,
Трепетно сердце забилось во мне.
Страстно, безумно тебя полюбя,
Весь я горю, как в огне.
Сколько счастья, сколько муки
Ты, любовь, несёшь с собой!
Час свиданья, час разлуки, -
Дышит всё тобой одной.
Снятся мне милые глазки твои,
Чудный твой стан, твоя красота.
Вся создана ты для знойной любви,
Вся ты любовь, вся – мечта.
Сколько счастья, сколько муки
Ты, любовь, несёшь с собой!
Час свиданья, час разлуки, -
Дышит всё тобой одной.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_80431afbe9afd92c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_80431afbe9afd92c','В час роковой','В час роковой, когда встретил тебя,
