INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9c0aaae12f86fabd','Вальс о вальсе','(«Вальс устарел, - говорит кое‑кто, смеясь...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Евтушенко, музыка: Эдуард Колмановский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vals_o_valse.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Вальс устарел, - говорит кое‑кто, смеясь...») | merged_versions: 1','- Вальс устарел, -
Говорит кое-кто, смеясь.
Век усмотрел
В нём отсталость и старость.
Робок, несмел,
Наплывает мой первый вальс...
Почему не могу
Я забыть этот вальс?
Твист и чарльстон,
Вы заполнили шар земной.
Вальс оттеснён,
Без вины виноватый.
Но, затаён,
Он всегда и везде со мной,
И несёт он меня,
И качает меня,
Как туманной волной.
Смеётся вальс
Над всеми модами века.
И с нами вновь
Танцует старая Вена.
И Штраус где-то тут сидит,
Наверно,
И кружкой в такт стучит,
На нас не ворчит...
Не ворчит...
Вальс воевал,
Он в шинели шёл, запылён.
Вальс напевал
Про Манчжурские сопки.
Вальс навевал
Нам на фронте осенний сон.
И, как друг фронтовой,
Не забудется он.
Вальс у костра
Где-то снова в тайге сейчас.
И Ангара
Подпевает, волнуясь.
И до утра
С нами сосны танцуют вальс...
Пусть проходят года,
Всё равно никогда
Не состарится вальс.
Поёт гармонь,
Поёт в ночном полумраке.
Он с нами, вальс,&nbsp;-
В ковбойке, а не во фраке.
Давай за вальс
Поднимем наши фляги,
И мы ему нальём -
Нальём и споём,
И споём...
- Вальс устарел,&nbsp;-
Говорит кое-кто, смеясь.
Век усмотрел
В нём отсталость и старость.
Робок, несмел,
Наплывает мой первый вальс.
Никогда не смогу,
Никогда не смогу
Я забыть этот вальс.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Вальс устарел, - говорит кое‑кто, смеясь...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9c0aaae12f86fabd'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9c0aaae12f86fabd','Вальс о вальсе','- Вальс устарел, -
Говорит кое-кто, смеясь.
Век усмотрел
В нём отсталость и старость.
Робок, несмел,
Наплывает мой первый вальс...
Почему не могу
Я забыть этот вальс?
Твист и чарльстон,
Вы заполнили шар земной.
Вальс оттеснён,
Без вины виноватый.
Но, затаён,
Он всегда и везде со мной,
И несёт он меня,
И качает меня,
Как туманной волной.
Смеётся вальс
Над всеми модами века.
И с нами вновь
Танцует старая Вена.
И Штраус где-то тут сидит,
Наверно,
И кружкой в такт стучит,
На нас не ворчит...
Не ворчит...
Вальс воевал,
Он в шинели шёл, запылён.
Вальс напевал
Про Манчжурские сопки.
Вальс навевал
Нам на фронте осенний сон.
И, как друг фронтовой,
Не забудется он.
Вальс у костра
Где-то снова в тайге сейчас.
И Ангара
Подпевает, волнуясь.
И до утра
С нами сосны танцуют вальс...
Пусть проходят года,
Всё равно никогда
Не состарится вальс.
Поёт гармонь,
Поёт в ночном полумраке.
Он с нами, вальс,&nbsp;-
В ковбойке, а не во фраке.
Давай за вальс
Поднимем наши фляги,
И мы ему нальём -
Нальём и споём,
И споём...
- Вальс устарел,&nbsp;-
Говорит кое-кто, смеясь.
Век усмотрел
В нём отсталость и старость.
Робок, несмел,
Наплывает мой первый вальс.
Никогда не смогу,
Никогда не смогу
Я забыть этот вальс.');
