INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_38fa50e55be8e6bb','Вальс расставания','(Песня из кинофильма «Женщины»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Константин Ваншенкин, музыка: Ян Френкель) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vals_rasstavaniya_film_zhenshiny.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из кинофильма «Женщины») | merged_versions: 1','Слышишь, тревожные дуют ветра?
Нам расставаться настала пора.
Кружится, кружится пёстрый лесок,
Кружится, кружится старый вальсок.
Старый, забытый, старый забытый вальсок.
Ты, совершая положенный путь,
В дальних краях это всё не забудь,&nbsp;-
Эту реку и прибрежный песок,
Этот негромко звучащий вальсок.
Этот негромкий, этот негромкий вальсок.
Мы расстаёмся, чтоб встретиться вновь:
Ведь остаётся на свете любовь.
Кружится первый осенний листок,
Кружится в памяти старый вальсок,
Юности нашей, юности нашей вальсок.
Волосы ветром сдувает со лба...
Музыка эта - как наша судьба.
Снегом слегка обжигает висок,
Кружится в сердуе тот старый вальсок.
В сердце тот старый, в сердце тот старый вальсок.
Слышишь, тревожные дуют ветра?
Нам расставаться настала пора.
Кружится, кружится пёстрый лесок,
Кружится, кружится старый вальсок.
Старый, забытый, старый забытый вальсок.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из кинофильма «Женщины»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_38fa50e55be8e6bb'), datetime('now')),datetime('now'));
