INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ffd4e646a32ebfa6','Вам не понять моей печали',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr1/12.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вам не понять моей печали,
Когда, растерзаны тоской,
Надолго вдаль не провожали
Того, кто властвует душой!
Того, кто властвует душой!
Вам не понять, вам не понять,
Вам не понять моей печали!
Вам не понять моей печали,
Когда в очах, вам дорогих,
Холодности вы не читали,
Презренья не видали в них.
Припев
Вам не понять моей печали,
Когда трепещущей рукой,
В порывах гнева, не сжигали
Письма подруги молодой.
Вам не понять моей печали!
Припев
Вам не понять моей печали,
Когда вы ревности вулкан
В своей груди не ощущали
И не тревожил вас обман.
Вам не понять моей печали!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ffd4e646a32ebfa6'), datetime('now')),datetime('now'));
