INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2b54f560be5075a4','Ваши пальцы пахнут ладаном','(посвящение актрисе Вере Холодной)','ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Александр Вертинский) | Старинные романсы | https://pesni.retroportal.ru/sr1/13.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | subtitle: (посвящение актрисе Вере Холодной) | merged_versions: 1','Ваши пальцы пахнут ладаном,
А в ресницах спит печаль.
Ничего теперь не надо нам,
Никого теперь не жаль.
И когда весенней Вестницей
Вы пойдете в синий край,
Сам Господь по белой лестнице
Поведёт Вас в светлый рай.
Тихо шепчет дьякон седенький,
За поклоном бьёт поклон
И метёт бородкой реденькой
Вековую пыль с икон.
Ваши пальцы пахнут ладаном,
А в ресницах спит печаль.
Ничего теперь не надо нам,
Никого теперь не жаль.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "retroportal-subtitle:(посвящение актрисе Вере Холодной)", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2b54f560be5075a4'), datetime('now')),datetime('now'));
