INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d103c332c1a902f0','Вдоль да по речке',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/07.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вдоль да по речке,
Вдоль да по Казанке
Серый селезень плывёт.
Ой, да люли, люли,
Ой, да люли, люли,
Серый селезень плывёт.
Вдоль да по бережку,
Вдоль да по крутому
Добрый молодец идёт.
Сам он со кудрями,
Сам он со русыми
Разговаривает:
&laquo;Кому мои кудри,
Кому мои русы
Достанутся расчесать?&raquo;
Доставались кудри,
Доставались русы
Старой бабе расчесать.
Как она ни чешет,
Как она ни гладит,
Только волосы дерёт.
Вдоль да по речке,
Вдоль да по Казанке,
Серый селезень плывёт.
Вдоль да по бережку,
Вдоль да по крутому
Добрый молодец идёт.
Сам он со кудрями,
Сам он со русыми
Разговаривает:
&laquo;Кому мои кудри,
Кому мои русы
Достанутся расчесать?&raquo;
Доставались кудри,
Доставались русы
Молодой вдове чесать.
Как она ни чешет,
Как она ни гладит,
Только горьки слёзы льёт.
Доставались кудри,
Доставались русы
Красной девице чесать.
Уж она и чешет,
Уж она и гладит,
Волос к волосу кладёт.
Вдоль да по речке,
Вдоль да по Казанке
Серый селезень плывёт.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d103c332c1a902f0'), datetime('now')),datetime('now'));
