INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8a4da974259c3ce5','Вдоль по улице метелица метёт',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Дмитрий Глебов, музыка: Александр Варламов) | Народные песни | https://pesni.retroportal.ru/np1/08.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вдоль по улице метелица метёт,
