INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_cbb44c0c5426c390','Вернись, я всё прощу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Ленский, музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr1/14.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вернись, я всё прощу: упрёки, подозренья,
Мучительную боль невыплаканных слёз,
Укор речей твоих, безумные мученья,
Позор и стыд твоих угроз.
Я упрекать тебя не стану и не смею:
Мы так недавно, так нелепо разошлись.
Ведь ты любил меня, и я была твоею!
Зачем же, зачем же ты ушёл? Вернись!
О, сколько, сколько раз вечернею порою
В запущенном саду на каменной скамье
Рыдала я, забытая тобою,
О милом, дорогом, о розе, о весне.
Я счастье прошлое благословляю.
О, если бы мечты мои сбылись!
Ведь я люблю тебя, люблю и проклинаю!
Отдай, отдай мне снова жизнь, вернись!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_cbb44c0c5426c390'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_cbb44c0c5426c390','Вернись, я всё прощу','Вернись, я всё прощу: упрёки, подозренья,
Мучительную боль невыплаканных слёз,
Укор речей твоих, безумные мученья,
Позор и стыд твоих угроз.
Я упрекать тебя не стану и не смею:
Мы так недавно, так нелепо разошлись.
Ведь ты любил меня, и я была твоею!
Зачем же, зачем же ты ушёл? Вернись!
О, сколько, сколько раз вечернею порою
В запущенном саду на каменной скамье
Рыдала я, забытая тобою,
О милом, дорогом, о розе, о весне.
Я счастье прошлое благословляю.
О, если бы мечты мои сбылись!
Ведь я люблю тебя, люблю и проклинаю!
Отдай, отдай мне снова жизнь, вернись!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_cbb44c0c5426c390_23b1f428e9763a9e','rpp_cbb44c0c5426c390','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/14.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_05759039ce00e07f','Вернулся я на Родину','(«Вернулся на Родину, шумят берёзки встречные...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Марк Фрадкин) | Патриотические песни | https://pesni.retroportal.ru/rodina/vernulsya_ya_na_rodinu.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Вернулся на Родину, шумят берёзки встречные...») | merged_versions: 1','Вернулся на Родину. Шумят берёзки встречные.
Я много лет без отпуска служил в чужом краю.
И вот иду как в юности я улицей Заречною,
И нашей тихой улицы совсем не узнаю.
Здесь вырос сад над берегом с тенистыми дорожками,
Окраины застроились, завода&nbsp;- не узнать.
В своей домашней кофточке, в косыночке горошками
Седая, долгожданная, меня встречает мать.
Здесь столько нами прожито, здесь столько троп исхожено,
Здесь столько испытали мы и радостей и гроз.
Пусть плакать в час свидания солдату не положено,
Но я любуюсь Родиной и не скрываю слёз.
Вернулся я на Родину. И у пруда под ивою
Ты ждёшь, как в годы давние, прихода моего...
Была бы наша Родина богатой да счастливою,
А выше счастья Родины нет в мире ничего!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Вернулся на Родину, шумят берёзки встречные...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_05759039ce00e07f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_05759039ce00e07f','Вернулся я на Родину','Вернулся на Родину. Шумят берёзки встречные.
