INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_46ed44183a0b7395','Верные друзья','(Песня из кинофильма «Верные друзья»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Тихон Хренников) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vernye_druzya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из кинофильма «Верные друзья») | merged_versions: 1','Шёл ли дальней стороною,
Плыл ли морем я, -
Всюду были вы со мною,
Верные друзья.
И бывало, в час тревоги,
В сумрачный денёк,
Освещал нам все дороги
Дружбы огонёк.
И в разлуке, и в печали
Были мы тверды,
Сколько раз мы выручали
Друга из беды.
Пусть проходят год за годом
Долгой чередой,&nbsp;-
Наша дружба остаётся
Вечно молодой.
В каждом слове, в каждом деле
Дружбе верен ты.
С дружбой всё яснее цели,
Ближе все мечты.
Старой дружбы, словно песни,
Забывать нельзя.
И идут по жизни вместе
Верные друзья!','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из кинофильма «Верные друзья»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_46ed44183a0b7395'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_46ed44183a0b7395','Верные друзья','Шёл ли дальней стороною,
Плыл ли морем я, -
Всюду были вы со мною,
Верные друзья.
И бывало, в час тревоги,
