INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a427f871dd6fa710','Весёлый марш','(«Надо! Надо! Надо нам, ребята, жизнь красивую прожить...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Харитонов, музыка: Владимир Шаинский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vesely_marsh.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Надо! Надо! Надо нам, ребята, жизнь красивую прожить...») | merged_versions: 1','Припев:
Надо!
Надо!
Надо нам, ребята,
Жизнь красивую прожить.
Надо что-то важное, ребята,
В нашей жизни совершить!
Сама собою жизнь ведь не построится,
Вода под камушек не потечёт.
Нам на достигнутом не успокоиться
И не снижать души своей полёт.
Припев
А мы работаем, пускай устали мы,
Но от усталости никто не хмур.
Под вечер солнышку мы скажем на небе:
Не уходило б ты на перекур.
Припев
А нашим девушкам мы скажем: милые,
Вы спойте ласково нам о любви.
С горами сможем мы тягаться силою,
Нам вдохновение даёте вы!
Припев
А в небе радуга, как звонкий колокол.
А небо синее глядит в глаза.
Мечта нам видится не белым облаком, -
Зарёй, летящею на парусах.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Надо! Надо! Надо нам, ребята, жизнь красивую прожить...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a427f871dd6fa710'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a427f871dd6fa710','Весёлый марш','Припев:
Надо!
Надо!
Надо нам, ребята,
Жизнь красивую прожить.
Надо что-то важное, ребята,
В нашей жизни совершить!
Сама собою жизнь ведь не построится,
Вода под камушек не потечёт.
Нам на достигнутом не успокоиться
И не снижать души своей полёт.
Припев
А мы работаем, пускай устали мы,
