INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b395884828db739b','Весенний марш','(«Восходит солнце ясное, блестит в траве роса...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Михалков, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/vesenniy_marsh.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Восходит солнце ясное, блестит в траве роса...») | merged_versions: 1','Восходит солнце ясное.
Блестит в траве роса.
Цветут вокруг прекрасные
Мои поля, мои леса.
Страна моя любимая,
На всей земле одна
Стоит никем непобедимая
Моя Советская страна!
Припев:
Товарищ, товарищ!
В труде и в бою
Храни беззаветно Отчизну свою!
С тобой твой великий
Советский народ.
Во имя свободы
Сквозь грозы, невзгоды
Он к цели заветной
Непреклонно идёт!
Кто может быть задорнее,
Чем наша молодёжь!
Проворней и упорнее
Ты не найдёшь, ты не найдёшь!
Легко и вольно дышится
В краю где мы живём.
И если где-то песня слышится,
Так это значит&nbsp;- мы поём.
Припев
Всё то, о чем мечтается,
Всё то, что мы хотим,
Всё то, что нам понравится,
Мы создадим, мы создадим!
В трудах, в боях проверенный
На много лет вперёд
Глядит и смело, и уверенно
Большой и дружный наш народ!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Восходит солнце ясное, блестит в траве роса...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b395884828db739b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b395884828db739b','Весенний марш','Восходит солнце ясное.
