INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fae0798278a65e53','Весна идёт','(«Журчат ручьи, кричат грачи...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Вольпин, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vesna_idet.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Журчат ручьи, кричат грачи...») | merged_versions: 1','По бульварам чистым шёл прохожий,
Птицы пели трели про апрель.
Нёс прохожий
Толстый чернокожий
Многоуважаемый портфель.
Шёл мужчина чинно и солидно,
Презирая птичий перезвон.
По лицу мужчины было видно,
Что весну не одобряет он.
Ему эта весна ни к чему...
И песня не нужна никому...
И вешняя вода ерунда...
Да! Да! Ерунда!
Журчат ручьи,
Кричат грачи,
И тает снег, и сердце тает.
И даже пень
В апрельский день
Берёзкой снова стать мечтает.
Весёлый шмель гудит весеннюю тревогу,
Кричат задорные весёлые скворцы,
Кричат скворцы
Во все концы:
&laquo;Весна идет - весне дорогу!&raquo;','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Журчат ручьи, кричат грачи...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fae0798278a65e53'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_fae0798278a65e53','Весна идёт','По бульварам чистым шёл прохожий,
Птицы пели трели про апрель.
Нёс прохожий
Толстый чернокожий
Многоуважаемый портфель.
Шёл мужчина чинно и солидно,
Презирая птичий перезвон.
По лицу мужчины было видно,
Что весну не одобряет он.
Ему эта весна ни к чему...
И песня не нужна никому...
И вешняя вода ерунда...
Да! Да! Ерунда!
Журчат ручьи,
Кричат грачи,
И тает снег, и сердце тает.
И даже пень
В апрельский день
Берёзкой снова стать мечтает.
Весёлый шмель гудит весеннюю тревогу,
