Кричат скворцы
Во все концы:
&laquo;Весна идет - весне дорогу!&raquo;');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_fae0798278a65e53_fdd5fd5e9aa30de5','rpp_fae0798278a65e53','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/vesna_idet.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6f257656890803ff','Весной Волга разольётся',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/09.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Весной Волга разольётся,
Волга матушка-река,
А сердечушко забьётся,
Заливает берега.
Сирень цветёт,
Не плачь, придёт...
Ой, Коля, грудь больно,
Любила – довольно.
С горя девка слёзы ронит,
Волга матушка-река,
А от песни Волга стонет,
Заливает берега.
Припев
Кто колечко моё носит,
Волга матушка-река,
Лихорадка того бросит,
Заливает берега.
Припев
Она моя сладка вишня,
Волга матушка-река,
Запоёт – далёко слышно,
Заливает берега.
Припев
Речка встанет, пойду по льду,
Волга матушка-река,
Милый бросит – новых найду,
Заливает берега.
Припев
Что мне делать – ум расшёлся,
Волга матушка-река,
Один есть – другой нашёлся,
Заливает берега.
Припев
Сошью платье из батиста,
Волга матушка-река,
Полюблю я гармониста,
Заливает берега.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6f257656890803ff'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6f257656890803ff','Весной Волга разольётся','Весной Волга разольётся,
Волга матушка-река,
А сердечушко забьётся,
Заливает берега.
Сирень цветёт,
Не плачь, придёт...
Ой, Коля, грудь больно,
Любила – довольно.
С горя девка слёзы ронит,
Волга матушка-река,
А от песни Волга стонет,
Заливает берега.
Припев
Кто колечко моё носит,
Волга матушка-река,
Лихорадка того бросит,
Заливает берега.
Припев
Она моя сладка вишня,
Волга матушка-река,
Запоёт – далёко слышно,
Заливает берега.
Припев
Речка встанет, пойду по льду,
Волга матушка-река,
Милый бросит – новых найду,
Заливает берега.
Припев
Что мне делать – ум расшёлся,
Волга матушка-река,
Один есть – другой нашёлся,
Заливает берега.
Припев
Сошью платье из батиста,
Волга матушка-река,
Полюблю я гармониста,
Заливает берега.
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6f257656890803ff_4ec1f20f16de4e0b','rpp_6f257656890803ff','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/09.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5fb7ff5be570ddb7','Ветка сирени',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Гальперин, музыка: Аркадий Волошин) | Старинные романсы | https://pesni.retroportal.ru/sr1/16.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','У вагона я ждал, расставаясь с тобой,
Полный грусти прощальных мгновений,
И в мечтах о былом, вся душою со мной,
Ты мне бросила ветку сирени.
Резкий голос звонка нас от дум оторвал,
Налетели потоки сомнений.
И, тебе глядя вслед, весь в слезах целовал
Я прощальную ветку сирени...
Поезд где-то исчез в серой дымке вдали,
Подплывали вечерние тени...
И бесцельно я брёл по дороге в пыли
С одинокою веткой сирени.
Я вернулся к себе... Этот вечер унёс
Все надежды, всю радость стремлений...
В эту ночь отцвела от объятий и слёз
Истомлённая ветка сирени...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5fb7ff5be570ddb7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5fb7ff5be570ddb7','Ветка сирени','У вагона я ждал, расставаясь с тобой,
Полный грусти прощальных мгновений,
И в мечтах о былом, вся душою со мной,
Ты мне бросила ветку сирени.
Резкий голос звонка нас от дум оторвал,
Налетели потоки сомнений.
И, тебе глядя вслед, весь в слезах целовал
Я прощальную ветку сирени...
Поезд где-то исчез в серой дымке вдали,
Подплывали вечерние тени...
И бесцельно я брёл по дороге в пыли
С одинокою веткой сирени.
Я вернулся к себе... Этот вечер унёс
Все надежды, всю радость стремлений...
В эту ночь отцвела от объятий и слёз
Истомлённая ветка сирени...');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_5fb7ff5be570ddb7_a97f7db5d9ce44e0','rpp_5fb7ff5be570ddb7','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/16.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_17397709259258e4','Вечер вальса','(«Видишь, небо потемнело, ярких окон вспыхнул ряд...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vecher_valsa.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Видишь, небо потемнело, ярких окон вспыхнул ряд...») | merged_versions: 1','Видишь, небо потемнело,
Ярких окон вспыхнул ряд.
Не напрасно ты надела
Самый лучший свой наряд.
От подъездов свет струится,
Так приветлив и знаком.
Вечер вальса состоится
В нашем клубе заводском.
В этом зале всех счастливей,
Всех красивей ты.
Как идут тебе сегодня
Эти первые цветы.
Ты со мною в лёгком танце
Мчишься, чуть дыша,&nbsp;-
И сама ещё не знаешь,
Как ты нынче хороша.
Звуки вальса, словно ветер,
То смолкают, то кружат.
Как спокойно руки эти
На плечах моих лежат.
И тогда я догадался
В вихре песен и огней,
Чем он будет, вечер вальса,
В жизни завтрашней моей.
Обещаньем новой встречи
Вальс звучит опять.
Пусть о многом в этот вечер
Не успели мы сказать.
Дай мне руку на прощанье,
Улыбнись тайком...
Вечер вальса, вечер вальса
В нашем клубе заводском.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Видишь, небо потемнело, ярких окон вспыхнул ряд...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_17397709259258e4'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_17397709259258e4','Вечер вальса','Видишь, небо потемнело,
