INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_17397709259258e4_f41f0b2dcd63c462','rpp_17397709259258e4','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/vecher_valsa.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ad0f1356f00922fd','Вечерний звон',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Томас Мур и Иван Козлов, музыка: Александр Алябьев) | Старинные романсы | https://pesni.retroportal.ru/sr1/15.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вечерний звон, вечерний звон!
Как много дум наводит он
О юных днях в краю родном,
Где я любил, где отчий дом.
И как я, с ним навек простясь,
Там слушал звон в последний раз!
Уже не зреть мне светлых дней
Весны обманчивой моей!
И сколько нет теперь в живых
Тогда весёлых, молодых!
И крепок их могильный сон;
Не слышен им вечерний звон.
Лежать и мне в земле сырой!
Напев унывный надо мной
В долине ветер разнесёт;
Другой певец по ней пройдёт.
И уж не я, а будет он
В раздумье петь вечерний звон!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ad0f1356f00922fd'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ad0f1356f00922fd','Вечерний звон','Вечерний звон, вечерний звон!
