INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_ad0f1356f00922fd_404e53aa7a9c2ee3','rpp_ad0f1356f00922fd','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/15.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ca37e52e51aa5b2d','Виновата ли я...',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/10.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Виновата ли я, виновата ли я,
Виновата ли я, что люблю?
Виновата ли я, что мой голос дрожал,
Когда пела я песню ему?
Виновата одна, виновата во всём.
Ещё хочешь себя оправдать.
Так зачем же, зачем в эту тёмную ночь
Позволяла себя целовать?
Целовал-миловал, целовал-миловал,
Говорил, что я буду его.
А я верила всё и, как роза цвела,
Потому что любила его.
Ой ты, мама моя, ой ты, мама моя!
Отпусти ты меня погулять.
Ночью звёзды горят, ночью ласки дарят,
Ночью все о любви говорят.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ca37e52e51aa5b2d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ca37e52e51aa5b2d','Виновата ли я...','Виновата ли я, виновата ли я,
