INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_ca37e52e51aa5b2d_0bc6244cf3fbba70','rpp_ca37e52e51aa5b2d','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/10.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d76476595757183b','Винтовка','(«Эх, бей, винтовка, метко, ловко...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Александр Лугин, музыка: Дмитрий Покрасс и Даниил Покрасс) | Песни военных лет | https://pesni.retroportal.ru/vov/vintovka.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Эх, бей, винтовка, метко, ловко...») | merged_versions: 1','С юга до Урала
Ты со мной шагала
Партизанскою тропой,
И врагов, бывало,
Падало немало,
Там, где пробирались мы с тобой.
Припев:
Эх, бей, винтовка, метко, ловко,
Без пощады по врагу!
Я тебе, моя винтовка,
Острой саблей помогу!
В поле и на шахте,
В цехе и на вахте
Комсомол неустрашим.
Скажет Сталин слово&nbsp;-
И врага любого
На его земле мы разгромим!
Припев
Вместе мы недавно
Воевали славно,
Был урок японцам дан.
Билась не одна ты:
Помогли гранаты
В битве возле озера Хасан!
Припев
Мы готовы к бою
С армией любою,
Коль придётся воевать.
Будем биться двое:
Я и ты со мною,
Вместе нам привычно побеждать!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Эх, бей, винтовка, метко, ловко...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d76476595757183b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d76476595757183b','Винтовка','С юга до Урала
