Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d76476595757183b_adf4ecbf183f54b7','rpp_d76476595757183b','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/vintovka.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bb60aa3a05ae6998','Вниз по Волге-реке',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня, стихи: Александр Шаховский) | Народные песни | https://pesni.retroportal.ru/np1/11.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вниз по Волге-реке,
С Нижня-Новгорода,
Снаряжён стружок,
Как стрела, летит.
Как на том на стружке,
На снаряженном,
Удалых гребцов
Сорок два сидят.
Как один-то из них,
Добрый молодец,
Призадумался,
Пригорюнился.
&laquo;Ах, о чём же ты,
Добрый молодец,
Призадумался,
Пригорюнился?..&raquo;
&laquo;Я задумался,
Пригорюнился
Об одной душе,
Красной девице.
Эх вы, братцы мои,
Вы товарищи,
Сослужите вы мне
Службу верную.
Киньте-бросьте меня
В Волгу-матушку,
Утоплю я в ней
Грусть-тоску мою.
Лучше в море мне быть
Утопивому,
Чем на свете жить
Нелюбимому&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bb60aa3a05ae6998'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bb60aa3a05ae6998','Вниз по Волге-реке','Вниз по Волге-реке,
С Нижня-Новгорода,
