Чем на свете жить
Нелюбимому&raquo;.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_bb60aa3a05ae6998_9d4716e9923139f2','rpp_bb60aa3a05ae6998','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/11.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6b97f1d682a7924d','Вниз по матушке по Волге',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/12.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вниз по матушке по Во... по Волге,
По широкому раздолью,
По широкому раздо... раздолью
Поднималась непогода.
Поднималась непого... погода,
Погодушка немалая,
Погодушка нема... немалая,
Немалая, волновая.
Немалая, волно... волновая,
Ничего в волнах не видно.
Ничего в волнах не ви... не видно,
Одна лодочка чернеет.
Одна лодочка чернее... чернеет,
Только паруса белеют.
Только паруса беле... белеют,
На гребцах шляпы чернеют.
На гребцах шляпы чернее... чернеют,
Сам хозяин во наряде,
Сам хозяин во наря... наряде,
В чёрном бархатном кафтане,
Уж как взговорит хозя... хозяин:
&laquo;Ну-те, грянемте, ребята,
Ну-те, грянемте, ребя... ребята,
Вниз по матушке по Волге.
Вниз по матушке по Во... по Волге.
Приворачивай, ребята,
Приворачивай, ребя... ребята,
Ко крутому бережочку!&raquo;','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6b97f1d682a7924d'), datetime('now')),datetime('now'));
