INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ddbeeaf194c3ab33','Внутренняя музыка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Огарёв, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr1/17.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Как дорожу я прекрасным мгновеньем!
Музыкой вдруг наполняется слух;
Звуки несутся с каким-то стремленьем,
Звуки откуда-то льются вокруг.
