INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c0ab7581ab976b77','Во кузнице',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/13.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Во кузнице, во кузнице.
Во кузнице молодые кузнецы,
Во кузнице молодые кузнецы.
Они куют, они куют.
