Носи, Дуня, не марай, не марай,
По праздникам одевай, одевай.
Во кузнице, во кузнице.
Во кузнице молодые кузнецы,
Во кузнице молодые кузнецы.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c0ab7581ab976b77'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c0ab7581ab976b77','Во кузнице','Во кузнице, во кузнице.
