INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4197f777fcf502e7','Во поле берёза стояла',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/14.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Во поле берёза стояла,
Во поле кудрявая стояла,
Люли, люли, стояла.
Некому берёзу заломати,
Некому кудряву заломати,
Люли, люли, заломати.
Как пойду я в лес, погуляю,
Белую берёзу заломаю,
Люли, люли, заломаю.
Срежу я с берёзы три пруточка,
Сделаю себе я три гудочка,
Люли, люли три гудочка.
Четвёртую балалайку,
Пойду я на новые сени,
Люли, люли на сени.
Стану в балалаечку играти,
Стану я милого будити.
Люли, люли, будити:
Встань ты, мой милый, проснися,
Ты, душа моя, пробудися.
Люли, люли пробудися.
Пойдём в терем веселиться.
Пойдём в терем веселиться,
Люли, люли, веселиться.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4197f777fcf502e7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4197f777fcf502e7','Во поле берёза стояла','Во поле берёза стояла,
