INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b22c84fd23990842','Во субботу, день ненастный',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/15.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Во субботу, день ненастный,
Нельзя, нельзя в поле, эх,
Нельзя в поле работать.
Нельзя в поле работать.
Нельзя в полюшке работать,
Ни... ни боронить, эх,
Ни боронить, ни пахать.
Ни боронить, ни пахать.
Мы пойдем с тобой, Ванюша,
Во... во зелёный, эх,
Во зелёный сад гулять.
Во зелёный сад гулять.
