INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ca7bf6f4a7becd29','Воевать мы мастера','(«Воевать мы мастера, и сегодня, как вчера...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Тихон Хренников) | Песни военных лет | https://pesni.retroportal.ru/vov/voevat_my_mastera.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Воевать мы мастера, и сегодня, как вчера...») | merged_versions: 1','Эй, герои! Разве не с кого
Брать нам в доблести пример?
Вспомним ратный подвиг Невского,
Боевой его манер.
Брал отвагой молодецкою
Он на озере Чудском,
И остались псы немецкие
Под холодным русским льдом!
Припев:
Воевать мы мастера,
И сегодня, как вчера,
По-геройски бьются русские бойцы.
И сегодня, как вчера,
Под могучее &laquo;ура&raquo;
Сыновья идут на битву, как отцы!
Не задаром распеваются
Нами песни про Петра,
В каждом сердце отзывается
Та великая пора.
Все пути, что были пройдены,
Помнит храбрый наш народ.
Боевая слава Родины
Нас на подвиги зовёт.
Припев
Люди мы такого норова,
Что дерёмся до конца.
Мы&nbsp;- наследники Суворова,
Полководца и бойца.
Славы русской не забыли мы
И суворовских побед,
В сердце свято сохранили мы
Боевой его завет.
Припев
Честь, и храбрость, и достоинство
Русских воинов-отцов
Носит в сердце наше воинство
Краснозвёздных храбрецов.
И звезда красноармейская
Прежней славою горит.
Разгромим орду злодейскую,
Враг, как прежде, будет бит!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Воевать мы мастера, и сегодня, как вчера...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ca7bf6f4a7becd29'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ca7bf6f4a7becd29','Воевать мы мастера','Эй, герои! Разве не с кого
