INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_ca7bf6f4a7becd29_8085eb26a22c24a8','rpp_ca7bf6f4a7becd29','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/voevat_my_mastera.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5b39cc610606173e','Возле речки','(«Возле речки, у дорожки, у тропы...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Яков Белинский, музыка: Вадим Кочетов) | Патриотические песни | https://pesni.retroportal.ru/rodina/vozle_rechki.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Возле речки, у дорожки, у тропы...») | merged_versions: 1','Эх, над нами вьётся знамя, красный шёлк!
По степи широкой шёл стрелковый полк,
А вокруг цвели колхозные поля&nbsp;-
Наша русская советская земля!
Возле речки, у дорожки, у тропы
На заре вязали девушки снопы,
Пели песню о пшенице золотой,
Зорька ясная пылала за рекой.
Над полями проиграл горнист сигнал.
Встал наш полк стрелковый в поле на привал
У реки передохнуть, перекурить.
Эх, не надо ль вам, девчата, подсобить?
И пошли расти колхозные скирды,
Будто войско быстро строится в ряды.
Светлым золотом цветёт привольный край.
Ох и славен наш колхозный урожай!
Потрудились, поработали бойцы,
Отличилися в работе молодцы.
И сказали наши девушки бойцам:
&laquo;Вы почаще приходите в гости к нам!&raquo;
&laquo;Благодарствуем, красавицы, за честь,
Только просим вас один вопрос учесть.
Наш наказ, девчата, будет вам таков:
Подыскать невест для наших женихов&raquo;.
Эх, над нами вьётся знамя, красный шёлк!
Провожали с песней девушки наш полк,
А вокруг цвели колхозные поля&nbsp;-
Наша русская советская земля!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Возле речки, у дорожки, у тропы...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5b39cc610606173e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5b39cc610606173e','Возле речки','Эх, над нами вьётся знамя, красный шёлк!
По степи широкой шёл стрелковый полк,
А вокруг цвели колхозные поля&nbsp;-
Наша русская советская земля!
Возле речки, у дорожки, у тропы
На заре вязали девушки снопы,
Пели песню о пшенице золотой,
Зорька ясная пылала за рекой.
Над полями проиграл горнист сигнал.
Встал наш полк стрелковый в поле на привал
У реки передохнуть, перекурить.
Эх, не надо ль вам, девчата, подсобить?
И пошли расти колхозные скирды,
Будто войско быстро строится в ряды.
Светлым золотом цветёт привольный край.
Ох и славен наш колхозный урожай!
Потрудились, поработали бойцы,
Отличилися в работе молодцы.
И сказали наши девушки бойцам:
&laquo;Вы почаще приходите в гости к нам!&raquo;
&laquo;Благодарствуем, красавицы, за честь,
Только просим вас один вопрос учесть.
Наш наказ, девчата, будет вам таков:
Подыскать невест для наших женихов&raquo;.
Эх, над нами вьётся знамя, красный шёлк!
Провожали с песней девушки наш полк,
А вокруг цвели колхозные поля&nbsp;-
Наша русская советская земля!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_5b39cc610606173e_8359f3850814511a','rpp_5b39cc610606173e','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/vozle_rechki.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8cf4f62d4977ff25','Волга-реченька глубока',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/16.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Волга-реченька глубока
Бьёт волнами берега.
Мил уехал, не простился,
Знать, любовь не дорога.
Ой, туманы голубые,
Серебристая волна.
Неужели ко мне милый
Не вернётся никогда!
Цвела вишня всем на диво,
Ветром сдуло белый цвет.
Я б другого полюбила,
Да Любови в сердце нет.
Возле бережка крутого
День и ночь волна шумит.
Хорошо любить такого,
Кто любовью дорожит.
Над рекой стоят туманы,
Красна солнца не видать.
А мой милый меня вспомнит,
И его я буду ждать.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8cf4f62d4977ff25'), datetime('now')),datetime('now'));
