INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_68999cb45e91e334','Вологда','(«Письма лично на почту ношу...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vologda.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Письма лично на почту ношу...») | merged_versions: 1','Письма, письма лично на почту ношу.
Словно, я роман с продолженьем пишу.
Знаю, знаю точно, где мой адресат,&nbsp;-
В доме, где резной палисад.
Где же моя темноглазая, где?
В Вологде-где-где-где?
В Вологде-где?
В доме, где резной палисад.
Шлю я, шлю я ей за пакетом пакет,
Только, только нет мне ни слова в ответ.
Значит, значит, надо иметь ей в виду:
Сам я за ответом приду.
Что б ни случилось, я к милой приду
В Вологду-гду-гду-гду,
В Вологду-гду.
Сам я за ответом приду.
Вижу, вижу алые кисти рябин,
Вижу, вижу дом её номер один.
Вижу, вижу сад со скамьёй у ворот,
Город, где судьба меня ждёт.
Вот потому-то мила мне всегда
Вологда-гда-гда-гда,
Вологда-гда,
Город, где судьба меня ждёт.
Где же моя темноглазая, где?
В Вологде-где-где-где?
В Вологде-где?
В доме, где резной палисад.
В доме, где резной палисад...
Слушать песню &laquo;Вологда&raquo; композитора Бориса Мокроусова на стихи Михаила Матусовского в исполнении  Анатолия Кашепарова и ВИА &laquo;Песняры&raquo; .','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Письма лично на почту ношу...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_68999cb45e91e334'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_68999cb45e91e334','Вологда','Письма, письма лично на почту ношу.
