INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_68999cb45e91e334_ca3f688d92059baf','rpp_68999cb45e91e334','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/vologda.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_348fbd3a373e7c8e','Воспоминание','(«Тихий рабочий посёлок спит под густою листвой...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Давид Самойлов, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vospominanie.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Тихий рабочий посёлок спит под густою листвой...») | merged_versions: 1','Тихий рабочий посёлок
Спит под густою листвой.
Вспомни подружек весёлых,
Тех, что дружили с тобой.
Вспомни о чём
Мы вечерком
Пели в саду заводском...
Вспомни, о чём мы мечтали,
Как мы смеялись тогда.
Вспомни, как вдаль улетали
Мы из родного гнезда
Ах, как далёк
Тот городок&nbsp;-
Путь между нами пролёг.
Улицу нашего детства
Хочется мне повидать,
Утренним солнцем согреться,
Выйти с друзьями опять&nbsp;-
В старый наш сад,
Где у оград
Юные липы стоят.
Знаю, мы встретимся снова
Светлой весенней порой,
Возле завода родного
Мы погуляем с тобой.
Снова споём
Мы вечерком
В нашем саду городском...','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Тихий рабочий посёлок спит под густою листвой...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_348fbd3a373e7c8e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_348fbd3a373e7c8e','Воспоминание','Тихий рабочий посёлок
Спит под густою листвой.
Вспомни подружек весёлых,
