INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1eadd0f0e4c59943','Вот на пути село большое',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/19.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вот на пути село большое,
Куда ямщик мой поглядел,
Его забилось ретивое,
И потихоньку он запел.
&laquo;Твоя краса меня сгубила,
Теперь мне белый свет постыл.
Скажи, зачем приворожила,
Коль я душе твоей не мил!
По мне лошадушки сгрустятся,
Расставшись, бедные, со мной.
Они уж больше не помчатся
Вдоль по дороге столбовой.
Недолго песней удалою,
Недолго тешить седока.
Уж скоро, скоро под землёю
Зароют тело ямщика&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1eadd0f0e4c59943'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1eadd0f0e4c59943','Вот на пути село большое','Вот на пути село большое,
