INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_54c31b58019822c3','Все за Родину','(«Все за Родину смело в бой идём...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Виктор Гусев, музыка: Тихон Хренников) | Патриотические песни | https://pesni.retroportal.ru/rodina/vse_za_rodinu.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Все за Родину смело в бой идём...») | merged_versions: 1','Не впервой нам, братцы, в жаркий бой ходить,
Не впервой нам, братцы, гада немца бить.
Помнит Украина, милая сестра
Дальние походы, эх, да ночи у костра.
Мы громили немца на родных полях.
Армия Советов крепла в тех боях.
В тех боях рождались красные полки,
В тех боях сражались, эх, да наши земляки.
Припев:
Все за Родину смело в бой идём.
До последнего фашистов перебьём!
За страну свою бьётся весь народ.
В бой за Сталина вперёд, вперёд!
Наш Ильич любимый в бой нас провожал.
Сталин нашу силу грозную ковал.
Годы пролетели, и в рассветный час,
Тот же враг жестокий вновь напал на нас.
Жжёт он наши сёла, грабит города.
Но мы помним, братцы, дальние года,
Не жалея жизни, мы врага громим.
Слышишь Украина, Беларусь и Крым!
Припев
Вам вернут свободу красные полки,
К вам идут на помощь братья-земляки.
Ленинское знамя силу нам даёт.
Сталин наше войско, наше грозное ведёт!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Все за Родину смело в бой идём...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_54c31b58019822c3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_54c31b58019822c3','Все за Родину','Не впервой нам, братцы, в жаркий бой ходить,
Не впервой нам, братцы, гада немца бить.
Помнит Украина, милая сестра
Дальние походы, эх, да ночи у костра.
Мы громили немца на родных полях.
Армия Советов крепла в тех боях.
В тех боях рождались красные полки,
В тех боях сражались, эх, да наши земляки.
Припев:
Все за Родину смело в бой идём.
До последнего фашистов перебьём!
За страну свою бьётся весь народ.
В бой за Сталина вперёд, вперёд!
Наш Ильич любимый в бой нас провожал.
Сталин нашу силу грозную ковал.
Годы пролетели, и в рассветный час,
Тот же враг жестокий вновь напал на нас.
Жжёт он наши сёла, грабит города.
Но мы помним, братцы, дальние года,
Не жалея жизни, мы врага громим.
Слышишь Украина, Беларусь и Крым!
Припев
Вам вернут свободу красные полки,
К вам идут на помощь братья-земляки.
Ленинское знамя силу нам даёт.
Сталин наше войско, наше грозное ведёт!
Припев');
