INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c156d04dc06bc1c0','Все поют на весенние темы','(«Все поют на весенние темы: и ручьи, и листва, и гудки...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Харитонов, музыка: Аркадий Островский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vse_poyut_na_vesennie_temy.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Все поют на весенние темы: и ручьи, и листва, и гудки...») | merged_versions: 1','Все поют на весенние темы:
И ручьи, и листва, и гудки,
И серьёзный комсорг из поэмы,
И на встречных путях сквозняки.
За Уральской грядою отвесной
Задержались ещё холода.
Молодые весенние песни
Раньше птиц прилетели туда.
Хорошо, если в новой скворешне
Распевает скворец озорной.
Но признание сердца, конечно,
Нам приятнее слушать весной.
Все поют на весенние темы:
И ручьи, и листва, и гудки,
И серьёзный комсорг из поэмы,
И на встречных путях сквозняки.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Все поют на весенние темы: и ручьи, и листва, и гудки...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c156d04dc06bc1c0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c156d04dc06bc1c0','Все поют на весенние темы','Все поют на весенние темы:
И ручьи, и листва, и гудки,
