INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_872699d29462bd1b','Всё, чем теперь сильны мы и богаты','(«Промчались годы боевые, в сердцах оставив вечный след...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Жаров, музыка: Зиновий Компанеец) | Патриотические песни | https://pesni.retroportal.ru/rodina/vse_chem_silny_my_i_bogaty.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Промчались годы боевые, в сердцах оставив вечный след...») | merged_versions: 1','Промчались годы боевые,
В сердцах оставив вечный след.
Мы, их свидетели живые,
Земле несём победный свет.
Припев:
Всё, чем теперь сильны мы и богаты,
Всё, чем отныне Родине горда,
В жарких сражениях с боем нами взято,
Славой народа стало навсегда!
Везде, где руки поднимает народ
На грязных палачей,
Отчизну нашу называют
Надеждой светлою своей.
Припев
Весь мир труда сегодня с нами,
И мы сердцами вместе с ним.
Зовут повсюду наше знамя
Любимым знаменем своим.
Припев
И нас, людей Страны Советов,
Родными братьями зовут.
И имя Сталина приветом
Из уст в уста передают!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Промчались годы боевые, в сердцах оставив вечный след...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_872699d29462bd1b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_872699d29462bd1b','Всё, чем теперь сильны мы и богаты','Промчались годы боевые,
В сердцах оставив вечный след.
Мы, их свидетели живые,
