INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fa1b607e08fb34eb','Вставай, патриот','(«Вперёд, товарищи, смелее, по зову мудрого вождя!..»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Зиновий Дунаевский) | Песни военных лет | https://pesni.retroportal.ru/vov/vstavaj_patriot.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Вперёд, товарищи, смелее, по зову мудрого вождя!..») | merged_versions: 1','Вставай, патриот, на защиту страны,
Наше грозное время не ждёт.
Повсюду умелые руки нужны
И герои нужны, патриот!
Припев:
Вперёд, товарищи, смелее,
По зову мудрого вождя!
Работай, силы не жалея,
Сражайся, жизни не щадя!
Чтоб вырвать победу в упорных боях,
Чтобы враг был жестоко разбит,
Пускай у станков, на колхозных полях
Боевая работа кипит!
Припев
Сестра и подруга, товарищ и брат,
Ни минуты не будем терять!
Пойдём в ополченье, в пожарный отряд,
Чтобы всюду победу ковать!
Припев
За правое дело мы в битву идём,
За Отчизну и волю свою.
Так будь же на страже и ночью и днём,
Будь героем в труде и в бою!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Вперёд, товарищи, смелее, по зову мудрого вождя!..»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fa1b607e08fb34eb'), datetime('now')),datetime('now'));
