INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4a31dbd19ff69dc2','Вставайте, люди русские!','(Хор из кинофильма «Александр Невский»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Луговской, музыка: Сергей Прокофьев) | Патриотические песни | https://pesni.retroportal.ru/rodina/vstavajte_lyudi_russkie.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Хор из кинофильма «Александр Невский») | merged_versions: 1','Вставайте, люди русские
На славный бой, на смертный бой!
