INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b5206d7994bce25a','Встреча Будённого с казаками','(«Ехал товарищ Будённый стороной родной...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Александр Чуркин, музыка: Василий Соловьёв-Седой) | Песни военных лет | https://pesni.retroportal.ru/vov/vstrecha_budennogo_s_kazakami.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Ехал товарищ Будённый стороной родной...») | merged_versions: 1','Ехал товарищ Будённый
Стороной родной
Встретил в долине зелёной
Конный полк донской
&laquo;Гей, здорово, казаки,
Удалые рубаки!&raquo;-
&laquo;Здравствуй, товарищ Будённый,
Наш орёл степной!&raquo;
&laquo;Как, казаки, поживаем,
Как, друзья, живём?
Весело ль песни спеваем,
Как врагов мы бьём?&raquo;
Отвечают казаки,
Удалые рубаки:
&laquo;Дюже с тобою мы, батько,
Жару им даём!
Чтобы очей не казали
В наш родимый край,
Чтобы в чём было ныряли
В Неман аль в Дунай.
Отомстим за колхозы
За горючие слёзы,-
В наши казацкие руки
Саблю только дай!
Только с войной мы покончим
Защитим наш край,
В нашу станицу, Будённый,
В гости приезжай.
У донского казака
Вдоволь хлеба и мёда
В хатах найдутся бандуры
Песни, знай, спевай!&raquo;
&laquo;Что же, спасибо, казаки,
Весь донской народ,
Грянем, как буря, в атаку
Все за мной, вперёд!
Храбро будем мы биться,
За родные станицы,
Враг под конём да под пикой
Смерть в бою найдёт!&raquo;','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Ехал товарищ Будённый стороной родной...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b5206d7994bce25a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b5206d7994bce25a','Встреча Будённого с казаками','Ехал товарищ Будённый
Стороной родной
