Враг под конём да под пикой
Смерть в бою найдёт!&raquo;');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b5206d7994bce25a_19c9cd3113ecc0e2','rpp_b5206d7994bce25a','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/vstrecha_budennogo_s_kazakami.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a22ef68dc7f0a341','Всю-то я вселенную проехал',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/20.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Всю-то я вселенную проехал,
Нигде милой не нашёл.
Я в Россию возвратился,
Сердцу слышится привет.
Где ж ты, светик, дорогая,
Сердцу весточку подай,
Где ж вы, очи голубые,
Где ж ты, прежняя любовь?
Ты заслышь мой голосочек,
Разлюбезная моя,
За твои за глазки голубые
Всю вселенную отдам!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a22ef68dc7f0a341'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a22ef68dc7f0a341','Всю-то я вселенную проехал','Всю-то я вселенную проехал,
