INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_a22ef68dc7f0a341_4c866733da0cc6d5','rpp_a22ef68dc7f0a341','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/20.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_879dd3f34edf4b92','Вчера, увенчана душистыми цветами',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Афанасий Фет, музыка: Антон Аренский) | Старинные романсы | https://pesni.retroportal.ru/sr1/18.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вчера, увенчана душистыми цветами,
Смотрела долго ты в зеркальное окно
На небо синее, горевшее звездами,
В аллею тополей с дрожащими листами, -
В аллею, где вдали так страшно и темно.
Забыла, может быть, ты за собою в зале
И яркий свет свечей, и нежные слова...
Когда помчался вальс и струны рокотали, -
Я видел – вся в цветах, исполнена печали,
К плечу слегка твоя склонялась голова.
Не думала ли ты: &laquo;Вон там, в беседке дальной,
На мраморной скамье теперь он ждёт меня
Под сумраком дерев, ревнивый и печальный;
Он взоры утомил, смотря на вихорь бальный,
И ловит тень мою в сиянии огня&raquo;.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_879dd3f34edf4b92'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_879dd3f34edf4b92','Вчера, увенчана душистыми цветами','Вчера, увенчана душистыми цветами,
Смотрела долго ты в зеркальное окно
На небо синее, горевшее звездами,
В аллею тополей с дрожащими листами, -
В аллею, где вдали так страшно и темно.
