INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_eadfb2ee7c7642da_f0a62ae6f0ba8096','rpp_eadfb2ee7c7642da','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/21.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_37caf4e4cf63b608','Выйду на улицу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/22.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Выйду на улицу – солнца нема,
Парни молодые свели меня с ума.
Выйду на улицу, гляну на село, -
Девки гуляют, и мне весело.
Матушка родная, дай воды холодной,
Сердце моё так и кидает в жар.
Раньше я гуляла в зелёном саду,
Думала на улицу век не пойду.
А теперь под вечер аж пятки горят –
Ноженьки резвые в пляску хотят.
Я пойду на улицу, к девкам пойду,
Голосом звонким я им подпою.
Матушка, слышишь, соловушек поёт,
А там, под горою, пляска идёт –
Девки голосистые звонко поют
Мне да молоденькой спать не дают.
Выйду на улицу – солнца нема,
Парни молодые свели меня с ума.
Выйду на улицу, гляну на село, -
Девки гуляют, и мне весело.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_37caf4e4cf63b608'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_37caf4e4cf63b608','Выйду на улицу','Выйду на улицу – солнца нема,
