INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c867331c7835d1ed','Высока волна на Волге','(«Высока волна на Волге раннею весною...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Жаров, музыка: Борис Терентьев) | Эстрадные песни | https://pesni.retroportal.ru/estrada/vysoka_volna_na_volge.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Высока волна на Волге раннею весною...») | merged_versions: 1','Высока волна на Волге раннею весною.
Сизый голубь и голубка вьются над волною.
Им летать в такую пору любо на просторе.
Легло широко, легло широко за рекою море.
Те же голуби кружились, улетев из дома,
У станицы, у Цимлянской, возле водоёма.
А теперь места другие, и вода другая
Вдали&nbsp;- Жигули, вдали&nbsp;- Жигули, рядом&nbsp;- ширь морская.
Тут и там на стройке мирной юность боевая
Подвиг свой вершит достойно, песни напевая.
Край родной растёт обильным, сильным и прекрасным.
Для нас занялась, для нас занялась зорька в небе ясном.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Высока волна на Волге раннею весною...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c867331c7835d1ed'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c867331c7835d1ed','Высока волна на Волге','Высока волна на Волге раннею весною.
