INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_365c2e6f2acbc370','Выхожу в родное поле','(«Выхожу в родное поле, плещут зрелые хлеба...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Соболев, музыка: Мариан Коваль) | Патриотические песни | https://pesni.retroportal.ru/rodina/vyhozhu_v_rodnoe_pole.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Выхожу в родное поле, плещут зрелые хлеба...») | merged_versions: 1','Выхожу в родное поле,
Плещут зрелые хлеба.
Неоглядное раздолье&nbsp;-
Наша светлая судьба!
Поле колхозное&nbsp;-
Гордость моя!
Нет ни жизни,
Нет ни счастья
Мне без тебя!
Здесь родились дед и прадед,
Здесь росли отец и мать.
Здесь я в праздничном наряде
Вышла молодость встречать!
Поле привольное&nbsp;-
Юность моя!
Нет ни жизни,
Нет ни счастья,
Мне без тебя!
Красоту свою и силу
В этом поле я взяла
В нём я пела и грустила
В нём любовь свою нашла.
Поле колхозное&nbsp;-
Гордость моя!
Нет ни жизни,
Нет ни счастья
Мне без тебя!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Выхожу в родное поле, плещут зрелые хлеба...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_365c2e6f2acbc370'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_365c2e6f2acbc370','Выхожу в родное поле','Выхожу в родное поле,
