INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_37511556c81b8758','Выхожу один я на дорогу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Лермонтов, музыка: Елизавета Шашина) | Старинные романсы | https://pesni.retroportal.ru/sr1/19.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Выхожу один я на дорогу;
Сквозь туман кремнистый путь блестит;
Ночь тиха. Пустыня внемлет богу.
И звезда с звездою говорит.
В небесах торжественно и чудно!
Спит земля в сияньи голубом...
Что же мне так больно и так чудно?
Жду ль чего? Жалею ли о чем?
Уж не жду от жизни ничего я,
И не жаль мне прошлого ничуть;
Я ищу свободы и покоя!
Я б хотел забыться и заснуть!
Но не тем холодным сном могилы...
Я б желал навеки так заснуть,
Чтоб в груди дремали жизни силы,
Чтоб, дыша, вздымалась тихо грудь;
Чтоб всю ночь, весь день, мой слух лелея,
Про любовь мне сладкий голос пел,
Надо мной чтоб, вечно зеленея,
Тёмный дуб склонялся и шумел.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_37511556c81b8758'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_37511556c81b8758','Выхожу один я на дорогу','Выхожу один я на дорогу;
Сквозь туман кремнистый путь блестит;
Ночь тиха. Пустыня внемлет богу.
И звезда с звездою говорит.
В небесах торжественно и чудно!
Спит земля в сияньи голубом...
Что же мне так больно и так чудно?
Жду ль чего? Жалею ли о чем?
Уж не жду от жизни ничего я,
И не жаль мне прошлого ничуть;
Я ищу свободы и покоя!
Я б хотел забыться и заснуть!
Но не тем холодным сном могилы...
Я б желал навеки так заснуть,
Чтоб в груди дремали жизни силы,
Чтоб, дыша, вздымалась тихо грудь;
Чтоб всю ночь, весь день, мой слух лелея,
Про любовь мне сладкий голос пел,
Надо мной чтоб, вечно зеленея,
Тёмный дуб склонялся и шумел.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_37511556c81b8758_0cc767e979fa9a72','rpp_37511556c81b8758','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/19.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3c0e4789cd7a35ff','Газовая косынка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Козырев, музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr1/20.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ты смотри никому не рассказывай,
Что душа лишь тобою полна,
Что тебя я в косыночке газовой
Дожидаюсь порой у окна,
Что тоскую, люблю тебя пламенно
И, страдая, хочу лишь тебя.
Ты молчи, всё скрывай, точно каменный,
Точно в сердце твоём нет огня.
Никому не скажи, что я нежная,
Что люблю, что грущу, что твоя,
Что сковало нас счастье безбрежное,
Что до смерти твоя буду я.
Если любишь меня, не отказывай,
Об одном только помни всегда –
Ничего про любовь не рассказывай,
Ничего, никому, никогда.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3c0e4789cd7a35ff'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3c0e4789cd7a35ff','Газовая косынка','Ты смотри никому не рассказывай,
