INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6439ddb39afb8f03','Гвардейский марш','(«Мы смерти не пугаемся, от пули не сгибаемся...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Арам Хачатурян) | Песни военных лет | https://pesni.retroportal.ru/vov/gvardejsky_marsh.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Мы смерти не пугаемся, от пули не сгибаемся...») | merged_versions: 1','В суровых походах, в огне и в бою,
Как знамя, проносим мы песню свою.
Гвардейское знамя к победе зовёт.
Гвардейская песня в атаку ведёт.
Припев:
Мы смерти не пугаемся,
От пули не сгибаемся,
От раны не шатаемся -
Такой уж мы народ!
Не раз огнём проверены,
Не раз в боях обстрелены,
И нас недаром Родина
Гвардейцами зовёт!
Гвардейское знамя&nbsp;- в десятках атак!
Геройски прославлен сапёр и моряк,
И конник, и лётчик, и снайпер, радист,
Отважный наводчик и храбрый танкист!
Припев
Кто держит оружье в умелых руках,
Тому честь и место в гвардейских полках!
Гвардейцы не дрогнут в суровые дни&nbsp;-
К борьбе и победе готовы они!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Мы смерти не пугаемся, от пули не сгибаемся...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6439ddb39afb8f03'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6439ddb39afb8f03','Гвардейский марш','В суровых походах, в огне и в бою,
