INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6ea4241a38dcf2f3','Главное, ребята, сердцем не стареть','(«Под крылом самолёта о чем-то поёт зелёное море тайги...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Гребенников и Николай Добронравов, музыка: Александра Пахмутова) | Эстрадные песни | https://pesni.retroportal.ru/estrada/glavnoe_rebyata_serdcem_ne_staret.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Под крылом самолёта о чем-то поёт зелёное море тайги...») | merged_versions: 1','Главное, ребята, сердцем не стареть,
Песню, что придумали, до конца допеть.
В дальний путь собрались мы, а в этот край таёжный
Только самолётом можно долететь.
Припев:
А ты, улетающий вдаль самолёт
В сердце своём сбереги...
Под крылом самолёта о чём-то поёт
Зелёное море тайги.
Лётчик над тайгою точный курс найдёт,
Прямо на поляну посадит самолёт.
Выйдет в незнакомый мир, ступая по-хозяйски
В общем-то зелёный, молодой народ.
Припев
Там веками ветры да снега мели,
Там совсем недавно геологи прошли.
Будем жить в посёлке мы пока-что небогато,
Чтобы все богатства взять из под земли.
Припев
Мчатся самолёты выше облаков,
Мчатся чуть похожие на больших орлов.
Мчатся над тобой они, а знаешь, дорогая,
Лёту к нам в Таёжный несколько часов.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Под крылом самолёта о чем-то поёт зелёное море тайги...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6ea4241a38dcf2f3'), datetime('now')),datetime('now'));
