INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_319ca94ce5ded0b6','Глухой, неведомой тайгою',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/23.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Глухой, неведомой тайгою,
Сибирской дальней стороной
Бежал бродяга с Сахалина
Звериной узкою тропой.
Шумит, бушует непогода,
Далёк, далёк бродяги путь.
Укрой, тайга его глухая,
Бродяга хочет отдохнуть.
Там, далеко за тёмным бором,
Оставил родину свою,
Оставил мать свою родную,
Детей, любимую жену.
&laquo;Умру, в чужой земле зароют,
Заплачет маменька моя.
Жена найдёт себе другого,
А мать сыночка – никогда&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_319ca94ce5ded0b6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_319ca94ce5ded0b6','Глухой, неведомой тайгою','Глухой, неведомой тайгою,
