INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c87338c4e5f0f99e','Гляжу в озёра синие','(Песня из телефильма «Тени исчезают в полдень»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Игорь Шаферан, музыка: Леонид Афанасьев) | Патриотические песни | https://pesni.retroportal.ru/rodina/glyazhu_v_ozera_sinie.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из телефильма «Тени исчезают в полдень») | merged_versions: 1','Гляжу в озёра синие,
В полях ромашки рву,
Зову тебя Россиею,
Единственной зову.
Спроси, переспроси меня&nbsp;-
Милее нет земли.
Меня здесь русским именем
Когда-то нарекли.
Гляжу в озёра синие,
В полях ромашки рву,
Зову тебя Россиею,
Единственной зову.
Не знаю счастья большего,
Чем жить одной судьбой:
Грустить с тобой, земля моя
И праздновать с тобой.
Красу твою не старили
Ни годы, ни беда,
Иванами да Марьями
Гордилась ты всегда.
Не все вернулись соколы&nbsp;-
Кто жив, а кто убит...
Но слава их высокая
Тебе принадлежит.
Красу твою не старили
Ни годы, ни беда,
Иванами да Марьями
Гордилась ты всегда.
Не знаю счастья большего,
Чем жить одной судьбой:
Грустить с тобой, земля моя
И праздновать с тобой.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из телефильма «Тени исчезают в полдень»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c87338c4e5f0f99e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c87338c4e5f0f99e','Гляжу в озёра синие','Гляжу в озёра синие,
