INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_658883e1024580f9','Голубой вагон','(Песня из мультфильма «Шапокляк»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Эдуард Успенский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/goluboy_vagon.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Шапокляк») | merged_versions: 1','Медленно минуты уплывают вдаль,
Встречи с ними ты уже не жди,
И хотя нам прошлого немного жаль,
Лучшее, конечно, впереди.
Скатертью, скатертью дальний путь стелется,
И упирается прямо в небосклон
Каждому, каждому в лучшее верится,
Катится, катится голубой вагон.
Если ты обидел вдруг кого-то зря,
Календарь закроет этот лист.
Жить без приключений нам никак нельзя,
Эй, прибавь-ка ходу, машинист.
Голубой вагон бежит-качается,
Скорый поезд набирает ход,
Ах, зачем же этот день кончается,
Лучше б он тянулся целый год.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Шапокляк»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_658883e1024580f9'), datetime('now')),datetime('now'));
