INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_658883e1024580f9_547721b476efa42f','rpp_658883e1024580f9','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/goluboy_vagon.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2e392f2e7b30ff2f','Голубчик мой, Ванюшка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/24.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Голубчик мой, Ванюшка, куда едешь ты?
- Не скажу...
Скажи, разлюбезный, Ваня размилой,
- На базар.
Голубчик мой, Ваня, возьми ж меня с собой.
- Не возьму.
Возьми, разлюбезный, Ваня размилой.
- Садись да на край.
Голубчик мой, Ванюшка, что у тебя в мешке?
- Не скажу.
Скажи, разлюбезный, Ваня, размилой.
- Яблоки.
Голубчик мой, Ванюшка, дай мне хоть один.
- Не дам.
Дай, разлюбезный, Ваня размилой.
- Возьми, да только гнилой.
Голубчик мой, Ванюшка, как мне его съесть?
- Не знаю.
Скажи, разлюбезный, Ваня размилой.
- Хороший срежь, а гнилой съешь.
Голубчик мой, Ванюшка, где ночуем мы?
- Не знаю.
Скажи, разлюбезный, Ваня размилой.
- На постоялом дворе.
Голубчик мой, Ванюшка, кто ж разбудит нас?
- Не знаю.
Скажи, разлюбезный, Ваня размилой.
- Есть захочешь – сама вскочишь.
Тррр, приехали, слезай.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2e392f2e7b30ff2f'), datetime('now')),datetime('now'));
