INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0792fd7b51133009','Гори, гори, моя звезда',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Чуевский, музыка: Пётр Булахов) | Старинные романсы | https://pesni.retroportal.ru/sr1/21.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вариант I
Гори, гори, моя звезда,
Гори, звезда, приветная.
Ты у меня одна заветная;
Другой не будет никогда.
Сойдёт ли ночь на землю ясная,
Звёзд много блещет в небесах.
Но ты одна, моя прекрасная,
Горишь в отрадных мне лучах.
Звезда надежды благодатная
Звезда любви волшебных дней.
Ты будешь вечно незакатная
В душе тоскующей моей.
Твоих лучей небесной силою
Вся жизнь моя озарена.
Умру ли я, ты над могилою
Гори, гори, моя звезда!
Вариант II
Гори, гори, моя звезда,
Звезда любви приветная!
Ты у меня одна заветная,
Другой не будет никогда,
Ты у меня одна заветная,
Другой не будет никогда!
Звезда любви волшебная,
Звезда прошедших лучших дней!
Ты будешь вечно незабвенная
В душе измученной моей!
Ты будешь вечно незабвенная
В душе измученной моей!
Твоих лучей небесной силою
Вся жизнь моя озарена;
Умру ли я, ты над могилою
Гори, сияй, моя звезда!
Умру ли я, ты над могилою
Гори, сияй, моя звезда!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0792fd7b51133009'), datetime('now')),datetime('now'));
