INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c55a53daa88e1124','Государственный Гимн России','(Государственный Гимн Российской Федерации)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Михалков, музыка: Александр Александров) | Патриотические песни | https://pesni.retroportal.ru/rodina/gosudarstvenny_gimn_rossii.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Государственный Гимн Российской Федерации) | merged_versions: 1','Россия&nbsp;- священная наша держава,
Россия&nbsp;- любимая наша страна.
Могучая воля, великая слава&nbsp;-
Твоё достоянье на все времена!
Славься, Отечество наше свободное,
Братских народов союз вековой,
Предками данная мудрость народная!
Славься, страна! Мы гордимся тобой!
От южных морей до полярного края
Раскинулись наши леса и поля.
Одна ты на свете! Одна ты такая&nbsp;-
Хранимая Богом родная земля!
Славься, Отечество наше свободное,
Братских народов союз вековой,
Предками данная мудрость народная!
Славься, страна! Мы гордимся тобой!
Широкий простор для мечты и для жизни
Грядущие нам открывают года.
Нам силу даёт наша верность Отчизне.
Так было, так есть и так будет всегда!
Славься, Отечество наше свободное,
Братских народов союз вековой,
Предками данная мудрость народная!
Славься, страна! Мы гордимся тобой!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Государственный Гимн Российской Федерации)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c55a53daa88e1124'), datetime('now')),datetime('now'));
