INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bb214684b586ccaf','Государственный Гимн СССР','(Вариант текста Гимна СССР 1943 года)','ru','ussr',NULL,'1943','pesni.retroportal.ru | (слова: Сергей Михалков и Габриэль Эль‑Регистан, музыка: Александр Александров) | Патриотические песни | https://pesni.retroportal.ru/rodina/gimn_sssr_stalin.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Вариант текста Гимна СССР 1943 года) | merged_versions: 2','Союз нерушимый республик свободных
Сплотила навеки Великая Русь.
Да здравствует созданный волей народов
Единый, могучий Советский Союз!
Славься, Отечество наше свободное,
Дружбы народов надёжный оплот!
Знамя советское, знамя народное
Пусть от победы к победе ведёт!
Сквозь грозы сияло нам солнце свободы,
И Ленин великий нам путь озарил:
Нас вырастил Сталин&nbsp;- на верность народу,
На труд и на подвиги нас вдохновил!
Славься, Отечество наше свободное,
Счастья народов надёжный оплот!
Знамя советское, знамя народное
Пусть от победы к победе ведёт!
Мы армию нашу растили в сраженьях.
Захватчиков подлых с дороги сметём!
Мы в битвах решаем судьбу поколений,
Мы к славе Отчизну свою поведём!
Славься, Отечество наше свободное,
Славы народов надёжный оплот!
Знамя советское, знамя народное
Пусть от победы к победе ведёт!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Вариант текста Гимна СССР 1943 года)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bb214684b586ccaf'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bb214684b586ccaf','Государственный Гимн СССР','Союз нерушимый республик свободных
