INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_bb214684b586ccaf_12e9e1724808d129','rpp_bb214684b586ccaf','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/gimn_sssr_stalin.html','reference',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_01860a846c8d85bd','Гренада','(«Гренада, Гренада, Гренада моя...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | Песни военных лет | https://pesni.retroportal.ru/vov/grenada.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Гренада, Гренада, Гренада моя...») | merged_versions: 1','(песня на стихи  Михаила&nbsp;Светлова )
Мы ехали шагом, мы мчались в боях,
И &laquo;Яблочко&raquo; песню держали в зубах,
А песенку эту поныне хранит
Трава молодая, степной малахит.
Но песню иную о дальней земле
Возил мой приятель с собою в седле,
Он пел, озирая родные края,
Гренада, Гренада, Гренада моя.
Он песенку эту твердил наизусть,
Откуда у хлопца испанская грусть?
Ответь, Александровск, и Харьков ответь
Давно ль по-испански вы начали петь?
Я хату покинул, пошёл воевать
Чтоб землю в Гренаде крестьянам отдать,
Прощайте родные, прощайте семья,
Гренада, Гренада, Гренада моя.
Мы мчались мечтая постичь поскорей
Грамматику боя, язык батарей.
Восход поднимался и падал опять,
И лошадь устала степями скакать.
Но &laquo;Яблочко&raquo; песню играл эскадрон
Смычками страданий на скрипках времён,
Где же, приятель, песня твоя,
Гренада, Гренада, Гренада моя.
Пробитое тело наземь сползло,
Товарищ впервые оставил седло,
Я видел, над трупом склонилась луна,
И мертвые губы шепнули Грена...
Да, в дальнюю область, заоблачный плёс
Ушёл мой приятель и песню унёс,
С тех пор не слыхали родные края
Гренада, Гренада, Гренада моя.
Отряд не заметил потери бойца
И &laquo;Яблочко&raquo; песню допел до конца,
Лишь по небу тихо сползла погодя
На бархат заката слезинка дождя.
Новые песни придумала жизнь,
Не надо, ребята, о песне тужить,
Не надо, не надо, не надо, друзья,
Гренада, Гренада, Гренада моя.
Музыку к стихотворению Михаила Светлова  &laquo;Гренада&raquo;  в разные годы писали композиторы  Константин Листов ,  Юрий Чичков ,  Микаэл Таривердиев ,  Виктор Берковский .','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Гренада, Гренада, Гренада моя...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_01860a846c8d85bd'), datetime('now')),datetime('now'));
