INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_018211f0c981c324','Да здравствует наша держава','(«Над Москвою чудесной, над любимой землей...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Шилов, музыка: Борис Александров) | Патриотические песни | https://pesni.retroportal.ru/rodina/da_zdravstvuet_nasha_derzhava.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Над Москвою чудесной, над любимой землей...») | merged_versions: 1','Да здравствует наша держава,
Отчизна великих идей,
Страна всенародного права
На радость и счастье людей!
За это священное право,
За жизнь и свободу свою
Великая наша держава
Врагов побеждала в бою.
Припев:
Над Москвою чудесной,
Над любимой землёй
Лейся, радостная песня
По нашей стране молодой!
Вейся, красное знамя,
Символ наших побед!
Ты горишь всегда над нами,
Как солнца ликующий свет!
По ленинским мудрым заветам
Нас партия к счастью ведёт.
И сталинской думой согреты
Страна и советский народ.
Несметны республик богатства,
И сил богатырских не счесть
В стране всенародного братства,
Где труд - это доблесть и честь.
Припев
От дальней советской границы
До башен старинных Кремля
Растут города и станицы,
Цветут золотые поля.
И с каждым зерном урожая,
И с новым ударом станка
Всё крепнет и крепнет родная,
Великая наша страна!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Над Москвою чудесной, над любимой землей...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_018211f0c981c324'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_018211f0c981c324','Да здравствует наша держава','Да здравствует наша держава,
