INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9cbd4900d3083809','Давно не бывал я в Донбассе','(«Давно не бывал я в Донбассе, тянуло в родные края...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Доризо, музыка: Никита Богословский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/davno_ne_byval_ya_v_donbasse.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Давно не бывал я в Донбассе, тянуло в родные края...») | merged_versions: 1','Давно не бывал я в Донбассе,
Тянуло в родные края,
Туда, где доныне осталась в запасе
Шахтёрская юность моя.
Осталась она неизменной,
Хотя от меня вдалеке.
Там девочка Галя живёт непременно
В рабочем своём городке.
В далёком живёт городке.
Отчаянно Галя красива,
Заметишь её за версту.
Бывалые парни глядят боязливо
На гордую ту красоту.
С тех пор хоть немало я прожил,
Душа красоте той верна.
В другую влюбился за то, что похожа
Глазами на Галю она.
Похожа на Галю она.
И вот наконец я в Донбассе,
Вот беленький домик её...
Седая хозяйка на чистой террасе
Спокойно стирает бельё.
Стою я в сторонке безмолвно,
Душа замирает в груди.
Прости меня, Галя, Галина Петровна,
Не знаю за что, но прости.
Не знаю за что, но прости.
Прости за жестокую память
О прежних косичках твоих,
За то, что мужчины бывают с годами
Моложе ровесниц своих.
Прости за те лунные ночи,
За то, что не в этом краю
Искал и нашел я похожую очень
На гордую юность мою
На давнюю юность твою.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Давно не бывал я в Донбассе, тянуло в родные края...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9cbd4900d3083809'), datetime('now')),datetime('now'));
