INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_852bafee8d7800d5','Даём мы великую клятву','(«Мы идём на врага не впервые, мы суровую школу прошли...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Александр Александров) | Песни военных лет | https://pesni.retroportal.ru/vov/daem_my_velikuyu_klyatvu.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Мы идём на врага не впервые, мы суровую школу прошли...») | merged_versions: 1','Мы идём на врага не впервые,
