INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b15f56fca5b43e8c','Далеко в Иркутской области','(«Далеко в Иркутской области, память тёплую храня...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Михаил Светлов, музыка: Матвей Блантер) | Песни военных лет | https://pesni.retroportal.ru/vov/daleko_v_irkutskoy_oblasti.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Далеко в Иркутской области, память тёплую храня...») | merged_versions: 1','Далеко в Иркутской области,
Память тёплую храня,
Ты о людях русской доблести
Помни, милая моя.
Тёмный лес, болото тряское,
Недвижим убитый конь.
И проходит муж твой ласковый
Через пушечный огонь.
Пролегла тропинка узкая
Для разведчика в ночи.
Стерегу берёзку русскую
От фашистской саранчи.
О тебе с великой силою
Я скучаю всё больней...
Славься, славься, моя милая,
Вместе с Родиной моей!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Далеко в Иркутской области, память тёплую храня...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b15f56fca5b43e8c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b15f56fca5b43e8c','Далеко в Иркутской области','Далеко в Иркутской области,
