INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_61fcd3ea1e3fe1c6','Далёко родные осины','(«Как мать, дожидается сына родная сторонка моя...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Василий Соловьёв-Седой) | Патриотические песни | https://pesni.retroportal.ru/rodina/daleko_rodnye_osiny.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Как мать, дожидается сына родная сторонка моя...») | merged_versions: 1','Далёко родные осины,
Далёко родные края...
Как мать, дожидается сына
Родная сторонка моя.
Там в доме нас ждёт-ожидает
Родимая мать у дверей,
Солдатское сердце тоскует
О родине милой своей.
Россия, Россия, Россия...
Мы в сердце тебя пронесли.
Прошли мы дороги большие,
Но краше страны не нашли...','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Как мать, дожидается сына родная сторонка моя...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_61fcd3ea1e3fe1c6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_61fcd3ea1e3fe1c6','Далёко родные осины','Далёко родные осины,
