INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_61fcd3ea1e3fe1c6_10c85f8bc74e91ff','rpp_61fcd3ea1e3fe1c6','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/daleko_rodnye_osiny.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4676f8bcbdf5fb46','Далеко-далеко','(«Далеко-далеко, где кочуют туманы...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Чуркин, музыка: Георгий Носов) | Патриотические песни | https://pesni.retroportal.ru/rodina/daleko_daleko.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Далеко-далеко, где кочуют туманы...») | merged_versions: 1','Далеко-далеко,
Где кочуют туманы,
Где от лёгкого ветра
Колышется рожь.
Ты в родимом краю
У степного кургана,
Обо мне вспоминая,
Как прежде, живёшь.
От далёкого друга
День и ночь непрестанно
Дорогой и желанной
Ты всё весточки ждёшь.
Небосклон над тобой
Опрокинулся синий,
Плещут быстрые реки,
Вздыхают моря.
Широко протянулась
Большая Россия&nbsp;-
Дорогая Отчизна
Твоя и моя.
О тебе, светлоокой.
Моей зорьке красивой,
На далёкой границе
Вновь задумался я.
Далеко-далеко
За лесами седыми,
Я твой сон и покой
Всякий час берегу.
Чтоб звериной тропой
В край, навеки родимый,
Не пройти никогда
Никакому врагу.
О тебе, моя зорька,
На далёкой заставе
В нашей жизни тревожной
Я забыть не могу.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Далеко-далеко, где кочуют туманы...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4676f8bcbdf5fb46'), datetime('now')),datetime('now'));
