INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1d37b7ed3dd44e13','Два весёлых гуся','(Песенка из мультфильма «Весёлая карусель»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (русская народная песня в обработке Виктора Купревича) | Песни для детей | https://pesni.retroportal.ru/deti/dva_veselyh_gusya.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песенка из мультфильма «Весёлая карусель») | merged_versions: 1','Жили у бабуси
Два весёлых гуся:
Один&nbsp;- серый,
Другой&nbsp;- белый&nbsp;-
Два весёлых гуся.
Вытянули шеи&nbsp;-
У кого длиннее?
Один&nbsp;- серый,
Другой&nbsp;- белый&nbsp;-
У кого длиннее?
Мыли гуси лапки
В луже у канавки.
Один&nbsp;- серый,
Другой&nbsp;- белый&nbsp;-
Спрятались в канавке.
Вот кричит бабуся:
Ой, пропали гуси!
