INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b80270733c2cc33d','Два молодчика садочком шли',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/26.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Два молодчика садочком шли,
Два удалые, зелёными!
Раз, два – люблю тебя, люблю тебя...
Два удалые, зелёными!
Пиджачки на них чернеются,
А рубашечки белеются.
Раз, два – люблю тебя, люблю тебя...
А рубашечки белеются.
Как во правой руке тросточка,
А во левой папиросочка.
Раз, да – люблю тебя, люблю тебя...
А во левой папиросочка.
Папиросочки покуривают,
Со девицами разговаривают.
Раз, два – люблю тебя, люблю тебя...
Со девицами разговаривают.
Все беседы и компании обошли,
Себя краше и милее не нашли.
Раз, два – люблю тебя, люблю тебя...
Себя краше и милее не нашли.
&laquo;Есть и лучше и краше есть –
Моему сердцу желания того нет.
Раз, два – люблю тебя, люблю тебя...
Моему сердцу желания того нет&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b80270733c2cc33d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b80270733c2cc33d','Два молодчика садочком шли','Два молодчика садочком шли,
