INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_53abbf35b39c90e0','Двадцать пять','(злободневные куплеты)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Владимир Дыховичный, музыка: Аркадий Островский) | Песни военных лет | https://pesni.retroportal.ru/vov/dvadcat_pyat.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: (злободневные куплеты) | merged_versions: 1','К поезду на станцию колхоз
Для бойцов подарков воз привёз.
Чтоб на фронт с гостинцами багаж
Прибыл точно в светлый праздник наш,
Так в письме решили написать:
&laquo;Красной Армии сегодня двадцать пять.
В знак того подарков вам послать
Мы хотим всего по двадцать пять:
Двадцать пять кило варенья,
Двадцать пять кульков печенья,
Двадцать пять флакончиков духов,
Двадцать пять отборных кур и петухов,
Двадцать пять коробок серных спичек,
Двадцать пять пуховых рукавичек,
Чтоб в мороз тепло было стрелять,
И приветов тоже ровно двадцать пять!&raquo;
На соседней станции в вагон
Подвезли подарков восемь тонн,
И, поскольку груз теперь иной,
Сделали поправки в наклалной.
Юбилейной цифры двадцать пять
Всё же порешили не менять,
И в записке значится опять:
&laquo;К празднику всего по двадцать пять:
Двадцать пять пудов варенья,
Двадцать пять кулей печенья,
Двадцать пять бутылочек духов,
Двадцать пять четвёрок кур и петухов,
Двадцать пять десятков серных спичек,
Двадцать пять полдюжин рукавичек,
Чтоб в мороз тепло было стрелять,
И приветов ровно пятью двадцать пять!&raquo;
Песня (злободневные куплеты) &laquo;Двадцать пять&raquo; из репертуара артиста эстрады  Владимира Филипповича Коралли , была написана в 1942 году. Премьера её состоялась в день двадцатипятилетия Красной Армии&nbsp;- песня открывала театрализованную программу джаза &laquo; Города-герои &raquo; в постановке  Михаила Яншина . Злободневные куплеты звучали и во  фронтовых концертах  джаз-оркестра под управлением  Клавдии Шульженко  и Владимира Коралли. Песню &laquo;Двадцать пять&raquo;  Владимир Коралли  исполнял и на склоне лет в своём ретроспективном обозрении &laquo; Эстрада, эстрада, эстрада моя! &raquo;','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(злободневные куплеты)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_53abbf35b39c90e0'), datetime('now')),datetime('now'));
