INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0b63cf2b501838b6','Дважды два - четыре','(из песен о школе)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пляцковский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/dvazhdy_dva_chetyre.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (из песен о школе) | merged_versions: 1','Дважды два&nbsp;- четыре,
Дважды два&nbsp;- четыре,
Это всем известно в целом мире,
Дважды два&nbsp;- четыре,
Дважды два&nbsp;- четыре,
Это всем известно в целом мире!
Припев:
Дважды два&nbsp;- четыре,
Дважды два&nbsp;- четыре,
А не три, а не пять&nbsp;-
Это надо знать!
Дважды два&nbsp;- четыре,
Дважды два&nbsp;- четыре,
А не шесть, а не семь&nbsp;-
Это ясно всем!
Трижды три навеки&nbsp;- девять,
Ничего тут не поделать!
И нетрудно сосчитать,
Сколько будет пятью пять!
Пятью пять&nbsp;- двадцать пять!
Пятью пять&nbsp;- двадцать пять!
Совершенно верно!
Припев
У кого, друзья, не спросим,
Шестью восемь&nbsp;- сорок восемь!
Шестью шесть&nbsp;- прошу учесть,
Неизменно тридцать шесть!
Шестью шесть&nbsp;- тридцать шесть!
Шестью шесть&nbsp;- тридцать шесть!
Совершенно верно!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(из песен о школе)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0b63cf2b501838b6'), datetime('now')),datetime('now'));
