INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_43ec774d3f945be5','Две гитары',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Аполлон Григорьев, музыка: Иван Васильев) | Старинные романсы | https://pesni.retroportal.ru/sr1/22.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Две гитары за стеной
Жалобно заныли...
С детства памятный напев,
Милый, это ты ли?
Эх, раз, ещё раз,
Ещё много, много раз!
Это ты, я узнаю
Ход твой в ре миноре
И мелодию твою
В частом переборе.
Эх, раз, ещё раз,
Ещё много, много раз!
Как тебя мне не узнать?
На тебе лежит печаль
Страстного веселья,
Бурного похмелья.
Эх, раз, ещё раз,
Ещё много, много раз!
Это ты, загул лихой,
Окол пунша грелки
И мелодия твоя
На мотив венгерки.
Эх, раз, ещё раз,
Ещё много, много раз!
Ах болит, ах болит
Голова с похмелья...
Уж мы пьём, мы будем пить
Целую неделю!
Эх, раз, ещё раз,
Ещё много, много раз!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_43ec774d3f945be5'), datetime('now')),datetime('now'));
