INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a3100be3fe9657fa','Девонька милая',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/27.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Девонька милая,
Девонька славная,
Девонька, радость моя.
Если б ты знала, моя ненаглядная,
Грустно мне так без тебя.
Утром проснусь, не успею опомниться,
Первая мысль о тебе:
Где ж моя девонька,
Любит ли, помнит ли
Друга в далёкой земле?
Мне эти карие
Грезятся глазоньки,
Чудные светлы, как май,
Они мои грёзы,
Они мои сказоньки,
Они – обетованный рай.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a3100be3fe9657fa'), datetime('now')),datetime('now'));
