INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b54d82388f6e50ee','Дельфины','(Песня из мультфильма «В порту»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Козлов, музыка: Марк Минков) | Песни для детей | https://pesni.retroportal.ru/deti/delfiny.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «В порту») | merged_versions: 1','Корабли в открытом море
Как птицы на воле.
В неизвестные просторы
Уносят смелых волны.
И плывут они куда-то
Вслед за солнечным закатом.
И весёлые дельфины
Провожают корабли.
А дельфины добрые,
А дельфины мокрые
На тебя глядят
Умными глазами.
А дельфины скромные,
А дельфины добрые
Просят, чтобы им
Сказку рассказали.
Есть в лазурном океане
Таинственный остров
Но найти его в тумане
Матросам так непросто
Среди волн отыщет берег
Только тот, кто в сказку верит
Только тот, кто сам сумеет
Людям сказку рассказать.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «В порту»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b54d82388f6e50ee'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b54d82388f6e50ee','Дельфины','Корабли в открытом море
