INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_416971a3bd51ef93','До свиданья, города и хаты','(«До свиданья, города и хаты, нас дорога дальняя зовёт...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Матвей Блантер) | Песни военных лет | https://pesni.retroportal.ru/vov/do_svidaniya_goroda_i_haty.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («До свиданья, города и хаты, нас дорога дальняя зовёт...») | merged_versions: 1','До свиданья, города и хаты,
Нас дорога дальняя зовёт,
Молодые, смелые ребята,
На заре уходим мы в поход.
На заре девчата выходите
Комсомольский провожать отряд
Вы без нас, девчата не грустите&nbsp;-
Мы с победою придём назад!
Мы развеем вражеские тучи,
Разметём преграды на пути
И врагу от смерти неминучей
От своей могилы не уйти!
Наступил великий час расплаты
Нам вручил оружие народ&nbsp;-
До свиданья, города и хаты,
На заре уходим мы в поход!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«До свиданья, города и хаты, нас дорога дальняя зовёт...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_416971a3bd51ef93'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_416971a3bd51ef93','До свиданья, города и хаты','До свиданья, города и хаты,
