INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bad8332498e6e519','Добрый жук','(Песня из кинофильма «Золушка»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Шварц, музыка: Антонио Спадавеккиа) | Песни для детей | https://pesni.retroportal.ru/deti/dobry_zhuk.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из кинофильма «Золушка») | merged_versions: 1','Встаньте, дети, встаньте в круг,
Встаньте в круг, встаньте в круг!
Жил на свете добрый жук,
Старый добрый друг.
Никогда он не ворчал,
Не кричал, не пищал,
Громко крыльями трещал,
Строго ссоры запрещал.
Встаньте, дети, встаньте в круг
Встаньте в круг, встаньте в круг!
Ты мой друг, и я твой друг,
