Очень уж душа легка
У него, весельчака.
Встаньте, дети, встаньте в круг
Встаньте в круг, встаньте в круг!
Ты мой друг, я твой друг,
Старый верный друг!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из кинофильма «Золушка»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bad8332498e6e519'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bad8332498e6e519','Добрый жук','Встаньте, дети, встаньте в круг,
