INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0d5a49be8cbfc134','Догорает румяный закат',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: В. Кульчинский, музыка: Милий Балакирев) | Старинные романсы | https://pesni.retroportal.ru/sr1/23.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Догорает румяный закат,
Золотистые меркнут вершины...
Тихий вечер дремотой объят,
Онемели леса и долины...
О, забудь, моё сердце, те дни,
Те мятежные дни вдохновенья,
Моё бедное сердце, усни!
Не вернёшь дорогие мгновенья!
Из-за туч показалась луна,
Озарив своим блеском поляны...
Ах, зачем же не может она
Исцелить мне душевные раны?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0d5a49be8cbfc134'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_0d5a49be8cbfc134','Догорает румяный закат','Догорает румяный закат,
Золотистые меркнут вершины...
Тихий вечер дремотой объят,
Онемели леса и долины...
О, забудь, моё сердце, те дни,
Те мятежные дни вдохновенья,
Моё бедное сердце, усни!
Не вернёшь дорогие мгновенья!
Из-за туч показалась луна,
Озарив своим блеском поляны...
Ах, зачем же не может она
Исцелить мне душевные раны?');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_0d5a49be8cbfc134_4ad50072e04db58b','rpp_0d5a49be8cbfc134','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/23.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_23f9ba478c5ba181','Домой, домой','(«Домой, домой! Над бухтой чайка вьётся...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/domoj_domoj.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Домой, домой! Над бухтой чайка вьётся...») | merged_versions: 1','Домой, домой! Над бухтой чайка вьётся,
Опять волна вскипает за кормой.
Скажи мне, друг, чьё сердце не забьётся,
Когда звучат слова: домой, домой!
&laquo;Домой, домой!&raquo;&nbsp;- поёт попутный ветер,
А ты глядишь, не отрывая глаз,
Ведь ничего милее нет на свете,
Чем дом родной, где ждут и любят нас!
Домой, домой, сквозь бури и ненастье,
Домой, домой мы держим курс прямой,
И тот лишь знает, что такое счастье,
Кто, кончив путь, спешит домой, домой!
Домой, домой пилот всегда стремится,
Моряк плывёт сквоь ветер штормовой,
Летят домой из дальних странствий птицы,
И мы спешим домой, домой, домой!
&laquo;Домой! Домой!&raquo;&nbsp;- в пути и на привале
Ты пел не раз от Родины вдали.
И где бы мы с тобой не побывали,
Мы дом родной повсюду берегли.
&laquo;Домой! Домой!&raquo;&nbsp;- поёт попутный ветер,
А ты глядишь, не отрывая глаз,
Ведь ничего дороже нет на свете,
Чем дом родной, где ждут и любят нас!
Домой! Домой! Домой! Домой!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Домой, домой! Над бухтой чайка вьётся...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_23f9ba478c5ba181'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_23f9ba478c5ba181','Домой, домой','Домой, домой! Над бухтой чайка вьётся,
