INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3cfcfa7adee6fe1b','Дорога-дорога','(«Оглянется каждый прохожий, увидя твой взгляд озорной...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Василий Соловьёв-Седой) | Патриотические песни | https://pesni.retroportal.ru/rodina/doroga-doroga.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Оглянется каждый прохожий, увидя твой взгляд озорной...») | merged_versions: 1','Оглянется каждый прохожий,
Увидя твой взгляд озорной...
Ты в ситцевом платье похожа
На яркий цветок полевой.
Припев:
Дорога-дорога
Нас в дальние дали зовёт...
Быть может, до счастья осталось немного,
Быть может, один поворот...
Глаза твои искрятся светом,
Но мимо проходит мой путь.
Быть может, я счастье проехал
И нужно назад повернуть?..
Припев
Метели, что ломятся в дверцы,
С дороги меня не собьют!
Мне только бы к милому сердцу
Найти побыстрее маршрут...
Припев
Оглянется каждый прохожий,
Увидя твой взгляд озорной...
Ты в ситцевом платье похожа
На яркий цветок полевой.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Оглянется каждый прохожий, увидя твой взгляд озорной...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3cfcfa7adee6fe1b'), datetime('now')),datetime('now'));
