INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_3cfcfa7adee6fe1b_8d263dad3ef63088','rpp_3cfcfa7adee6fe1b','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/doroga-doroga.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_15e01a9c8a58ead4','Дороги дальние','(«Чуть горит зари полоска узкая...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Иван Молчанов, музыка: Леонид Бакалов) | Патриотические песни | https://pesni.retroportal.ru/rodina/dorogi_dalnie.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Чуть горит зари полоска узкая...») | merged_versions: 1','Чуть горит зари полоска узкая,
Золотая, тихая струя...
Ой ты, мать-земля родная, русская,
Дорогая родина моя!
В серебре деревья, как хрустальные,
Но тревожен зимний их убор.
И бегут, бегут дороги дальние
Средь полей в немереный простор.
Чья душа с тоскою не оглянется:
Сквозь туман, взрывая ночь и тьму,
Вражья рать по тем дорогам тянется
К городу родному твоему.
Ой, дороги, дымные, военные,
За Москву тяжёлые бои!..
На дорогах воры иноземные
Растеряли головы свои.
Не для них сады у нас посажены,
Молодые, светлые сады,
Не для них дороги наши лажены,
Не для них построены мосты.
Ты гори, зари полоска узкая!
По земле ползёт пожара дым...
Мы тебя, земля родная, русская,
Никогда в обиду не дадим!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Чуть горит зари полоска узкая...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_15e01a9c8a58ead4'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_15e01a9c8a58ead4','Дороги дальние','Чуть горит зари полоска узкая,
