INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_15e01a9c8a58ead4_9acd12d661d3be4b','rpp_15e01a9c8a58ead4','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/dorogi_dalnie.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5c8872ca9dd1213d','Дорогой длинною',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Константин Подревский, музыка: Борис Фомин) | Старинные романсы | https://pesni.retroportal.ru/sr1/24.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ехали на тройке с бубенцами,
А вдали мелькали огоньки...
Эх, когда бы мне теперь за вами,
Душу бы развеять от тоски!
Дорогой длинною, погодой лунною,
Да с песней той, что вдаль летит звеня,
И с той старинною, да семиструнною,
Что по ночам так мучила меня!
Да выходит, пели мы задаром,
Понапрасну ночь за ночью жгли.
Если мы покончили со старым,
Так и ночи эти отошли!
Дорогой длинною, погодой лунною,
Да с песней той, что вдаль летит звеня,
И с той старинною, да семиструнною,
Что по ночам так мучила меня!
В даль родную новыми путями
Нам отныне ехать суждено!
Ехали на тройке с бубенцами,
Да теперь проехали давно!
Дорогой длинною, погодой лунною,
Да с песней той, что вдаль летит звеня,
И с той старинною, да семиструнною,
Что по ночам так мучила меня!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5c8872ca9dd1213d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5c8872ca9dd1213d','Дорогой длинною','Ехали на тройке с бубенцами,
