INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_5c8872ca9dd1213d_6a11bb2338ad7487','rpp_5c8872ca9dd1213d','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/24.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8823ca02b57b2352','Дорожная','(«Змеится под колёсами стальное полотно...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Васильев, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/dorozhnaya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Змеится под колёсами стальное полотно...») | merged_versions: 1','Змеится под колёсами стальное полотно,
Без устали, без устали смотрю, смотрю в окно.
Леса, равнины русские, пригорки да кусты,
Платформы деревянные, железные мосты...
Припев:
Любимая, знакомая, широкая, зелёная,
Земля родная, Родина, привольное житьё!
Эх, сколько мною видано, эх, сколько мною езжено,
Эх, сколько мною пройдено&nbsp;- и всё вокруг моё!
То фабрика кирпичная&nbsp;- высокая труба,
То хата побелённая, то в поле молотьба...
И всё-то сердцу дорого, и нет версты такой,
Посёлка или города, чтоб был тебе чужой.
Припев
Уже роса за стёклами, уже видать луну,
А я стою, прикованный к вагонному окну...
Уже пора посвечивать ночному фонарю,
А я гляжу на сумерки и тихо говорю:
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Змеится под колёсами стальное полотно...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8823ca02b57b2352'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8823ca02b57b2352','Дорожная','Змеится под колёсами стальное полотно,
Без устали, без устали смотрю, смотрю в окно.
