INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8d3aadd49ff159b5','Дремлют чинары',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка неизвестного автора) | Старинные романсы | https://pesni.retroportal.ru/sr1/25.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Дремлют чинары под твоим окном,
Льются звуки гитары, тихо всходит луна,
Звуки несутся из груди, словно рвутся,
Плачут, рыдают, рокочут, как волна.
С гитарой стою, тебя молю,
Тебя зову ко мне на грудь.
И всё забудь, но помни только об одном,
Что под твоим окном стою с мольбой,
Мольбой одной и умереть
У ног твоих готов за любовь.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8d3aadd49ff159b5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8d3aadd49ff159b5','Дремлют чинары','Дремлют чинары под твоим окном,
Льются звуки гитары, тихо всходит луна,
Звуки несутся из груди, словно рвутся,
Плачут, рыдают, рокочут, как волна.
С гитарой стою, тебя молю,
Тебя зову ко мне на грудь.
И всё забудь, но помни только об одном,
Что под твоим окном стою с мольбой,
Мольбой одной и умереть
У ног твоих готов за любовь.');
