INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_53f35b338c2ac978','Дрозды','(«Вы слыхали, как поют дрозды?»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Островой, музыка: Владимир Шаинский) | Патриотические песни | https://pesni.retroportal.ru/rodina/drozdy.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Вы слыхали, как поют дрозды?») | merged_versions: 1','Вы слыхали, как поют дрозды?
Нет, не те дрозды, не полевые,
А дрозды, волшебники-дрозды,
Певчие избранники России.
Вот они расселись по лесам,
Зазвучали до самозабвенья.
Узнаю я их по голосам,
Звонких повелителей мгновенья.
Звуки вырастают, как цветы&nbsp;-
Грустные, весёлые, любые,
То горячие до красноты,
То холодновато-голубые.
Достают до утренней звезды,
Радугами падают на травы...
Шапки прочь, в лесу поют дрозды,
Для души поют, а не для славы!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Вы слыхали, как поют дрозды?»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_53f35b338c2ac978'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_53f35b338c2ac978','Дрозды','Вы слыхали, как поют дрозды?
Нет, не те дрозды, не полевые,
А дрозды, волшебники-дрозды,
Певчие избранники России.
Вот они расселись по лесам,
