INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c690c36010463b47','Дума о Родине','(«Когда вечерняя звезда взойдёт на синем небосклоне...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Вадим Малков, музыка: Серафим Туликов) | Патриотические песни | https://pesni.retroportal.ru/rodina/duma_o_rodine.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Когда вечерняя звезда взойдёт на синем небосклоне...») | merged_versions: 1','Когда вечерняя звезда взойдёт на синем небосклоне,
И день горячего труда устало голову приклонит,
Тогда я слышу голос твой, страна великих расстояний,
Морей полуночный прибой, полей безоблачных дыханье.
Я слышу шаг седых веков, набатный звон колоколов.
В святой борьбе, в отваге воинов твой трудный путь я вижу, Родина.
Твоим дыханьем я согрет, веду с орбиты славных лет
К далёким звёздам дерзкий свет, чтоб ты была сильней, страна богатырей!
Проходит время над землёй. Отцов в пути сменяют дети...
Отчизна, жить твоей судьбой&nbsp;- прекрасней нет судьбы на свете!
Дорога дальняя зовёт, и нету ей конца и края,
И счастлив, кто по ней идёт к твоей мечте, страна родная!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Когда вечерняя звезда взойдёт на синем небосклоне...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c690c36010463b47'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c690c36010463b47','Дума о Родине','Когда вечерняя звезда взойдёт на синем небосклоне,
