INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2f4aab4b28c94737','Едут новосёлы','(«Ой ты, зима морозная, ноченька яснозвёздная!..»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Солохин, музыка: Евгений Родыгин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/edut_novosely.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Ой ты, зима морозная, ноченька яснозвёздная!..») | merged_versions: 1','Родины просторы, горы и долины,
В серебро одетый зимний лес грустит.
Едут новосёлы по земле целинной,
Песня молодая далеко летит.
Припев:
Ой ты, зима морозная,
Ноченька яснозвёздная!
Скоро ли я увижу
Свою любимую в степном краю?
Вьётся дорога длинная,
Здравствуй земля целинная!
Здравствуй, простор широкий,
Весну и молодость встречай свою!
Зашумят метели, затрещат морозы,
Но друзей целинных нелегко сломить.
На полях бескрайних вырастут совхозы, -
Только без тебя немножко грустно будет жить.
Припев
Ты ко мне приедешь раннею весною
Молодой хозяйкой прямо в новый дом.
С голубым рассветом тучной целиною
Трактора мы вместе рядом поведём.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Ой ты, зима морозная, ноченька яснозвёздная!..»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2f4aab4b28c94737'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_2f4aab4b28c94737','Едут новосёлы','Родины просторы, горы и долины,
