INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c9e11a7e1dcaffd2','Ёжик резиновый','(«Песенка о ёжике»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Юнна Мориц, музыка: Сергей Никитин) | Песни для детей | https://pesni.retroportal.ru/deti/ezhik_rezinovy.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: («Песенка о ёжике») | merged_versions: 1','По роще калиновой,
По роще осиновой
На именины к щенку
В шляпке малиновой
Шёл ёжик резиновый
С дырочкой в правом боку.
Были у ёжика
Зонтик от дождика,
Шляпа и пара галош.
Божьей коровке,
Цветочной головке
Ласково кланялся ёж.
&laquo;Здравствуйте, ёлки!
На что вам иголки?
Разве мы волки вокруг?
Как вам не стыдно!
Это обидно,
Когда ощетинился друг.&raquo;
Небо лучистое,
Облако чистое.
На именины к щенку
Ёжик резиновый
Шёл и насвистывал
Дырочкой в правом боку.
&laquo;Милая птица,
Извольте спуститься&nbsp;-
Вы потеряли перо.
На красной аллее,
Где клёны алеют,
Ждёт вас находка в бюро.&raquo;
Небо лучистое,
Облако чистое.
На именины к щенку
Ёжик резиновый
Шёл и насвистывал
Дырочкой в правом боку.
Много дорожек
Прошёл этот ёжик.
А что подарил он дружку?
Об этом он Ване
Насвистывал в ванне
Дырочкой в правом боку.
Небо лучистое,
Облако чистое.
На именины к щенку
Ёжик резиновый
Шёл и насвистывал
Дырочкой в правом боку.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(«Песенка о ёжике»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c9e11a7e1dcaffd2'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c9e11a7e1dcaffd2','Ёжик резиновый','По роще калиновой,
