INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_79d3be32c1a56087','Ёлка','(Песня сочинена в 1937 году и посвящена Наталии Сац)','ru','ussr',NULL,'1937','pesni.retroportal.ru | (слова: Ольга Высоцкая, музыка: Михаил Раухвергер) | Песни для детей | https://pesni.retroportal.ru/deti/pesnya_elka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня сочинена в 1937 году и посвящена Наталии Сац) | merged_versions: 1','Соберёмся вместе мы
На празднике своём,
Потанцуем весело
И песенку споём.
Припев:
Не шуми ты, ёлка,
Не роняй иголки,
Соберём сегодня мы всех ребят,
Песни новогодние пусть звенят!
Ёлочка игрушками
Украшена кругом,
Синими хлопушками,
Серебряным дождём.
Припев
Вот на праздник радостный
Пришёл к нам Дед Мороз.
Много разных сладостей
Ребятам он принёс.
Припев
Встретим праздник песнями
О детстве золотом.
Жить нам всё чудеснее,
Всё лучше с каждым днём.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня сочинена в 1937 году и посвящена Наталии Сац)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_79d3be32c1a56087'), datetime('now')),datetime('now'));
