INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_39e758e4779bdd9a_47d4fdb9adf89d3e','rpp_39e758e4779bdd9a','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/pesenka_elochka.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_94b57602e7e4a51c','Ёлочка - зелёная иголочка','(Детская новогодняя песня)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Ида Векшегонова, музыка: Зиновий Компанеец) | Песни для детей | https://pesni.retroportal.ru/deti/elochka_zelenaya_igolochka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Детская новогодняя песня) | merged_versions: 1','Не рубили ёлочку
Мы на Новый год&nbsp;-
Возле дома нашего
Ёлочка растёт.
Припев:
Ёлочка, ёлочка,
Зелёная иголочка,
Шишки золотистые
Искры серебристые,
Вся ты в белом инее,
Только небо&nbsp;- синее.
Облепили ёлочку
Звёзды и флажки,
И горят на ёлочке
Чудо-огоньки.
Припев
Возле нашей ёлочки
Водим хоровод,
Здравствуй, здравствуй, ёлочка!
Здравствуй, Новый год!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Детская новогодняя песня)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_94b57602e7e4a51c'), datetime('now')),datetime('now'));
