INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_83290c811e2f91ac','Енисей - брат полярных морей','(«Пробудился от зимнего сна, сбросил цепи свои Енисей...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Фролов, музыка: Сергей Кайдан-Дёшкин) | Патриотические песни | https://pesni.retroportal.ru/rodina/enisej-brat_polyarnyh_morey.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Пробудился от зимнего сна, сбросил цепи свои Енисей...») | merged_versions: 1','Пробудился от зимнего сна,
Сбросил цепи свои Енисей.
И в Сибирь прилетела весна,
Зашептала улыбкой своей.
Припев:
Енисей, Енисей, по дороге широкой твоей
Днём и ночью плывут корабли!
До полярных морей ты несёшь, Енисей,
Славу гордую русской земли!
И в далёкий поход теплоход
Провожают оркестры в порту.
Он, как знамя, на север несёт
Имя &laquo;Ленин&raquo; на белом борту.
Припев
Над волною широкой твоей
Разлилась бирюзовая ширь.
Покорил и тебя, Енисей,
Наш великий народ-богатырь!
Припев
Много рек у Отчизны моей,
Много песен слагает народ.
Так пускай о тебе, Енисей,
Эту песню народ запоёт!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Пробудился от зимнего сна, сбросил цепи свои Енисей...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_83290c811e2f91ac'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_83290c811e2f91ac','Енисей - брат полярных морей','Пробудился от зимнего сна,
