INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_83290c811e2f91ac_e0edda5052847276','rpp_83290c811e2f91ac','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/enisej-brat_polyarnyh_morey.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_614fb41c3266f5e3','«Ермак» («Ревела буря», «Смерть Ермака»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Кондратий Рылеев) | Народные песни | https://pesni.retroportal.ru/np1/29.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вариант I (из песенников XX века)
Ревела буря, дождь шумел,
Во мраке молнии блистали,
И беспрерывно гром гремел,
И ветры в дебрях бушевали...
Ко славе страстию дыша,
В стране суровой и угрюмой,
На диком бреге Иртыша
Сидел Ермак, объятый думой.
Товарищи его трудов,
Побед и громкозвучной славы
Среди раскинутых шатров
Беспечно спали средь дубравы.
Страшась вступать с героем в бой,
Кучум к шатрам, как тать презренный,
Прокрался тайною тропой,
Татар толпами окруженный.
Мечи сверкнули в их руках,
И окровавилась долина,
И пала, грозная в боях,
Не обнажив мечей, дружина.
Ермак воспрянул ото сна
И, гибель зря, стремится в волны,
Душа отвагою полна...
Но далеко от брега чёлны!
Иртыш волнуется сильней...
Ермак все силы напрягает –
И мощною рукой своей
Валы седые рассекает.
Ревела буря... Вдруг луной
Иртыш кипящий осребрился,
И труп, низвергнутый волной,
В броне медяной озарился.
Носились тучи, дождь шумел,
И молнии ещё сверкали,
И гром вдали ещё гремел,
И ветры в дебрях бушевали.
Вариант II (более полный, 1822 год)
Ревела буря, дождь шумел;
Во мраке молнии летали;
И беспрерывно гром гремел
И ветры в дебрях бушевали...
Ко славе страстию дыша,
В стране суровой и угрюмой,
На диком берегу Иртыша
Сидел Ермак, объятый думой.
Товарищи его трудов,
Побед и громозвучной славы,
Среди раскинутых шатров
Беспечно спали, близ дубравы.
&laquo;О, спите, спите&raquo; - мнил Герой,
&laquo;Друзья под бурею ревущей;
С рассветом глас раздастся мой,
На славу иль на смерть зовущий!&raquo;
&laquo;Вам нужен отдых; сладкий сон
И в бурю храбрых успокоит;
В мечтах напомнит славу он
И силы ратников удвоит.
Кто жизни не щадил своей
В разбоях злато добывая:
Тот думать будет ли о ней,
За Русь святую погибая?&raquo;
&laquo;Своей и вражьей кровью смыв
Все преступленья буйной жизни
И за победы заслужив
Благословения отчизны.&raquo;
Но роковой его удел
Уже сидел с Героем рядом
И с сожалением глядел
На жертву любопытным взглядом.
Ревела буря - дождь шумел;
Во мраке молнии летали;
И беспрерывно гром гремел
И ветры в дебрях бушевали.
Иртыш кипел в крутых брегах,
Вздымалися седые волны,
И рассыпались с рёвом в прах,
Бия о брег, козачьи чолны.
С вождём покой объятья сна
Дружина храбрая вкушала;
С Кучумом буря лишь одна
На их погибель не дремала!
Страшась вступить с Героем в бой,
Кучум к шатрам, как тать презренный,
Прокрался тайною тропой,
Татар толпами окруженный.
Мечи сверкнули в их руках -
И окровавилась долина,
И пала грозная в боях,
Не обнажив мечей, дружина...
Ермак воспрянул ото сна,
И, гибель зря, стремится в волны,
Душа отвагою полна,
Но далеко от брега челны!
Иртыш волнуется сильней -
Ермак все силы напрягает,
И мощною рукой своей
Валы седые рассекает...
Плывёт... уж близко челнока -
Но сила року уступила,
И, закипев страшней, река
Героя с шумом проглотила.
Лишивши сил богатыря
Бороться с ярою волною,
Тяжёлый панцирь - дар царя
Стал гибели его виною.
Ревела буря... вдруг луной
Иртыш кипящий осребрился,
И труп, извергнутый волной
В броне медяной озарился.
Носились тучи, дождь шумел,
И молнии ещё сверкали,
И гром вдали ещё гремел,
И ветры в дебрях бушевали.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_614fb41c3266f5e3'), datetime('now')),datetime('now'));
