INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_614fb41c3266f5e3_0a9cebec4e3aa763','rpp_614fb41c3266f5e3','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/29.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_22f655ae26ce2a10','Если б гармошка умела','(Песня из кинофильма «Солдат Иван Бровкин»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Анатолий Лепин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/esli_b_garmoshka_umela.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из кинофильма «Солдат Иван Бровкин») | merged_versions: 1','Не для тебя ли в садах наших вишни
Рано так начали зреть?
Рано весёлые звёздочки вышли,
Чтоб на тебя поглядеть.
Припев:
Если б гармошка умела
Всё говорить, не тая...
Русая девушка в кофточке белой,
Где ж ты, ромашка моя?
Птицы тебя всюду песней встречают,
Ждёт ветерок у окна.
Ночью дорогу тебе освещает,
Выйдя навстречу, луна.
В мире тебя нет красивей,
Ты - словно песнь соловья.
Ты, словно в небе, широком и синем,
Ранняя зорька моя.
Мне, дорогая, сердечные муки
Спать до утра не дают.
Ведь о тебе все гармони в округе
Лучшие песни поют.
Припев
Где ж ты, откликнись, подружка моя?','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из кинофильма «Солдат Иван Бровкин»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_22f655ae26ce2a10'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_22f655ae26ce2a10','Если б гармошка умела','Не для тебя ли в садах наших вишни
