Припев
Где ж ты, откликнись, подружка моя?');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_22f655ae26ce2a10_59fe2d10d6a80771','rpp_22f655ae26ce2a10','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/esli_b_garmoshka_umela.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_24845eade6f29047','Если бы парни всей земли','(«Парни, парни, это в наших силах...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Василий Соловьёв-Седой) | Эстрадные песни | https://pesni.retroportal.ru/estrada/esli_by_parni_vsej_zemli.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Парни, парни, это в наших силах...») | merged_versions: 1','Если бы парни всей земли
Вместе собраться однажды могли,
Вот было б весело в компании такой
И до грядущего подать рукой.
Припев:
Парни, парни, это в наших силах
Землю от пожара уберечь.
Мы за мир, за дружбу,
За улыбки милых,
За сердечность встреч.
Если бы парни всей земли
Хором бы песню одну завели
Вот было б здорово,
Вот это был бы гром.
Давайте, парни, хором запоём!
Припев
Если бы парни всей земли
Миру присягу свою принесли,
Вот было б радостно тогда на свете жить.
Давайте, парни, навсегда дружить!
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Парни, парни, это в наших силах...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_24845eade6f29047'), datetime('now')),datetime('now'));
