INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7cdacb6f0d96f047','Если можешь - прости',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русский текст: Иосифа Аркадьева, музыка: Джованни Раймондо) | Старинные романсы | https://pesni.retroportal.ru/sr1/26.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Мне сегодня так больно,
Слёзы взор мой туманят,
Эти слёзы невольно
Я роняю в тиши.
Сердце вдруг встрепенулось,
Так тревожно забилось,
Всё былое проснулось –
Если можешь, прости!
Мой нежный друг,
Часто слёзы роняю
И с тоской вспоминаю
Дни прошедшей любви.
Я жду тебя, как прежде,
Ну, не будь таким жестоким.
Мой нежный друг,
Если можешь, прости!
Я пишу тебе снова,
Видишь капли на строчках,
Всё кругом так сурово
Без тебя, без любви.
Твои письма читаю,
Не могу оторваться
И листки их целую –
Если можешь, прости!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7cdacb6f0d96f047'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7cdacb6f0d96f047','Если можешь - прости','Мне сегодня так больно,
