INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_7cdacb6f0d96f047_f814456afc4af920','rpp_7cdacb6f0d96f047','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/26.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_df443eff4de6a129','Есть на Волге утёс',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Александр Навроцкий) | Народные песни | https://pesni.retroportal.ru/np1/30.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','(Песня о Степане Разине)
Есть на Волге утёс, диким мохом оброс
Он с вершины до самого края;
И стоит сотни лет, только мохом одет,
Ни нужды, ни заботы не зная.
На вершине его не растёт ничего,
Только ветер свободный гуляет,
Да могучий орёл свой притон там завёл
И на нём свои жертвы терзает.
Из людей лишь один на утёсе том был,
Лишь один до вершины добрался,
И утёс человека того не забыл,
И с тех пор его именем звался.
И хотя каждый год по церквам на Руси
Человека того проклинают,
Но приволжский народ о нём песни поёт
И с почётом его вспоминает.
Раз, ночною порой, возвращаясь домой,
Он один на утёс тот взобрался
И в полуночной мгле на высокой скале
Там всю ночь до зари оставался.
Много дум в голове родилось у него,
Много дум он в ту ночь передумал.
И под говор волны, средь ночной тишины
Он великое дело задумал.
Но свершить не успел он того, что хотел,
И не то ему пало на долю;
И расправой крутой да кровавой рукой
Не помог он народному горю.
Не владыкою был он в Москву привезён,
Не почётным пожаловал гостем,
И не ратным вождём, на коне и с мечом,
Он сложил свои буйные кости...
И Степан, будто знал, никому не сказал,
Никому своих дум не поведал,
Лишь утёсу тому, где он был, одному
Он те думы хранить заповедал.
И поныне стоит тот утёс и хранит
Он заветные думы Степана;
И лишь с Волгой одной вспоминает порой
Удалое житье атамана.
Но зато, если есть на Руси хоть один,
Кто с корыстью житейской не знался,
Кто свободу, как мать дорогую, любил
И во имя её подвизался, -
Пусть тот смело идёт, на утёс тот взойдёт,
Чутким ухом к вершине приляжет,
И утёс-великан всё, что думал Степан,
Всё тому смельчаку перескажет.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_df443eff4de6a129'), datetime('now')),datetime('now'));
