INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_df443eff4de6a129_c3b8a484ac989534','rpp_df443eff4de6a129','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/30.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f86e6a86114decf5','Есть на севере хороший городок','(«Есть на севере хороший городок, он в лесах суровых северных залёг...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Виктор Гусев, музыка: Тихон Хренников) | Песни военных лет | https://pesni.retroportal.ru/vov/est_na_severe_horoshij_gorodok.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Есть на севере хороший городок, он в лесах суровых северных залёг...») | merged_versions: 1','Есть на севере хороший городок,
Он в лесах суровых северных залёг.
Русская метелица там кружит, поёт,
Там моя подруженька, душенька живёт.
Письмоносец, ей в окошко постучи,
Письмецо моё заветное вручи!
Принимайте весточку с дальней стороны,
С поля битвы жаркого, с мировой войны.
Слышишь, милая, далёкая моя,
Защищаем мы родимые края!
В ноченьки морозные, в ясные деньки
В бой выходят грозные красные полки.
Мы захватчиков-фашистов разобьём,
С красным знаменем по Родине пройдём.
А война закончится, и настанет срок,-
Ворочусь я в северный милый городок.
Я по небу, небу синему промчусь,
Прямо к милому окошку опущусь.
Постучусь в окошечко, и душа замрёт...
Выходи, красавица, друг любезный ждёт!
Есть на севере хороший городок,
Он в лесах суровых северных залёг.
Русская метелица там кружит, поёт,
Там моя подруженька, душенька живёт.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Есть на севере хороший городок, он в лесах суровых северных залёг...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f86e6a86114decf5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f86e6a86114decf5','Есть на севере хороший городок','Есть на севере хороший городок,
