INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f76a85afe7749a6f','Жалобно стонет ветер осенний',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: А. Пугачёв, музыка: Дмитрий Михайлов) | Старинные романсы | https://pesni.retroportal.ru/sr1/27.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Жалобно стонет ветер осенний,
Листья кружатся поблекшие;
Сердце наполнилось чувством томления:
Помнится счастье утекшее.
Помнятся летние ночи весёлые,
Нежные речи приветные,
Очи лазурные, рученьки белые,
Ласки любви бесконечные.
Всё, что, бывало, любил беззаветно я,
Всё, во что верилось мне,
Эти ласки и речи приветные
Были лишь грёзы одне!
Медленно кружатся листья осенние,
Ветер в окошко стучит...
Память о тех счастливых мгновениях
Душу мою бередит.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f76a85afe7749a6f'), datetime('now')),datetime('now'));
