INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_137ae527771462b0','«Живёт моя отрада» («Живёт моя красотка»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Рыскин, музыка: Михаил Шишкин) | Старинные романсы | https://pesni.retroportal.ru/sr1/28.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Живёт моя отрада в высоком терему,
А в терем тот высокий нет хода никому.
Я знаю, у красотки есть сторож у крыльца.
Никто не загородит дорогу молодца.
Войду я к милой в терем и брошусь в ноги к ней.
Была бы только ночка, да ночка потемней.
Была бы только ночка, да ночка потемней.
Была бы только тройка, да тройка порезвей.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_137ae527771462b0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_137ae527771462b0','«Живёт моя отрада» («Живёт моя красотка»)','Живёт моя отрада в высоком терему,
А в терем тот высокий нет хода никому.
Я знаю, у красотки есть сторож у крыльца.
Никто не загородит дорогу молодца.
Войду я к милой в терем и брошусь в ноги к ней.
Была бы только ночка, да ночка потемней.
Была бы только ночка, да ночка потемней.
Была бы только тройка, да тройка порезвей.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_137ae527771462b0_957107383746b6e3','rpp_137ae527771462b0','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/28.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_32ab6ed0edf202ba','Жить стало лучше','(«Весел напев городов и полей - жить стало лучше, жить стало веселей...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Александр Александров) | Патриотические песни | https://pesni.retroportal.ru/rodina/zhit_stalo_luchshe.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Весел напев городов и полей - жить стало лучше, жить стало веселей...») | merged_versions: 1','Звонки как птицы, одна за другой,
Песни летят над советской страной,
Весел напев городов и полей&nbsp;-
Жить стало лучше, жить стало веселей!
Дружно страна и растёт и поёт,
С песнею новое счастье куёт.
Глянешь на солнце&nbsp;- и солнце светлей.
Жить стало лучше, жить стало веселей!
Всюду простор для ума и для рук,
Всюду находишь друзей и подруг.
Старость&nbsp;- теплее и юность&nbsp;- смелей.
Жить стало лучше, жить стало веселей!
Знай, Ворошилов, мы все начеку,
Пяди земли не уступим врагу
Силушка есть у отцов и детей.
Жить стало лучше, жить стало веселей!
Хочется всей необъятной страной
Сталину крикнуть &laquo;Спасибо, Родной!&raquo;
Долгие годы живи, не болей
Жить стало лучше, жить стало веселей!
Звонки как птицы, одна за другой,
Песни летят над советской страной,
Весел напев городов и полей&nbsp;-
Жить стало лучше, жить стало веселей!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Весел напев городов и полей - жить стало лучше, жить стало веселей...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_32ab6ed0edf202ba'), datetime('now')),datetime('now'));
