INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2f91c763f095554b','Журавлёнок','(«Ушло тепло с полей и стаю журавлей...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Игорь Шаферан, музыка: Эдуард Колмановский) | Патриотические песни | https://pesni.retroportal.ru/rodina/zhuravlenok.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Ушло тепло с полей и стаю журавлей...») | merged_versions: 1','Ушло тепло с полей,
И стаю журавлей
Ведёт вожак в заморский край зелёный.
Летит печально клин,
И весел лишь один,
Один какой-то журавлёнок несмышлёный.
Он рвётся в облака,
Торопит вожака,
Но говорит ему вожак сурово:
&laquo;Пусть та земля теплей,
А родина&nbsp;- милей,
Милей&nbsp;- запомни, журавлёнок, это слово!
Запомни шум берёз
И тот крутой откос,
Где мать тебя увидела летящим.
Запомни навсегда,
Иначе никогда,
Дружок, не станешь журавлём ты настоящим!&raquo;
У нас лежат снега,
У нас гудит пурга,
И голосов совсем не слышно птичьих,
А где-то там, вдали,
Курлычут журавли,
Они о родине заснеженной курлычут...','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Ушло тепло с полей и стаю журавлей...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2f91c763f095554b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_2f91c763f095554b','Журавлёнок','Ушло тепло с полей,
