INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_187f44d2d93240a3','За горами, за Карпатскими','(«За горами, за Карпатскими где дымят костры солдатские...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Чуркин, музыка: Георгий Носов) | Патриотические песни | https://pesni.retroportal.ru/rodina/za_gorami_za_karpatskimi.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («За горами, за Карпатскими где дымят костры солдатские...») | merged_versions: 1','За горами, за Карпатскими,
Где дымят костры солдатские,
Над долинами и ярами до зари горят,
Напевал про очи карие молодой солдат.
Пел солдат про степи русские,
Где тропинки вьются узкие.
Где у домика заветного на ветру степном
Старый клён шумит приветливо под родным окном.
Там при раннем ясном месяце,
Что над белым садом светится,
На село выходит девушка, косы по плечам.
На крутом далёком бережке
Друга повстречай.
А солдаты песню слушали.
Даже вздохом не нарушили.
Вдаль лилась она, широкая,
В тишине ночной
Про девичьи очи карие и про дом родной.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«За горами, за Карпатскими где дымят костры солдатские...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_187f44d2d93240a3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_187f44d2d93240a3','За горами, за Карпатскими','За горами, за Карпатскими,
Где дымят костры солдатские,
