INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1e44cf56a605977d','За Ленинград','(«Весеннее солнце горит на знамёнах...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: К. Чистяков) | Песни военных лет | https://pesni.retroportal.ru/vov/za_leningrad.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Весеннее солнце горит на знамёнах...») | merged_versions: 1','Весеннее солнце горит на знамёнах,
Нева, словно море, бурлит.
Боец ленинградский, боец непреклонный
Как прежде за город стоит!
Припев:
Твёрже, шаг, ряды держите строже.
С нами Сталин, нет для нас преград.
Наглый враг быть должен уничтожен,
На врага! На врага! Вперёд за Ленинград!
Идём мы за город, родной и любимый,
За мир и за счастье людей,
За милую мать, за жену дорогую,
За наших отцов и детей.
Припев
Борьба нелегка&nbsp;- озверелая свора
Опасна в безумьи своём.
Все силы в кулак соберём для разгрома,
Всю волю свою соберём!
Припев:
Твёрже, шаг, ряды держите строже.
С нами Сталин, нет для нас преград.
Подлый враг быть должен уничтожен,
На врага! На врага! На врага! За Родину, вперед!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Весеннее солнце горит на знамёнах...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1e44cf56a605977d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1e44cf56a605977d','За Ленинград','Весеннее солнце горит на знамёнах,
