INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_1e44cf56a605977d_8258298141fdd470','rpp_1e44cf56a605977d','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/za_leningrad.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_01b701aa1c41be69','За нами город Ленина','(«Не даст ни винтовка, ни сердце осечку!..»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Владимир Лившиц, музыка: Александр Владимирцов) | Песни военных лет | https://pesni.retroportal.ru/vov/za_nami_gorod_lenina.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Не даст ни винтовка, ни сердце осечку!..») | merged_versions: 1','Не даст ни винтовка, ни сердце осечку!
Огнём их проверить мы в битве смогли
За каждую рощу, за каждую речку,
За каждый клочок нашей русской земли.
Над немцами ворон-добытчик прокаркал,
Немецкие трупы валялись кругом.
Так бились клюкановцы в августе жарком
С насевшим на них бесноватым врагом.
Припев:
За нами город Ленина,
За нами вся страна.
Свою судьбу доверила
Тебе и мне она.
Мы все испытали: и голод, и холод,
И жажду, и боль, и жару, и пургу.
За нашей спиною&nbsp;- прославленный город,
К нему не пройти, не прорваться врагу.
Клянёмся, живым не отпустим фашиста!
Клянёмся, пусть громче грохочет гроза!
Стоять, как стояли четыре радиста,
Смертельной опасности глядя в глаза!
Припев
О мести взывают развалины, трубы,
И детские трупы, и дым городов.
И мстить, как бойцы лейтенанта Кострубо,
Любой из нас, братья, сегодня готов.
За подлым врагом по кровавому следу
Мы грозно рванёмся в решающий час.
Штыком и гранатой мы вырвем победу,
Лучистое солнце сияет для нас!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Не даст ни винтовка, ни сердце осечку!..»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_01b701aa1c41be69'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_01b701aa1c41be69','За нами город Ленина','Не даст ни винтовка, ни сердце осечку!
Огнём их проверить мы в битве смогли
