Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_01b701aa1c41be69_fab0c86e1b30440a','rpp_01b701aa1c41be69','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/za_nami_gorod_lenina.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_38655944523de3db','За окном в тени мелькает',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Яков Полонский, музыка: Пётр Чайковский) | Старинные романсы | https://pesni.retroportal.ru/sr1/29.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','За окном в тени мелькает русая головка.
Ты не спишь, моё мученье, ты не спишь, плутовка!
Выходи ко мне навстречу!
С жаждой поцелуя,
К сердцу сердце молодое
Пламенно прижму я.
Ты не бойся, если звёзды
Слишком ярко светят:
Я плащом тебя одену
Так, что не заметят...
Если сторож нас окликнет, -
Назовись солдатом,
Если спросят, с кем была ты, -
Отвечай, что с братом!
Под надзором богомолки
Ведь тюрьма наскучит...
А неволя поневоле
Хитрости научит!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_38655944523de3db'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_38655944523de3db','За окном в тени мелькает','За окном в тени мелькает русая головка.
Ты не спишь, моё мученье, ты не спишь, плутовка!
Выходи ко мне навстречу!
С жаждой поцелуя,
К сердцу сердце молодое
Пламенно прижму я.
Ты не бойся, если звёзды
Слишком ярко светят:
Я плащом тебя одену
Так, что не заметят...
Если сторож нас окликнет, -
Назовись солдатом,
Если спросят, с кем была ты, -
Отвечай, что с братом!
Под надзором богомолки
Ведь тюрьма наскучит...
А неволя поневоле
Хитрости научит!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_38655944523de3db_c0f6e711b6228a3e','rpp_38655944523de3db','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/29.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_207c5dc407e6cac5','За родину - вперёд!','(«Суровое время, горячее время...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Исаак Дунаевский) | Песни военных лет | https://pesni.retroportal.ru/vov/za_rodinu_vpered.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Суровое время, горячее время...») | merged_versions: 1','Суровое время, горячее время
Пришло для Отчизны родной.
Вставай, подымайся, советское племя,
На подвиг и труд боевой!
Припев:
Твёрже шаг, ряды держите строже!
С нами Сталин, с нами весь народ.
Наглый враг быть должен уничтожен, -
На врага! За Родину&nbsp;- вперёд!
И верой и правдой достойно и смело
Отчизне послужим в бою.
Идём мы, товарищ, за правое дело&nbsp;-
За честь и свободу свою.
Припев
Борьба нелегка&nbsp;- озверелая свора
Опасна в безумьи своём.
Все силы в кулак соберём для отпора,
Всю волю свою соберем!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Суровое время, горячее время...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_207c5dc407e6cac5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_207c5dc407e6cac5','За родину - вперёд!','Суровое время, горячее время
