INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_207c5dc407e6cac5_f91e84e1f8643649','rpp_207c5dc407e6cac5','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/za_rodinu_vpered.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fc2a6584697dc8bc','За фабричной заставой','(Песня из кинофильма «Они были первыми»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Марк Фрадкин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/za_fabrichnoj_zastavoj.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из кинофильма «Они были первыми») | merged_versions: 1','За фабричной заставой,
Где закаты в дыму,
Жил парнишка кудрявый,
Лет семнадцать ему.
О весенних рассветах
Тот парнишка мечтал,
Мало видел он света,
Добрых слов не слыхал.
Знал он горькое лихо,
Знал безрадостный труд,
Жил на улице тихой,
Где с гудками встают.
Парню очень хотелось
Счастье здесь увидать,
За рабочее дело
Он ушёл воевать.
Рядом с девушкой верной,
Был он тих и несмел,
Ей любви своей первой
Объяснить не умел.
И она не успела
Даже слово сказать -
За рабочее дело
Он ушёл воевать.
И, порубленный саблей,
Он на землю упал,
Кровь ей отдал до капли,
На прощанье сказал:
&laquo;Умираю, но скоро
Наше солнце взойдёт&raquo;.
Шёл парнишке в ту пору
Восемнадцатый год.
За фабричной заставой,
Где закаты в дыму,
Жил парнишка кудрявый,
Лет семнадцать ему.
Парню очень хотелось
Счасть здесь увидать,
За рабочее дело
Он ушёл воевать...','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из кинофильма «Они были первыми»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fc2a6584697dc8bc'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_fc2a6584697dc8bc','За фабричной заставой','За фабричной заставой,
