INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e0fe5c2cbbff328d','За что мы любим родину свою','(«Я вам скажу, подруги дорогие...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Антон Пришелец, музыка: Павел Акуленко) | Патриотические песни | https://pesni.retroportal.ru/rodina/za_chto_my_lyubim_rodinu_svoyu.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Я вам скажу, подруги дорогие...») | merged_versions: 1','Я вам скажу, подруги дорогие,
Как хорошо нам жить в родном краю.
Споёмте все, расскажем в нашей песне
За что мы любим Родину свою.
Родимый край мы с детства полюбили
За шум лесов и тишину долин,
За то, что наше поле, словно море,
За то, что в нём весёлый гул машин.
За то, подруги, Родину мы любим,
Что нет нигде другой страны такой,
За то, что в ней живёт великий Сталин&nbsp;-
Учитель, друг и наш отец родной.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Я вам скажу, подруги дорогие...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e0fe5c2cbbff328d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e0fe5c2cbbff328d','За что мы любим родину свою','Я вам скажу, подруги дорогие,
Как хорошо нам жить в родном краю.
Споёмте все, расскажем в нашей песне
За что мы любим Родину свою.
Родимый край мы с детства полюбили
За шум лесов и тишину долин,
За то, что наше поле, словно море,
За то, что в нём весёлый гул машин.
За то, подруги, Родину мы любим,
Что нет нигде другой страны такой,
За то, что в ней живёт великий Сталин&nbsp;-
Учитель, друг и наш отец родной.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_e0fe5c2cbbff328d_cd6d63906d2dad0f','rpp_e0fe5c2cbbff328d','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/za_chto_my_lyubim_rodinu_svoyu.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a67f9de6a09f1d48','«Забыли вы» («Глядя на луч пурпурного заката»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Павел Козлов, музыка: Андрей Оппель) | Старинные романсы | https://pesni.retroportal.ru/sr1/30.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Глядя на луч пурпурного заката,
Стояли мы на берегу Невы.
Вы руку жали мне; промчался без возврата
Тот сладкий миг, его забыли вы.
До гроба Вы клялись любить поэта;
Боясь людей, боясь пустой молвы,
Вы не исполнили священного обета,
Свою любовь, и ту забыли Вы.
Но смерть близка, близка моя могила.
Когда умру, - как тихий шум травы,
Мой голос прозвучит и скажет Вам уныло:
&laquo;Он Вами жил, его забыли Вы&raquo;.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a67f9de6a09f1d48'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a67f9de6a09f1d48','«Забыли вы» («Глядя на луч пурпурного заката»)','Глядя на луч пурпурного заката,
Стояли мы на берегу Невы.
Вы руку жали мне; промчался без возврата
Тот сладкий миг, его забыли вы.
До гроба Вы клялись любить поэта;
Боясь людей, боясь пустой молвы,
Вы не исполнили священного обета,
Свою любовь, и ту забыли Вы.
Но смерть близка, близка моя могила.
Когда умру, - как тихий шум травы,
Мой голос прозвучит и скажет Вам уныло:
&laquo;Он Вами жил, его забыли Вы&raquo;.');
