INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9f0392542f8e912d','Завеса спущена',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Татьяна Котляревская ⁄ Татьяна Толстая ⁄) | Старинные романсы | https://pesni.retroportal.ru/sr1/31.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Завеса спущена! Не надо притворяться!
Окончен жизни путь, бесцельный и пустой!
Нет сил надеяться, нет сил сопротивляться,
Настал расплаты час с бездушною судьбой!
Зачем же с прежнею мучительной тоскою
Сомненья прошлых дней закрались в сердце вновь?
И вместо нового, желанного покоя –
Волненья старые, тревога и любовь!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9f0392542f8e912d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9f0392542f8e912d','Завеса спущена','Завеса спущена! Не надо притворяться!
Окончен жизни путь, бесцельный и пустой!
Нет сил надеяться, нет сил сопротивляться,
Настал расплаты час с бездушною судьбой!
Зачем же с прежнею мучительной тоскою
Сомненья прошлых дней закрались в сердце вновь?
И вместо нового, желанного покоя –
Волненья старые, тревога и любовь!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_9f0392542f8e912d_ce745991bfe4fef2','rpp_9f0392542f8e912d','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/31.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9aa0679820c71ba5','Залётная','(«Над землёй из края в край песня проносилась...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Островой, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/zaletnaya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Над землёй из края в край песня проносилась...») | merged_versions: 1','Над землёй из края в край
Песня проносилась.
Увидала кузнеца&nbsp;-
В гости попросилась.
Пляшут искры, молот бьёт.
Хорошо кузнец куёт.
Значит, новою подковой,
Значит, новою подковой
Конь на улице сверкнёт.
Полетела песня вдаль,
По широкой воле.
Навестила молодёжь
На колхозном поле.
Льётся колос через край
Значит, будет урожай
Стало жито золотое
Стало жито золотое
Только зёрна собирай.
Пограничная река
Льётся на просторе.
Села песня посидеть
У солдат в дозоре.
Встали горы до небес,
Что-то шепчет тёмный лес.
Зорко смотрит пограничник,
Зорко смотрит пограничник,
Чтобы хищник не пролез.
Над землёй из края в край
Песня проносилась.
Облетела всю страну
И в Москве спустилась.
Вышла песня на парад
Ей народ повсюду рад.
Хорошо шагать нам вместе,
Хорошо шагать нам вместе,
С нашей молодостью в ряд!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Над землёй из края в край песня проносилась...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9aa0679820c71ba5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9aa0679820c71ba5','Залётная','Над землёй из края в край
