INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_9aa0679820c71ba5_59fe378eb24e815d','rpp_9aa0679820c71ba5','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/zaletnaya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b9223ae8be39fc62','Замучен тяжёлой неволей',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (народная песня, слова: Григорий Мачтет) | Народные песни | https://pesni.retroportal.ru/np1/31.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Замучен тяжёлой неволей,
Ты славною смертью почил...
В борьбе за народное дело
Ты голову честно сложил...
Служил ты недолго, но честно
Для блага родимой земли...
И мы – твои братья по делу –
Тебя на кладбище снесли...
Наш враг над тобой не глумился,
Кругом тебя были свои.
Мы сами, родимый закрыли
Орлиные очи твои...
Не горе нам душу давило,
Не слёзы блистали в очах,
Когда мы, прощаясь с тобою,
Землёй засыпали твой прах.
Нет, злоба нас только душила,
Мы к битве с врагами рвались
И мстить за тебя беспощадно
Над прахом твоим поклялись!
С тобою одна нам дорога:
Как ты, мы в острогах сгниём.
Как ты, для народного дела
Мы головы наши снесём.
Как ты, мы, быть может, послужим
Лишь почвой для новых людей,
Лишь грозным пророчеством новых,
Грядущих и доблестных дней...
Но знаем, как знал ты, родимый,
Что скоро из наших костей
Подымется мститель суровый,
И будет он нас посильней!..','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b9223ae8be39fc62'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b9223ae8be39fc62','Замучен тяжёлой неволей','Замучен тяжёлой неволей,
Ты славною смертью почил...
В борьбе за народное дело
Ты голову честно сложил...
Служил ты недолго, но честно
Для блага родимой земли...
И мы – твои братья по делу –
Тебя на кладбище снесли...
Наш враг над тобой не глумился,
Кругом тебя были свои.
Мы сами, родимый закрыли
Орлиные очи твои...
Не горе нам душу давило,
Не слёзы блистали в очах,
Когда мы, прощаясь с тобою,
Землёй засыпали твой прах.
Нет, злоба нас только душила,
Мы к битве с врагами рвались
И мстить за тебя беспощадно
Над прахом твоим поклялись!
С тобою одна нам дорога:
Как ты, мы в острогах сгниём.
Как ты, для народного дела
Мы головы наши снесём.
Как ты, мы, быть может, послужим
Лишь почвой для новых людей,
Лишь грозным пророчеством новых,
Грядущих и доблестных дней...
Но знаем, как знал ты, родимый,
Что скоро из наших костей
Подымется мститель суровый,
И будет он нас посильней!..');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b9223ae8be39fc62_6560c5eb07d6c348','rpp_b9223ae8be39fc62','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/31.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_41e49f2495d18104','«Зачем любить, зачем страдать?» («Уйди, мой бедный друг»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Евгений Юрьев) | Старинные романсы | https://pesni.retroportal.ru/sr1/33.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Уйди! Уйди! К чему мольбы и слёзы!
К мольбам любви, как лёд, я холодна!..
Я дочь полей и, как поэта грёзы,
Капризна я, изменчива, вольна.
Напрасно ты с горячею мольбою
К моей груди, мой бедный друг, прильнёшь...
Твоих страданий я не успокою,
Со мною счастья, знай, ты не найдёшь.
Зачем, зачем любить?
Зачем, зачем страдать?
Хочу я вольной жить,
Лишь песни распевать!
Пусть в шутках и цветах
Сон жизни пролетит,
Пусть песня на устах
Свободою звучит!
Луна в выси над спящим садом светит;
Любовью дышит эта ночь вокруг.
Но в этом сердце отклика не встретит
Любви призыв, мой нежный, бедный друг!
Была пора, и я ждала свиданья,
И сердце билось трепетно в груди;
Но всё прошло... Оставь свои признанья!
Уйди, забудь, мой бедный друг! Уйди!
Зачем, зачем любить?
Зачем, зачем страдать?
Хочу я вольной жить,
Лишь песни распевать!
Пусть в шутках и цветах
Сон жизни пролетит,
Пусть песня на устах
Свободою звучит!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_41e49f2495d18104'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_41e49f2495d18104','«Зачем любить, зачем страдать?» («Уйди, мой бедный друг»)','Уйди! Уйди! К чему мольбы и слёзы!
К мольбам любви, как лёд, я холодна!..
Я дочь полей и, как поэта грёзы,
Капризна я, изменчива, вольна.
Напрасно ты с горячею мольбою
К моей груди, мой бедный друг, прильнёшь...
Твоих страданий я не успокою,
Со мною счастья, знай, ты не найдёшь.
Зачем, зачем любить?
Зачем, зачем страдать?
Хочу я вольной жить,
Лишь песни распевать!
Пусть в шутках и цветах
Сон жизни пролетит,
Пусть песня на устах
Свободою звучит!
Луна в выси над спящим садом светит;
Любовью дышит эта ночь вокруг.
Но в этом сердце отклика не встретит
Любви призыв, мой нежный, бедный друг!
Была пора, и я ждала свиданья,
И сердце билось трепетно в груди;
Но всё прошло... Оставь свои признанья!
Уйди, забудь, мой бедный друг! Уйди!
Зачем, зачем любить?
Зачем, зачем страдать?
Хочу я вольной жить,
Лишь песни распевать!
Пусть в шутках и цветах
Сон жизни пролетит,
Пусть песня на устах
Свободою звучит!');
