INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_59c0035d1f076e6b','Зачем ты при встрече?',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Владимир Бакалейников) | Старинные романсы | https://pesni.retroportal.ru/sr1/34.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Зачем ты при встрече порою
В глаза мне пытливо глядишь,
Зачем с затаённой тоскою
За мною ревниво следишь?
Тебе я поведал волненья,
Невзгоды, печали мои,
Заветные грёзы сомненья
И радости светлой любви.
Ты знаешь, как мною любима,
Как я обожаю тебя.
И ревностью, грустью томимый,
Волнуюсь, страдаю любя.
Зачем же при встрече порою
В глаза мне пытливо глядишь,
Зачем с затаённой тоскою
За мною ревниво следишь?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_59c0035d1f076e6b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_59c0035d1f076e6b','Зачем ты при встрече?','Зачем ты при встрече порою
