INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4f61e0bd44037823','Зачем?» «Скажи зачем тебя я встретил',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка Александр Давыдов / Саша Давыдов /) | Старинные романсы | https://pesni.retroportal.ru/sr1/32.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Скажи, зачем тебя я встретил,
Зачем тебя я полюбил,
Зачем твой взор улыбкой мне ответил
И счастье в жизни подарил?
Тебя отнимут у меня,
Ты не моя, ты не моя!
Не видеть мне твоих лобзаний,
Не слышать мне твоих речей,
Не разделять с тобой твоих страданий
И тихой радости твоей.
Тебя отнимут у меня,
Ты не моя, ты не моя!
Нам крест тяжёлого страданья
В замену счастья должно несть,
Не плачь, не плачь, мой друг,
Твои рыданья
Душа не в силах перенесть.
Тебя не вырвут у меня,
Навек я твой, а ты моя!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4f61e0bd44037823'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4f61e0bd44037823','Зачем?» «Скажи зачем тебя я встретил','Скажи, зачем тебя я встретил,
