INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_53096f70248700ca','Звезда',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Лермонтов, музыка: Виктор Оранский) | Старинные романсы | https://pesni.retroportal.ru/sr1/35.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вверху одна
Горит звезда,
Мой взор она
Манит всегда;
Мои мечты
Она влечёт
И с высоты
Меня зовёт!
Таков же был
Тот нежный взор,
Что я любил
Судьбе в укор.
Усталых вежд
Я не смыкал,
Я без надежд
К нему взирал.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_53096f70248700ca'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_53096f70248700ca','Звезда','Вверху одна
Горит звезда,
Мой взор она
Манит всегда;
Мои мечты
Она влечёт
И с высоты
Меня зовёт!
Таков же был
Тот нежный взор,
Что я любил
Судьбе в укор.
Усталых вежд
Я не смыкал,
Я без надежд
К нему взирал.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_53096f70248700ca_af128066893e1637','rpp_53096f70248700ca','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/35.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a20edf78e5f65ef4','Звезда моих полей','(«Легла роса, спустился вечер синий...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Людмила Давидович и Виктор Драгунский, музыка: Никита Богословский) | Патриотические песни | https://pesni.retroportal.ru/rodina/zvezda_moih_poley.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Легла роса, спустился вечер синий...») | merged_versions: 1','Легла роса, спустился вечер синий.
Доносит ветер через ширь лугов&nbsp;-
И свежий запах скошенной полыни,
И эхо дальнее девичьих голосов...
Легла роса, спустился вечер синий.
И надо мной сияет, как всегда,
Звезда моих полей, звезда моей России&nbsp;-
Страны единственной прекрасная звезда!
И в час, когда нашёл я на чужбине
Простой букет из полевых цветов&nbsp;-
Я вспомнил запах скошенной полыни,
И эхо дальнее девичьих голосов.
И сколько бы сраженья не носили,
В душе моей со мной была всегда
Звезда моих полей, звезда моей России&nbsp;-
Страны единственной прекрасная звезда!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Легла роса, спустился вечер синий...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a20edf78e5f65ef4'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a20edf78e5f65ef4','Звезда моих полей','Легла роса, спустился вечер синий.
Доносит ветер через ширь лугов&nbsp;-
И свежий запах скошенной полыни,
И эхо дальнее девичьих голосов...
Легла роса, спустился вечер синий.
И надо мной сияет, как всегда,
Звезда моих полей, звезда моей России&nbsp;-
Страны единственной прекрасная звезда!
И в час, когда нашёл я на чужбине
Простой букет из полевых цветов&nbsp;-
Я вспомнил запах скошенной полыни,
И эхо дальнее девичьих голосов.
И сколько бы сраженья не носили,
В душе моей со мной была всегда
Звезда моих полей, звезда моей России&nbsp;-
Страны единственной прекрасная звезда!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_a20edf78e5f65ef4_2f334be4caa007c7','rpp_a20edf78e5f65ef4','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/zvezda_moih_poley.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7ec5e94fad72bb7d','Звёздочка','(«Мы работаем с подружкой дорогою в самом небе над красавицей Москвою...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Яков Белинский, музыка: Аркадий Островский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/zvezdochka.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Мы работаем с подружкой дорогою в самом небе над красавицей Москвою...») | merged_versions: 1','Мы работаем с подружкой дорогою
В самом небе над красавицей Москвою.
В синем небе выше тучек поднебесных
Мы возводим этажи домов чудесных.
Нам бы с милой объясниться в разговорах,
Да работаем мы в разных стройконторах.
Я на Пресне строю дом солидный новый,
А подружка - в переулке на Садовой.
Лишь настанет ночь и снова вспыхнет ярко
На Садовой огонёк электросварки.
То не звёздочка далекая мигает&nbsp;-
Это мне привет подружка посылает.
Я на Пресне дорогой не забываю&nbsp;-
Огоньком на огонёк ей отвечаю.
Над Москвою темно-синими ночами
Мы с подружкою беседуем часами.
Выходной денёк нескучный над рекою
Разговор мы свой закончим с дорогою.
Досказать ей на земле хотелось мне бы
Всё о чем я не успел сказать на небе.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Мы работаем с подружкой дорогою в самом небе над красавицей Москвою...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7ec5e94fad72bb7d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7ec5e94fad72bb7d','Звёздочка','Мы работаем с подружкой дорогою
В самом небе над красавицей Москвою.
В синем небе выше тучек поднебесных
