INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c37bd80481356324','«Звёзды на небе» («Снился мне сад»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Елизавета Дитерихс, музыка: Борис Борисов) | Старинные романсы | https://pesni.retroportal.ru/sr1/36.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Снился мне сад в подвенечном уборе,
В этом саду мы с тобою вдвоём.
Звёзды на небе, звёзды на море,
Звёзды и в сердце моём.
Листьев ли шёпот иль ветра порывы
Чуткой душою я жадно ловлю.
Взоры глубоки, уста молчаливы:
Милый, о милый, люблю.
Тени ночные плывут на просторе,
Счастье и радость разлиты кругом.
Звёзды на небе, звёзды на море,
Звёзды и в сердце моём.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c37bd80481356324'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c37bd80481356324','«Звёзды на небе» («Снился мне сад»)','Снился мне сад в подвенечном уборе,
В этом саду мы с тобою вдвоём.
