INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_196ac4af0fa9aef1','Звенит гитара над рекою','(«Костёр ночной... Простор речной... Волна поёт...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лев Ошанин, музыка: Анатолий Новиков) | Эстрадные песни | https://pesni.retroportal.ru/estrada/zvenit_gitara_nad_rekoyu.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Костёр ночной... Простор речной... Волна поёт...») | merged_versions: 1','Звенит гитара над рекою,
На берегу костры горят...
Мы оба гости здесь с тобою
Из разных стран, сестра и брат.
В твоём краю не меркнет лето,
У нас зимой снега кругом.
Мы с двух концов большого света,
А на реке сейчас вдвоём.
Припев:
Костёр ночной...
Простор речной...
Волна поёт...
И наша маленькая лодочка плывёт...
И вот как будто мчимся вдаль мы -
Встают иные берега:
Твои раскидистые пальмы,
Мои берёзы и снега.
И всё у нас с тобой иное,
И мы по-разному росли,
Но мы живём мечтой одною,
Хоть между нами полземли.
Припев
Звенит гитара над рекою,
И не спеша бежит река,
И рядом с белою рукою
Темнеет смуглая рука.
Пускай придёт пора проститься,
Друг друга долго не видать,
Но сердце с сердцем, словно птицы,
Конечно, встретятся опять.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Костёр ночной... Простор речной... Волна поёт...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_196ac4af0fa9aef1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_196ac4af0fa9aef1','Звенит гитара над рекою','Звенит гитара над рекою,
