INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4be2410163adf272','Здравствуй, Россия!','(«Слава отчизне Ленина и Сталина!..»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Дмитрий Покрасс и Даниил Покрасс) | Патриотические песни | https://pesni.retroportal.ru/rodina/zdravstvuy_rossiya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Слава отчизне Ленина и Сталина!..») | merged_versions: 1','Здравствуй вовеки, Родина любимая,
Братских народов могучий союз!
Крепни, твердыня несокрушимая,
Гордая великая Советская Русь!
Припев:
Слава отчизне Ленина и Сталина!
Слава отчизне свободы и труда!
Правду народную,
Волю свободную
Мы не отдадим никому никогда!
Светом победным, звёзды пятикрылые,
Ярче сияйте на башнях Кремля!
Пусть рассветает с новою силою,
Славою овеяна, родная земля!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Слава отчизне Ленина и Сталина!..»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4be2410163adf272'), datetime('now')),datetime('now'));
