INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_77a423ca4621f9d6','Здравствуй, юность','(«Мы поём, и наша песня пусть звенит не только здесь...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Наум Лабковский, музыка: Моисей Феркельман) | Эстрадные песни | https://pesni.retroportal.ru/estrada/zdravstvuj_yunost.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Мы поём, и наша песня пусть звенит не только здесь...») | merged_versions: 1','Здравствуй, юность, пой, счастливая, песню-вальс,
Медь оркестра в небо синее поднялась.
Вместе мы, друзья, и не петь нельзя.
Здравствуй, праздник, праздник юности&nbsp;– фестиваль.
Припев:
Мы поём, и наша песня пусть звенит не только здесь&nbsp;-
Мы хотим, чтоб эту песню пел весь зал и город весь.
Мы хотим, чтоб с ней родилась наша дружба и любовь
Чтобы счастье в ней искрилось и друзьям бодрило кровь,
Мы хотим, чтоб эту песню пел весь зал и город весь.
Многих наций руки встретились в первый раз,
И в улыбке дружбы светятся сотни глаз
Мы живём одной трудовой семьёй,
Здравствуй, праздник, праздник юности&nbsp;– фестиваль.
Припев
Пусть сегодня мы расстанемся на года,
Но друзьями мы останемся навсегда.
Обещаньем нам будет этот вальс,
Праздник мира, праздник юности&nbsp;– фестиваль.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Мы поём, и наша песня пусть звенит не только здесь...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_77a423ca4621f9d6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_77a423ca4621f9d6','Здравствуй, юность','Здравствуй, юность, пой, счастливая, песню-вальс,
