INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4c1948986b78bb25','Зелёными просторами','(«Зелёными просторами легла моя страна...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Владимир Захаров) | Патриотические песни | https://pesni.retroportal.ru/rodina/zelenymi_prostorami.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Зелёными просторами легла моя страна...») | merged_versions: 1','Вариант I:
Зелёными просторами
Легла моя страна.
На все четыре стороны
Раскинулась она.
Её посты расставлены
В полях и в рудниках.
Страна моя прославлена
На всех материках.
Колхозы, шахты, фабрики&nbsp;-
Один сплошной поток...
Плывут её кораблики
На запад и восток;
Плывут во льды полярные
В морозы, в бури, в дождь.
В стране моей ударная
Повсюду молодёжь.
Ударная, упрямая,&nbsp;-
Не молодёжь&nbsp;- литьё.
И песня эта самая
Поётся про неё.
О том, как в дни ненастные
Она молотит рожь,
О том, как в ночи ясные
Свои обозы красные
Выводит молодёжь.
Уверенно стоит она
У каждого станка.
Проверена, испытана
Проворная рука.
В труде не успокоится
И выстоит в бою
За мир, который строится,
За родину свою.
Вариант II:
Зелёными просторами
Легла моя страна.
На все четыре стороны
Раскинулась она.
А над ней стальные соколы
И день, и ночь парят.
И огни её высокие
Над всей землёй горят.
Гремят победной песнею
Заводы и поля.
И мы Победой гордые
Проходим у Кремля!
Наше знамя шёлком шитое
Пылает в вышине
И лежат пути открытые
Для нас по всей стране!
Куда б ты ни поехал,
Куда б ты ни пошёл,
Повсюду наша молодость,
Повсюду Комсомол.
Все мы Сталиным воспитаны
В родном своём краю,
Все проверены, все испытаны
В работе и в бою.
Зелёными просторами
Легла моя страна.
На все четыре стороны
Раскинулась она.
А над ней стальные соколы
И день, и ночь парят.
И огни её высокие
Над всей землёй горят.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Зелёными просторами легла моя страна...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4c1948986b78bb25'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4c1948986b78bb25','Зелёными просторами','Вариант I:
