INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1c3fd668e063c060','Земля моя раздольная','(Песня из кинофильма «Свадьба с приданым»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Борис Мокроусов) | Патриотические песни | https://pesni.retroportal.ru/rodina/zemlya_moya_razdolnaya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из кинофильма «Свадьба с приданым») | merged_versions: 1','Зацветает степь лесами,
А в лесах поля цветут.
Это сделали мы сами,
Это наш великий труд.
Припев:
Земля моя раздольная,
Широкие поля,
Богатая и вольная
Красавица земля!
Хорошо нам жить на свете
Беспокойным, молодым,
И мороз, и знойный ветер
Если надо укротим.
Припев
Свет звезды на башне Спасской
Виден нам во всех краях.
Оживают чудо-сказки
В наших доблестных делах.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из кинофильма «Свадьба с приданым»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1c3fd668e063c060'), datetime('now')),datetime('now'));
