INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e2ca7d89e48c0fc8','Зимний вальс','(«Белым снегом вся Москва запушена...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Коваленков, музыка: Сигизмунд Кац) | Эстрадные песни | https://pesni.retroportal.ru/estrada/zimnij_vals.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Белым снегом вся Москва запушена...») | merged_versions: 1','Белым снегом вся Москва запушена.
Ярким светом гладь катков озарена.
В ясном небе, синем небе золотые огоньки.
Серебром сверкают, режут лёд коньки...
Припев:
Звенят коньки... Снежок московский вьётся...
Вперёд, друзья! Погодка хороша, хороша!
Что нам мороз, коль сердце жарко бьётся,
И, словно песня, в даль летит душа!
Снова снегом вся Москва запушена.
Ярким светом гладь катков озарена.
Словно птица, юность мчится, серебрится звонкий лёд,
Ветер молодо и радостно поёт...
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Белым снегом вся Москва запушена...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e2ca7d89e48c0fc8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e2ca7d89e48c0fc8','Зимний вальс','Белым снегом вся Москва запушена.
Ярким светом гладь катков озарена.
