INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f8b6cda2890b1a13','Зимний праздник','(Новогодняя детская песенка)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Нина Саконская, музыка: Михаил Раухвергер) | Песни для детей | https://pesni.retroportal.ru/deti/zimniy_prazdnik.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Новогодняя детская песенка) | merged_versions: 1','Ясный день, замечательный воздух!
Забирайте коньки&nbsp;- и на лёд!
Встретим так новогодний наш отдых,
Чтоб потом вспоминать целый год.
Припев:
На санях хорошо, на коньках хорошо,
И с горы хорошо прокатится!
Но сейчас веселей, в десять раз веселей
Возле ёлки играть и кружиться!
Серпантина бумажные стружки,
Извиваясь, над нами шуршат,
Из мешка доставая игрушки,
Дед Мороз поздравляет ребят.
Припев
Ватный снег на иголках не тает,
Как сосульки, блестят леденцы.
Огоньков разноцветная стая,
Голосов молодых бубенцы.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Новогодняя детская песенка)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f8b6cda2890b1a13'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f8b6cda2890b1a13','Зимний праздник','Ясный день, замечательный воздух!
Забирайте коньки&nbsp;- и на лёд!
Встретим так новогодний наш отдых,
