INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_f8b6cda2890b1a13_1d5e1cf07b9525c5','rpp_f8b6cda2890b1a13','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/zimniy_prazdnik.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7c5a2662b37aa055','И не раз и не два','(Песня из спектакля «Фельдмаршал Кутузов»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Григорий Гридов, музыка: Борис Фомин) | Песни военных лет | https://pesni.retroportal.ru/vov/i_ne_raz_i_ne_dva.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: (Песня из спектакля «Фельдмаршал Кутузов») | merged_versions: 1','На родных полях завыли ураганы,
Тучи полегли над самою землёй.
Огневым дождём встречать гостей незваных
Пробил час, товарищ боевой!
Припев:
Мы не раз и не два недруга учили
Обходить стороной русские луга.
И не раз, и не два мы в поход ходили,
И не раз, и не два били мы врага!
Были мы всегда отвагою богаты.
И, когда страна скликала нас в поход,
Лавою стальной на всех врагов заклятых
Поднимал сынов своих народ.
Припев
Пронесли в боях мы предков наших славу,
Не согнула нас свинцовая гроза,
Встали в ряд один: Бородино, Полтава,
Перекоп и финские леса.
Припев
За разбой и кровь пощады нет фашистам,
Наш огонь врага с лица земли сметёт.
Не померкнет солнце в нашем небе чистом.
В бой-победный Сталин нас ведёт!
Припев
Родину беречь нам завещали деды,
Жизни не щадя, в атаку шли отцы.
Выпал час и нам сражаться до победы&nbsp;-
В бой! Вперёд! За Родину, бойцы!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(Песня из спектакля «Фельдмаршал Кутузов»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7c5a2662b37aa055'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7c5a2662b37aa055','И не раз и не два','На родных полях завыли ураганы,
Тучи полегли над самою землёй.
Огневым дождём встречать гостей незваных
Пробил час, товарищ боевой!
Припев:
Мы не раз и не два недруга учили
Обходить стороной русские луга.
И не раз, и не два мы в поход ходили,
И не раз, и не два били мы врага!
Были мы всегда отвагою богаты.
И, когда страна скликала нас в поход,
Лавою стальной на всех врагов заклятых
Поднимал сынов своих народ.
Припев
Пронесли в боях мы предков наших славу,
Не согнула нас свинцовая гроза,
Встали в ряд один: Бородино, Полтава,
Перекоп и финские леса.
Припев
За разбой и кровь пощады нет фашистам,
Наш огонь врага с лица земли сметёт.
Не померкнет солнце в нашем небе чистом.
В бой-победный Сталин нас ведёт!
Припев
Родину беречь нам завещали деды,
Жизни не щадя, в атаку шли отцы.
Выпал час и нам сражаться до победы&nbsp;-
В бой! Вперёд! За Родину, бойцы!
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_7c5a2662b37aa055_2ffc2024f46ebb4f','rpp_7c5a2662b37aa055','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/i_ne_raz_i_ne_dva.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_14383f2ecd82e960','И опять во дворе','(«И опять во дворе нам пластинка поёт...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лев Ошанин, музыка: Аркадий Островский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/i_opyat_vo_dvore.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («И опять во дворе нам пластинка поёт...») | merged_versions: 1','Ты не грусти, может быть, ещё встретимся,
Я от тебя не сбегу никуда.
Сколько в пути ни пробуду я месяцев,
А возвращусь хоть на вечер сюда.
Припев:
И опять во дворе
Нам пластинка поёт,
И проститься с тобой
Всё никак не даёт!
Не отнимай свою руку, пожалуйста,
Как бы судьба ни сложилась для нас.
Завтра забудь меня, маме пожалуйся,
Но поцелуй на прощанье хоть раз.
Припев
В туфлях на гвоздиках, в тоненьком свитере,
Глупая, всё тебя мучит одно:
Как бы подружки тебя не увидели
Да старики, что стучат в домино.
Припев
Губы не прячь и вокруг не поглядывай,
Ты уж как хочешь, а мне по душе
Помнить квартиру сто двадцать девятую,
Твой огонёк на шестом этаже.
Припев
Ты не грусти, может быть, ещё встретимся,
Я от тебя не сбегу никуда.
Сколько в пути ни пробуду я месяцев,
А возвращусь хоть на вечер сюда.
Припев
Текст песни Льва Ошанина  &laquo;А у нас во дворе есть девчонка одна...&raquo;  на музыку Аркадия Островского.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«И опять во дворе нам пластинка поёт...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_14383f2ecd82e960'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_14383f2ecd82e960','И опять во дворе','Ты не грусти, может быть, ещё встретимся,
Я от тебя не сбегу никуда.
Сколько в пути ни пробуду я месяцев,
А возвращусь хоть на вечер сюда.
Припев:
И опять во дворе
Нам пластинка поёт,
И проститься с тобой
Всё никак не даёт!
Не отнимай свою руку, пожалуйста,
Как бы судьба ни сложилась для нас.
Завтра забудь меня, маме пожалуйся,
Но поцелуй на прощанье хоть раз.
Припев
В туфлях на гвоздиках, в тоненьком свитере,
Глупая, всё тебя мучит одно:
Как бы подружки тебя не увидели
Да старики, что стучат в домино.
Припев
Губы не прячь и вокруг не поглядывай,
Ты уж как хочешь, а мне по душе
Помнить квартиру сто двадцать девятую,
Твой огонёк на шестом этаже.
Припев
Ты не грусти, может быть, ещё встретимся,
Я от тебя не сбегу никуда.
Сколько в пути ни пробуду я месяцев,
А возвращусь хоть на вечер сюда.
Припев
Текст песни Льва Ошанина  &laquo;А у нас во дворе есть девчонка одна...&raquo;  на музыку Аркадия Островского.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_14383f2ecd82e960_690327c55fa12525','rpp_14383f2ecd82e960','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/i_opyat_vo_dvore.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a3b55bffb3dda658','И тихо и ясно',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Константин Медведский, музыка: Евгения Греве-Соболевская) | Старинные романсы | https://pesni.retroportal.ru/sr1/38.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','И тихо и ясно, и пахнет сиренью,
И где-то звенит соловей,
И веет мечтательно сладкою ленью
От этих широких аллей.
Река чуть трепещет холодною сталью,
Не в силах мечты превозмочь.
И дышит любовью,
И дышит печалью весенняя страстная ночь.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a3b55bffb3dda658'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a3b55bffb3dda658','И тихо и ясно','И тихо и ясно, и пахнет сиренью,
И где-то звенит соловей,
