INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b3f54f7427554d63','Из-за гор-горы',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/32.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Из-за гор-горы едут мазуры,
Из-за гор-горы едут мазуры.
Едут, едут мазурочки,
Везут, везут нам веночки,
Венок золотой, венок золотой.
Приехали панычи во тёмной ночи,
Приехали панычи во тёмной ночи.
Стук, бряк во колечко:
&laquo;Выйди, выйди на крылечко,
Дай коню воды, дай коню воды&raquo;.
&laquo;Не могу я встать, коню воды дать,
Не могу я встать, коню воды дать.
Мне матуся приказала,
Чтоб я с паном не гуляла,
Матуси боюсь, матуси боюсь&raquo;.
&laquo;Матуси не бойсь, садись на мой конь,
Матуси не бойсь, садись на мой конь.
На мой конь скорей садися,
Вместе с бурею несися
В венке золотом, в венке золотом&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b3f54f7427554d63'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b3f54f7427554d63','Из-за гор-горы','Из-за гор-горы едут мазуры,
