INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b3f54f7427554d63_a689172d21a8c6da','rpp_b3f54f7427554d63','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/32.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f00b96e8d66f2eb3','Из-за острова на стрежень',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (музыка народная, слова: Дмитрий Садовников) | Народные песни | https://pesni.retroportal.ru/np1/33.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','(самая известная песня о&nbsp;Степане&nbsp;Разине)
Из-за острова на стрежень,
На простор речной волны
Выплывают расписные
Острогрудые челны.
На переднем Стенька Разин,
Обнявшись, сидит с княжной,
Свадьбу новую справляет
Он, весёлый и хмельной.
А она, потупив очи,
Ни жива и ни мертва,
Молча слушает хмельные
Атмановы слова.
Позади их слышен ропот:
&laquo;Нас на бабу променял,
Только ночь с ней провозжался,
Сам на утро бабой стал&raquo;.
Этот ропот и насмешки
Слышит грозный атаман,
И могучею рукою
Обнял персиянки стан.
Брови чёрные сошлися,
Надвигается гроза.
Буйной кровью налилися
Атамановы глаза.
&laquo;Ничего не пожалею,
Буйну голову отдам!&raquo; -
Раздаётся голос властный
По окрестным берегам.
&laquo;Волга, Волга, мать родная,
Волга – русская река,
Не видала ты подарка
От донского казака!
Чтобы не было раздора
Между вольными людьми,
Волга, Волга, мать родная,
На, красавицу прими!&raquo;
Мощным взмахом поднимает
Он красавицу княжну
И за борт её бросает
В набежавшую волну.
&laquo;Что ж вы, братцы, приуныли?
Эй ты, Филька, чёрт, пляши!
Грянем песню удалую
На помин её души!..&raquo;
Из-за острова на стрежень,
На простор речной волны
Выплывают расписные
Острогрудые челны.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f00b96e8d66f2eb3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f00b96e8d66f2eb3','Из-за острова на стрежень','(самая известная песня о&nbsp;Степане&nbsp;Разине)
