INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_16816701f1d62104','К нам приходит Новый год','(Детская праздничная хороводная песенка)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Зоя Петрова, музыка: Вера Герчик) | Песни для детей | https://pesni.retroportal.ru/deti/k_nam_prihodit_novy_god.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Детская праздничная хороводная песенка) | merged_versions: 1','Хорошо, что каждый год
К нам приходит Новый год,
Зажигает нашу ёлку
И заводит хоровод.
Припев:
Если танца будет мало,
Есть у танца поворот:
Мы станцуем всё сначала
А потом&nbsp;- наоборот!
Ну-ка, шире, шире круг,
Выходи смелее, друг!
Веселей в ладоши хлопай,
Не жалей сегодня рук!
Припев
Даже месяц в этот раз
Не спускает с ёлки глаз,
И снежинки за окошком
Смотрят с завистью на нас.
Припев
Мы под ёлочкой плясать
Можем целых три часа,
И нисколько не устанем,&nbsp;-
Вот такие чудеса!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Детская праздничная хороводная песенка)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_16816701f1d62104'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_16816701f1d62104','К нам приходит Новый год','Хорошо, что каждый год
