INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c9254d4309d0597b','Кабы не было зимы','(Песня из мультфильма «Зима в Простоквашино»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Юрий Энтин, музыка: Евгений Крылатов) | Песни для детей | https://pesni.retroportal.ru/deti/kaby_ne_bylo_zimy.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Зима в Простоквашино») | merged_versions: 1','Кабы не было зимы
В городах и сёлах,
Никогда б не знали мы
Этих дней весёлых.
Не кружила б малышня
Возле снежной бабы,
Не петляла бы лыжня,
Кабы, кабы, кабы...
Не петляла бы лыжня,
Кабы, кабы, кабы...
Кабы не было зимы,
В этом нет секрета&nbsp;-
От жары б увяли мы,
Надоело б лето.
Не пришла бы к нам метель
На денёк хотя бы.
И снегирь не сел на ель,
Кабы, кабы, кабы...
И снегирь не сел на ель,
Кабы, кабы, кабы...
Кабы не было зимы,
А всё время лето,
Мы б не знали кутерьмы
Новогодней этой.
Не спешил бы Дед Мороз
К нам через ухабы,
Лёд на речке не замёрз,
Кабы, кабы, кабы...
Лед на речке не замёрз,
Кабы, кабы, кабы...','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Зима в Простоквашино»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c9254d4309d0597b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c9254d4309d0597b','Кабы не было зимы','Кабы не было зимы
