INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9c3e50d8b6b357a3','Казаки в Берлине','(«По берлинской мостовой кони шли на водопой...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Цезарь Солодарь, музыка: Дмитрий Покрасс) | Песни военных лет | https://pesni.retroportal.ru/vov/kazaki_v_berline.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («По берлинской мостовой кони шли на водопой...») | merged_versions: 1','По берлинской мостовой
Кони шли на водопой,
Шли, потряхивая гривой,
Кони-дончаки.
Распевает верховой:
&laquo;Эх, ребята, не впервой
Нам поить коней казачьих
Из чужой реки.&raquo;
Припев:
Казаки, казаки,
Едут, едут По Берлину
Наши казаки.
Он коней повёл шажком,
Видит: девушка с флажком
И с косою под пилоткой
На углу стоит.
Выпрямилась, как лоза,
Бирюзой горят глаза.
&laquo;Не задерживай движенья!&raquo;
Казаку кричит.
Припев
Задержаться бы он рад,
Но, поймав сердитый взгляд,
&laquo;Ну, ребята, марш за мной!&raquo;&nbsp;-
Крикнул на скаку.
Лихо конница прошла,
А дивчина расцвела,
Нежный взгляд&nbsp;- не по уставу
Дарит казаку.
Припев
По берлинской мостовой
Снова едет верховой,
Про свою любовь к дивчине
Распевает так:
&laquo;Хоть далёко синий Дон,
Хоть далёко милый дом,
Но землячку и в Берлине
Повстречал казак...&raquo;
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«По берлинской мостовой кони шли на водопой...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9c3e50d8b6b357a3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9c3e50d8b6b357a3','Казаки в Берлине','По берлинской мостовой
Кони шли на водопой,
Шли, потряхивая гривой,
Кони-дончаки.
Распевает верховой:
&laquo;Эх, ребята, не впервой
Нам поить коней казачьих
Из чужой реки.&raquo;
Припев:
Казаки, казаки,
Едут, едут По Берлину
Наши казаки.
Он коней повёл шажком,
Видит: девушка с флажком
И с косою под пилоткой
На углу стоит.
Выпрямилась, как лоза,
Бирюзой горят глаза.
&laquo;Не задерживай движенья!&raquo;
Казаку кричит.
Припев
Задержаться бы он рад,
Но, поймав сердитый взгляд,
&laquo;Ну, ребята, марш за мной!&raquo;&nbsp;-
Крикнул на скаку.
Лихо конница прошла,
А дивчина расцвела,
Нежный взгляд&nbsp;- не по уставу
Дарит казаку.
Припев
По берлинской мостовой
Снова едет верховой,
Про свою любовь к дивчине
Распевает так:
&laquo;Хоть далёко синий Дон,
Хоть далёко милый дом,
Но землячку и в Берлине
Повстречал казак...&raquo;
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_9c3e50d8b6b357a3_be5fc4afa7a9297e','rpp_9c3e50d8b6b357a3','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/kazaki_v_berline.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_81ddfeb4ab700a89','Казачья круговая','(«Клинок и седло да конёк быстроногий...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Анатолий Софронов, музыка: Анатолий Новиков) | Песни военных лет | https://pesni.retroportal.ru/vov/kazachya_krugovaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Клинок и седло да конёк быстроногий...») | merged_versions: 1','Клинок и седло да конёк быстроногий&nbsp;-
Казачья судьбина-судьба...
Зовёт казака из станицы в дорогу,
В поход боевая труба.
Гей, гей, казаки, по полкам, эскадронам,
Питомцы студёной волны;
Мы тихого Дона, родимого Дона
И в жизни, и в смерти сыны.
Война подымается пламенем вещим,
Вполнеба огней языки.
От моря до моря, как молнии, блещут
Казачьи кривые клинки.
Качаясь в седле, ты объедешь, товарищ,
В боях половину Земли,
Но где бы ты ни был, ты в сердце оставишь
Степные свои ковыли.
Пройдёшь через дым, через пепел пожарищ
В казачьем походном седле...
И слава о Доне о синем, товарищ,
Пройдёт за тобой по земле.
Гей, гей, казаки, по полкам, эскадронам,
Питомцы студёной волны;
Мы тихого Дона, родимого Дона
И в жизни, и в смерти сыны.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Клинок и седло да конёк быстроногий...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_81ddfeb4ab700a89'), datetime('now')),datetime('now'));
