INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1dccb91414b01a7f','Как yпоительны в России вечеpа','(Песня из репертуара группы «Белый орёл»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Виктор Пеленягрэ, музыка: Александр Добронравов) | Патриотические песни | https://pesni.retroportal.ru/rodina/kak_upoitelny_v_rossii_vechera.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из репертуара группы «Белый орёл») | merged_versions: 1','Как упоительны в России вечера,
Любовь, шампанское, закаты, переулки.
Ах, лето красное, забавы и прогулки,
Как упоительны в России вечера.
Балы, красавицы, лакеи, юнкера
И вальсы Шуберта, и хруст французской булки.
Любовь, шампанское, закаты, переулки,
Как упоительны в России вечера.
Как упоительны в России вечера,
В закатном блеске пламенеет снова лето,
И только небо в голубых глазах поэта,
Как упоительны в России вечера.
Пускай всё сон, пускай любовь игра,
Ну что тебе мои порывы и объятия.
На том и этом свете буду вспоминать я,
Как упоительны в России вечера.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из репертуара группы «Белый орёл»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1dccb91414b01a7f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1dccb91414b01a7f','Как yпоительны в России вечеpа','Как упоительны в России вечера,
