INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a4ffe15cf4767358','Как в степи кубанской','(Песня из кинофильма «Кавалер золотой звезды»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Яков Шведов, музыка: Тихон Хренников) | Патриотические песни | https://pesni.retroportal.ru/rodina/kak_v_stepi_kubanskoy.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из кинофильма «Кавалер золотой звезды») | merged_versions: 1','Эх вы, степи степи над Кубань-рекой!
Ехали мы с песней в полудённый зной
Через перекаты по родным степям.
Девушки в дороге повстречались нам.
Обо всём казачки разузнать спешат.
Мы им отвечали по-казацки в лад:
Соколы летают только в облаках -
В облаках дорога всюду широка.
Скоро степь напоим мы живой водой.
Станет много краше милый край степной.
Зори золотые мы в ночи зажжём,
А казачек наших мы в поход зовём.
Эх, вы степи-степи над Кубань-рекой!
Ехали мы с песней степью-целиной.
Ехал, как на праздник, с нами весь народ
По степным дорогам в трудовой поход.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из кинофильма «Кавалер золотой звезды»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a4ffe15cf4767358'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a4ffe15cf4767358','Как в степи кубанской','Эх вы, степи степи над Кубань-рекой!
