INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_76fd1250c2a61558','Как в степи сожжённой','(«Я люблю, но об этом никто не узнает...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Анатолий Лепин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/kak_v_stepi_sozhzhennoj.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Я люблю, но об этом никто не узнает...») | merged_versions: 1','Как в степи, степи сожжённой вырастал дубок.
Он сперва пустил зелёный, маленький росток.
Под горячими лучами смело он стоял,
Вглубь земли он рос корнями, силу набирал...
Припев:
Я люблю,
Но об этом никто не узнает.
Знаю я&nbsp;-
Наше счастье растёт-подрастает.
Наши чувства крепки как степные дубки.
Я люблю
И душа расцветает!
Дуб могучий, дуб курчавый зашумит весной,
Мы с тобой пойдём в дубравы полосой лесной.
Лес увидем в полной силе посреди степей.
Это мы его растили в юности своей.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Я люблю, но об этом никто не узнает...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_76fd1250c2a61558'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_76fd1250c2a61558','Как в степи сожжённой','Как в степи, степи сожжённой вырастал дубок.
Он сперва пустил зелёный, маленький росток.
