INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6e88d07fe2dfed9a','Как за нашим за двором',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/34.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Как за нашим, за нашим, за нашим за двором,
За двором, за двором, за двором, за двором
Растёт трава, растёт трава, растёт травка шелкова,
Шелковая трава, шелковая трава.
По той траве, по той траве, по той траве пава шла.
Пава шла, девица, пава шла, девица.
За павою, за павою, за павою пан летел,
Пан летел, пан летел, пан летел, пан летел.
Кличет: &laquo;Пава!&raquo;, кличет: &laquo;Пава!&raquo;, кличет: &laquo;Пава ты моя!
Ты моя, ты моя, ты моя, ты моя!&raquo;
&laquo;Нет, я, сударь, нет, я, сударь, нет, я, сударь, не твоя,
Не твоя, не твоя, не твоя, не твоя.
Я павлина, я павлина, я павлинова жена.
Вольная, вольная, вольная, вольная!&raquo;','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6e88d07fe2dfed9a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6e88d07fe2dfed9a','Как за нашим за двором','Как за нашим, за нашим, за нашим за двором,
За двором, за двором, за двором, за двором
Растёт трава, растёт трава, растёт травка шелкова,
Шелковая трава, шелковая трава.
По той траве, по той траве, по той траве пава шла.
Пава шла, девица, пава шла, девица.
За павою, за павою, за павою пан летел,
Пан летел, пан летел, пан летел, пан летел.
Кличет: &laquo;Пава!&raquo;, кличет: &laquo;Пава!&raquo;, кличет: &laquo;Пава ты моя!
Ты моя, ты моя, ты моя, ты моя!&raquo;
&laquo;Нет, я, сударь, нет, я, сударь, нет, я, сударь, не твоя,
Не твоя, не твоя, не твоя, не твоя.
Я павлина, я павлина, я павлинова жена.
Вольная, вольная, вольная, вольная!&raquo;');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6e88d07fe2dfed9a_275594c966b0901a','rpp_6e88d07fe2dfed9a','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/34.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b43e21e64bdb54d3','Как мила её головка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Туманский, музыка: Александр Даргомыжский) | Старинные романсы | https://pesni.retroportal.ru/sr1/39.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Как мила её головка
В белом облаке чалмы,
Как пристало к ней раздумье
В томный час вечерней тьмы;
Как роскошно алой тканью
Разрисован гибкий стан,
Скажешь, - розами одета,
Скажешь, - гость волшебных стран!
А глаза – живые звёзды,
Что за нега и краса!
В них сквозь влагу брызжут искры,
Сквозь огонь блестит роса.
Это Гурия пророка,
Предвещающая рай!
И желание сгорай!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b43e21e64bdb54d3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b43e21e64bdb54d3','Как мила её головка','Как мила её головка
В белом облаке чалмы,
Как пристало к ней раздумье
В томный час вечерней тьмы;
Как роскошно алой тканью
Разрисован гибкий стан,
Скажешь, - розами одета,
Скажешь, - гость волшебных стран!
А глаза – живые звёзды,
Что за нега и краса!
В них сквозь влагу брызжут искры,
Сквозь огонь блестит роса.
Это Гурия пророка,
Предвещающая рай!
И желание сгорай!');
