INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_71c25167e14d966f','Как не любить мне эту землю','(Песня из репертуара Людмилы Зыкиной и Александры Стрельченко)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Лазарев-Мильдон, музыка: Валентин Левашов) | Патриотические песни | https://pesni.retroportal.ru/rodina/kak_ne_lyubit_mne_etu_zemlyu.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из репертуара Людмилы Зыкиной и Александры Стрельченко) | merged_versions: 1','Как не любить мне эту землю,
Где мне дано свой век прожить:
И эту синь, и эту зелень,
И тропку тайную во ржи!
Мне хорошо в твоих раздольях,
Моя любовь, моя земля.
Крестьянка русская в ладонях
Весною нянчила тебя.
Как не любить мне эту пашню,
Что битва кровью обожгла,
Как мне забыть за правду павших
Крестьян из нашего села!
Земля, под грозами ты мокла,
Сквозь бури шла и ожила.
Скажи, а всё ли сделать смог я,
Чтоб ты любить меня могла?
Когда к тебе я припадаю
В суровой нежности своей,
В твоём тепле я вспоминаю
Ладони матери моей.
Как не любить мне эту землю!
На сайте &laquo;Retroportal.ru&raquo; опубликовано эксклюзивное интервью корреспондента газеты &laquo;Русская Жизнь&raquo; Галины Артамоновой с поэтом Владимиром Лазаревевым-Мильдоном об истории создания им  поэтического текста марша &laquo;Прощание славянки&raquo; .','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из репертуара Людмилы Зыкиной и Александры Стрельченко)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_71c25167e14d966f'), datetime('now')),datetime('now'));
