INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_693c3b4a39a4dbab','Как пойду я на быструю речку',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/35.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Как пойду я на быструю речку,
Сяду я да на крут бережок,
Посмотрю на родную сторонку,
На зелёный приветный лужок.
Ты сторонка, сторонка родная,
Нет на свете привольней тебя.
Уж ты, нива моя золотая,
Да высокие наши хлеба.
Эх ты, русское наше приволье,
Краю нет на луга и поля.
Ты – широкое наше раздолье,
Ты – родимая матерь-земля.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_693c3b4a39a4dbab'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_693c3b4a39a4dbab','Как пойду я на быструю речку','Как пойду я на быструю речку,
