INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_693c3b4a39a4dbab_ff9d5f19a17a51ed','rpp_693c3b4a39a4dbab','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/35.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a3bb8bebea69418c','Как сладко с тобою мне быть',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Пётр Рындин, музыка: Михаил Глинка) | Старинные романсы | https://pesni.retroportal.ru/sr1/40.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Как сладко с тобою мне быть
И молча душой погружаться
В лазурные очи твои.
Всю пылкость, все страсти души
Так сильно они выражают,
Как слово не выразит их.
И сердце трепещет невольно
При виде тебя!
Люблю я смотреть на тебя,
Как много в улыбке отрады
И неги в движеньях твоих.
Напрасно хочу заглушить
Порывы душевных волнений
И сердце рассудком унять.
Не слушает сердце рассудка
При виде тебя!
Нежданною чудной звездой
Явилась ты предо мною
И жизнь озарила мою.
Сияй же, указывай путь,
Веди к непривычному счастью
Того, кто надежды не знал.
И сердце утонит в восторге
При виде тебя!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a3bb8bebea69418c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a3bb8bebea69418c','Как сладко с тобою мне быть','Как сладко с тобою мне быть
