INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e1e92ff38d2dc9bc','Каким ты был, таким остался','(Песня из кинофильма «Кубанские казаки»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/kakim_ty_byl_takim_ostalsya_kubanskie_kazaki.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из кинофильма «Кубанские казаки») | merged_versions: 1','Каким ты был, таким остался,
Орёл степной, казак лихой...
Зачем, зачем ты снова повстречался,
Зачем нарушил мой покой?
Зачем опять в своих утратах
Меня ты хочешь обвинить?
В одном, в одном я только виновата,
Что нету сил тебя забыть.
Свою судьбу с твоей судьбою
Пускай связать я не могла,
Но я жила, жила одним тобою,
Я всю войну тебя ждала.
Ждала, когда наступят сроки,
Когда вернёшься ты домой.
И горьки мне, горьки твои упрёки,
Горячий мой, упрямый мой.
Твоя печаль, твоя обида,
Твои тревоги - ни к чему:
Смотри, смотри - душа моя открыта,
Тебе открыта одному.
Но ты взглянуть не догадался,
Умчался вдаль, казак лихой...
Каким ты был, таким ты и остался,
Но ты и дорог мне такой!','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из кинофильма «Кубанские казаки»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e1e92ff38d2dc9bc'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e1e92ff38d2dc9bc','Каким ты был, таким остался','Каким ты был, таким остался,
