INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_429c276d41ee040b','Какое небо голубое','(«Песня лисы Алисы и кота Базилио»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Булат Окуджава, музыка: Алексей Рыбников) | Песни для детей | https://pesni.retroportal.ru/deti/kakoe_nebo_goluboe.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: («Песня лисы Алисы и кота Базилио») | merged_versions: 1','Лап то бу ди дубудай, лап то бу ди дубудай...
лап то бу ди дубуда дай, лай лай лай лалалалалала.
Лап то бу ди дубудай, лап то бу ди дубудай,
лай лай лай лалалалалала!
Пока живут на свете хвастуны,
Мы прославлять судьбу свою должны!
Какое небо голубое,
Мы не сторонники разбоя:
На хвастуна не нужен нож,
Ему немного подпоёшь&nbsp;-
И делай с ним, что хошь!
Покуда живы жадины вокруг,
Удачи мы не выпустим из рук.
Какое небо голубое,
Мы не сторонники разбоя:
На жадину не нужен нож,
Ему покажешь медный грош&nbsp;-
И делай с ним, что хошь!
Покуда есть на свете дураки,
Обманом жить нам, стало быть, с руки.
Какое небо голубое,
Мы не сторонники разбоя:
На дурака не нужен нож,
Ему с три короба наврёшь&nbsp;-
И делай с ним, что хошь!
Какое небо голубое,
Живут на свете эти трое.
Им, слава богу, нет конца,
Как говорится, зверь бежит&nbsp;-
И прямо на ловца!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(«Песня лисы Алисы и кота Базилио»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_429c276d41ee040b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_429c276d41ee040b','Какое небо голубое','Лап то бу ди дубудай, лап то бу ди дубудай...
лап то бу ди дубуда дай, лай лай лай лалалалалала.
