INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d3665928d0f4653d','«Калинка» («Калинка-малинка моя!»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Иван Ларионов) | Народные песни | https://pesni.retroportal.ru/np1/36.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Калинка, калинка, калинка моя!
В саду ягода малинка, малинка моя!
Ах! Под сосною под зеленою
Спать положите вы меня;
Ай, люли, люли, ай, люли, люли,
Спать положите вы меня.
Калинка, калинка, калинка моя!
В саду ягода малинка, малинка моя!
Ах! Сосёнушка ты зелёная,
Не шуми же надо мной!
Ай, люли, люли, ай, люли, люли,
Не шуми же надо мной!
Калинка, калинка, калинка моя!
В саду ягода малинка, малинка моя!
Ах! Красавица, душа-девица,
Полюби же ты меня!
Ай, люли, люли, ай, люли, люли,
Полюби же ты меня!
Калинка, калинка, калинка моя!
В саду ягода малинка, малинка моя!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d3665928d0f4653d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d3665928d0f4653d','«Калинка» («Калинка-малинка моя!»)','Калинка, калинка, калинка моя!
