В саду ягода малинка, малинка моя!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d3665928d0f4653d_a4e215f0f454114b','rpp_d3665928d0f4653d','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/36.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_379ea79334e4a6a6','Калитка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Будищев, музыка: Всеволод Буюкли) | Старинные романсы | https://pesni.retroportal.ru/sr1/41.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Лишь только вечер затеплится синий,
Лишь только звёзды зажгут небеса
И черёмух серебряный иней
Жемчугами украсит роса.
Отвори потихоньку калитку
И войди в тихий садик, как тень.
Не забудь потемнее накидку,
Кружева на головку надень.
Там, где гуще сплетаются ветки,
У беседки тебя подожду
И на самом пороге беседки
С милых уст кружева отведу.
Отвори потихоньку калитку
И войди в тихий садик, как тень.
Не забудь потемнее накидку,
Кружева на головку надень.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_379ea79334e4a6a6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_379ea79334e4a6a6','Калитка','Лишь только вечер затеплится синий,
