INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_379ea79334e4a6a6_d82e70d88f831fb9','rpp_379ea79334e4a6a6','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/41.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bed218eb753f8028','Камаринская',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова народные, музыка: Михаил Глинка) | Народные песни | https://pesni.retroportal.ru/np1/37.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ох, ты, сукин сын, камаринский мужик,
Задрал ножки та й на печке лежит.
Лежит, лежит та й попорхивает,
Правой ножкою подёргивает.
Сам на девушек помаргивает,
Над женою выкамаривает:
- Ты вставай, молодая жена!
Скорей завтрак готовь, сатана!
Ой, комар ты, наш камаринский мужик,
Собрался в лес, по дорожке бежит.
Он бежит, бежит, пошучивает,
Свои усики покручивает.
Тише, тише топочите!
Пол не проломите!
У нас под полом вода,
В воде не утоните!
Пошла плясать,
Ногой топнула.
Аж хата покачнулась
И дверь хлопнула.
Хорошо, подружка, пляшешь!
Хорошо ты дроби бьёшь!
Только тем и не хороша,
Что припевок не поёшь!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bed218eb753f8028'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bed218eb753f8028','Камаринская','Ох, ты, сукин сын, камаринский мужик,
Задрал ножки та й на печке лежит.
Лежит, лежит та й попорхивает,
Правой ножкою подёргивает.
Сам на девушек помаргивает,
Над женою выкамаривает:
- Ты вставай, молодая жена!
Скорей завтрак готовь, сатана!
Ой, комар ты, наш камаринский мужик,
Собрался в лес, по дорожке бежит.
Он бежит, бежит, пошучивает,
Свои усики покручивает.
Тише, тише топочите!
Пол не проломите!
У нас под полом вода,
В воде не утоните!
Пошла плясать,
Ногой топнула.
Аж хата покачнулась
И дверь хлопнула.
Хорошо, подружка, пляшешь!
Хорошо ты дроби бьёшь!
Только тем и не хороша,
Что припевок не поёшь!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_bed218eb753f8028_d5b2efe66c22bf1c','rpp_bed218eb753f8028','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/37.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ae53948e0279392d','«Караван» («Мы странно встретились...»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Борис Тимофеев-Еропкин, музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr1/42.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Мы странно встретились и странно разойдёмся,
Улыбкой нежности роман окончен наш.
И если памятью к прошедшему вернёмся,
То скажем: &laquo;Это был мираж&raquo;.
Так иногда в таинственной пустыне
Мелькают образы далёких, чудных стран.
Но это призраки, и снова небо сине,
И вдаль идёт усталый караван.
И мы, как путники, обмануты миражем,
Те сны неверные не в силах уберечь.
Мы никогда друг другу не расскажем
Всю тайну наших встреч.
Припев
Пусть впереди всё призрачно, туманно,
Как наших чувств стремительный обман.
Мы странно встретились, и ты уйдешь нежданно,
Как в путь уходит караван.
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ae53948e0279392d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ae53948e0279392d','«Караван» («Мы странно встретились...»)','Мы странно встретились и странно разойдёмся,
Улыбкой нежности роман окончен наш.
