Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_ae53948e0279392d_9857373737b94066','rpp_ae53948e0279392d','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/42.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bbd2349af644d2e8','Катюша','(«Расцветали яблони и груши, поплыли туманы над рекой...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Матвей Блантер) | Эстрадные песни | https://pesni.retroportal.ru/estrada/katyusha.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Расцветали яблони и груши, поплыли туманы над рекой...») | merged_versions: 1','Расцветали яблони и груши,
Поплыли туманы над рекой.
Выходила на берег Катюша,
На высокий берег на крутой.
Выходила, песню заводила
Про степного, сизого орла,
Про того, которого любила,
Про того, чьи письма берегла.
Ой ты, песня, песенка девичья,
Ты лети за ясным солнцем вслед.
И бойцу на дальнем пограничье
От Катюши передай привет.
Пусть он вспомнит девушку простую,
Пусть услышит, как она поёт,
Пусть он землю бережет родную,
А любовь Катюша сбережёт.
Расцветали яблони и груши,
Поплыли туманы над рекой.
Выходила на берег Катюша,
На высокий берег на крутой.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Расцветали яблони и груши, поплыли туманы над рекой...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bbd2349af644d2e8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bbd2349af644d2e8','Катюша','Расцветали яблони и груши,
Поплыли туманы над рекой.
Выходила на берег Катюша,
На высокий берег на крутой.
Выходила, песню заводила
