INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_32a45a8f6168e3aa_8bc87cb4ecc08bda','rpp_32a45a8f6168e3aa','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/43.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1e02053b3671104a','Клятва наркому','(«Великий день настал, и вышли миллионы...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Виссарион Саянов, музыка: Дмитрий Шостакович) | Песни военных лет | https://pesni.retroportal.ru/vov/klyatva_narkomu.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Великий день настал, и вышли миллионы...») | merged_versions: 1','Великий день настал, и вышли миллионы
На беспощадный бой за Родину свою
Клянётся вся страна наркому обороны:
Мы выполним приказ, мы победим в бою.
От черноморских вод до зыби океана
Один победный клич гремит во всех краях:
Клянёмся ускорять победу неустанно
Всей доблестью в труде, всей храбростью в боях.
Клянёмся победить и, мужество утроив,
На море, на земле и в небе бить врагов.
Нам приказал нарком, и встал народ героев,
И станут наши дни легендою веков.
И пусть трепещет враг, мы все стеною встали
На грозных рубежах своей страны родной
Великий час настал&nbsp;- ведёт к победе Сталин.
Его приказ&nbsp;- закон, смелее в грозный бой!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Великий день настал, и вышли миллионы...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1e02053b3671104a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1e02053b3671104a','Клятва наркому','Великий день настал, и вышли миллионы
На беспощадный бой за Родину свою
Клянётся вся страна наркому обороны:
Мы выполним приказ, мы победим в бою.
От черноморских вод до зыби океана
Один победный клич гремит во всех краях:
Клянёмся ускорять победу неустанно
Всей доблестью в труде, всей храбростью в боях.
Клянёмся победить и, мужество утроив,
На море, на земле и в небе бить врагов.
Нам приказал нарком, и встал народ героев,
И станут наши дни легендою веков.
И пусть трепещет враг, мы все стеною встали
На грозных рубежах своей страны родной
Великий час настал&nbsp;- ведёт к победе Сталин.
Его приказ&nbsp;- закон, смелее в грозный бой!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_1e02053b3671104a_2a11f52aef5071c6','rpp_1e02053b3671104a','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/klyatva_narkomu.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4c97519be869b3dd','Когда б имел златые горы',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/38.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вариант I
&laquo;Когда б имел златые горы
И реки полные вина,
Всё отдал бы за ласки, взоры,
Чтоб ты владела мной одна&raquo;.
&laquo;Не упрекай несправедливо,
Скажи всю правду ты отцу –
Тогда свободно и счастливо
С молитвой мы пойдём к венцу&raquo;.
&laquo;Не раз, Мария, твою руку
Просил я у отца, не раз.
Отец не понял моей муки,
Жестокий сердцу дал отказ&raquo;.
Тогда бежать я с ним решилась,
Поверив клятве роковой,
На божий храм перекрестилась,
В слезах взглянув на дом родной.
Умчались мы в страну чужую,
А через год он изменил,
Забыл он клятву ту святую,
А сам другую полюбил.
А мне сказал, стыдясь измены:
&laquo;Ступай обратно в дом отца.
Оставь, Мария, мои стены,
Я провожу тебя с крыльца.
За речи, ласки огневые
Я награжу тебя конём.
Уздечку, хлыстик золотые
Седельце шито жемчугом&raquo;.
&laquo;Не надо мне твоей уздечки,
Не надо мне твово коня,
Ты пропил горы золотые
И реки полные вина&raquo;.
Вариант II
&laquo;Когда б имел златые горы
И реки, полные вина,
Всё отдал бы за ласки, взоры,
Чтоб ты владела мной одна&raquo;.
&laquo;Не упрекай несправедливо,
Скажи всю правду ты отцу.
Тогда свободно и счастливо
С молитвой мы пойдем к венцу&raquo;.
&laquo;Ах, нет, твою, голубка, руку
Просил я у него не раз.
Но он не понял мою муку
И дал жестокий мне отказ.
Спроси у сердца ты совета,
Страданьем тронута моим.
И, веря святости обета,
Беги с возлюбленным своим».
&laquo;Ну как же, милый, я покину
Семью родную и страну?
Ведь ты заедешь на чужбину
И бросишь там меня одну&raquo;.
Умчались мы в страну чужую,
А через год он изменил,
Забыл и клятву роковую,
Когда другую полюбил.
А мне сказал, стыдясь измены:
&laquo;Ступай обратно в дом отца.
Оставь, Мария, мои стены!&raquo;
И проводил меня с крыльца.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4c97519be869b3dd'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4c97519be869b3dd','Когда б имел златые горы','Вариант I
&laquo;Когда б имел златые горы
И реки полные вина,
Всё отдал бы за ласки, взоры,
Чтоб ты владела мной одна&raquo;.
&laquo;Не упрекай несправедливо,
Скажи всю правду ты отцу –
Тогда свободно и счастливо
С молитвой мы пойдём к венцу&raquo;.
&laquo;Не раз, Мария, твою руку
Просил я у отца, не раз.
Отец не понял моей муки,
Жестокий сердцу дал отказ&raquo;.
Тогда бежать я с ним решилась,
Поверив клятве роковой,
На божий храм перекрестилась,
В слезах взглянув на дом родной.
Умчались мы в страну чужую,
А через год он изменил,
Забыл он клятву ту святую,
А сам другую полюбил.
А мне сказал, стыдясь измены:
&laquo;Ступай обратно в дом отца.
Оставь, Мария, мои стены,
Я провожу тебя с крыльца.
За речи, ласки огневые
Я награжу тебя конём.
Уздечку, хлыстик золотые
Седельце шито жемчугом&raquo;.
&laquo;Не надо мне твоей уздечки,
Не надо мне твово коня,
Ты пропил горы золотые
И реки полные вина&raquo;.
Вариант II
&laquo;Когда б имел златые горы
И реки, полные вина,
Всё отдал бы за ласки, взоры,
Чтоб ты владела мной одна&raquo;.
&laquo;Не упрекай несправедливо,
Скажи всю правду ты отцу.
Тогда свободно и счастливо
С молитвой мы пойдем к венцу&raquo;.
&laquo;Ах, нет, твою, голубка, руку
Просил я у него не раз.
Но он не понял мою муку
И дал жестокий мне отказ.
Спроси у сердца ты совета,
Страданьем тронута моим.
И, веря святости обета,
Беги с возлюбленным своим».
&laquo;Ну как же, милый, я покину
Семью родную и страну?
Ведь ты заедешь на чужбину
И бросишь там меня одну&raquo;.
Умчались мы в страну чужую,
А через год он изменил,
Забыл и клятву роковую,
Когда другую полюбил.
А мне сказал, стыдясь измены:
&laquo;Ступай обратно в дом отца.
Оставь, Мария, мои стены!&raquo;
И проводил меня с крыльца.');
