INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4a744f81e0999943','Когда б он знал',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Евдокия Растопчина, музыка: Елизавета Кочубей) | Старинные романсы | https://pesni.retroportal.ru/sr1/44.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Когда б он знал, что пламенной душою
С её душой сливаюсь тайно я,
Когда б он знал, что горькою тоскою
Отравлена младая жизнь моя!
Когда б он знал, как страстно и как нежно
Он, мой кумир, рабой своей любим...
Когда б он знал, что в грусти безнадежной
Увяну я, не понятая им!..
Когда б он знал, когда б он знал!
Когда б он знал, как дорого мне стоит,
Как тяжело мне с ним притворной быть!
Когда б он знал, как томно сердце ноет,
Когда велит мне гордость страсть таить!..
Когда б он знал, какое испытанье
Спокойный взор его приносит мне,
Когда взамен немного обожанья
Обидный хлад я зрю в его душе!
Когда б он знал, когда б он знал!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4a744f81e0999943'), datetime('now')),datetime('now'));
