INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_75b0802d3bfff305','Когда друзья встречаются','(«Ты песню пой, иди вперёд...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Андрей Досталь, музыка: Борис Карамышев) | Эстрадные песни | https://pesni.retroportal.ru/estrada/kogda_druzya_vstrechayutsya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Ты песню пой, иди вперёд...») | merged_versions: 1','Когда друзья встречаются,
То всё поёт вокруг, то всё поёт вокруг,
Ведь дружба начинается
С пожатьем крепким рук, с пожатьем крепким рук.
Припев:
Ты песню пой, иди вперёд,
Тебя с собой мечта зовёт!
Ты песню пой, ты песню пой, иди вперёд,
Тебя мечта зовёт!
Идут друзья по городу,
Идут среди полей, идут среди полей,
И всё, что сердцу дорого,
Пред ними на земле, пред ними на земле.
Припев
Пусть жизнь порой не балует,
Не лёгок путь прямой, не лёгок путь прямой,
Идут друзья, не жалуясь,
Дорогою одной, дорогою одной.
Припев
А вдруг друзья расстанутся,
И это не беда, и это не беда,
Ведь дружба их останется
На долгие года, на долгие года.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Ты песню пой, иди вперёд...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_75b0802d3bfff305'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_75b0802d3bfff305','Когда друзья встречаются','Когда друзья встречаются,
