INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3c78a5aa8b4425e3','«Когда предчувствием разлуки» («Утрата»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Яков Полонский, музыка: Давид Ашкенази) | Старинные романсы | https://pesni.retroportal.ru/sr1/45.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Когда предчувствием разлуки
Мне грустно голос ваш звучал,
Когда, смеясь, я ваши руки
В своих руках отогревал,
Когда дорога яркой далью
Меня манила из глуши –
Я вашей тайною печалью
Гордился в глубине души.
Перед непризнанной любовью
Я весел был в прощальный час,
Но боже мой! – с какою болью
Тогда очнулся я без вас!
Какими тягостными снами
Томит, смущая мой покой,
Всё, недосказанное вами,
И недослушанное мной,
Всё, недосказанное вами,
И недослушанное мной.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3c78a5aa8b4425e3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3c78a5aa8b4425e3','«Когда предчувствием разлуки» («Утрата»)','Когда предчувствием разлуки
