INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_76e2cb1f838e3a81','«Когда я на почте служил ямщиком»*',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Людвик Кондратович (Владислав Сырокомля), перевод: Леонид Трефолев) | Народные песни | https://pesni.retroportal.ru/np1/39.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Когда я на почте служил ямщиком,
Был молод, имел я силёнку,
И крепко же, братцы, в селенье одном
Любил я в ту пору девчонку.
Сначала не чуял я в девке беду,
Потом задурил не на шутку:
Куда ни поеду, куда ни пойду,
Всё к милой сверну на минутку.
И любо оно, да покоя-то нет,
А сердце болит всё сильнее.
Однажды даёт мне начальник пакет:
&laquo;Свези, мол, на почту живее!&raquo;
Я принял пакет – и скорей на коня,
И по полю вихрем помчался,
А сердце щемит, да щемит у меня,
Как будто с ней век не видался.
И что за причина, понять не могу,
И ветер так воет тоскливо...
И вдруг – словно замер мой конь на бегу,
И в сторону смотрит пугливо.
Забилося сердце сильней у меня,
И глянул вперед я в тревоге,
Потом соскочил с удалого коня, -
И вижу я труп на дороге.
А снег уж совсем ту находку занёс,
Метель так и пляшет над трупом.
Разрыл я сугроб-то и к месту прирос, -
Мороз заходил под тулупом.
Под снегом-то, братцы, лежала она...
Закрылися карие очи.
Налейте, налейте скорее вина,
Рассказывать больше нет мочи!
Слова народной песни &laquo;Когда я на почте служил ямщиком&raquo; написал белорусский и польский поэт Людвик Кондратович (Ludwik Władysław Franciszek Kondratowicz), более известный под псевдонимом Владислав Сырокомля (Władysław Syrokomla), перевод на русский язык сделал Леонид Трефолев. В оригинале стихотворение Людвика Кондратовича о ямщике называется &laquo;Почтальон&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_76e2cb1f838e3a81'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_76e2cb1f838e3a81','«Когда я на почте служил ямщиком»*','Когда я на почте служил ямщиком,
Был молод, имел я силёнку,
