Слова народной песни &laquo;Когда я на почте служил ямщиком&raquo; написал белорусский и польский поэт Людвик Кондратович (Ludwik Władysław Franciszek Kondratowicz), более известный под псевдонимом Владислав Сырокомля (Władysław Syrokomla), перевод на русский язык сделал Леонид Трефолев. В оригинале стихотворение Людвика Кондратовича о ямщике называется &laquo;Почтальон&raquo;.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_76e2cb1f838e3a81_1aa3605faed2e3be','rpp_76e2cb1f838e3a81','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/39.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8210e3699ff9f845','«Колокольчик» («Однозвучно гремит колокольчик»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Иван Макаров, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr1/46.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Однозвучно гремит колокольчик,
И дорога пылится слегка,
И уныло по ровному полю
Заливается песнь ямщика,
Заливается песнь ямщика.
Столько чувства в той песне унылой.
Столько грусти в напеве родном,
Что в груди моей, хладной, остылой,
Разгорелося сердце огнём.
Разгорелося сердце огнём!
И припомнил я ночи другие,
И родные поля и леса,
И на очи, давно уж сухие,
Набежала, как искра, слеза.
Набежала, как искра, слеза.
Однозвучно гремит колокольчик,
Издали отдаваясь слегка...
И замолк мой ямщик, а дорога
Предо мной далека, далека.
Предо мной далека, далека!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8210e3699ff9f845'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8210e3699ff9f845','«Колокольчик» («Однозвучно гремит колокольчик»)','Однозвучно гремит колокольчик,
И дорога пылится слегка,
И уныло по ровному полю
Заливается песнь ямщика,
Заливается песнь ямщика.
Столько чувства в той песне унылой.
Столько грусти в напеве родном,
Что в груди моей, хладной, остылой,
Разгорелося сердце огнём.
Разгорелося сердце огнём!
И припомнил я ночи другие,
И родные поля и леса,
И на очи, давно уж сухие,
Набежала, как искра, слеза.
Набежала, как искра, слеза.
Однозвучно гремит колокольчик,
Издали отдаваясь слегка...
И замолк мой ямщик, а дорога
Предо мной далека, далека.
Предо мной далека, далека!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_8210e3699ff9f845_1601019d048ee372','rpp_8210e3699ff9f845','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/46.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a541f41b53289977','Колокольчики мои',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Толстой, музыка: Пётр Булахов) | Старинные романсы | https://pesni.retroportal.ru/sr1/47.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Колокольчики мои,
Цветики степные!
Что глядите на меня,
Тёмно-голубые?
И о чём звените вы
В день весёлый мая,
Средь некошеной травы
Головой качая?
Конь несёт меня стрелой
На поле открытом;
Он вас топчет под собой,
Бьёт своим копытом.
Колокольчики мои,
Цветики степные!
Не кляните вы меня,
Тёмно-голубые!
Я бы рад вас не топтать,
Рад промчаться мимо,
Но уздой не удержать
Бег неукротимый!
Я лечу, лечу стрелой,
Только пыль взметаю;
Конь несёт меня лихой,
А куда? Не знаю.
Гой вы, цветики мои,
Цветики степные!
Что глядите на меня,
Тёмно-голубые?
И о чём грустите вы
В день весёлый мая,
Средь некошеной травы
Головой качая?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a541f41b53289977'), datetime('now')),datetime('now'));
