INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_dbce2b1ba084374e','Колыбеленка','(«Баю, баю, баю-бай, засыпай моё дитя...»)','ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | Народные песни | https://pesni.retroportal.ru/np1/17.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | subtitle: («Баю, баю, баю-бай, засыпай моё дитя...») | merged_versions: 1','(народная колыбельная песня)
Дитятко моё качаю,
Колыбеленку спеваю.
Баю, баю, баю-бай,
Засыпай моё дитя,
Ноченьки не боитя.
Солнышко взойдёте,
Красное взойдёте,
Буде добрый день.
Баю-бай.
Птичка божия летала,
В поле зерна собирала.
Баю, баю, баю-бай,
Засыпай моё дитя,
Ноченьки не боитя.
Солнышко взойдёте,
Красное взойдёте,
Буде добрый день.
Баю-бай.
Птичка на двор залетала,
Добры вести щебетала.
Баю, баю, баю-бай,
Засыпай моё дитя,
Ноченьки не боитя.
Солнышко взойдете,
Красное взойдёте,
Буде добрый день.
Баю-бай.
Буде лето не пекливо,
Зимня стужа не злоблива.
Баю, баю, баю-бай,
Засыпай моё дитя,
Ноченьки не боитя.
Солнышко взойдёте,
Красное взойдете,
Буде добрый день.
Баю-бай.
Колыбеленку спеваю,
Снов к Ивасю зазываю.
Баю, баю, баю-бай,
Засыпай моё дитя,
Да никого не боитя -
Буде добрым свет.
Баю-бай, баю-бай, баю-бай...','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "retroportal-subtitle:(«Баю, баю, баю-бай, засыпай моё дитя...»)", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_dbce2b1ba084374e'), datetime('now')),datetime('now'));
