INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6090b7f89d87ca04','Конь, мой конь','(«Любо ехать мне домой с поля бранной славы»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Александр Прокофьев, музыка: Сергей Потоцкий) | Песни военных лет | https://pesni.retroportal.ru/vov/budet_gitleru_konec.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Любо ехать мне домой с поля бранной славы») | merged_versions: 1','Любо ехать мне домой
С поля бранной славы.
Дай дорогу, лес ты мой,
Друг ты мой кудрявый!
Припев:
Конь, мой конь,
Звени, звени лёгкою подковою!
Ждут меня златые дни,
Очи васильковые...
Дышит вся земля весной,
Волей долгожданной,
Обнимает край родной
Лаской несказанной!
Припев
Вся Святая наша Русь
Мне летит навстречу,
Побеждая смерть и грусть
Жизнью долговечной!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Любо ехать мне домой с поля бранной славы»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6090b7f89d87ca04'), datetime('now')),datetime('now'));
