INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a6d1349c6df2d224','«Корабли» («Мы никогда друг друга не любили»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr1/48.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Мы никогда друг друга не любили,
В своих сердцах привета не носили,
Случайных встреч и взоров не ценили
И разошлись, как ночью корабли...
Но, разойдясь, сквозь сумраки ночные
Мы с трепетом в сердцах своих прочли,
Что наши души близкие, родные,
Что полюбить друг друга мы могли...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a6d1349c6df2d224'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a6d1349c6df2d224','«Корабли» («Мы никогда друг друга не любили»)','Мы никогда друг друга не любили,
В своих сердцах привета не носили,
Случайных встреч и взоров не ценили
И разошлись, как ночью корабли...
Но, разойдясь, сквозь сумраки ночные
Мы с трепетом в сердцах своих прочли,
Что наши души близкие, родные,
Что полюбить друг друга мы могли...');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_a6d1349c6df2d224_2a3731eb31f22b93','rpp_a6d1349c6df2d224','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr1/48.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_423f399e5331bd3b','Коробейники',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Некрасов) | Народные песни | https://pesni.retroportal.ru/np1/40.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','&laquo;Ой, полна, полна моя коробушка,
Есть и ситец, и парча,
Пожалей, моя зазнобушка,
Молодецкого плеча!
Пойду выйду в рожь высокую,
Там до ночки погожу,
А завижу черноокую –
Все товары разложу&raquo;.
Вот и пала ночь туманная,
Ждёт удалый молодец:
&laquo;Чу! Идёт, пришла моя желанная!&raquo;
Продает товар купец.
Катя бережно торгуется,
Всё боится передать,
Парень с девицей целуется,
Просит цены набавлять:
&laquo;Цены сам платил немалые,
Не торгуйся, не скупись,
Подставляй-ка губки алые,
Ближе к молодцу садись!..&raquo;
Знала только ночка тёмная,
Как поладили они.
Распрямись ты, рожь высокая,
Тайну свято сохрани!
Ой, легка, легка коробушка,
Плеч не режет ремешок,
А всего взяла зазнобушка
Бирюзовый перстенёк.
Дал ей ситцу штуку целую,
Ленту алую для кос,
Поясок – рубашку белую
Подпоясать в сенокос...
Всё поклала ненаглядная
В короб, кроме перстенька:
&laquo;Не хочу ходить нарядная
Без сердечного дружка!&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_423f399e5331bd3b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_423f399e5331bd3b','Коробейники','&laquo;Ой, полна, полна моя коробушка,
