INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_423f399e5331bd3b_c6803adb8dba62b5','rpp_423f399e5331bd3b','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/40.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_916b3534e621684c','Костры горят далёкие','(«Костры горят далёкие, луна в реке купается...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Иван Шамов, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/kostry_goryat_dalekie.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Костры горят далёкие, луна в реке купается...») | merged_versions: 1','Костры горят далёкие,
Луна в реке купается,
А парень с милой девушкой
На лавочке прощается.
Глаза у парня ясные,
Как угольки горящие,
Быть может, не прекрасные,
Но, в общем, подходящие.
Девчата голосистые
Пропели все страдания,
Лишь слышны на скамеечке
Сердечные вздыхания.
Костры дымят потухшие,
Луна за лес спускается,
А парень с милой девушкой
Никак не распрощается.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Костры горят далёкие, луна в реке купается...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_916b3534e621684c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_916b3534e621684c','Костры горят далёкие','Костры горят далёкие,
