INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_916b3534e621684c_87b269ed6d20a585','rpp_916b3534e621684c','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/kostry_goryat_dalekie.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_92c38078c5e62e62','Край родной','(«Я лучшего края на свете не знаю...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Антон Пришелец, музыка: Юрий Слонов) | Патриотические песни | https://pesni.retroportal.ru/rodina/kraj_rodnoj.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Я лучшего края на свете не знаю...») | merged_versions: 1','Я лучшего края на свете не знаю,
Да есть ли такие края!
Дорожка степная, тропинка лесная,
Сторонка родная моя.
Зелёные рощи как море, как море
Шумит золотая волна.
Стоит среди поля берёзка в дозоре
Далёко, далёко видна.
Под вечер за речкой гармонь заиграет,
Зальётся свирель словья.
Дорожка степная, тропинка лесная,
Сторонка родная моя.
Тяжёлые годы прошли мы стобою,
Запомнятся наши дела.
И небо над нами опять голубое,
И снова ты вся зацвела.
За синие реки, за теплые горы,
Всё шире с темна до темна,
По всем необъятным советским просторам
Гремит трудовая волна.
Цвети, расстилайся от края до края,
От моря к далёким морям
Дорожка степная, тропинка лесная,
Сторонка родная моя.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Я лучшего края на свете не знаю...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_92c38078c5e62e62'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_92c38078c5e62e62','Край родной','Я лучшего края на свете не знаю,
Да есть ли такие края!
Дорожка степная, тропинка лесная,
Сторонка родная моя.
Зелёные рощи как море, как море
Шумит золотая волна.
Стоит среди поля берёзка в дозоре
Далёко, далёко видна.
Под вечер за речкой гармонь заиграет,
Зальётся свирель словья.
Дорожка степная, тропинка лесная,
Сторонка родная моя.
Тяжёлые годы прошли мы стобою,
Запомнятся наши дела.
И небо над нами опять голубое,
И снова ты вся зацвела.
За синие реки, за теплые горы,
Всё шире с темна до темна,
По всем необъятным советским просторам
Гремит трудовая волна.
Цвети, расстилайся от края до края,
От моря к далёким морям
Дорожка степная, тропинка лесная,
Сторонка родная моя.');
