INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5217655616df672a','Красный сарафан',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Цыганов, музыка: Александр Варламов) | Старинные романсы | https://pesni.retroportal.ru/sr2/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не шей ты мне, матушка,
Красный сарафан,
Не входи, родимая,
Попусту в изъян.
Рано мою косыньку
На две расплетать.
Прикажи мне русую
В ленту убирать!
Пускай непокрытая
Шёлковой фатой,
Очи молодецкие
Веселят собой!
То ли житьё девичье,
Чтоб его менять,
Торопиться замужем
Охать да вздыхать!
Золотая волюшка
Мне милей всего!
Не хочу я с волюшкой
В свете ничего!
Дитя моё, дитятко,
Дочка милая!
Головка победная,
Неразумная!
Не век тебе пташечкой
Звонко распевать,
Легкокрылой бабочкой
По цветам порхать.
Заблекнут на щёченьках
Маковы цветы,
Прискучат забавушки,
Стоскуешься ты!
А мы и при старости
Себя веселим,
Младость вспоминаючи,
На детей глядим!
И я молодёшенька
Была такова,
И мне те же в девушках
Пелися слова.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5217655616df672a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5217655616df672a','Красный сарафан','Не шей ты мне, матушка,
