INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fde4ce389d4bc078','Крошка Вилли Винки','(Шотландская народная детская песенка)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (русский текст: Ирина Токмакова, музыка: Сергей Никитин) | Песни для детей | https://pesni.retroportal.ru/deti/kroshka_villi_vinki.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Шотландская народная детская песенка) | merged_versions: 1','Крошка Вилли Винки
Ходит и глядит,
Кто не снял ботинки,
Кто ещё не спит.
Стукнет вдруг в окошко
Или дунет в щель,
Вилли Винки крошка
Лечь велит в постель.
Где ты, Вилли Винки,
Влезь-ка к нам в окно,
Кошка на перинке
Спит уже давно.
Спят в конюшне пони,
Начал пёс дремать,
Только мальчик Джонни
Не ложится спать!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Шотландская народная детская песенка)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fde4ce389d4bc078'), datetime('now')),datetime('now'));
