INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b123d0532ee1d0a1','Кубанская походная','(«Пишет мне казачка - чёрные глаза...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Валентин Кручинин) | Песни военных лет | https://pesni.retroportal.ru/vov/kubanskaya_pohodnaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Пишет мне казачка - чёрные глаза...») | merged_versions: 1','Пишет мне казачка&nbsp;- чёрные глаза,
На письме застыла девичья слеза.
Э-эх, чёрные глаза,
На письме застыла девичья слеза.
Пишет мне казачка, пишет прямо в полк:
&laquo;Бить в бою фашистов&nbsp;- твой священный долг!&raquo;
Э-эх, пишет прямо в полк:
&laquo;Бить в бою фашистов&nbsp;- твой священный долг!&raquo;
&laquo;Ты недаром вывел лучшего коня,
Ты увёз недаром сердце у меня.
Э-эх, лучшего коня,
Ты увёз недаром сердце у меня...&raquo;
Я тебе отвечу, девушка-дружок:
Бить врагов поможет дедовский клинок!
Э-эх, дедовский клинок,
Ненависть казачья, верный мой конёк!
А ещё, казачка, помни обо мне,
Это мне поможет тоже на войне.
Э-эх, помни обо мне,
Это мне поможет тоже на войне.
Обо мне, казачка, думать не устань,
Я вернусь с победой снова на Кубань!
Э-эх, думать не устань,
Я вернусь с победой снова на Кубань!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Пишет мне казачка - чёрные глаза...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b123d0532ee1d0a1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b123d0532ee1d0a1','Кубанская походная','Пишет мне казачка&nbsp;- чёрные глаза,
