INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_680a4d44dc6b2f6d','Лебединая песнь',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Мария Пуаре) | Старинные романсы | https://pesni.retroportal.ru/sr2/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я грущу. Если можешь понять
Мою душу, доверчиво нежную,
Приходи ты со мной попенять
На судьбу мою, странно мятежную.
Мне не спится в тоске по ночам,
Думы мрачные сон отгоняют,
И горючие слёзы невольно к очам,
Как в прибое волна, приливают.
Как-то странно и дико мне жить без тебя,
Сердце лаской любви не согрето;
Иль мне правду сказали, что будто моя
Лебединая песня пропета.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_680a4d44dc6b2f6d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_680a4d44dc6b2f6d','Лебединая песнь','Я грущу. Если можешь понять
Мою душу, доверчиво нежную,
Приходи ты со мной попенять
На судьбу мою, странно мятежную.
Мне не спится в тоске по ночам,
Думы мрачные сон отгоняют,
И горючие слёзы невольно к очам,
Как в прибое волна, приливают.
Как-то странно и дико мне жить без тебя,
Сердце лаской любви не согрето;
Иль мне правду сказали, что будто моя
Лебединая песня пропета.');
