INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_afcccb9a76a00885','Летел голубь',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np1/41.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Летел голубь, летел голубь со голубицею,
Гулял молодец с красной девицею.
Гулял молодец с красной девицею;
&laquo;Как бы этому ты молодцу голубицей была,
Как бы этому ты молодцу голубицей была,
Кабы ты, красна девица, в моём тереме жила.
Кабы ты, красна девица, в моём тереме жила,
В моём тереме жила, мне невестой была&raquo;.
&laquo;В твоём тереме жила да невестой была?&raquo;
&laquo;Я бы золотом украсил, жемчугами уделил!&raquo;
&laquo;Ты бы золотом украсил, жемчугами уделил?&raquo;
&laquo;Я бы летом в платье в этом на коляске стал катать!&raquo;
&laquo;Ты бы летом в платье в этом на коляске стал катать?&raquo;
&laquo;Я бы зимнею порою на лаковых санях!&raquo;
&laquo;Ты бы зимнею порою на лаковых санях?&raquo;
&laquo;На лаковых санях и на паре-лошадях!&raquo;
Летел голубь, летел голубь со голубицею,
Гулял молодец с красной девицею.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_afcccb9a76a00885'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_afcccb9a76a00885','Летел голубь','Летел голубь, летел голубь со голубицею,
