INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_afcccb9a76a00885_dc912ac00bb1e752','rpp_afcccb9a76a00885','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/41.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3adf3ee48b8182fe','Летите, голуби','(«Летите, голуби, летите, для вас нигде преграды нет...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/letite_golubi.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Летите, голуби, летите, для вас нигде преграды нет...») | merged_versions: 1','Летите, голуби, летите,
Для вас нигде преграды нет!
Несите, голуби, несите
Народам мира наш привет!
Пусть над землёю ветер стонет,
Пусть в чёрных тучах небосвод,&nbsp;-
В пути вас коршун не догонит,
С пути вас буря не собьёт.
Во имя счастья и свободы,
Летите, голуби, вперёд!
Глядят с надеждою народы
На ваш стремительный полёт.
Летите, голуби, летите,
В лучах зари и в грозной мгле,
Зовите, голуби, зовите
К труду и миру на земле!','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Летите, голуби, летите, для вас нигде преграды нет...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3adf3ee48b8182fe'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3adf3ee48b8182fe','Летите, голуби','Летите, голуби, летите,
