INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f296e9ca5718a358','Летят утки',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Летят утки, летят утки и два гуся.
Ох, кого люблю, кого люблю – не дождуся.
Я влюбилась, я влюбилась, молодая.
Ох, знать, судьба, знать, судьба моя такая.
Мил уехал, мил уехал за Воронеж.
Ох, теперь его, теперь его не воротишь.
Когда, милый, когда, милый, бросать станешь,
Ох, не рассказы... не рассказывай, что знаешь.
Ох, как трудно, ох, как трудно расстаются –
Ох, глазки смотрят, глазки смотрят, слЁзы льются.
Цветёт колос, цветёт колос, к земле клонит,
Ох, по милому, по милому сердце ноет.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f296e9ca5718a358'), datetime('now')),datetime('now'));
