INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_850791045f05526f','Лизавета','(«Ты ждёшь, Лизавета, от друга привета...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Никита Богословский) | Песни военных лет | https://pesni.retroportal.ru/vov/lizaveta.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Ты ждёшь, Лизавета, от друга привета...») | merged_versions: 1','Ты ждёшь, Лизавета,
От друга привета,
Ты не спишь до рассвета,
Всё грустишь обо мне.
Одержим победу,
К тебе я приеду
На горячем вороном коне.
Приеду весною,
Ворота открою.
Я с тобой, ты со мною
Неразлучны вовек.
В тоске и тревоге
Не стой на пороге,
Я вернусь, когда растает снег.
Моя дорогая,
Я жду и мечтаю,
Улыбнись мне, встречая,
Был я в храбром бою.
Эх, как бы дожить бы
До свадьбы-женитьбы
И обнять любимую свою!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Ты ждёшь, Лизавета, от друга привета...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_850791045f05526f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_850791045f05526f','Лизавета','Ты ждёшь, Лизавета,
