INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f21a9db9912a85d5','Лирическая песенка','(Песня из кинофильма «Сердца четырёх»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Юрий Милютин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/liricheskaya_pesenka_serdca_chetyreh.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из кинофильма «Сердца четырёх») | merged_versions: 1','Всё стало вокруг голубым и зелёным,
В ручьях зажурчала, запела вода.
Вся жизнь потекла по весенним законам -
Теперь от любви не уйти никуда...
Любовь от себя никого не отпустит.
Под каждым окошком поют соловьи.
Любовь никогда не бывает буз грусти,
И это приятней, чем грусть буз любви...','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из кинофильма «Сердца четырёх»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f21a9db9912a85d5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f21a9db9912a85d5','Лирическая песенка','Всё стало вокруг голубым и зелёным,
В ручьях зажурчала, запела вода.
Вся жизнь потекла по весенним законам -
Теперь от любви не уйти никуда...
Любовь от себя никого не отпустит.
Под каждым окошком поют соловьи.
Любовь никогда не бывает буз грусти,
И это приятней, чем грусть буз любви...');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_f21a9db9912a85d5_e2e5aa3a9ed3957d','rpp_f21a9db9912a85d5','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/liricheskaya_pesenka_serdca_chetyreh.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b37ad92b23c33602','Лирические припевки',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ах, запевай, подружка, песню,
Запевай котору хошь,
А про любовь только не надо, -
Моё сердце не тревожь.
А про любовь только не надо, -
Моё сердце не тревожь.
Ах, балалаечка играет, -
Слышу, дроля мой идёт,
А моё сердце замирает –
Про меня песни поёт.
А моё сердце замирает –
Про меня песни поёт.
Ах, только в доме украшенье,
Когда солнышко взойдёт.
А только сердцу утешенье,
Когда дролечка придёт.
А только сердцу утешенье,
Когда дролечка придёт.
Ах, два знакомые крылечка
В памяти осталися:
А на одном крыльце влюблялись,
На другом рассталися.
А на одном крыльце влюблялись,
На другом рассталися.
Ах, дорогой, такая сила
Одолела вдруг меня:
А сколько было – всех забыла,
Не могу забыть тебя!
А сколько было – всех забыла,
Не могу забыть тебя!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b37ad92b23c33602'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b37ad92b23c33602','Лирические припевки','Ах, запевай, подружка, песню,
