INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b37ad92b23c33602_183041a472230550','rpp_b37ad92b23c33602','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/02.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_41bcb0bd6aac13c7','Лихая артиллерийская','(«То не буря, то не молния, не гром...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Виктор Гусев, музыка: Тихон Хренников) | Песни военных лет | https://pesni.retroportal.ru/vov/lihaya_artillerijskaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («То не буря, то не молния, не гром...») | merged_versions: 1','То не буря, то не молния, не гром&nbsp;-
Это мы огонь по ворогам ведём,
Улыбаются родимые леса,
Эх, эх, как приятно слышать ваши голоса!
Окликают реки радостные нас,
Ну-ка всыпьте им, ребята, ещё раз,
Артиллерия родимая гремит,
Эх, эх, недаром поговорка говорит:
Припев:
Хорошо служить в пехоте,
Эх, хорошо!
Лучше в кавалерии,
А всего приятней, братцы,
Это - в артиллерии!
Где ребята молодцы как на подбор?
У кого с врагом короткий разговор?
В артиллерии ребята удальцы,
Эх, в артиллерии солдаты храбрецы.
Сам Суворов наше мужество хвалил,
В бой Кутузов за Отечество водил,
Мы громили неприятеля не раз,
Эх, эх, ведь недаром поговрка есть у нас!
Припев
Мы закончили с победою войну
И вернулися в родную сторону,
Нас девчата повстречали у ворот:
&laquo;Эх, ну, ребята, расскажите про поход!&raquo;
Чтоб, девчата, пушки нас не подвели&nbsp;-
По Берлину мы из них огонь вели,
И громя врага в решительном бою
Эх, эх, повторяли поговорку мы свою!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«То не буря, то не молния, не гром...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_41bcb0bd6aac13c7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_41bcb0bd6aac13c7','Лихая артиллерийская','То не буря, то не молния, не гром&nbsp;-
Это мы огонь по ворогам ведём,
Улыбаются родимые леса,
Эх, эх, как приятно слышать ваши голоса!
Окликают реки радостные нас,
Ну-ка всыпьте им, ребята, ещё раз,
Артиллерия родимая гремит,
Эх, эх, недаром поговорка говорит:
Припев:
Хорошо служить в пехоте,
Эх, хорошо!
Лучше в кавалерии,
А всего приятней, братцы,
Это - в артиллерии!
Где ребята молодцы как на подбор?
У кого с врагом короткий разговор?
В артиллерии ребята удальцы,
Эх, в артиллерии солдаты храбрецы.
Сам Суворов наше мужество хвалил,
В бой Кутузов за Отечество водил,
Мы громили неприятеля не раз,
Эх, эх, ведь недаром поговрка есть у нас!
Припев
Мы закончили с победою войну
И вернулися в родную сторону,
Нас девчата повстречали у ворот:
&laquo;Эх, ну, ребята, расскажите про поход!&raquo;
Чтоб, девчата, пушки нас не подвели&nbsp;-
По Берлину мы из них огонь вели,
И громя врага в решительном бою
Эх, эх, повторяли поговорку мы свою!
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_41bcb0bd6aac13c7_961ad59f62a6c2a4','rpp_41bcb0bd6aac13c7','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/lihaya_artillerijskaya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c2dc2ed3f88519b4','Лодочка','(Песня из фильма «Верные друзья»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Тихон Хренников) | Эстрадные песни | https://pesni.retroportal.ru/estrada/pesnya_lodochka_film_vernye_druzya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из фильма «Верные друзья») | merged_versions: 1','Берёзы подмосковные
Шумели вдалеке.
Плыла-качалась лодочка
По Яузе-реке.
Мы плыли по течению
Сторонкою родной,
И вместе тесно не было
Нам в лодочке одной.
От вёсел вдоль по Яузе
Струился светлый след.
С тех пор, друзья-товарищи,
Прошло немало лет.
Давно уж мы разъехались
Во все концы страны,
Но дружбе мы по-старому,
По-прежнему верны.
Над нами небо Родины,
И так светло кругом,
Как будто мы на лодочке,
Как в юности, плывём.
И путь наш не кончается,
Простор речной широк:
И гонит, гонит лодочку
Попутный ветерок.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из фильма «Верные друзья»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c2dc2ed3f88519b4'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c2dc2ed3f88519b4','Лодочка','Берёзы подмосковные
