INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3b464e1f3252d659','Лучинушка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/03.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Лучина, лучинушка березовая!
Что же ты, лучинушка, не ясно горишь?
А мне, молодёшеньке, ох, всю ночку не спать,
Всю ночку не спать, младой постелюшку стлать.
Постелюшку стлать-то мне, мила друга ждать.
Первый сон заснула я – мила друга нет.
Другой сон заснула я – ох, сердечного нет,
Третий сон заснула я – заря&nbsp;– белый свет!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3b464e1f3252d659'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3b464e1f3252d659','Лучинушка','Лучина, лучинушка березовая!
Что же ты, лучинушка, не ясно горишь?
А мне, молодёшеньке, ох, всю ночку не спать,
