INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1a6ad9a09246b091','Любимый город','(Песня из кинофильма «Истребители»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Никита Богословский) | Патриотические песни | https://pesni.retroportal.ru/rodina/lyubimy_gorod.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из кинофильма «Истребители») | merged_versions: 1','В далёкий край товарищ улетает,
Родные ветры вслед за ним летят.
Любимый город в синей дымке тает,
Знакомый дом, зелёный сад и нежный взгляд.
Пройдёт товарищ все бои и войны,
Не зная сна, не зная тишины.
Любимый город может спать спокойно,
И видеть сны, и зеленеть среди весны.
Когда ж домой товарищ мой вернётся,
За ним родные ветры прилетят,
Любимый город другу улыбнётся,
Знакомый дом, зелёный сад, весёлый взгляд.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из кинофильма «Истребители»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1a6ad9a09246b091'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1a6ad9a09246b091','Любимый город','В далёкий край товарищ улетает,
Родные ветры вслед за ним летят.
Любимый город в синей дымке тает,
