INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_65271e9135c27d2a','Маленькой ёлочке холодно зимой','(Новогодняя песня «Ёлочка»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Зоя Александрова, музыка: Михаил Карасёв) | Песни для детей | https://pesni.retroportal.ru/deti/malenkoj_elochke_holodno_zimoj.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Новогодняя песня «Ёлочка») | merged_versions: 1','Маленькой ёлочке
Холодно зимой,
Из лесу ёлочку
Взяли мы домой.
Беленький заинька
Елочку просил:
&laquo;Мятного пряничка
Зайке принеси!&raquo;
Белочка прыгала
В шубке голубой:
&laquo;Ёлочка, ёлочка,
Я пойду с тобой!&raquo;
Маленькой ёлочке
В комнатах тепло,
Заяц и белочка
Дышат на стекло.
Красные зяблики
Вьются у окна,
В теплой проталинке
Ёлочка видна.
Сколько на ёлочке
Шариков цветных,
Розовых пряников,
Шишек золотых!
Сколько под ёлочкой
Маленьких ребят!
Топают, хлопают,
Весело кричат:
&laquo;Ёлочка, ёлочка,
Яркие огни,
Синими бусами,
Ёлочка, звени,
Ветку нарядную
Ниже опусти,
Нас шоколадною
Рыбкой угости!
Встанем под ёлочкой
В дружный хоровод.
Весело, весело
Встретим Новый год!&raquo;','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Новогодняя песня «Ёлочка»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_65271e9135c27d2a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_65271e9135c27d2a','Маленькой ёлочке холодно зимой','Маленькой ёлочке
