INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8aabf74a52f3fcde','Малиновка','(«Малиновки заслыша голосок...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Поперечный, музыка: Эдуард Ханок) | Эстрадные песни | https://pesni.retroportal.ru/estrada/malinovki_zaslysha_golosok.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Малиновки заслыша голосок...») | merged_versions: 1','Малиновки заслыша голосок,
Припомню я забытые свиданья,
В три жёрдочки берёзовый мосток
Над тихою речушкой без названья.
Припев:
Прошу тебя, в час розовый
Напой тихонько мне,
Как дорог край берёзовый
В малиновой заре.
А волны шли неведомо куда
И камушки у берега качали,
И пела нам малиновка тогда
О том, о чём напрасно мы молчали.
Припев
Сожжён мосток, ушла из сердца боль,
Исчезла речка, вдаль умчалась юность.
Но песня, словно первая любовь,
Малиновкой опять ко мне вернулась.
Припев
Слушать песню &laquo;Малиновка&raquo; композитора Эдуарда Ханка на стихи Анатолия Поперечного в исполнении белорусского  ВИА &laquo;Верасы&raquo; .','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Малиновки заслыша голосок...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8aabf74a52f3fcde'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8aabf74a52f3fcde','Малиновка','Малиновки заслыша голосок,
