INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_8aabf74a52f3fcde_33cb6cc89bb59c61','rpp_8aabf74a52f3fcde','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/malinovki_zaslysha_golosok.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b4a5736023c903f6','Малиновый звон','(«Сквозь полудрёму и сон слышу малиновый звон...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Поперечный, музыка: Александр Морозов) | Патриотические песни | https://pesni.retroportal.ru/rodina/malinovy_zvon.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Сквозь полудрёму и сон слышу малиновый звон...») | merged_versions: 1','Сквозь полудрёму и сон
Слышу малиновый звон...
Это&nbsp;- рассвета гонцы&nbsp;-
В травах звенят бубенцы;
Это&nbsp;- средь русских равнин
Вспыхнули гроздья рябин;
Это&nbsp;- в  родимой глуши
Что-то коснулось  души.
Припев:
Малиновый звон на заре...
Скажи своей милой земле,
Что я в нее с детства влюблён,
Как в этот малиновый звон.
Этот малиновый звон
От материнских окон,
От той высокой звезды
Да от минувшей беды...
Пыльный затеплится шлях,
Где мы бродили в полях,
Где на заре как сквозь сон
Слышен малиновый звон.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Сквозь полудрёму и сон слышу малиновый звон...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b4a5736023c903f6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b4a5736023c903f6','Малиновый звон','Сквозь полудрёму и сон
