INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bed845f109e9eb38','Марш артиллеристов','(«Артиллеристы, Сталин дал приказ!..»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Виктор Гусев, музыка: Тихон Хренников) | Песни военных лет | https://pesni.retroportal.ru/vov/marsh_artilleristov.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Артиллеристы, Сталин дал приказ!..») | merged_versions: 1','Горит в сердцах у нас любовь к земле родимой,
Мы в смертный бой идём за честь родной страны.
Пылают города, охваченные дымом,
Гремит в седых лесах суровый бог войны.
Припев:
Артиллеристы, Сталин дал приказ!
Артиллеристы, зовёт Отчизна нас!
Из тысяч грозных батарей
За слёзы наших матерей,
За нашу Родину&nbsp;- огонь! Огонь!
Узнай, родная мать, узнай, жена-подруга,
Узнай, далёкий дом и вся моя семья,
Что бьёт и жжёт врага стальная наша вьюга,
Что волю мы несём в родимые края.
Припев
Пробьёт победы час, придёт конец похода,
Но прежде, чем уйти к домам своим родным,
В честь нашего вождя, в честь нашего народа
Мы радостный салют в полночный час дадим.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Артиллеристы, Сталин дал приказ!..»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bed845f109e9eb38'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bed845f109e9eb38','Марш артиллеристов','Горит в сердцах у нас любовь к земле родимой,
