INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2f9e1388d79f0a1d','Марш весёлых ребят','(Из кинофильма «Весёлые ребята»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/marsh_veselyh_rebyat.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Из кинофильма «Весёлые ребята») | merged_versions: 1','Легко на сердце от песни весёлой,
Она скучать не даёт никогда.
И любят песни деревни и сёла,
И любят песни большие города.
Нам песня строить и жить помогает,
Она как друг и зовёт и ведёт.
И тот, кто с песней по жизни шагает,
Тот никогда и нигде не пропадёт!
Мы можем петь и смеяться, как дети
Среди упорной борьбы и труда,
Ведь мы такими родились на свете,
Что не сдаёмся нигде и никогда.
Нам песня строить и жить помогает,
Она как друг, и зовёт и ведёт.
И тот, кто с песней по жизни шагает,
Тот никогда и нигде не пропадёт!','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Из кинофильма «Весёлые ребята»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2f9e1388d79f0a1d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_2f9e1388d79f0a1d','Марш весёлых ребят','Легко на сердце от песни весёлой,
