INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4f39f6ffc9ddf5a1','Марш защитников Москвы','(«Мы не дрогнем в бою за столицу свою...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Алексей Сурков, музыка: Борис Мокроусов) | Песни военных лет | https://pesni.retroportal.ru/vov/marsh_zashitnikov_moskvy.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Мы не дрогнем в бою за столицу свою...») | merged_versions: 1','В атаку стальными рядами
Мы поступью твердой идём.
Родная столица за нами,
Рубеж наш назначен Вождём.
Припев:
Мы не дрогнем в бою за столицу свою,
Нам родная Москва дорога.
Нерушимой стеной, обороной стальной
Разгромим, уничтожим врага!
На марше равняются взводы
Гудит под ногами земля,
За нами родные заводы
И красные звёзды Кремля.
Припев
Для счастья своими руками
Мы строили город родной.
За каждый расколотый камень
Отплатим мы страшной ценой.
Припев
Не смять богатырскую силу,
Могуч наш заслон огневой.
Мы выроем немцу могилу
В туманных полях под Москвой.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Мы не дрогнем в бою за столицу свою...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4f39f6ffc9ddf5a1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4f39f6ffc9ddf5a1','Марш защитников Москвы','В атаку стальными рядами
