INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_054b004f7a6dc043','Матушка, голубушка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: С. Ниркомский, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr2/04.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Матушка, голубушка, солнышко моё!
Пожалей, родимая, дитятко твоё!
Словно змея лютая сердце мне сосёт
И целую ноченьку спать мне не даёт.
Всё мне что-то грезится, будто наяву,
Спать когда ложуся я, молитву творю.
То залётной пташечкой песенка слышна:
Сердце замирает, - так сладка она!
Что это, родимушка, сталося со мной?
Видно, приключился мне злой недуг какой?
Али нет, родимая, чем мне пособить?
- Знать, приспело, дитятко, времечко любить!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_054b004f7a6dc043'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_054b004f7a6dc043','Матушка, голубушка','Матушка, голубушка, солнышко моё!
