INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d80e80131c96a585','Матушка, что во поле пыльно',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/04.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','- Матушка, матушка, что во поле пыльно?
Сударыня матушка, что во поле пыльно?
- Дитятко милое, кони разыгралися.
- Матушка, матушка, на двор гости едут,
Сударыня матушка, на двор гости едут!..
- Дитятко милое, я тебя не выдам!
- Матушка, матушка, на крылечко идут,
Сударыня матушка, на крылечко идут!..
- Дитятко милое, не бойсь, не пужайся...
- Матушка, матушка, в нову горницу идут,
Сударыня матушка, в нову горницу идут!..
- Дитятко милое, я тебя не выдам!
- Матушка, матушка, за столы садятся,
Сударыня матушка, за столы садятся!
- Дитятко милое, не бойсь, не пужайся!
- Матушка, матушка, образа снимают,
Сударыня матушка... Меня благословляют...
- Дитятко милое, господь с тобою!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d80e80131c96a585'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d80e80131c96a585','Матушка, что во поле пыльно','- Матушка, матушка, что во поле пыльно?
