INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d80e80131c96a585_3ba728930f167805','rpp_d80e80131c96a585','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/04.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2b39effb947caecd','«Медовый, аметистовый» («Аметистовый медовый»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Константин Подревский, музыка: Валентин Кручинин) | Старинные романсы | https://pesni.retroportal.ru/sr2/05.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Зачем насмешкою ответил, обидел, ласку не ценя?
Да разве без тебя на свете друзей не будет у меня?
Дела нет мне до такого, до речистого...
Был бы сахарный, медовый, аметистовый,
Да в душе пожара нет, потухло зарево! Эх!
Пой, звени, моя гитара, разговаривай!
Пой, звени, моя гитара, разговаривай!
Ты раньше был родней родного, дороже, чем отец и мать...
Пришлось как недруга лихого тебя от сердца оторвать.
Припев
Прощай, иди своей дорогой, грустить не буду, так и знай!
Ты только прошлого не трогай да лихом зря не вспоминай!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2b39effb947caecd'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_2b39effb947caecd','«Медовый, аметистовый» («Аметистовый медовый»)','Зачем насмешкою ответил, обидел, ласку не ценя?
