INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_2b39effb947caecd_b4cb8d347bf7a801','rpp_2b39effb947caecd','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/05.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3a6e26c06c967a3d','Меж высоких хлебов',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Некрасов) | Народные песни | https://pesni.retroportal.ru/np2/05.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Меж высоких хлебов затерялося
Небогатое наше село.
Горе горькое по свету шлялося
И на нас невзначай набрело.
Ой, беда приключилася страшная!
Мы такой незнавали вовек:
Как у нас, голова бесшабашная –
Застрелился чужой человек!
Суд приехал... допросы... тошнёхонько!
Догадались деньжонок собрать:
Осмотрел его лекарь скорёхонько
И велел где-нибудь закопать.
Меж двумя хлебородными нивами,
Где прошёл неширокий долок,
Под большими плакучими ивами
Успокоился бедный стрелок.
Будут песни к нему хороводные
Из села на заре долетать,
Будут нивы ему хлебородные
Безгреховные сны навевать.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3a6e26c06c967a3d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3a6e26c06c967a3d','Меж высоких хлебов','Меж высоких хлебов затерялося
