INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_3a6e26c06c967a3d_f82b606fecc791a7','rpp_3a6e26c06c967a3d','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/05.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_13fe7a265353fb95','Меж крутых бережков',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Матвей Ожегов) | Народные песни | https://pesni.retroportal.ru/np2/06.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Меж крутых бережков Волга-речка течёт,
А на ней по волнам лёгка лодка плывёт.
В ней сидит молодец, шапка с кистью на нём,
Он, с верёвкой в руках, волны резал веслом.
Он ко бережку плыл, лодку вмиг привязал,
Сам на берег взошёл, соловьём просвистал.
А на береге том высок терем стоял.
В нём красотка жила, он её вызывал.
Одинока она – растворила окно,
Приняла молодца по верёвке умно.
Ночку всю пировал с ненаглядной душой,
Утром рано с зарёй возвращался домой.
Муж красавицы был воевода лихой,
Молодца повстречал он в саду над рекой.
Долго бились они на крутом берегу,
Не хотел уступить воевода врагу.
Но последний удар их судьбу порешил
И конец их вражде навсегда положил...
Волга в волны свои молодца приняла,
По реке, по волнам шапка с кистью плыла.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_13fe7a265353fb95'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_13fe7a265353fb95','Меж крутых бережков','Меж крутых бережков Волга-речка течёт,
