INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_13fe7a265353fb95_4b29242f6bd3ef62','rpp_13fe7a265353fb95','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/06.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_789a51ca997a2159','Меня ты вовсе не любила',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: А.Николаев, музыка: Д.Николаев) | Старинные романсы | https://pesni.retroportal.ru/sr2/06.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Меня ты вовсе не любила,
Я был тебе чужой;
Зачем же ты меня губила,
Зачем смеялась надо мной?
Хотя в порывах озлобленья
Порой тебе проклятья шлю
За бесконечные мученья,
Но всё же я тебя люблю!
Без всяких чувств, играя страстью,
Меня ты увлекла;
Сама меня манила к счастью
И дать его мне не могла.
Я не достоин сожалений,
Я в жизни сам себя гублю,
Ты злой мой дух, ты злой мой гений,
Но всё же я тебя люблю!
Я в жизни всё, ты это знаешь,
Принёс к твоим ногам,
Чего же ты ещё желаешь?
Быть может, жизнь, - так я отдам.
Я перенёс все муки ада.
Я их теперь ещё терплю;
Тебя мне ненавидеть надо,
А я, безумец, всё люблю!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_789a51ca997a2159'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_789a51ca997a2159','Меня ты вовсе не любила','Меня ты вовсе не любила,
