INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_789a51ca997a2159_2164d042263d0089','rpp_789a51ca997a2159','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/06.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_148c59e4d5757a6f','Месяц на небе',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (украинская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/08.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вариант I
Мисяць на нэби, зироньки сияють,
Тихо по морю човен плывэ.
В човне дивчина письню спивае,
А козак чуе, серденько мре.
Письня та мыла, письня та люба,
Все прокоханья, все про любовь,
Як мы любились та й разишлися,
Теперь зийшлися навики знов.
Ой очи, очи, очи дивочи,
Тэмни, ак ничка, ясни, ак дэнь.
Вы ж мэни, очи Вик вкоротили,
Дэж вы навчилысь зводыт людей?
Вариант II
Місяць на небі, зіроньки сяють,
Тихо по морю човен пливе
В човні дівчина пісню співає,
А козак чує серденько мре.
Ця пісня мила, ця пісня люба,
Всё про кохання, всё про любов,
Як ми любились тай розійшлися,
Тепер навіки зійшлися знов.
Ой очі, очі, очі дівочі,
Темні як нічка, ясні як день.
Ви ж мене очі плакать навчили,
Де ж ви навчились зводить людей.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_148c59e4d5757a6f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_148c59e4d5757a6f','Месяц на небе','Вариант I
