INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_148c59e4d5757a6f_8f064b72ed6b128f','rpp_148c59e4d5757a6f','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/08.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_158853916fdbf79b','Милая, ты услышь меня',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Гердель, музыка: Эмиль Вальдтейфель) | Старинные романсы | https://pesni.retroportal.ru/sr2/07.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Милая,
Ты услышь меня,
Под окном стою
Я с гитарою!
Так взгляни ж на меня
Хоть один только раз,
Ярче майского дня
Чудный блеск твоих глаз!
Ночь тиха была,
Соловьи поют,
Чудный запах роз
Всюду носится...
Припев
Мы гуляем с тобой,
Луна светит на нас
И в лазурной воде
Отражается!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_158853916fdbf79b'), datetime('now')),datetime('now'));
