INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_39e884b5f639a10c','Миленький ты мой',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | Народные песни | https://pesni.retroportal.ru/np2/07.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','(русский народный романс)
- Миленький ты мой,
Возьми меня с собой!
Там, в краю далёком,
Буду тебе женой.
- Милая моя,
Взял бы я тебя,
Но там, в краю далёком,
Есть у меня жена.
- Миленький ты мой,
Возьми меня с собой!
Там, в краю далёком,
Буду тебе сестрой.
- Милая моя,
Взял бы я тебя.
Но там, в краю далёком,
Есть у меня сестра.
- Миленький ты мой,
Возьми меня с собой!
Там в краю далёком,
Буду тебе чужой.
- Милая моя,
Взял бы я тебя.
Но там, в краю далёком,
Чужая ты мне не нужна.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_39e884b5f639a10c'), datetime('now')),datetime('now'));
