- Миленький ты мой,
Возьми меня с собой!
Там в краю далёком,
Буду тебе чужой.
- Милая моя,
Взял бы я тебя.
Но там, в краю далёком,
Чужая ты мне не нужна.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_39e884b5f639a10c_278a8c6d1ef3b575','rpp_39e884b5f639a10c','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/07.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f61c35682b11c368','Мне всё равно',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Фёдор Миллер, музыка: Александр Даргомыжский) | Старинные романсы | https://pesni.retroportal.ru/sr2/08.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Мне всё равно, страдать иль наслаждаться,
К страданьям я привыкла уж давно,
Готова плакать и смеяться,
Мне всё равно!
Мне всё равно, враги ли мне найдутся,
Я к клеветам привыкла уж давно.
Пускай бранят, пускай смеются,
Мне всё равно!
Мне всё равно, сердечная ли награда,
Любовь забыта мной давно,
Меня не любят? И не надо!
Мне всё равно!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f61c35682b11c368'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f61c35682b11c368','Мне всё равно','Мне всё равно, страдать иль наслаждаться,
