INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_f61c35682b11c368_1bec72badd528d1c','rpp_f61c35682b11c368','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/08.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_419709ca0301c179','Моё мимолётное счастье',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Владимир Гончаров) | Старинные романсы | https://pesni.retroportal.ru/sr4/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Моё мимолётное счастье,
Мой друг, мой подарок судьбы!
Чарующий сон в дни ненастья,
Мой мир, воплотивший мечты!
Как больно с тобой расставаться,
Как сладко надеждою жить...
Как трудно в тебя не влюбляться
И горько тебя не любить!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_419709ca0301c179'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_419709ca0301c179','Моё мимолётное счастье','Моё мимолётное счастье,
