INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6f038b7a42b2059c','Мой Вася','(«Весенний цвет легко роняет липа...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Георгий Ходосов, музыка: Оскар Фельцман) | Эстрадные песни | https://pesni.retroportal.ru/estrada/moj_vasya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Весенний цвет легко роняет липа...») | merged_versions: 1','Весенний цвет легко роняет липа.
За ним к тебе летят мои мечты.
В кино смотрела я вчера Жерар Филиппа,
А всё казалось мне, что это ты,
Мой Вася!
Как нежный плеск весёлого фонтана,
Любимый голос песенки хорош.
И если слушала я даже Ив Монтана,
То мне казалось, это ты поёшь,
Мой Вася!
Свистит судья&nbsp;– и вновь кипит работа,
Футболки запестрели, как цветы.
И если сходу гол забил Ильин в ворота,
То мне казалось, это сделал ты,
Мой Вася!
С тобою хорошо при лунном свете
Мечтать о недалёком ясном дне,
Когда начнутся путешествия в ракете,
То самым первым будет на Луне
Мой Вася!
Он первым будет даже на Луне!','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Весенний цвет легко роняет липа...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6f038b7a42b2059c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6f038b7a42b2059c','Мой Вася','Весенний цвет легко роняет липа.
За ним к тебе летят мои мечты.
В кино смотрела я вчера Жерар Филиппа,
А всё казалось мне, что это ты,
Мой Вася!
Как нежный плеск весёлого фонтана,
Любимый голос песенки хорош.
И если слушала я даже Ив Монтана,
То мне казалось, это ты поёшь,
Мой Вася!
Свистит судья&nbsp;– и вновь кипит работа,
Футболки запестрели, как цветы.
И если сходу гол забил Ильин в ворота,
То мне казалось, это сделал ты,
Мой Вася!
С тобою хорошо при лунном свете
Мечтать о недалёком ясном дне,
Когда начнутся путешествия в ракете,
То самым первым будет на Луне
Мой Вася!
Он первым будет даже на Луне!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6f038b7a42b2059c_4d05d81e13521de4','rpp_6f038b7a42b2059c','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/moj_vasya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5d4dc9e6c79d5e0b','Мой костёр в тумане светит',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Яков Полонский, музыка: Фёдор Садовский) | Старинные романсы | https://pesni.retroportal.ru/sr2/09.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Мой костёр в тумане светит,
Искры гаснут на лету...
Ночью нас никто не встретит,
Мы простимся на мосту.
Ночь пройдёт, и спозаранок
В степь далёко, милый мой,
Я уйду с толпой цыганок
За кибиткой кочевой.
На прощанье шаль с каймою
Ты на мне узлом стяни!
Как концы её, с тобою
Мы сходились в эти дни.
Кто-то мне судьбу предскажет?
Кто-то завтра, сокол мой,
На груди моей развяжет
Узел, стянутый тобой?
Вспоминай, коли другая,
Друга милого любя,
Будет песни петь, играя
На коленях у тебя!
Мой костёр в тумане светит,
Искры гаснут на лету...
Ночью нас никто не встретит,
Мы простимся на мосту.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5d4dc9e6c79d5e0b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5d4dc9e6c79d5e0b','Мой костёр в тумане светит','Мой костёр в тумане светит,
