INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_47d92572fa0c9127','Мой милый друг, ты хочешь знать',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Э. Орлова, музыка: Г. Гофман) | Старинные романсы | https://pesni.retroportal.ru/sr2/10.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Мой милый друг, ты хочешь знать:
Люблю ли иль тобою лишь играю?
Не знаю я, что отвечать,
Ведь, право, я сама того не знаю.
Сказать тебе иль не сказать?
Но нет, нет, нет, я тайну не открою!
Старайся сам всё разгадать,
Напрасно не терзайся ты душою.
Одно запомни навсегда:
Не требуй от меня ты объяснений.
Люблю похохотать, всегда я весела
И не терплю ни вздохов, ни волнений.
Зачем страдать? Зачем вздыхать?
Не лучше ли веселью предаваться?
Я не люблю в тиши мечтать,
Свободою хочу я наслаждаться.
Бери же всё, что даст судьба,
Никто не может ей сопротивляться.
Ведь наша жизнь так коротка...
Так стоит ли тужить и волноваться?
Одно запомни навсегда:
Не требуй от меня ты объяснений.
Люблю похохотать, всегда я весела
И не терплю ни вздохов, ни волнений.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_47d92572fa0c9127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_47d92572fa0c9127','Мой милый друг, ты хочешь знать','Мой милый друг, ты хочешь знать:
