INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f3ad7e67c1f981f5','Мой муж молодой',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/09.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Мой муж молодой работяга был,
Работяга, тяга, тяга, работяга был.
А я, молода, не ленива была,
Не ленива, не ленива, расторопливая.
Он поехал пахать, позабыл пахало,
Позабыл, позабыл, позабыл пахало.
Я взяла пахало и за ним побежала,
Всё за ним, всё за ним, всё за ним побежала.
Он поехал боронить, позабыл боронку,
Позабыл, позабыл, позабыл боронку.
Я взяла боронку да за ним вдогонку,
Всё за ним, всё за ним, всё за ним вдогонку.
Он поехал сеять, позабыл лукошко,
Позабыл, позабыл, позабыл лукошко.
Я взяла лукошко да за ним в окошко,
Всё за ним, всё за ним, всё за ним в окошко.
Мой муж молодой работяга был,
Работяга, тяга, тяга, работяга был.
А я, молода, не ленива была,
Не ленива, не ленива, расторопливая.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f3ad7e67c1f981f5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f3ad7e67c1f981f5','Мой муж молодой','Мой муж молодой работяга был,
Работяга, тяга, тяга, работяга был.
