INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e00be21cdff07501','Молчи, грусть, молчи...',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Д''Актиль ⁄ Анатолий Френкель ⁄, музыка: Григорий Березовский) | Старинные романсы | https://pesni.retroportal.ru/sr2/11.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Тоска, печаль, надежды ушли,
Друга нет, неприветно вокруг;
В ночной тишине я слышу рыданья –
Стон души о разбитой любви...
Молчи, грусть, молчи!
Не тронь старых ран,
Сказки любви дорогой
Не вернуть никогда, никогда.
Уснуть навек, забыться скорей,
Незаметно уйти от всего,
Жизнь шуткой была жестокой и злою,
Расставаться мне с нею не жаль.
Молчи, грусть, молчи!
Не тронь старых ран,
Сказки любви дорогой
Не вернуть никогда, никогда.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e00be21cdff07501'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e00be21cdff07501','Молчи, грусть, молчи...','Тоска, печаль, надежды ушли,
