Не вернуть никогда, никогда.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_e00be21cdff07501_806222c0c4e11d20','rpp_e00be21cdff07501','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/11.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7ce1fdb38df3a003','Морская гвардия','(«Морская гвардия идёт уверенно...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Юрий Милютин) | Песни военных лет | https://pesni.retroportal.ru/vov/morskaya_gvardiya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Морская гвардия идёт уверенно...») | merged_versions: 1','Родных кораблей патриоты
Со львиной отвагой в груди&nbsp;-
Гвардейцы советского флота
Всегда и везде впереди.
Припев:
Морская гвардия идёт уверенно,
Любой опасности глядит она в глаза.
В боях испытана, в огне проверена,
Морская гвардия&nbsp;- для недругов гроза!
Гвардейцы воюют на юге
И возле полярных широт,
Не страшны им штормы и вьюги,
Не страшен им дальний поход.
Припев
Гвардейцы в сердцах начертали
Короткое слово: вперёд!
Растил их героями Сталин,
И Сталин к победе ведёт.
Припев
Сквозь минное поле пробьются,
Пройдут сквозь огонь батарей,
Повсюду победы добьются
Герои&nbsp;- гвардейцы морей.
Припев
Взовьётся гвардейское знамя,
И гордо расскажет оно,
Как грозные взрывы и пламя
Врага провожали на дно.
Припев
И слава о подвигах флота,
О гвардии нашей морской
Останется в сердце народа,
В душе благородной людской.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Морская гвардия идёт уверенно...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7ce1fdb38df3a003'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7ce1fdb38df3a003','Морская гвардия','Родных кораблей патриоты
