INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_7ce1fdb38df3a003_f58c60d4e17d38c5','rpp_7ce1fdb38df3a003','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/morskaya_gvardiya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f335512d75315eec','Московская','(«Соседи дружные, ребята нужные...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Илья Финк, музыка: Матвей Блантер) | Песни военных лет | https://pesni.retroportal.ru/vov/moskovskaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Соседи дружные, ребята нужные...») | merged_versions: 1','Полуночная мгла над столицей легла,
В небе зоркие шарят лучи...
Город спит, но не спят сотни смелых ребят -
Москвичи, москвичи, москвичи...
Припев:
Соседи дружные, ребята нужные,
Они сумеют отстоять свой дом,
Простой кирпичный дом, совсем обычный дом,
Но был всегда для них тот дом родным гнездом.
Стал в Москве каждый дом неприступным гнездом,
Бастионом стал каждый кирпич.
И москвич говорит: &laquo;Если дом мой сгорит,
Так какой же тогда я москвич?&raquo;
Припев
Над ночною Москвой разгорается бой,
Вражий коршун зенитками сбит!
И москвич говорит: &laquo;Ты сгорел, Мессершмидт,
А Москва никогда не сгорит!&raquo;
Припев
В каждом доме посты, словно фронт, крепок тыл,
На врага поднялась вся страна!
И недаром бойцам, москвичам-молодцам,
Боевые дают ордена!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Соседи дружные, ребята нужные...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f335512d75315eec'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f335512d75315eec','Московская','Полуночная мгла над столицей легла,
