INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_f335512d75315eec_2b7aa8e31f8fb9b9','rpp_f335512d75315eec','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/moskovskaya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6d78d829e59ad028','Мы едем, едем, едем...','(Песенка из кинофильма «Весёлые путешественники»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Михалков, музыка: Михаил Старокадомский) | Песни для детей | https://pesni.retroportal.ru/deti/my_edem_edem_edem.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песенка из кинофильма «Весёлые путешественники») | merged_versions: 1','Мы едем, едем, едем
В далёкие края.
Весёлые соседи,
Счастливые друзья.
Нам весело живётся,
Мы песенку поём,
А в песне той поётся
Про то, как мы живем:
Красота! Красота!
Мы везём с собой кота,
Чижика, собаку, Петьку-забияку,
Обезьяну, попугая.
Вот компания какая!
Вот компания какая!
Мы ехали, мы пели
И с песенкой простой
Все вместе, как сумели,
Приехали домой.
Нам солнце вслед светило,
Нас ветер обдувал,
И весело нам было,
И каждый напевал:
Красота! Красота!
Мы везём с собой кота,
Чижика, собаку, Петьку-забияку,
Обезьяну, попугая.
Вот компания какая!
Вот компания какая!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песенка из кинофильма «Весёлые путешественники»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6d78d829e59ad028'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6d78d829e59ad028','Мы едем, едем, едем...','Мы едем, едем, едем
