INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6d78d829e59ad028_eb98893506be3ace','rpp_6d78d829e59ad028','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/my_edem_edem_edem.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_afadacc4f4aee922','Мы на лодочке катались',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/10.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Мы на лодочке катались,
Золотистой, золотой, -
Не гребли, а целовались,
Не качай, брат, головой.
В лесу, говорят, в бору, говорят,
Растёт, говорят, сосёнка,
Понравилась мне, молодцу,
Весёлая девчонка.
Не кукуй горько, кукушка,
На осине проклятой,
Сядь на белую берёзу,
Прокукуй над сиротой.
В лесу, говорят, в бору, говорят,
Растёт, говорят, сосёнка.
Понравилась мне, молодцу,
Пригожая девчонка.
Я тогда тебе поверю,
Что любовь верна у нас,
Поцелуй меня, приятка,
Без отрыву сорок раз.
Ты, говорит, ходи, говорит,
Ко мне, говорит, почаще.
Ты, говорит, носи, говорит,
Пряники послаще.
Где мы с миленьким встречались,
Там зелёная трава,
Где мы с милой расставались,
Там посохли дерева.
В лесу, говорят, в бору, говорят,
Росла, говорят, сосёнка,
Уж больно мне понравилась
Смышленая девчонка.
Меня маменька ругает,
Тятька боле бережёт:
Как иду с гулянки поздно,
Он с поленом стережёт.
Я, говорит, тебя, говорит,
Сынок, говорит, уважу!
Я, говорит, тебе, говорит,
Гуляночку налажу!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_afadacc4f4aee922'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_afadacc4f4aee922','Мы на лодочке катались','Мы на лодочке катались,
