INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c3bc52bc11fe5549','На Дальнем Востоке','(«На восток мы завтра улетаем...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Виктор Гусев, музыка: Юрий Милютин) | Патриотические песни | https://pesni.retroportal.ru/rodina/na_dalnem_vostoke.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («На восток мы завтра улетаем...») | merged_versions: 1','На восток мы завтра улетаем,
Самолёт уходит поутру.
Там течёт Амур&nbsp;- река родная
Нашей Волге, нашему Днепру.
Припев:
Летим мы, товарищ, дорогой высокой,
Наш путь над тайгою пролёг.
Байкал мой глубокий, Амур мой широкий&nbsp;-
Наш Дальний Советский Восток!
Край могучей, радостной работы,
Комсомольский, смелый, молодой,
Край, согретый Сталинской заботой,
Озарённый Сталинской звездой.
Припев
Край ты наш, могучий и родимый!
Если грянут грозные бои,
Никому тебя не отдадим мы,
Часовые верные твои!
Припев
На восток уходят самолёты,
Танков ход нельзя остановить.
В бой пойдут танкисты и пилоты
На чужой земле врага громить!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«На восток мы завтра улетаем...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c3bc52bc11fe5549'), datetime('now')),datetime('now'));
