INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2853e2097b7639f1','На заре ты её не буди',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Афанасий Фет, музыка: Александр Варламов) | Старинные романсы | https://pesni.retroportal.ru/sr2/14.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','На заре ты её не буди,
На заре она сладко так спит!
Утро дышит у ней на груди,
Ярко пышет на ямках ланит.
И подушка её горяча
И горяч утомительный сон,
И, чернеясь, бегут на плеча
Косы лентой с обеих сторон.
А вчера у окна ввечеру
Долго-долго сидела она
И следила по тучам игру,
Что, скользя, затевала луна.
И чем ярче играла луна,
И чем громче свистал соловей,
Всё бледней становилась она,
Сердце билось больней и больней.
Оттого-то на юной груди,
На ланитах так утро горит.
Не буди ж ты её, не буди...
На заре она сладко так спит!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2853e2097b7639f1'), datetime('now')),datetime('now'));
