INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_86baaea871992057','На Заречной улице','(Песня из кинофильма «Весна на Заречной улице»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Борис Мокроусов) | Патриотические песни | https://pesni.retroportal.ru/rodina/vesna_na_zarechnoj_ulice.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (Песня из кинофильма «Весна на Заречной улице») | merged_versions: 1','Когда весна пpидёт, не знаю.
Пpойдyт дожди, сойдyт снега.
Hо ты мне, yлица pодная,
И в непогодy доpога.
На этой улице подростком
Гонял по крышам голубей
И здесь, на этом перекрёстке,
С любовью встретился своей.
Теперь и сам не рад, что встретил.
Моя душа полна тобой.
Зачем, зачем на белом свете
Есть безответная любовь?
На свете много улиц славных,
Но не сменяю адрес я.
В моей судьбе ты стала главной,
Родная улица моя.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(Песня из кинофильма «Весна на Заречной улице»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_86baaea871992057'), datetime('now')),datetime('now'));
