INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5ff2d1d9096e01a7','На побывку едет молодой моряк','(«Отчего у нас в посёлке у девчат переполох?..»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Виктор Боков, музыка: Александр Аверкин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/na_pobyvky_edet_molodoj_moryak.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Отчего у нас в посёлке у девчат переполох?..») | merged_versions: 1','Отчего у нас в посёлке
У девчат переполох?
Кто их поднял спозаранок,
Кто их так встревожить мог?
На побывку едет
Молодой моряк,
Грудь его в медалях,
Ленты в якорях.
За рекой за косогором
Встали девушки гурьбой.
&laquo;Здравствуй,&nbsp;– все сказали хором,&nbsp;–
Черноморский наш герой!&raquo;
Каждой руку жмёт он
И глядит в глаза,
А одна смеется:
&laquo;Целовать нельзя!&raquo;
Полегоньку отдыхает
У родителей в дому.
Хором девушки вздыхают:
&laquo;Мы не нравимся ему!&raquo;
Ни при чём наряды,
Ни при чём фасон&nbsp;–
Ни в одну девчонку
Не влюбился он!
Ходит, шутит он со всеми,
Откровенно говорит:
&laquo;Как проснусь, тотчас же море
У меня в ушах шумит.
Где под солнцем юга
Ширь безбрежная,
Ждёт меня подруга
Нежная&raquo;.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Отчего у нас в посёлке у девчат переполох?..»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5ff2d1d9096e01a7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5ff2d1d9096e01a7','На побывку едет молодой моряк','Отчего у нас в посёлке
