INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8493c7390e2ff8b3','На работу, кума, на работу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (шуточная русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/11.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Пошли девки на работу,
На работу, кума, на работу!
На работе припотели,
Припотели, кума, припотели.
Искупаться захотели,
Захотели, кума, захотели.
Поскидали рубашонки,
Рубашонки, кума, рубашонки.
Поскакали во речонку,
Во речонку, кума, во речонку.
Отколь взялся тут Игнашка?
Тут Игнашка, кума, тут Игнашка!
Забрал девичьи рубашки,
Рубашки, кума, рубашонки.
Одна девка всех смелее,
Всех смелее, кума, всех смелее.
Выскочила из речонки,
Из речонки, кума, из речонки.
Побежала за Игнашкой,
За Игнашкой, кума, за Игнашкой:
&laquo;Отдай девичьи рубашки,
Рубашки, кума, рубашонки...&raquo;
Пошли девки на работу,
На работу, кума, на работу!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8493c7390e2ff8b3'), datetime('now')),datetime('now'));
