Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Пpойдy по Абpикосовой, свеpнy на Виногpаднyю...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3cac9060dfd32f1c'), datetime('now')),datetime('now'));
