INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_587f06be3e1165f0','Над волною голубой','(«Над волною голубою блещут зори...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Жаров, музыка: Константин Листов) | Патриотические песни | https://pesni.retroportal.ru/rodina/nad_volnoyu_goluboj.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Над волною голубою блещут зори...») | merged_versions: 1','Над волною голубою блещут зори...
Высоко поднялся к небу флотский флаг...
Эти зори на чужом, далёком море
Повидали мы с тобой, лихой моряк.
Я походы боевые вспоминаю...
Предо мной встают виденья грозных лет...
Краше моря и тебя, земля родная,
И дороже ничего на свете нет.
В стороне моей от края и до края
Снова слышатся напевы мирных лет...
Краше моря и тебя, земля родная,
И дороже ничего на свете нет.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Над волною голубою блещут зори...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_587f06be3e1165f0'), datetime('now')),datetime('now'));
