INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8530293d557b978a','Над окошком месяц',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Есенин, музыка: Евгений Попов) | Старинные романсы | https://pesni.retroportal.ru/sr2/13.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Над окошком месяц. Под окошком ветер,
Облетевший тополь серебрист и светел.
Дальний плач тальянки, голос одинокий –
И такой родимый, и такой далёкий.
Плачет и смеётся песня лиховая.
Где ты, моя липа? Липа вековая?
Я и сам когда-то в праздник спозаранку
Выходил к любимой, развернув тальянку.
А теперь я милой ничего не значу.
Под чужую песню и смеюсь и плачу.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8530293d557b978a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8530293d557b978a','Над окошком месяц','Над окошком месяц. Под окошком ветер,
