INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_72d7d1731981e77c','Над полями да над чистыми',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Рославлев, музыка: Елизавета Горина) | Народные песни | https://pesni.retroportal.ru/np2/12.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Над полями да над чистыми
Месяц птицею летит,
И серебряными искрами
Поле ровное блестит.
Ну, дружней, звончей, бубенчики,
Заливные голоса!
Эх ты, удаль молодецкая!
Эх ты, девичья краса!
Гривы инеем кудрявятся,
Порошит снежком лицо.
Выходи встречать, красавица,
Друга мила на крыльцо.
Припев
Глянут в душу очи ясные,
Закружится голова...
С милым жизнь, что солнце красное,
А без мила – трын-трава!..
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_72d7d1731981e77c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_72d7d1731981e77c','Над полями да над чистыми','Над полями да над чистыми
