Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_72d7d1731981e77c_54c1c03e10bdbf40','rpp_72d7d1731981e77c','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/12.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_856ec86ebbbd35d5','Накинув плащ',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Соллогуб, музыка неизвестного автора) | Старинные романсы | https://pesni.retroportal.ru/sr2/15.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Накинув плащ, с гитарой под полою,
К её окну приник в тиши ночной,
Не разбужу ль я песней удалою
Роскошный сон красавицы младой.
О, не страшись меня, младая дева!
Не возмущу твоих прекрасных снов
Неистовством разгульного напева.
Чиста и песнь, когда чиста любовь.
Я здесь пою так тихо и смиренно
Лишь для того, чтоб услыхала ты,
И песнь моя есть фимиам священный
Пред алтарём богини красоты.
И, может быть, услышав серенаду
И из неё хоть что-нибудь поймешь,
И, может быть, поющему в награду
&laquo;Люблю тебя&raquo; - сквозь сон произнесёшь.
Звезда любви, волшебница земная...
Я слышу тон и звук её речей,
Я вижу стан её высокий
И тёмный шёлк её кудрей.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_856ec86ebbbd35d5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_856ec86ebbbd35d5','Накинув плащ','Накинув плащ, с гитарой под полою,
К её окну приник в тиши ночной,
