INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_856ec86ebbbd35d5_7809230e752f31d1','rpp_856ec86ebbbd35d5','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/15.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7c4976a9c62a378f','Нам звёзды кроткие сияли',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Плещеев, музыка: Пётр Чайковский) | Старинные романсы | https://pesni.retroportal.ru/sr2/16.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Нам звёзды кроткие сияли,
Чуть веял тихий ветерок,
Кругом цветы благоухали
И волны ласково журчали
У наших ног.
Мы были юны, мы любили,
И с верой вдаль смотрели мы;
В нас грёзы радужные жили
И нам не страшны вьюги были
Седой зимы.
Где ж эти ночи с их сияньем,
С благоухающей красой,
И волн таинственным роптаньем,
Надежд восторженных мечтаний
Где светлый рой? Где светлый рой?
Померкли звёзды, и уныло
Поникли блеклые цветы...
Когда ж, о сердце, всё, что было,
Что нам весна с тобой дарила,
Забудешь ты? Забудешь ты?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7c4976a9c62a378f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_7c4976a9c62a378f','Нам звёзды кроткие сияли','Нам звёзды кроткие сияли,
