INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_7c4976a9c62a378f_8f5cde84acc2e8f9','rpp_7c4976a9c62a378f','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/16.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0bebbbd73a6cabf7','Напоминание',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Александр Варламов) | Старинные романсы | https://pesni.retroportal.ru/sr2/17.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ты помнишь ли тот взгляд красноречивый,
Который мне любовь твою открыл?
Он в будущем мне был залог счастливый,
Он душу мне огнём воспламенил.
В тот светлый миг одной улыбкой смела
Надежду поселить в твоей груди...
Какую власть я над тобой имела!
Я помню всё... Но ты, - ты помнишь ли?
Ты помнишь ли минуты ликованья,
Когда для нас так быстро дни неслись?
Когда ты ждал в любви моей признанья
И верным быть уста твои клялись?
Ты мне внимал, довольный, восхищённый,
В очах твоих горел огонь любви.
Каких мне жертв не нёс ты упоённый?
Я помню всё... Но ты, - ты помнишь ли?
Ты помнишь ли, когда в уединенье
Я столько раз с заботою немой
Тебя ждала, завидя в отдаленье;
Как билась грудь от радости живой?
Ты помнишь ли, как в робости невольной
Тебе кольцо я отдала с руки?
Как счастьем я твоим была довольна?
Я помню всё... Но ты, - ты помнишь ли?
Ты помнишь ли, вечерними часами
Как в песнях мне страсть выразить умел?
Ты помнишь ли ночь, яркую звездами?
Ты помнишь ли, как ты в восторге млел?
Я слёзы лью, о прошлом грудь тоскует,
Но хладен ты и сердцем уж вдали!
Тебя тех дней блаженство не чарует,
Я помню всё... Но ты, - ты помнишь ли?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0bebbbd73a6cabf7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_0bebbbd73a6cabf7','Напоминание','Ты помнишь ли тот взгляд красноречивый,
