INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_0bebbbd73a6cabf7_42d2431b63ae50d5','rpp_0bebbbd73a6cabf7','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/17.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_eaccd938fd5b1c0e','Наш край','(«То берёзка, то рябина...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Антон Пришелец, музыка: Дмитрий Кабалевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/nash_kraj.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («То берёзка, то рябина...») | merged_versions: 1','То берёзка, то рябина,
Куст ракиты над рекой&nbsp;-
Край родной, навек любимый,
Где найдешь ещё такой?
От морей до гор высоких,
Посреди родных широт,
Всё бегут, бегут дороги,
И зовут они вперёд.
Солнцем залиты долины,
И куда ни бросишь взгляд,
Край родной, навек любимый,
Весь цветёт, как вешний сад.
Детство наше золотое
Всё светлее с каждым днём,
Под счастливою звездою
Мы живём в краю родном.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«То берёзка, то рябина...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_eaccd938fd5b1c0e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_eaccd938fd5b1c0e','Наш край','То берёзка, то рябина,
