INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9c90ef05efc50ff4','Не брани меня, родная',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Разоренов, музыка: Александр Дюбюк) | Старинные романсы | https://pesni.retroportal.ru/sr2/18.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не брани меня, родная,
Что я так люблю его,
Скучно, скучно, дорогая,
Жить одной мне без него.
Я не знаю, что такое
Вдруг случилося со мной:
Что-то рвётся ретивое
И терзаюсь я тоской.
Всё оно во мне заныло,
Вся горю я, как огнём.
Всё не мило, всё постыло,
И страдаю я по нём.
В ясный день и тёмны ночи,
И во сне и наяву
Слёзы мне туманят очи,
Всё летела б я к нему.
Мне не нужны все наряды,
Ленты, камни и парчи.
Кудри молодца и взгляды
Сердце бедное зажгли.
Сжалься, сжалься же, родная,
Перестань меня бранить.
Знать, судьба моя такая,
Что должна его любить.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9c90ef05efc50ff4'), datetime('now')),datetime('now'));
