INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b1999d2c1767773a','Не будите меня, молоду',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/13.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Не будите меня, молоду,
Да утром рано, поутру,
Разбудите молоду,
Да когда солнышко взойдёт.
Разбудите меня, молоду,
Да когда солнышко взойдёт.
Когда солнышко взойдёт,
Роса на землю упадёт.
Когда солнышко взойдёт,
Да роса на землю упадёт,
Роса на землю упадёт,
Пастух выйдет на лужок.
Пастух выйдет на лужок.
Да заиграет во рожок,
Хорошо пастух играет,
Выговаривает.
Хорошо пастух играет,
Выговаривает:
- Выгоняй, народ, скотину
На широкую долину!
Выгоняй, народ, скотину
На широкую долину,
На широкую долину,
На зелёну луговину!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b1999d2c1767773a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b1999d2c1767773a','Не будите меня, молоду','Не будите меня, молоду,
