INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_212b949d3ed6b1ac','Не велят Маше за реченьку ходить',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/14.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Не велят Маше за ре... за реченьку ходить,
Не велят Маше моло... ах, молодчика любить,
Ах, молодчика любить.
А молодчик-то люби... любитель дорогой,
Он не чувствует любо... ох, любови никакой,
Ох, любови никакой.
Какова любовь на све... на свете горюча:
Стоит Машенька, запла... ох, заплаканы глаза,
Ох, заплаканы глаза.
Призатёртые кисе... кисейны рукава.
Знать, на Машеньку побе... ох, победушка была,
Ох, победушка была.
Знать на Машеньку побе... победушка пришла;
Видно, Машеньку брани... эх, бранили за дружка,
Эх, бранили за дружка.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_212b949d3ed6b1ac'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_212b949d3ed6b1ac','Не велят Маше за реченьку ходить','Не велят Маше за ре... за реченьку ходить,
