INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b1a7c13722bd6911','Не верит он',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Н.Н., музыка: Пётр Булахов) | Старинные романсы | https://pesni.retroportal.ru/sr2/19.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не верит он, что взор его прекрасный
Меня, как вешний солнца луч, живит,
Что разлюбить его хочу напрасно,
Что лишь по нём душа моя болит.
Не верит он, что в час уединенья
В ушах моих звучат его слова,
Что за него с слезою умиленья
Летит к творцу горячая мольба.
Не верит он, что быть мне с ним так сладко,
Что сердце радостно дрожит при нём...
Что я люблю его от всех украдкой,
Что день и ночь лишь думаю о нём.
Поверит он – не раз ему вздохнётся,
Когда вся жизнь моя пройдет, как сон.
На мой привет тогда он отзовётся,
Любовь мою тогда оценит он.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b1a7c13722bd6911'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b1a7c13722bd6911','Не верит он','Не верит он, что взор его прекрасный
