INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6b5da4b82eefb1af','Не жалею, не зову, не плачу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Есенин, музыка: Григорий Пономаренко) | Старинные романсы | https://pesni.retroportal.ru/sr2/20.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не жалею, не зову, не плачу,
Всё пройдёт, как с белых яблонь дым.
Увяданья золотом охваченный,
Я не буду больше молодым.
Ты теперь не так уж будешь биться,
Сердце, тронутое холодком,
И страна берёзового ситца
Не заманит шляться босиком.
Дух бродяжий! Ты всё реже, реже,
Расшевеливаешь пламень уст.
О моя утраченная свежесть,
Буйство глаз и половодье чувств.
Я теперь скупее стал в желаньях,
Жизнь моя? Иль ты приснилась мне?
Словно я весенней гулкой ранью
Проскакал на розовом коне.
Все мы, все мы в этом мире тленны,
Тихо льётся с клёнов листьев медь...
Будь же ты вовек благословенно,
Что пришло процвесть и умереть.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6b5da4b82eefb1af'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6b5da4b82eefb1af','Не жалею, не зову, не плачу','Не жалею, не зову, не плачу,
Всё пройдёт, как с белых яблонь дым.
Увяданья золотом охваченный,
