INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6b5da4b82eefb1af_fefbfe61cb9710ec','rpp_6b5da4b82eefb1af','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/20.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f1f9ca0300bcb1c8','«Не лукавьте» («Моя душечка»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Александр Дюбюк) | Старинные романсы | https://pesni.retroportal.ru/sr2/21.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Моя душечка, моя ласточка,
Взор суровый свой прогони.
Иль не видишь ты, как измучен я?!
Пожалей меня, не гони!
Не лукавьте, не лукавьте!
Ваша песня не нова.
Ах, оставьте, ах, оставьте!
Все слова, слова, слова...
Моя душечка, моя ласточка,
Я нашёл в тебе, что искал.
Пожалей меня, не гони меня,
Как измучен я и устал.
Припев
Ты любовь моя, ты вся жизнь моя,
За тебя весь мир я б отдал.
Верь мне, милая, верь, желанная, -
Никогда я так не страдал.
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f1f9ca0300bcb1c8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f1f9ca0300bcb1c8','«Не лукавьте» («Моя душечка»)','Моя душечка, моя ласточка,
Взор суровый свой прогони.
Иль не видишь ты, как измучен я?!
Пожалей меня, не гони!
Не лукавьте, не лукавьте!
Ваша песня не нова.
Ах, оставьте, ах, оставьте!
Все слова, слова, слова...
Моя душечка, моя ласточка,
Я нашёл в тебе, что искал.
Пожалей меня, не гони меня,
Как измучен я и устал.
Припев
Ты любовь моя, ты вся жизнь моя,
За тебя весь мир я б отдал.
Верь мне, милая, верь, желанная, -
Никогда я так не страдал.
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_f1f9ca0300bcb1c8_7a33c4f419e8dc96','rpp_f1f9ca0300bcb1c8','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/21.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f9bde620884c9238','Не надо встреч',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Д''Актиль / Анатолий Френкель /, музыка: Юлий Хайт) | Старинные романсы | https://pesni.retroportal.ru/sr2/22.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Узор судьбы чертит неслышный след:
Твоё лицо я вижу вновь так близко;
И веет вновь дыханьем прошлых лет
Передо мной лежащая записка...
Не надо встреч... Не надо продолжать...
Не нужно слов, клянусь тебе, не стоит!
И, если вновь больное сердце ноет,
Заставь его застыть и замолчать!
Ведь мне знаком, мучительно знаком
Твой каждый жест, законченный и грубый,
Твоей души болезненный излом,
И острый взгляд, и чувственные губы...
Припев
Я не хочу былого осквернить
Игрою чувств минутного возврата,
Что было раз – тому уже не быть,
Твоей рукой всё сорвано и смято.
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f9bde620884c9238'), datetime('now')),datetime('now'));
