INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a07fcfd16d9cbb59','Не одна во поле дороженька',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/15.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Не одна-то ли, да одна, ай, во поле дорожка,
Во поле дороженька, эх, во поле дороженька.
Не одна-то ли дороженька, ай, дорожка пролегала,
Она пролегала, эх, она пролегала.
Эх, частым ельничком доро... ай, дорожка зарастала,
Она зарастала, эх, она зарастала.
Молодым-то ли горьким, ай, горьким осинничком
Её заломало. Эх, её заломало.
Как по той ли по дороженьке, ай, по той ли дорожке
Нельзя ни проехать, ой, да ни проехать, ни пройти...','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a07fcfd16d9cbb59'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a07fcfd16d9cbb59','Не одна во поле дороженька','Не одна-то ли, да одна, ай, во поле дорожка,
