INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_dfaeb1aa62cf141b','Не пой, красавица, при мне',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Пушкин) | Старинные романсы | https://pesni.retroportal.ru/sr2/23.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не пой, красавица, при мне
Ты песен Грузии печальной:
Напоминают мне оне
Другую жизнь и берег дальный,
Берег дальный.
Увы, напоминают мне
Твои жестокие напевы
И степь, и ночь, и при луне
Черты далёкой милой девы,
Милой девы!..','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_dfaeb1aa62cf141b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_dfaeb1aa62cf141b','Не пой, красавица, при мне','Не пой, красавица, при мне
