INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_dfaeb1aa62cf141b_c5db8c9864b90ebf','rpp_dfaeb1aa62cf141b','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/23.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1d04d875149faa52','Не пробуждай воспоминаний',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Н.Н., музыка: Пётр Булахов) | Старинные романсы | https://pesni.retroportal.ru/sr2/24.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не пробуждай воспоминаний
Минувших дней, минувших дней, -
Не возродить былых желаний
В душе моей, в душе моей.
И на меня свой взор опасный
Не устремляй, не устремляй;
Мечтой любви, мечтой прекрасной
Не увлекай, не увлекай!
Однажды счастье в жизни этой
Вкушаем мы, вкушаем мы,
Святым огнём любви согреты,
Оживлены, оживлены.
Но кто её огонь священный
Мог погасить, мог погасить,
Тому уж жизни незабвенной
Не возвратить, не возвратить!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1d04d875149faa52'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1d04d875149faa52','Не пробуждай воспоминаний','Не пробуждай воспоминаний
Минувших дней, минувших дней, -
Не возродить былых желаний
В душе моей, в душе моей.
И на меня свой взор опасный
Не устремляй, не устремляй;
Мечтой любви, мечтой прекрасной
Не увлекай, не увлекай!
Однажды счастье в жизни этой
Вкушаем мы, вкушаем мы,
Святым огнём любви согреты,
Оживлены, оживлены.
Но кто её огонь священный
Мог погасить, мог погасить,
Тому уж жизни незабвенной
Не возвратить, не возвратить!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_1d04d875149faa52_a5b5ce81a6a5923c','rpp_1d04d875149faa52','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/24.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8e8f178c4313b60e','Не смолкай, говори...',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Арсений Голенищев-Кутузов, музыка неизветсного автора) | Старинные романсы | https://pesni.retroportal.ru/sr1/08.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не смолкай, говори... В ласке речи твоей,
В беззаветном веселье свиданья
Принесла мне с собою ты свежесть полей
И цветов благовонных лобзанья.
Я внимаю тебе - и целебный обман
Сердце властной мечтою объемлет,
Мне мерещится ночь... В лунном блеске туман
Над сверкающим озером дремлет.
Ни движенья, ни звука вокруг, ни души!
Беспредметная даль пред очами,
Мы с тобою вдвоём в полутьме и тиши,
Под лазурью, луной и звездами.
Только воды дрожат, только дышат цветы
Да туманится воздух росистый
И, горя сквозь туман, как звезда с высоты,
В душу светит мне взгляд твой лучистый.
В беспредельном молчаньи теней и лучей
Шепчешь ты про любовь и участье...
Не смолкай, говори... В ласке речи твоей
Мне звучит беспредельное счастье!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8e8f178c4313b60e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8e8f178c4313b60e','Не смолкай, говори...','Не смолкай, говори... В ласке речи твоей,
