INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4656d15a7c099f07','Не страшна мне Волга‑матушка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Кольцов, музыкальная обработка: Милий Балакирев) | Народные песни | https://pesni.retroportal.ru/np2/16.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Не страшна мне, добру молодцу,
Волга-матушка широкая,
Леса тёмные, дремучие,
Вьюги зимние крещенские!
Уж как было по тёмным лесам,
Пировал я зимы круглые
По чужим краям, на свой талант
Погулял я, поохотился.
А по Волге, моей матушке,
По родимой, по кормилице,
Вместе с братьями за добычею
На край света летал соколом.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4656d15a7c099f07'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4656d15a7c099f07','Не страшна мне Волга‑матушка','Не страшна мне, добру молодцу,
Волга-матушка широкая,
Леса тёмные, дремучие,
Вьюги зимние крещенские!
Уж как было по тёмным лесам,
Пировал я зимы круглые
По чужим краям, на свой талант
Погулял я, поохотился.
А по Волге, моей матушке,
По родимой, по кормилице,
Вместе с братьями за добычею
На край света летал соколом.');
