INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8cf4f651a056e878','Не сырой ли дубик разгорается',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/17.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Не сырой ли дубик разгорается?
Ой, ле, ой, лелю, да разгорается.
Моему дружочку немогается,
Ой, ле, ой, лелю, да немогается.
Немогается дружку Иванушку,
Ой, ле, ой, лелю, дружку Иванушку.
Я пойду – схожу к дружку Иванушке,
Ой, ле, ой, лелю, дружку Иванушке.
Я скажу ему, да про здоровьице,
Ой, ле, ой, лелю, да про здоровьице.
&laquo;Как оно, милый, твое здоровьице?
Ой, ле, ой, лелю, твое здоровьице?&raquo;.
&laquo;Моё здоровьице, да возголовьице,
Ой, ле, ой, лелю, да возголовьице&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8cf4f651a056e878'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8cf4f651a056e878','Не сырой ли дубик разгорается','Не сырой ли дубик разгорается?
