INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6fac32ecdac50ce5','Не уезжай ты, мой голубчик',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Николай Пашков) | Старинные романсы | https://pesni.retroportal.ru/sr2/29.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не уезжай ты, мой голубчик!
Печальна жизнь мне без тебя.
Дай на прощанье обещанье,
Что не забудешь ты меня.
Скажи ты мне, скажи ты мне,
Что любишь меня, что любишь меня...
Когда порой тебя не вижу,
Грустна, задумчива хожу.
Когда речей твоих не слышу,
Мне кажется, я не живу.
Скажи ты мне, скажи ты мне,
Что любишь меня, что любишь меня...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6fac32ecdac50ce5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6fac32ecdac50ce5','Не уезжай ты, мой голубчик','Не уезжай ты, мой голубчик!
Печальна жизнь мне без тебя.
Дай на прощанье обещанье,
Что не забудешь ты меня.
