INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_9e6be5093a8af245_19fe705b784bb47f','rpp_9e6be5093a8af245','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/18.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_76b0712dcf0cec3c','Неделька',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/19.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','В воскресенье я на ярмарку ходила,
Веретен да кудельку купила...
Тюря, тюря, тюря, тюря, тюря, тюря-ря,
Тюря, тюря, тюря, тюря, тюря-ря.
В понедельник я банюшку топила,
А во вторник я в банюшку ходила...
Припев
Тебя, миленький мой, в среду встречала,
А в четверг я тебя провожала...
Припев
Эх, да в пятницу не прядут, не мотают,
Во субботу всех померших поминают...
Припев
Так-то, миленький мой, ласковый Емелька,
Проработала всю эту я недельку.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_76b0712dcf0cec3c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_76b0712dcf0cec3c','Неделька','В воскресенье я на ярмарку ходила,
