INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b97df3372bbe0f9e','Неприятность эту мы переживём','(Песня из мультфильма «Лето кота Леопольда»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Аркадий Хайт, музыка: Борис Савельев) | Песни для детей | https://pesni.retroportal.ru/deti/nepriyatnost_etu_my_perezhivem.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Лето кота Леопольда») | merged_versions: 1','В небесах высоко
Ярко солнце светит.
До чего же хорошо
Жить на белом свете!
Если вдруг грянет гром
В середине лета,
Неприятность эту
Мы переживём.
Мелкий дождь бьёт в окно,
Хмурится природа,
Но известно давно&nbsp;-
Нет плохой погоды.
Всё желтеет кругом,
И уходит лето,
Неприятность эту
Мы переживём.
Я иду и пою
Обо всём хорошем.
И улыбку свою
Я дарю прохожим.
Если в сердце чужом
Не найду ответа,
Неприятность эту
Мы переживём.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Лето кота Леопольда»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b97df3372bbe0f9e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b97df3372bbe0f9e','Неприятность эту мы переживём','В небесах высоко
