INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_964565cba7d0900a','Несокрушимая и легендарная','(«Несокрушимая и легендарная, в боях познавшая радость побед...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Осип Колычев, музыка: Александр Александров) | Песни военных лет | https://pesni.retroportal.ru/vov/nesokrushimaya_i_legendarnaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Несокрушимая и легендарная, в боях познавшая радость побед...») | merged_versions: 1','Над страною шумят как знамёна
Двадцать семь героических лет.
Отзвук славных боёв отдалённых,
Весь твой путь в наших песнях воспет.
Припев:
Несокрушимая и легендарная,
В боях познавшая радость побед&nbsp;-
Тебе любимая, родная армия
Шлёт наша Родина песню&nbsp;- привет.
Родилась ты под знаменем алым
В восемнадцатом грозном году.
Всех врагов ты всегда сокрушала,
Победишь ты фашистов орду.
Припев
Ленинград мы в боях отстояли,
Отстояли родной Сталинград.
Нас ведёт в наступление Сталин,
Наши танки фашистов громят!
Припев
Победит наша сила&nbsp;- известно,
Гений Сталина в бой нас ведёт.
Наша армия в битвах бессмертна,
Как бессмертен Советский Народ.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Несокрушимая и легендарная, в боях познавшая радость побед...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_964565cba7d0900a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_964565cba7d0900a','Несокрушимая и легендарная','Над страною шумят как знамёна
Двадцать семь героических лет.
