INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_964565cba7d0900a_898361f41f41ba73','rpp_964565cba7d0900a','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/nesokrushimaya_i_legendarnaya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8a37fbc5c8eadae7','Нет, не любил',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Эрнесто Дельпрейте, перевод: Михаил Медведев, музыка: Альфонсо Гуэрчиа) | Старинные романсы | https://pesni.retroportal.ru/sr2/25.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Он говорил мне: &laquo;Будь ты моею,
И стану жить я, страстью сгорая;
Прелесть улыбки, нега во взоре
Мне обещают радости рая&raquo;.
Бедному сердцу так говорил он,
Бедному сердцу так говорил он, -
Но не любил он, нет, не любил он,
Нет, не любил он, ах, не любил меня!
Он говорил мне: &laquo;Яркой звездою
Мрачную душу ты озарила,
Ты мне надежду в душу вселила,
Сны наполняя сладкой мечтою&raquo;.
То улыбался, то слёзы лил он,
То улыбался, то слёзы лил он, -
Но не любил он, нет, не любил он,
Нет, не любил он, ах, не любил меня!
Он обещал мне, бедному сердцу,
Счастье и грёзы, страсти, восторги,
Нежно он клялся жизнь усладить мне
Вечной любовью, вечным блаженством.
Сладкою речью сердце сгубил он,
Сладкою речью сердце сгубил он, -
Но не любил он, нет, не любил он,
Нет, не любил он, ах, не любил меня!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8a37fbc5c8eadae7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8a37fbc5c8eadae7','Нет, не любил','Он говорил мне: &laquo;Будь ты моею,
