INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_8a37fbc5c8eadae7_1c6123aa21a864f9','rpp_8a37fbc5c8eadae7','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/25.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8cbbb8767118ce7d','Нет, не люблю я вас',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Соллогуб, музыка: Пётр Булахов) | Старинные романсы | https://pesni.retroportal.ru/sr2/26.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Нет, не люблю я Вас, да и любить не стану!
Коварных Ваших глаз не верю я обману.
Остыл огонь души, и сердце охладело!
Вы очень хороши, да мне какое дело!
Пора мне поберечь себя от слов опасных,
От снега белых плеч и взоров ложно страстных.
В них, знаю я давно, куда как мало прока,
И, право, мне грешно ждать нового урока.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8cbbb8767118ce7d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8cbbb8767118ce7d','Нет, не люблю я вас','Нет, не люблю я Вас, да и любить не стану!
