INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d376675e9139a931','Нет, не тебя так пылко я люблю',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Лермонтов) | Старинные романсы | https://pesni.retroportal.ru/sr2/27.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Нет, не тебя так пылко я люблю,
Не для меня красы твоей блистанье:
Люблю в тебе я прошлого страданье
И молодость погибшую мою.
Когда порой я на тебя смотрю,
В твои глаза вникая долгим взором,
Таинственным я занят разговором,
Но не с тобой я сердцем говорю.
Я говорю с подругой милых дней;
В твоих чертах ищу черты другие;
В устах живых – уста давно немые,
В глазах огонь угаснувших очей.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d376675e9139a931'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d376675e9139a931','Нет, не тебя так пылко я люблю','Нет, не тебя так пылко я люблю,
Не для меня красы твоей блистанье:
Люблю в тебе я прошлого страданье
И молодость погибшую мою.
Когда порой я на тебя смотрю,
В твои глаза вникая долгим взором,
Таинственным я занят разговором,
Но не с тобой я сердцем говорю.
Я говорю с подругой милых дней;
В твоих чертах ищу черты другие;
В устах живых – уста давно немые,
В глазах огонь угаснувших очей.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d376675e9139a931_16adac84e848fee9','rpp_d376675e9139a931','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/27.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0d01f63e5a3102d4','Нет, нет, не хочу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: А. Сурин, музыка: Борис Кейль) | Старинные романсы | https://pesni.retroportal.ru/sr2/28.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Разлюбила и довольно,
Исстрадалась я душой.
До сих пор и сердцу больно,
Вы играли лишь со мной!
Нет, нет, не хочу!
Ничего я не хочу!
Не клянитесь – всё напрасно,
Не открою Вам души.
Я любила пылко, страстно,
Но рыдала лишь в тиши.
Припев
Я счастлива лишь мечтаньем,
Призрак прошлого ловлю:
Вспоминаю ночь, свиданье...
Но уж вновь не полюблю!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0d01f63e5a3102d4'), datetime('now')),datetime('now'));
