INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3ed630c647d684cc','Ничего мне на свете не надо',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Николай Титов) | Старинные романсы | https://pesni.retroportal.ru/sr2/30.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ничего мне на свете не надо,
Я готов всё отдать, полюбя.
Мне осталась одна лишь отрада –
Баловать и лелеять тебя.
Я внимательно слушаю сказки,
Их из уст твоих жадно ловлю.
Я смотрю на лазурные глазки
И хочу говорить, что люблю.
Я люблю тебя крепко, голубка,
Для меня ты дороже всего.
Я люблю твои алые губки
И улыбку лица твоего.
Я люблю твою косу густую,
Так люблю, что сказать нет и слов.
Дай хоть раз я тебя поцелую,
И тогда умереть я готов.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3ed630c647d684cc'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3ed630c647d684cc','Ничего мне на свете не надо','Ничего мне на свете не надо,
