INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1537282459afd3d4','Ничто в поле не колышется',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/20.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ничто в поле не колышется,
Только грустный напев где-то слышится.
Пастушок напевал песню дивную,
В этой песне вспоминал свою милую.
&laquo;Как напала на меня грусть жестокая, -
Разлюбила меня черноокая...&raquo;
Ничто в полюшке не колышется,
Только грустный напев где-то слышится.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1537282459afd3d4'), datetime('now')),datetime('now'));
