INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_1537282459afd3d4_36fc50de22645a82','rpp_1537282459afd3d4','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/20.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d147591e8a40dc98','Нищая',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Пьер-Жан Беранже, русский текст: Дмитрий Ленский, музыка: Александр Алябьев) | Старинные романсы | https://pesni.retroportal.ru/sr2/31.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Зима, метель, и в крупных хлопьях
При сильном ветре снег валит.
У входа в храм, одна, в отрепьях,
Старушка нищая стоит...
И милостыни ожидая,
Она всё тут с клюкой своей,
И летом, и зимой, слепая!..
Подайте ж милостыню ей!
Сказать ли вам, старушка эта
Как двадцать лет тому жила!
Она была мечтой поэта,
И слава ей венок плела.
Когда она на сцене пела,
Париж в восторге был от ней.
Она соперниц не имела...
Подайте ж милостыню ей!
Бывало, после представленья
Ей от толпы проезда нет.
И молодёжь от восхищенья
Гремела &laquo;браво&raquo; ей вослед.
Вельможи случая искали
Попасть в число её гостей;
Талант и ум в ней уважали.
Подайте ж милостыню ей!
В то время торжества и счастья
У ней был дом; не дом – дворец,
И в этом доме сладострастья
Томились тысячи сердец.
Какими пышными хвалами
Кадил ей круг её гостей –
При счастье все дружатся с нами.
Подайте ж милостыню ей!
Святая воля провиденья...
Артистка сделалась больна,
Лишилась голоса и зренья
И бродит по миру одна.
Бывало, бедный не боится
Прийти за милостыней к ней,
Она ж у вас просить стыдится...
Подайте ж милостыню ей!
Ах, кто с такою добротою
В несчастье ближним помогал,
Как эта нищая с клюкою,
Когда амур её ласкал.
Она всё в жизни потеряла!..
О! Чтобы в старости своей
Она на промысл не роптала,
Подайте ж милостыню ей!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d147591e8a40dc98'), datetime('now')),datetime('now'));
