INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6191a52bb553a648','Но я Вас все-таки люблю',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Ленский, музыка: Николай Артемьев) | Старинные романсы | https://pesni.retroportal.ru/sr2/32.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вы мной играете, я вижу,
Смешна для Вас любовь моя,
Порою Вас я ненавижу,
На Вас молюсь порою я...
Вас позабыть не знаю средства,
Я сердцем искренно скорблю:
Хоть в Вас царит одно кокетство,
Но я Вас всё-таки люблю!
Не мало душ Вы погубили,
Но это Вам не всё ль равно?
Ах, никогда Вы не любили,
И Вам любить не суждено.
Надежда мне лишь утешенье,
Да, я надеюсь и терплю.
Бездушны Вы, в том нет сомненья,
Но я Вас всё-таки люблю!
Наступит время, может статься,
К Вам в сердце вкрадется любовь,
Вы перестанете смеяться,
И страсть взволнует вашу кровь.
Терзанья Ваши сознавая,
Свои мученья искуплю...
Я Вам таких же мук желаю...
Но я Вас всё-таки люблю!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6191a52bb553a648'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6191a52bb553a648','Но я Вас все-таки люблю','Вы мной играете, я вижу,
Смешна для Вас любовь моя,
