INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b89d8afbb63fef27','Но я знаю, ты любишь другого',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Мятлев, музыка: Сергей Чарский) | Старинные романсы | https://pesni.retroportal.ru/sr2/33.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я увидел тебя и, увидев, постиг
Всё, что в мире есть мёртвом живого,
Я сказал бы тебе, что люблю каждый миг,
Но я знаю, ты любишь другого.
Глядя в очи твои, внемля песне твоей,
Я шепнул бы заветное слово,
Но я знаю, что ты мне ответишь: &laquo;Забудь!&raquo; -
Потому что ты любишь другого.
Я бы грезил тобой и не спал бы ночей
И, от пения пьян хорового,
Не спускал бы с тебя я влюблённых очей,
Но я знаю, ты любишь другого.
Глядя в очи твои, внемля песне твоей,
Я шепнул бы заветное слово,
Но я знаю, что ты мне ответишь: &laquo;Забудь!&raquo; -
Потому что ты любишь другого.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b89d8afbb63fef27'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b89d8afbb63fef27','Но я знаю, ты любишь другого','Я увидел тебя и, увидев, постиг
