INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_195cbcdaf8dc943f','Новогодняя полька','(Детская новогодняя песня)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Георгий Ладонщиков, музыка: Татьяна Потапенко) | Песни для детей | https://pesni.retroportal.ru/deti/novogodnyaya_polka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Детская новогодняя песня) | merged_versions: 1','Наша ёлка зелена,
И нарядна, и стройна.
Сразу тысячи огней
Вспыхнули на ней!
Припев:
Ах, как в школе
Весело сегодня!
По душе ребятам
Вечер новогодний!
Под баян ученики&nbsp;-
Плясуны и шутники&nbsp;-
Приглашают учениц,
В танцах мастериц.
Припев
Хоть учитель наш и строг,
Удержать не может ног,
Водит с нами хоровод,
Пляшет и поёт.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Детская новогодняя песня)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_195cbcdaf8dc943f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_195cbcdaf8dc943f','Новогодняя полька','Наша ёлка зелена,
И нарядна, и стройна.
Сразу тысячи огней
Вспыхнули на ней!
Припев:
Ах, как в школе
Весело сегодня!
По душе ребятам
Вечер новогодний!
Под баян ученики&nbsp;-
Плясуны и шутники&nbsp;-
Приглашают учениц,
В танцах мастериц.
Припев
Хоть учитель наш и строг,
Удержать не может ног,
Водит с нами хоровод,
Пляшет и поёт.
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_195cbcdaf8dc943f_2bdb38e77fbd053d','rpp_195cbcdaf8dc943f','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/novogodnyaya_polka.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3eafdb59a4d58283','Ночи безумные',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Апухтин, музыка: Александр Спиро) | Старинные романсы | https://pesni.retroportal.ru/sr2/34.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ночи безумные, ночи бессонные,
Речи несвязные, взоры усталые,
Ночи, последним огнём озарённые,
Осени мёртвой цветы запоздалые...
Ночи бессонные, ночи безумные.
Пусть даже время рукой беспощадною
Мне указало, что было в Вас ложного,
Всё же лечу я к Вам памятью жадною,
В прошлом ответа ищу невозможного.
Ночи бессонные, ночи безумные!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3eafdb59a4d58283'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3eafdb59a4d58283','Ночи безумные','Ночи безумные, ночи бессонные,
