INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fdcce51c80099f85','Ночь светла',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Леонид Граве и Николай Языков, музыка: Михаил Шишкин) | Старинные романсы | https://pesni.retroportal.ru/sr2/35.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ночь светла, над рекой тихо светит луна,
И блестит серебром голубая волна.
Тёмный лес... Там в тиши изумрудных ветвей
Звонких песен своих не поёт соловей.
Под луной расцвели голубые цветы,
Они в сердце моём пробуждают мечты.
К тебе в грёзах лечу, твоё имя твержу,
В эту ночь о тебе, милый друг, всё грущу.
Милый друг, нежный друг, я, как прежде любя,
В эту ночь при луне вспоминаю тебя.
В эту ночь при луне на чужой стороне,
Милый друг, нежный друг, вспоминай обо мне.
В эту ночь при луне, на чужой стороне,
Милый друг, нежный друг, вспоминай обо мне!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fdcce51c80099f85'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_fdcce51c80099f85','Ночь светла','Ночь светла, над рекой тихо светит луна,
