INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_89a88a5871ca0a98','О бедном гусаре замолвите слово',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Андрей Петров) | Старинные романсы | https://pesni.retroportal.ru/sr2/36.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','О бедном гусаре замолвите слово:
Ваш муж не пускает меня на постой.
Но женское сердце нежнее мужского,
И сжалиться может оно надо мной.
Я в доме у вас не нарушу покоя,
Скромнее меня не найти из полка.
И если свободен ваш дом от постоя,
То нет ли хоть в сердце у вас уголка?
О бедном гусаре замолвите слово...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_89a88a5871ca0a98'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_89a88a5871ca0a98','О бедном гусаре замолвите слово','О бедном гусаре замолвите слово:
