INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_578ea3a0967ec68c','О Первой конной','(Песня из кинофильма «Первая конная»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Георгий Бёрезко, музыка: Николай Крюков и Гавриил Попов) | Песни военных лет | https://pesni.retroportal.ru/vov/pervaya_konnaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: (Песня из кинофильма «Первая конная») | merged_versions: 1','Чёрная рать обступила границы,
Родина кличет нас в новый поход.
Вспомним Касторную, вспомним Царицын,
Вспомним, друзья, девятнадцатый год!
Коршуны вьются над нашей границей,
Вьются над крышами наших домов.
Вспомним Касторную, вспомним Царицын,
Встретим по-старому новых врагов!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(Песня из кинофильма «Первая конная»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_578ea3a0967ec68c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_578ea3a0967ec68c','О Первой конной','Чёрная рать обступила границы,
