INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_af9b9932db513ee0','О, если б мог выразить в звуке',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Григорий Лишин, музыка: Леонид Малашкин) | Старинные романсы | https://pesni.retroportal.ru/sr2/38.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','О, если б мог выразить в звуке
Всю силу страданий моих,
В душе твоей стихли бы муки,
И ропот сомненья затих;
И я б отдохнул, дорогая,
Страдание высказав всё.
Заветному звуку внимая,
Разбилось бы сердце твоё.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_af9b9932db513ee0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_af9b9932db513ee0','О, если б мог выразить в звуке','О, если б мог выразить в звуке
Всю силу страданий моих,
