INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2a406bdb9ab2d348','О, не целуй меня!',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Александр Варламов) | Старинные романсы | https://pesni.retroportal.ru/sr2/39.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','О, не целуй меня! Твои лобзанья
Волнуют кровь во мне, родят желанья!
Не обнимай меня! Твои объятья
Меня лишают сил, хоть рад страдать я.
Взгляни, как бледен я! Нет воли, силы!
О, не ласкай меня, друг добрый, милый!
О, не ласкай меня, друг добрый, милый!
Не разжигай во мне любви напрасно,
Не искушай меня любовью страстной!
О, не шепчи ты мне речей безумных,
Не убивай, молю, благоразумных
Идей и чувств во мне! Не знать нам счастья!
Так не люби меня с такою страстью!
Так не люби меня с такою страстью!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2a406bdb9ab2d348'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_2a406bdb9ab2d348','О, не целуй меня!','О, не целуй меня! Твои лобзанья
Волнуют кровь во мне, родят желанья!
Не обнимай меня! Твои объятья
