INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e6cd5c5e76f7c0c0','О, позабудь былые увлеченья',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Татьяна Котляревская ⁄ Татьяна Толстая ⁄) | Старинные романсы | https://pesni.retroportal.ru/sr2/43.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','О, позабудь былые увлеченья,
Уйди, не верь обману красоты!
Не разжигай заснувшие мученья,
Не воскрешай минувшие мечты!..
Не вспоминай о том, что позабыто,
Уж я не та, что некогда была!
Всему конец! Прошедшее разбито!..
Огонь потух и не даёт тепла!...
Пойми меня! Пойми, что безнадёжно
Я откажусь от милых светлых грёз,
Чтоб дать изведать безмятежной,
Святой любви, отрадных чистых слёз!
Не в силах жить без бурь и без тревоги,
Идти с тобой по новому пути,
Я брошу всё, сойду с твоей дороги!
Забудь меня, пойми и всё прости!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e6cd5c5e76f7c0c0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e6cd5c5e76f7c0c0','О, позабудь былые увлеченья','О, позабудь былые увлеченья,
