INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_374fdead2c57a784','Облака','(Песня из мультфильма «Трям! Здравствуйте!»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Козлов, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/oblaka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Трям! Здравствуйте!») | merged_versions: 1','Мимо белого яблока луны,
Мимо красного яблока заката
Облака из неведомой страны
К нам спешат и опять бегут куда-то.
Припев:
Облака&nbsp;- белогривые лошадки.
Облака, что вы мчитесь без оглядки?
Не смотрите вы, пожалуйста, свысока,
А по небу прокатите нас, облака.
Мы помчимся в заоблачную даль
Мимо гаснущих звезд на небосклоне.
К нам неслышно опустится звезда
И ромашкой останется в ладони.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Трям! Здравствуйте!»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_374fdead2c57a784'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_374fdead2c57a784','Облака','Мимо белого яблока луны,
