INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_374fdead2c57a784_f33c05e483ad9eaf','rpp_374fdead2c57a784','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/oblaka.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_30aca7193cc06be3','Обойми, поцелуй',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Кольцов, музыка: Милий Балакирев) | Старинные романсы | https://pesni.retroportal.ru/sr2/41.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Обойми, поцелуй,
Приголубь, приласкай,
Ещё раз, поскорей,
Поцелуй горячей.
Что печально глядишь?
Что на сердце таишь?
Не тоскуй, не горюй,
Из очей слёз не лей;
Мне не надобно их,
Мне не нужно тоски.
Мучит душу мою
Твой печальный убор;
Для чего ты в него
Нарядила себя?
Разрядись, уберись
В свой наряд голубой
И на плечи накинь
Шаль с каймой расписной.
Как мне мило теперь
Любоваться тобой!
Как весна хороша
Ты, невеста моя!
Обойми ж, поцелуй,
Приголубь, приласкай,
Ещё раз, поскорей
Поцелуй горячей!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_30aca7193cc06be3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_30aca7193cc06be3','Обойми, поцелуй','Обойми, поцелуй,
