INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ba9391befb03b3d6','Одесса','(Песня из оперетты «Белая акация»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владимир Масс и Михаил Червинский, музыка: Исаак Дунаевский) | Эстрадные песни | https://pesni.retroportal.ru/estrada/odessa_operetta_belaya_akaciya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из оперетты «Белая акация») | merged_versions: 1','Когда я пою о широком просторе,
О море, зовущем в чужие края,
О ласковом море, о счастье и горе,
Пою о тебе я, Одесса моя!
Припев:
Я вижу везде твои ясные зори, Одесса!
Со мною везде твоё небо и море, Одесса!
Ты - в сердце моём! Ты - всюду со мной!
Одесса - мой город родной!
Когда я пою о любви без предела,
О людях, умеющих верить и ждать,
О гроздьях душистых акации белой,
Тебе я спешу эту песню отдать.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из оперетты «Белая акация»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ba9391befb03b3d6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ba9391befb03b3d6','Одесса','Когда я пою о широком просторе,
