INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d8e6ecc70da0080d','Одинокая гармонь','(«Снова замерло всё до рассвета...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/odinokaya_garmon.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Снова замерло всё до рассвета...») | merged_versions: 1','Снова замерло всё до рассвета,
Дверь не скрипнет, не вспыхнет огонь,
Только слышно на улице где-то
Одинокая бродит гармонь...
То пойдёт на поля, за ворота
То обратно вернётся опять,
Словно ищет в потёмках кого-то
И не может никак отыскать...
Веет с поля ночная прохлада,
С яблонь цвет облетает густой...
Ты признайся, кого тебе надо,
Ты скажи гармонист молодой...
Может радость твоя недалёко
Да не знает, её ли ты ждёшь;
Что-ж ты бродишь всю ночь одиноко,
Что-ж ты девушкам спать не даёшь...
История создания песни  &laquo;Одинокая гармонь&raquo;  поэтом Михаилом Исаковским и композитором Борисом Мокроусовым рассказана на страницах  web-архива радиопередачи &laquo;Встреча с песней&raquo; .','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Снова замерло всё до рассвета...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d8e6ecc70da0080d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d8e6ecc70da0080d','Одинокая гармонь','Снова замерло всё до рассвета,
