INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d8e6ecc70da0080d_1322c2212b2f37cb','rpp_d8e6ecc70da0080d','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/odinokaya_garmon.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6d0a2e43795e6d3b','Ой хмелю, мий хмелю',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/21.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','&laquo;Ой хмелю, мий хмелю,
Хмелю зэлэненький,
Дэ ж ты, хмэлю, зиму зимував,
Ш ой не розвивався?&raquo;
&laquo;Зимував я зиму,
Зимував я другу,
Зимував я в лузи на калыни,
Тай не розвивався...&raquo;
&laquo;Ой сну ж мий сыну,
Сыну молодэнький.
Дэ ж ты, сыну, ничку ночував,
Ш ой не роззувався?&raquo;
&laquo;Ночував я ничку,
Ночцвав я другу,
Ночцвав я у той вдовыци,
Шо свататы буду!&raquo;
&laquo;Ой сыну ж, мий сыну,
Ты моя дытино,
Не женыся на той удовыци,
Бо шастя не будэ!
Бо Вдовине сердце
Як осине солнце, -
Воно свитыть, свитыть та не грие,
Все холодом вие.
А дивоче сердце
Як веснянэ солнце, -
Ой хоч воно та й хмарнесеньке,
А все теплэсенькэ&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6d0a2e43795e6d3b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6d0a2e43795e6d3b','Ой хмелю, мий хмелю','&laquo;Ой хмелю, мий хмелю,
