INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6d0a2e43795e6d3b_7318f8610890891c','rpp_6d0a2e43795e6d3b','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/21.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0979be5748492555','Ой, да как хотела меня мать',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/23.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ой, да как хотела меня мать,
Да, за первого отдать.
А тот первый паренёк – неверный,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за второго отдать.
А тот вторый парень – невесёлый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за третьего отдать.
А тот третий – что во поле ветер,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
За четвёртого отдать.
А четвёртый – ни живой, ни мёртвый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за пятого отдать.
А тот пятый – пьяница проклятый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за шёстого отдать.
А тот шёстый – росточком недорослый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за сеемого отдать.
А тот сеемый – красивый, весёлый,
Сам не хотел меня взять.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0979be5748492555'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_0979be5748492555','Ой, да как хотела меня мать','Ой, да как хотела меня мать,
Да, за первого отдать.
А тот первый паренёк – неверный,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за второго отдать.
А тот вторый парень – невесёлый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за третьего отдать.
А тот третий – что во поле ветер,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
За четвёртого отдать.
А четвёртый – ни живой, ни мёртвый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за пятого отдать.
А тот пятый – пьяница проклятый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за шёстого отдать.
А тот шёстый – росточком недорослый,
Ой, не отдай меня, мать.
Ой, да как хотела меня мать,
Да, за сеемого отдать.
А тот сеемый – красивый, весёлый,
Сам не хотел меня взять.');
