INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b6ed27d1b5be3361','Ой, мороз, мороз',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/24.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ой, мороз, мороз,
Не морозь меня,
Не морозь меня, моего коня.
Не морозь меня, моего коня,
Моего коня белогривого.
Моего коня белогривого,
У меня жена, ох, ревнивая.
У меня жена, ох, красавица,
Ждёт меня домой, ждёт печалится.
Я вернусь домой на закате дня.
Обниму жену, напою коня.
Ой, мороз, мороз,
Не морозь меня,
Не морозь меня, моего коня.
Имеются сведения о том, что песня &laquo;Ой, мороз, мороз&raquo; является не русской народной, а авторским произведением певицы, хормейстера, солистки Воронежского русского народного хора Марии Павловны Уваровой (1923-2017), что &laquo;песня была написана ею в декабре 1954 года для дуэта с мужем&raquo; Александром Михайловичем Уваровым (1924-2003). Некоторые источники информации утверждают, что авторами песни являются оба супруга, однако, дескать, в 1959 году в процессе издания грампластинки с этой песней &laquo;из-за халатности авторство не было зафиксировано&raquo; на её этикетке.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b6ed27d1b5be3361'), datetime('now')),datetime('now'));
