INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6926a437e523afc1','Ой, на гори та жныци жнуть',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/25.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ой, на гори та жныци жнуть,
Ой, на гори та жныци жнуть,
А по-пид горою,
Яром-долыною,
Козакы йдуть.
