INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3f3ad885156fd365','Окрасился месяц багрянцем',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (стихи: Адельберт фон Шамиссо *, перевод Дмитрий Минаев, музыка: Яков Пригожий) | Народные песни | https://pesni.retroportal.ru/np2/26.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Окрасился месяц багрянцем,
Где волны шумели у скал.
- Поедем, красотка, кататься,
Давно я тебя поджидал.
- Я еду с тобою охотно,
Я волны морские люблю.
Дай парусу полную волю,
Сама же я сяду к рулю.
- Ты правишь в открытое море,
Где с бурей не справиться нам.
В такую шальную погоду
Нельзя доверяться волнам.
- Нельзя? Почему ж, дорогой мой?
А в прошлой, минувшей судьбе,
Ты помнишь, изменник коварный,
Как я доверялась тебе?
И это сказавши, вонзила
В грудь ножик булатный ему.
Сама с обессиленным сердцем
Нырнула в морскую волну.
Окрасился месяц багрянцем,
Где волны шумели у скал.
- Поедем, красотка, кататься,
Давно я тебя поджидал.
Примечание: * во многих песенниках по-прежнему &laquo;Окрасился месяц багрянцем&raquo; указывают как песню русскую народную.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3f3ad885156fd365'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3f3ad885156fd365','Окрасился месяц багрянцем','Окрасился месяц багрянцем,
