INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9b4c985c3f4922d1','«Он виноват» («Не говорите мне о нём»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Мария Перроте) | Старинные романсы | https://pesni.retroportal.ru/sr2/42.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Не говорите мне о нём:
Ещё былое не забыто;
Он виноват один во всём,
Что сердце бедное разбито.
Ах! Не говорите мне о нём,
Не говорите мне о нём!
Он виноват, что я грустна,
Что верить людям перестала,
Что сердцем я совсем одна,
Что молодой я жить устала.
Ах, не говорите мне о нём,
Не говорите мне о нём!
Зачем напомнили о нём?
Былые дни уж не вернутся!
Всё в прошлом, прошлое всё в нём,
Вот потому и слёзы льются.
Ах! Не говорите мне о нём,
Не говорите мне о нём!
Он виноват, но если б он
Задумал бы вернуться снова,
Забыла б горе я, как сон,
Не упрекнув его ни словом.
Ах! так говорите мне о нём,
Так говорите мне о нём!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9b4c985c3f4922d1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9b4c985c3f4922d1','«Он виноват» («Не говорите мне о нём»)','Не говорите мне о нём:
