INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_7172155138355158','Он так меня любил',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Апухтин, музыка: Пётр Чайковский) | Старинные романсы | https://pesni.retroportal.ru/sr2/44.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Нет, не любила я! Но странная забота
Теснила грудь мою, когда он приходил;
То вся краснела я, боялася чего-то, -
Он так меня любил, он так меня любил!
Чтоб нравиться ему тогда, цветы и те наряды
Я берегла, что он по сердцу находил;
С ним говорила я, его ловила взгляды…
Он так меня любил, он так меня любил!
Но раз он мне сказал: &laquo;В ту рощу в час заката
Придёшь ли?&raquo; - &laquo;Да, приду...&raquo; Но не хватило сил;
Я в рощу не пошла, он ждал меня напрасно!
Он так меня любил, он так меня любил!
Тогда уехал он, сердясь на неудачу;
Несчастный, как меня проклясть он должен был!
Я не увижусь с ним, мне тяжело, я плачу...
Он так меня любил! Он так меня любил!
Он так меня любил! Он так меня любил!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_7172155138355158'), datetime('now')),datetime('now'));
