INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_930672eb3c6ece12','От людей на деревне не спрятаться','(Песня Матвея из фильма «Дело было в Пенькове»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Доризо, музыка: Кирилл Молчанов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/ot_lyudej_na_derevne_ne_spryatatsya_delo_bylo_v_penkove.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня Матвея из фильма «Дело было в Пенькове») | merged_versions: 1','От людей на деревне не спрятаться,
Нет секретов в деревне у нас.
Не сойтись, разойтись, не сосвататься
В стороне от придирчивых глаз.
Ночью в поле такая акустика;
Уж такая у нас тишина.
Скажешь слово любимой у кустика&nbsp;-
Речь твоя всей округе слышна.
Но не бойся, тебя не обидим мы,
Не пугайся земляк земляка.
Здесь держать можно двери открытыми,
Что надёжней любого замка.
За полями, садами, за пасекой
Не уйти от придирчивых глаз.
Тем, кто держит свой камень за пазухой,
Ох, и трудно в деревне у нас.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня Матвея из фильма «Дело было в Пенькове»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_930672eb3c6ece12'), datetime('now')),datetime('now'));
