INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ce9e49820cc6c26f','От улыбки хмурый день светлей','(Песня из мультфильма «Крошка Енот»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пляцковский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/ot_ulybki_hmury_den_svetley.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Крошка Енот») | merged_versions: 1','От улыбки хмурый день светлей,
От улыбки в небе радуга проснётся...
Поделись улыбкою своей,
И она к тебе не раз ещё вернётся.
Припев:
И тогда наверняка, вдруг запляшут облака,
И кузнечик запиликает на скрипке...
С голубого ручейка начинается река,
Ну, а дружба начинается с улыбки.
С голубого ручейка начинается река,
Ну, а дружба начинается с улыбки.
От улыбки солнечной одной
Перестанет плакать самый грустный дождик.
Сонный лес простится с тишиной
И захлопает в зелёные ладоши.
Припев
От улыбки станет всем теплей -
И слону и даже маленькой улитке...
Так пускай повсюду на земле,
Будто лампочки, включаются улыбки!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Крошка Енот»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ce9e49820cc6c26f'), datetime('now')),datetime('now'));
