INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_08914fd51383546c','Отгадай, моя родная',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Толстой, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr2/45.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Отгадай, моя родная, отчего я так грустна,
И сижу всегда одна я у косящата окна?
Отчего с такой заботой каждый день чего-то жду?
Каждый день ищу чего-то и чего-то не найду,
И чего-то не найду!
Лягу ли в постель – не спится, мысли бродят вдалеке,
Голова моя кружится, и сердечушко в тоске.
Отгадай, моя родная, - то любовь или печаль?
Посмотри, я не больная, а мне всё чего-то жаль,
А мне всё чего-то жаль!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_08914fd51383546c'), datetime('now')),datetime('now'));
