INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ede6f23710ecf69d','Отговорила роща золотая',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Есенин, музыка: Григорий Пономаренко) | Старинные романсы | https://pesni.retroportal.ru/sr2/46.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Отговорила роща золотая
Берёзовым, весёлым языком,
И журавли, печально пролетая,
Уж не жалеют больше ни о ком.
Стою один среди равнины голой,
А журавлей относит ветер вдаль,
Я полон дум о юности весёлой,
Но ничего в прошедшем мне не жаль.
Не жаль мне лет, растраченных напрасно,
Не жаль души сиреневую цветь.
В саду горит костёр рябины красной,
Но никого не может он согреть.
Отговорила роща золотая
Берёзовым, весёлым языком,
И журавли, печально пролетая,
Уж не жалеют больше ни о ком.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ede6f23710ecf69d'), datetime('now')),datetime('now'));
