INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4808c6723ec097d9','Отойди',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Бешенцев, музыка: Александр Давыдов) | Старинные романсы | https://pesni.retroportal.ru/sr2/47.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Отойди, не гляди, скройся с глаз ты моих!
Сердце ноет в груди, нету сил никаких
Сердце ноет в груди, нету сил никаких!
Отойди, отойди!
Для меня ли твоя красота, посуди,
Счастья нет у меня, один крест на груди,
Счастья нет у меня, один крест на груди!
Отойди, отойди!
Иль играть хочешь ты наболевшей душой
И всю мощь красоты испытать надо мной,
И всю мощь красоты испытать надо мной?
Отойди, отойди!
Мне блаженства с тобой не дадут, не дадут,
А тебя с красотой продадут, продадут,
А тебя с красотой продадут, продадут!
Отойди, отойди!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4808c6723ec097d9'), datetime('now')),datetime('now'));
