INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_4808c6723ec097d9_ba924a6ab8777353','rpp_4808c6723ec097d9','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr2/47.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1c0f86b53ec5a344','Отцвели хризантемы',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Шумский, музыка: Николай Харито) | Старинные романсы | https://pesni.retroportal.ru/sr2/48.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','В том саду, где мы с Вами встретились,
Ваш любимый куст хризантем расцвел,
И в моей груди расцвело тогда
Чувство яркое нежной любви...
Отцвели уж давно хризантемы в саду,
Но любовь все живет в моем сердце больном...
Опустел наш сад, Вас давно уж нет,
Я брожу один, весь измученный,
И невольные слёзы катятся
Пред увядшим кустом хризантем...
Отцвели уж давно хризантемы в саду,
Но любовь все живет в моем сердце больном...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1c0f86b53ec5a344'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1c0f86b53ec5a344','Отцвели хризантемы','В том саду, где мы с Вами встретились,
