INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_46093eeef6e41cbe','Отчего затуманился взор мой слезой',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Э. Орлова, музыка: Д. Николаев) | Старинные романсы | https://pesni.retroportal.ru/sr3/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Отчего затуманился взор мой слезой
И сжимается сердце в груди,
Отчего, изнывая душою больной,
Я не жду ничего впереди?
Было время, с надеждой и верой в добро
Билось радостно сердце моё.
Тогда думалось мне, что исчезло то зло,
Что печали и скорбь далеко!
И верилось мне, что судьба мне пошлёт
Беспредельное счастье в любви,
И верилось мне, что любовь не пройдёт,
И что светлые дни впереди.
Но, увы, не сбылися надежды мои,
Не видать мне уж радостных дней!
Лишь обман встречу я вместо чистой любви,
Только недругов – вместо друзей!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_46093eeef6e41cbe'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_46093eeef6e41cbe','Отчего затуманился взор мой слезой','Отчего затуманился взор мой слезой
