INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4952cf1a3df45f12','Отчий дом','(«Как живёшь ты, отчий дом...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Андрей Дементьев, музыка: Евгений Мартынов) | Патриотические песни | https://pesni.retroportal.ru/rodina/otchiy_dom.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Как живёшь ты, отчий дом...») | merged_versions: 1','Радость или грусть нас ждут потом...
Но всему начало&nbsp;- отчий дом.
Там у колыбели матери нам пели
Песню любви.
Вновь сейчас во мне звучит она.
Ждёт меня наш домик в три окна.
Близко ли, далеко&nbsp;- свет родимых окон
Вечно не померкнет для меня.
Припев:
Как живёшь ты, отчий дом,
В светлой грусти о былом?
Я у дома, у крыльца родного,
Встречи жду и вновь пою.
Здравствуй, милый отчий дом!
Будь за нас спокоен.
Где б я ни был&nbsp;- ты всегда, всегда со мною.
Я согрет твоим теплом.
Сколько бы на свете мне ни жить,&nbsp;-
Век его доверьем дорожить.
Но уж так ведётся, юность расстается
С домом родным.
Годы, словно сны, над ним летят,
Я ловлю душой отцовский взгляд.
Мама дни и ночи ждёт желанной почты.
Помните об этом, сыновья!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Как живёшь ты, отчий дом...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4952cf1a3df45f12'), datetime('now')),datetime('now'));
