INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1bf5e3d4ed60ffca','Очи чёрные',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Гребёнка, музыка: Флориан Герман, Адальджизо Феррарис) | Старинные романсы | https://pesni.retroportal.ru/sr3/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Очи чёрные, очи страстные!
Очи жгучие и прекрасные!
Как люблю я вас! Как боюсь я вас!
Знать, увидел вас я в недобрый час!
Ох, недаром вы глубины темней!
Вижу траур в вас по душе моей,
Вижу пламя в вас я победное:
Сожжено на нём сердце бедное.
Но не грустен я, не печален я,
Утешительна мне судьба моя:
Всё, что лучшего в жизни бог дал нам,
В жертву отдал я огневым глазам!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1bf5e3d4ed60ffca'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1bf5e3d4ed60ffca','Очи чёрные','Очи чёрные, очи страстные!
Очи жгучие и прекрасные!
Как люблю я вас! Как боюсь я вас!
Знать, увидел вас я в недобрый час!
