INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b89905afafd50f7f','Первая любовь','(«Скоро ночь проходит лунная...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лидия Некрасова, музыка: Александр Долуханян) | Эстрадные песни | https://pesni.retroportal.ru/estrada/pervaya_lyubov.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Скоро ночь проходит лунная...») | merged_versions: 1','Обласкала Москву весна...
Тёплой ночью пойдём гулять.
Люди спят, ну а нам не до сна&nbsp;-
Столько надо друг другу сказать...
Постоим над Москвой-рекой,
Поглядим на высотный дом...
Он построен для нас с тобой
И учиться мы будем в нём!
Припев:
Скоро ночь проходит лунная...
День счастливый вспыхнет вновь...
Озарила годы юные
Первая любовь!
Вот и ночи настал конец...
Разливается свет зари...
Розовеет чудесный дворец -
На него ещё раз посмотри!
Дни пройдут, пролетят года&nbsp;-
Не забыть нам рассветный час!
Не забыть никогда-никогда
Те мечты, что сроднили нас...
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Скоро ночь проходит лунная...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b89905afafd50f7f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b89905afafd50f7f','Первая любовь','Обласкала Москву весна...
