INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b89905afafd50f7f_c154ec8c009a2472','rpp_b89905afafd50f7f','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/pervaya_lyubov.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_17e38a40482379fa','Первоклашка','(Песня из фильма «Утро без отметок»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Юрий Энтин, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/pervoklashka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из фильма «Утро без отметок») | merged_versions: 1','Первоклашка, первоклассник
У тебя сегодня праздник!
Он серьёзный и весёлый&nbsp;-
Встреча первая со школой.
Был вчера ещё только ребёнок,
Ничего не поделаешь тут.
Называли тебя дошколёнок,
А теперь первоклашкой зовут.
Всё потом в образцовом порядке,
И вопрос ни один не возник.
Ни помарочки нету в тетрадке,
Чист как синее небо дневник.
Пусть на плечи ложатся заботы,
Но тебе ли о них унывать?
С понедельника и до субботы
Будешь знания ты добывать.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из фильма «Утро без отметок»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_17e38a40482379fa'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_17e38a40482379fa','Первоклашка','Первоклашка, первоклассник
