INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e1209cce6d312d0c','Перевоз Дуня держала',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/27.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Перевоз Дуня держала,
Держала, держала,
Перевозчика наняла,
Наняла, наняла.
В роще калина,
Тёмно, не видно
Соловушки поют.
Пришёл к Дуне батюшка,
Батюшка, батюшка:
&laquo;Перевези меня, Дунюшка,
Дунюшка, Дунюшка!&raquo;
Припев
&laquo;А я тебя не ждала,
Не ждала, не ждала.
Перевозчика угнала,
Угнала, угнала&raquo;.
Припев
Пришёл к Дуне милый друг,
Милый друг, милый друг:
&laquo;Перевези меня, Дуня, в луг,
В зелен луг, в зелен луг!&raquo;
Припев
&laquo;А я тебя, мой дружок,
Всё ждала, всё ждала,
Перевозчика наняла,
Наняла, наняла&raquo;.
В роще калина,
Все стало видно,
И соловушки поют.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e1209cce6d312d0c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e1209cce6d312d0c','Перевоз Дуня держала','Перевоз Дуня держала,
