INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bdc403f3a9a2bc98','«Пересохни, Волга-речка» («Волжские страдания»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/28.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Пересохни, Волга-речка,
Перестань болеть, сердечко.
Он завлёк меня речами,
Я не стала спать ночами.
Дарю платок синей каймы,
Возьмёшь в руки – меня вспомни.
Ой ты, милый, вспомни, вспомни,
Как гуляли ночки тёмны.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bdc403f3a9a2bc98'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bdc403f3a9a2bc98','«Пересохни, Волга-речка» («Волжские страдания»)','Пересохни, Волга-речка,
Перестань болеть, сердечко.
Он завлёк меня речами,
Я не стала спать ночами.
Дарю платок синей каймы,
Возьмёшь в руки – меня вспомни.
Ой ты, милый, вспомни, вспомни,
Как гуляли ночки тёмны.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_bdc403f3a9a2bc98_e8c572b4c123dffe','rpp_bdc403f3a9a2bc98','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/28.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_94a4881dd737dac6','Песенка Буратино','(Песня из музыкального фильма «Приключения Буратино»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Юрий Энтин, музыка: Алексей Рыбников) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_buratino.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из музыкального фильма «Приключения Буратино») | merged_versions: 1','Кто доброй сказкой входит в дом?
Кто с детства каждому знаком?
Кто не учёный, не поэт,
А покорил весь белый свет,
Кого повсюду узнают,
Скажите, как его зовут?
Бу! Ра! Ти! Но! Буратино!
На голове его колпак,
Но околпачен будет враг,
Злодеям он покажет нос
И рассмешит друзей до слёз,
Он очень скоро будет тут,
Скажите, как его зовут?
Бу! Ра! Ти! Но! Буратино!
Он окружён людской молвой,
Он не игрушка&nbsp;- он живой!
В его руках от счастья ключ,
И потому он так везуч,
Все песенки о нём поют,
Скажите, как его зовут!
Бу! Ра! Ти! Но! Буратино!
Я убедился нынче сам,
Что надо верить чудесам.
Понять всё это мне помог
Один весёлый паренёк.
Ребята, не сочтя за труд,
Скажите, как его зовут?
Бу! Ра! Ти! Но! Буратино!
Есть у меня теперь сынок.
Я буду с ним не очень строг.
Он из полена вдруг возник&nbsp;-
Великий юный озорник.
Таких, как он, повсюду ждут.
Скажите, как его зовут?
Бу! Ра! Ти! Но! Буратино!
Свободу куклам он принёс.
Ему отныне предан пёс.
Ах, не опишет и перо,
Какой восторг в груди Пьеро.
И все же, он&nbsp;- великий плут.
Скажите, как его зовут?
Бу! Ра! Ти! Но! Буратино!
И Дуремар, и Карабас
Мной одурачены не раз.
Лиса хитра и кот-прохвост,
Но ведь и я не так-то прост,
Недаром обо мне поют.
Все знают, что меня зовут:
Бу! Ра! Ти! Но! Буратино!
Бу! Ра! Ти! Но! Бу! Ра! Ти! Но!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из музыкального фильма «Приключения Буратино»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_94a4881dd737dac6'), datetime('now')),datetime('now'));
