INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_98d8bbde325d08ec','Песенка Деда Мороза','(Песня из мультфильма «Дед Мороз и лето»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Юрий Энтин, музыка: Евгений Крылатов) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_deda_moroza.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Дед Мороз и лето») | merged_versions: 1','Последний лист календаря
Остался на стене.
Весь год трудился я не зря!
Пора в дорогу мне!
Чтоб ёлочка под Новый год
Надела свой наряд,
Игрушки я беру в поход,
Подарки для ребят.
Проеду сотни вёрст подряд,
Чтоб в ночь под Новый год
Надела ёлочка наряд
И встала в хоровод.
Подарки детям я вручу,
Ведь нет меня добрей!
Награды лучшей не хочу,
Чем радость всех детей!
Бывал в гостях я у ребят
И видел наяву
Зелёный лес, зелёный сад,
Зелёную траву!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Дед Мороз и лето»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_98d8bbde325d08ec'), datetime('now')),datetime('now'));
