INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a9453a6a72fa25c6','Песенка кота Леопольда','(Песня из мультфильма «Прогулка кота Леопольда»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Аркадий Хайт, музыка: Борис Савельев) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_kota_leopolda.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Прогулка кота Леопольда») | merged_versions: 1','Кручу, кручу, кручу педали, кручу,
С горы, с горы, с горы как птица лечу.
Спешу, спешу, спешу, спешу налегке
Навстречу радуге&nbsp;- дуге.
Пусть, пусть дорога вдаль летит,
Грусть пусть на сердце не лежит,
Мне всё на свете по плечу,
И с песней этой качу по свету,
Качу, качу куда хочу.
Терпи, терпи, терпи кагда тяжело,
Скрипи, скрипи ты подо мною седло,
Не смей, не смей, не смей на миг ослабеть,
Сумей себя преодолеть.
Лечу, лечу, лечу не знаю куда,
Хочу, хочу чтоб это было всегда,
Сильней, сильней, сильней лишь зубы сомкну,
Но я назад не поверну!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Прогулка кота Леопольда»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a9453a6a72fa25c6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a9453a6a72fa25c6','Песенка кота Леопольда','Кручу, кручу, кручу педали, кручу,
С горы, с горы, с горы как птица лечу.
Спешу, спешу, спешу, спешу налегке
Навстречу радуге&nbsp;- дуге.
Пусть, пусть дорога вдаль летит,
Грусть пусть на сердце не лежит,
Мне всё на свете по плечу,
И с песней этой качу по свету,
Качу, качу куда хочу.
Терпи, терпи, терпи кагда тяжело,
Скрипи, скрипи ты подо мною седло,
Не смей, не смей, не смей на миг ослабеть,
