INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a5bf253df6d646c8','Песенка крокодила Гены','(Песня из мультфильма «Чебурашка»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Тимофеевский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_krokodila_geny.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Чебурашка») | merged_versions: 1','Пусть бегут неуклюже
Пешеходы по лужам,
А вода по асфальту рекой.
И неясно прохожим
В этот день непогожий,
Почему я весёлый такой?
Припев:
А я играю на гармошке
У прохожих на виду.
К сожаленью, день рожденья
Только раз в году.
Прилетит вдруг волшебник
В голубом вертолёте
И бесплатно покажет кино.
С днём рожденья поздравит
И, наверно, оставит
Мне в подарок пятьсот эскимо.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Чебурашка»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a5bf253df6d646c8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a5bf253df6d646c8','Песенка крокодила Гены','Пусть бегут неуклюже
