INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_993a66d6c6c16d9b','Песенка Львёнка и Черепахи','(Песня из мультфильма «Как Львёнок и Черепаха пели песню»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Козлов, музыка: Геннадий Гладков) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_lvenka_i_cherepahi.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Как Львёнок и Черепаха пели песню») | merged_versions: 1','Я на солнышке сижу,
Я на солнышко гляжу...
Всё сижу и сижу-у
И на солнышко гляжу.
-&nbsp;Не &laquo;сижу&raquo;, а &laquo;лежу&raquo;...
-&nbsp;Это ты лежишь, а я сижу!
Носорог, рог, рог идёт,
Крокодил, дил, дил плывёт.
Только я всё сижу (лежу)
И на солнышко гляжу...
Рядом львёночек лежит
И ушами шевелит,
Только я я всё лежу
И на львёнка не гляжу.
-&nbsp;И всё-таки надо петь&nbsp;- &laquo;лежу&raquo;!
-&nbsp;И-и-и рааз...
Я на солнышке лежу,
Я на солнышко гляжу...
Всё лежу и лежу
И на солнышко гляжу.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Как Львёнок и Черепаха пели песню»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_993a66d6c6c16d9b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_993a66d6c6c16d9b','Песенка Львёнка и Черепахи','Я на солнышке сижу,
