INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_12adaabd04129198','Песенка мамонтёнка','(Песня из мультфильма «Мама для мамонтёнка»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Дмитрий Непомнящий, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_mamontenka.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Мама для мамонтёнка») | merged_versions: 1','По синему морю, к зелёной земле
Плыву я на белом своём корабле.
На белом своём корабле,
На белом своём корабле.
Меня не пугают ни волны, ни ветер,&nbsp;-
Плыву я к единственной маме на свете.
Плыву я сквозь волны и ветер
К единственной маме на свете.
Плыву я сквозь волны и ветер
