INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2929fe9d4d4bf4a1','Песенка про папу','(«Папа может, папа может быть кем угодно...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Танич, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_pro_papu.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: («Папа может, папа может быть кем угодно...») | merged_versions: 1','Сколько песен мы с вами вместе
Спели маме моей родной,
А про папу до этой песни
Песни не было ни одной!
Припев:
Папа может, папа может
Всё, что угодно,
Плавать брассом, спорить басом,
Дрова рубить!
Папа может, папа может
Быть кем угодно,
Только мамой, только мамой
Не может быть!
Только мамой, только мамой
Не может быть!
Припев
Папа в доме&nbsp;- и дом исправный,
Газ горит и не гаснет свет.
Папа в доме, конечно, главный,
Если мамы случайно нет!
Припев
И с задачкою трудной самой
Папа справится&nbsp;- дайте срок!
Мы потом уж решаем с мамой
Все, что папа решить не смог!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(«Папа может, папа может быть кем угодно...»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2929fe9d4d4bf4a1'), datetime('now')),datetime('now'));
