INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ac564c6e1c183fdb','Песенка Фунтика','(Песня из мультфильма «Приключения поросёнка Фунтика»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Валерий Шульжик, музыка: Владимир Львовский) | Песни для детей | https://pesni.retroportal.ru/deti/pesenka_porosenka_funtika.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из мультфильма «Приключения поросёнка Фунтика») | merged_versions: 1','Хорошо бродить по свету
С карамелькой за щекой.
А ещё одну для друга
Взять в кармашке про запас.
Потому что, потому что
Всех нужнее и дороже,
Всех доверчивей и строже
В этом мире доброта.
Хорошо бродить по улице
С теплым кроликом за пазухой,
Принимая как награду
Сердца маленького стук.
Хорошо бродить по городу
С белым голубем в цилиндре,
С красным шариком на ниточке,
И с улыбкой до ушей.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из мультфильма «Приключения поросёнка Фунтика»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ac564c6e1c183fdb'), datetime('now')),datetime('now'));
