INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d81b4d5f85c6cefc','Песенка Чебурашки','(Песня из музыкальной аудиопостановки «Чебурашка»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Эдуард Успенский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/pesnya_cheburashki.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из музыкальной аудиопостановки «Чебурашка») | merged_versions: 1','Я был когда-то странной
Игрушкой безымянной,
К которой в магазине
Никто не подойдёт.
Теперь я Чебурашка,
Мне каждая дворняжка
При встрече сразу
Лапу подаёт!
Мне не везло сначала,
И даже так бывало:
Ко мне на день рожденья
Никто не приходил.
Теперь я вместе с Геной
Он необыкновенный,
Он самый лучший
В мире крокодил!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из музыкальной аудиопостановки «Чебурашка»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d81b4d5f85c6cefc'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d81b4d5f85c6cefc','Песенка Чебурашки','Я был когда-то странной
