В мире крокодил!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d81b4d5f85c6cefc_1fa4e942f2971b44','rpp_d81b4d5f85c6cefc','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/pesnya_cheburashki.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_206e31c908aaee84','Песня мщения','(«К оружью зовёт священная месть! За волю! За счастье! За честь!..»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Виктор Винников, музыка: Матвей Блантер) | Песни военных лет | https://pesni.retroportal.ru/vov/pesnya_msheniya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («К оружью зовёт священная месть! За волю! За счастье! За честь!..») | merged_versions: 1','Вставайте, друзья! Вперёд, бесстрашно в бой!
Земля кругом залита огнём,
Бандит озверелый творит разбой,
Всех грабя и ночью, и днём.
Он хочет отнять сокровища твои&nbsp;-
Свободу, землю, и честь, и кров,
Он жаждет весь мир потопить в крови
И стать властелином рабов.
Припев:
К оружью зовёт священная месть!
За волю! За счастье! За честь!
Ты слышишь, идущий на бой:
Все народы с тобой!
За позор и за кровь отомсти!
Злых собак фашистских бей
И прах развей!
Всем народам ты мир возврати!
Железной пятой затоптаны поля,
В огне дымятся твой дом и двор,
Всё то, что могла уродить земля,
Уносит безжалостный вор.
По рекам из слёз, дорогам из костей
Крадётся зверь, занеся топор,
Он рубит на части твоих детей,
Жену отдаёт на позор.
Припев
Вставайте, друзья, на бой за честь свою,
Навек расправьтесь за всё с врагом!
Нам лучше погибель найти в бою,
Чем жить у фашиста рабом!
Бесстрашно иди на бешенного пса,
Коли его и руби, и рви!
Пускай за злодейства свои он сам
В своей захлебнётся крови!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«К оружью зовёт священная месть! За волю! За счастье! За честь!..»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_206e31c908aaee84'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_206e31c908aaee84','Песня мщения','Вставайте, друзья! Вперёд, бесстрашно в бой!
