INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_206e31c908aaee84_d333c9376ebab75f','rpp_206e31c908aaee84','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/pesnya_msheniya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4b668554e44c281d','Песня о бушлате','(«Ты видел Севастополь, ты знаешь Ленинград...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Николай Флёров, музыка: Борис Терентьев) | Песни военных лет | https://pesni.retroportal.ru/vov/pesnya_o_bushlate.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Ты видел Севастополь, ты знаешь Ленинград...») | merged_versions: 1','От волжских круч до крепостей Кронштадта,
От южных скал до северной земли
Мы в бескозырках и в морских бушлатах
Дорогой легендарною прошли.
И с той поры тех памятных походов
Я в море дальнем и на берегу,
Как боевую славу мореходов,
Тебя, бушлат любимый, берегу.
Припев:
Поговорим с тобой наедине...
Ты был со мной в бою&nbsp;- в дыму, в огне.
Ты видел Севастополь,
Ты знаешь Ленинград,
Мой славный морской бушлат.
Я помню час: декабрьскою пургою
В бой за Москву шагал морской отряд.
Я ранен был. Тогда меня тобою
Друзья укрыли, дорогой бушлат.
И сразу мне теплей и легче стало,
Я сквозь дремоту слышал пушек гром.
И нам с тобою сердце подсказало,
Что все вперёд на запад мы идём.
Припев
Тот день настал: военные метели
Утихли над волной и над землёй.
Во фронтовых бушлатах и шинелях
Мы шли на праздник дружною семьёй.
Дошёл и я до гавани далёкой,
Где долго ждали и жена и мать.
И лишь тогда подруге кареокой
С усталых плеч тебя позволил снять.
Припев
Шумят хлеба, в печах металл вскипает,
Гудит в плотинах волжская вода,
К высотам счастья радостно шагает
Отчизна славы, мира и труда.
Но если вновь, безумием объятый,
Решится враг на нас пойти войной,
То выйдем мы в шинелях и бушлатах,
Чтоб дать ему последний грозный бой.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Ты видел Севастополь, ты знаешь Ленинград...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4b668554e44c281d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4b668554e44c281d','Песня о бушлате','От волжских круч до крепостей Кронштадта,
