INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_58ce6aa4f0845f97_2122e6661130e704','rpp_58ce6aa4f0845f97','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/pesnya_o_volge.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c8dacab6926e636c','Песня о далёкой Родине','(песня из телефильма «Семнадцать мгновений весны»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Роберт Рождественский, музыка: Микаэл Таривердиев) | Патриотические песни | https://pesni.retroportal.ru/rodina/pesnya_o_dalekoj_rodine.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (песня из телефильма «Семнадцать мгновений весны») | merged_versions: 1','Я прошу: хоть ненадолго,
Боль моя, ты покинь меня.
Облаком, сизым облаком
Ты полети к родному дому,
Отсюда к родному дому.
Берег мой, покажись вдали
Краешком, тонкой линией.
Берег мой, берег ласковый,
Ах, до тебя, родной, доплыть бы,
Доплыть бы хотя б когда-нибудь.
Где-то далеко, очень далеко
Идут грибные дожди.
Прямо у реки, в маленьком саду
Созрели вишни, склонясь до земли.
Где-то далеко в памяти моей
Сейчас, как в детстве, тепло,
Хоть память укрыта
Такими большими снегами.
Ты, гроза, напои меня
Допьяна, да не до смерти.
Вот опять, как в последний раз,
Я всё гляжу куда-то в небо,
Как будто ищу ответа...
Я прошу: хоть ненадолго,
Боль моя, ты покинь меня.
Облаком, сизым облаком
Ты полети к родному дому,
Отсюда к родному дому.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(песня из телефильма «Семнадцать мгновений весны»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c8dacab6926e636c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c8dacab6926e636c','Песня о далёкой Родине','Я прошу: хоть ненадолго,
