INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6b21519d624ead4f','Песня о Днепре','(«У прибрежных лоз, у высоких круч...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Марк Фрадкин) | Песни военных лет | https://pesni.retroportal.ru/vov/pesnya_o_dnepre.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («У прибрежных лоз, у высоких круч...») | merged_versions: 1','У прибрежных лоз, у высоких круч
И любили мы и росли.
Ой, Днипро, Днипро, ты широк, могуч,
Над тобой летят журавли.
Ты увидел бой, Днепр-отец река,
Мы в атаку шли под горой.
Кто погиб за Днепр, будет жить века,
Коль сражался он как герой.
Враг напал на нас, мы с Днепра ушли.
Смертный бой гремел, как гроза.
Ой, Днипро, Днипро, ты течёшь вдали,
И волна твоя как слеза.
Из твоих стремнин ворог воду пьёт,
Захлебнётся он той водой.
Славный день настал, мы идём вперёд
И увидимся вновь с тобой.
Кровь фашистских псов пусть рекой течёт,
Враг советский край не возьмёт.
Как весенний Днепр, всех врагов сметёт
Наша армия, наш народ.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«У прибрежных лоз, у высоких круч...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6b21519d624ead4f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6b21519d624ead4f','Песня о Днепре','У прибрежных лоз, у высоких круч
И любили мы и росли.
Ой, Днипро, Днипро, ты широк, могуч,
