INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_416c4f02e64ceb7e','Песня о Партии','(«Славой овеяна, волею спаяна...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Александр Александров) | Патриотические песни | https://pesni.retroportal.ru/rodina/pesnya_o_partii.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Славой овеяна, волею спаяна...») | merged_versions: 1','Страны небывалой свободные дети,
Сегодня мы гордую песню поём
О партии самой могучей на свете,
О самом большом человеке своём.
Припев:
Славой овеяна, волею спаяна,
Крепни и здравствуй во веки веков
Партия Ленина, партия Сталина
Мудрая партия большевиков!
Страну Октября создала на земле ты
Могучую Родину вольных людей.
Стоит как утёс государство Советов
Рождённое силой и правдой твоей.
Припев
Изменников подлых гнилую породу
Ты грозно сметаешь с пути своего.
Ты гордость народа, ты мудрость народа,
Ты сердце народа и совесть его.
Припев
И Маркса и Энгельса пламенный гений
Предвидел коммуны грядущий восход.
Дорогу к свободе наметил нам Ленин
И Сталин великий по ней нас ведёт.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Славой овеяна, волею спаяна...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_416c4f02e64ceb7e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_416c4f02e64ceb7e','Песня о Партии','Страны небывалой свободные дети,
