INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_416c4f02e64ceb7e_49a5e9aa6a6c02ae','rpp_416c4f02e64ceb7e','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/pesnya_o_partii.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_34b4533f3e412dda','Песня о Родине','(«Широка страна моя родная...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/shiroka_strana_moya_rodnaya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Широка страна моя родная...») | merged_versions: 1','Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
От Москвы до самых до окраин,
С южных гор до северных морей
Человек проходит, как хозяин
Необъятной Родины своей.
Всюду жизнь и вольно и широко,
Точно Волга полная, течёт.
Молодым везде у нас дорога,
Старикам везде у нас почёт.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
Наши нивы глазом не обшаришь,
Не упомнишь наших городов,
Наше слово гордое&nbsp;- товарищ&nbsp;-
Нам дороже всех красивых слов.
С этим словом мы повсюду дома.
Нет для нас ни чёрных, ни цветных.
Это слово каждому знакомо,
С ним везде находим мы родных.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
За столом никто у нас не лишний,
По заслугам каждый награждён,
Золотыми буквами мы пишем
Всенародный Сталинский закон.
Этих слов величие и славу
Никакие годы не сотрут:
Человек всегда имеет право
На ученье, отдых и на труд.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
Над страной весенний ветер веет.
С каждым днём всё радостнее жить,
И никто на свете не умеет
Лучше нас смеяться и любить.
Но сурово брови мы насупим,
Если враг захочет нас сломать,
Как невесту, Родину мы любим,
Бережём, как ласковую мать.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Широка страна моя родная...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_34b4533f3e412dda'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_34b4533f3e412dda','Песня о Родине','Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
От Москвы до самых до окраин,
С южных гор до северных морей
Человек проходит, как хозяин
Необъятной Родины своей.
Всюду жизнь и вольно и широко,
Точно Волга полная, течёт.
Молодым везде у нас дорога,
Старикам везде у нас почёт.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
Наши нивы глазом не обшаришь,
Не упомнишь наших городов,
Наше слово гордое&nbsp;- товарищ&nbsp;-
Нам дороже всех красивых слов.
С этим словом мы повсюду дома.
Нет для нас ни чёрных, ни цветных.
Это слово каждому знакомо,
С ним везде находим мы родных.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
За столом никто у нас не лишний,
По заслугам каждый награждён,
Золотыми буквами мы пишем
Всенародный Сталинский закон.
Этих слов величие и славу
Никакие годы не сотрут:
Человек всегда имеет право
На ученье, отдых и на труд.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.
Над страной весенний ветер веет.
С каждым днём всё радостнее жить,
И никто на свете не умеет
Лучше нас смеяться и любить.
Но сурово брови мы насупим,
Если враг захочет нас сломать,
Как невесту, Родину мы любим,
Бережём, как ласковую мать.
Широка страна моя родная,
Много в ней лесов, полей и рек!
Я другой такой страны не знаю,
Где так вольно дышит человек.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_34b4533f3e412dda_f624a3fa365afe99','rpp_34b4533f3e412dda','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/shiroka_strana_moya_rodnaya.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e437f403b6a196b3','Песня о снежинке','(Песня из кинофильма «Чародеи»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Леонид Дербенёв, музыка: Евгений Крылатов) | Песни для детей | https://pesni.retroportal.ru/deti/pesnya_o_snezhinke.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из кинофильма «Чародеи») | merged_versions: 1','Когда в дом входит год молодой,
А старый уходит вдаль,
Снежинку хрупкую спрячь в ладонь,
Желание загадай.
Смотри с надеждой в ночную синь,
Некрепко ладонь сжимай.
И всё, о чём мечталось, проси,
Загадывай и желай!
Припев:
И Новый год,
Что вот-вот настанет,
Исполнит вмиг мечту твою,
Если снежинка не растает,
В твоей ладони не растает,
Пока часы двенадцать бьют,
Пока часы двенадцать бьют!
Когда в дом входит год молодой,
А старый уходит прочь,
Дано мечте свершиться любой -
Такая уж это ночь.
Затихнет всё и замрёт вокруг
В предверии новых дней,
И обернётся снежинка вдруг
Жар-птицей в руке твоей.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из кинофильма «Чародеи»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e437f403b6a196b3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e437f403b6a196b3','Песня о снежинке','Когда в дом входит год молодой,
