INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_e437f403b6a196b3_bad79de88c2edc25','rpp_e437f403b6a196b3','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/pesnya_o_snezhinke.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_43bf762497ff70f6','Песня о Чижовке','(«На миг, на минуточку вспомним, товарищ...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Яков Шведов, музыка: Исаак Дунаевский) | Песни военных лет | https://pesni.retroportal.ru/vov/pesnya_o_chizhovke.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («На миг, на минуточку вспомним, товарищ...») | merged_versions: 1','На миг, на минуточку вспомним, товарищ,
Как бой за Чижовку вели.
Мы шли в наступленье при свете пожарищ,
То склады горели вдали.
Предместье Чижовка. Задание ясно.
Брать штурмом пришлось каждый дом.
На улице Светлой, на улице Красной
Врага мы встречали огнём.
Припев:
Штыком и гранатой, солдатской сноровкой
Мы взяли немало преград.
Мы знали, сражаясь за нашу Чижовку:
Ведём бой за свой Сталинград!
Гремела грозою пять дней канонада,
Стал чёрным вокруг небосклон.
Сквозь пламя повёл комиссар Виноградов
Без страха на штурм батальон.
При вспышке ракет по условному знаку
В сражение танки вошли.
Мы ринулись тотчас за ними в атаку
За счастье советской земли.
Припев
Сверкали огнём орудийные дула,
Сметая фашистов огнём...
Вошли мы в Чижовку, в лицо нам пахнуло
Привольным донским ветерком.
Нигде никогда нам не знать остановки,
Дорога одна нам: вперёд!
Наш бой за Чижовку, как бой за Каховку,
Поймет и оценит народ.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«На миг, на минуточку вспомним, товарищ...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_43bf762497ff70f6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_43bf762497ff70f6','Песня о Чижовке','На миг, на минуточку вспомним, товарищ,
