INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_43bf762497ff70f6_7809bcd03f75d2c0','rpp_43bf762497ff70f6','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/pesnya_o_chizhovke.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c6d6898910002e44','Песня про Катюшу','(«И на море, и на суше, и по дорогам фронтовым...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Владимир Захаров) | Песни военных лет | https://pesni.retroportal.ru/vov/pesnya_pro_katyushu.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («И на море, и на суше, и по дорогам фронтовым...») | merged_versions: 1','И на море, и на суше,
И по дорогам фронтовым
Ходит русская &laquo;Катюша&raquo;,
Ходит шагом боевым.
Немцам Главный штаб прикажет
Эх, чтобы шли они вперёд;
Эх, так &laquo;Катюша&raquo; слово скажет&nbsp;-
Как метлою, скажем, подметёт.
Налетит &laquo;Катюша&raquo; вихрем&nbsp;-
Эх, чем её остановить!
Эх, ты задумал, Гитлер, &laquo;Тигров&raquo;
На &laquo;Катюшу&raquo;, скажем, натравить.
Но такие им гостинцы
Эх, приготовила она,
Что осталась от зверинца
Только, скажем, &laquo;химия&raquo; одна!
У красавицы &laquo;Катюши&raquo;
Эх, всё выходит в аккурат!
&laquo;Словно рыбу немцев глушит&raquo;&nbsp;-
Про &laquo;Катюшу&raquo;, скажем, говорят.
Говорят, и после смерти
Эх, слышат немцы грозный шквал,
Эх, и что даже на том свете
Лезут, скажем, прятаться в подвал!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«И на море, и на суше, и по дорогам фронтовым...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c6d6898910002e44'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c6d6898910002e44','Песня про Катюшу','И на море, и на суше,
И по дорогам фронтовым
