INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8bf4c3f34a110a76','Песня смелых','(«Стелются чёрные тучи, молнии в небе снуют...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Алексей Сурков, музыка: Виктор Белый) | Песни военных лет | https://pesni.retroportal.ru/vov/pesnya_smelyh.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Стелются чёрные тучи, молнии в небе снуют...») | merged_versions: 1','Стелются чёрные тучи,
Молнии в небе снуют,
В облаке пыли летучей
Трубы тревогу поют.
С бандой фашистов сразиться
Смелых Отчизна зовёт.
Смелого пуля боится,
Смелого штык не берёт.
Ринулись ввысь самолёты,
Двинулся танковый строй,
С песней стрелковые роты
Вышли за Родину в бой.
Песня - крылатая птица&nbsp;-
Смелых скликает в поход.
Смелого пуля боится,
Смелого штык не берёт.
Славой бессмертной покроем
В битвах свои имена.
Только отважным героям
Радость победы дана.
Смелый к победе стремится,
Смелым&nbsp;- дорога вперёд.
Смелого пуля боится,
Смелого штык не берёт.
Смелый дерётся с врагами,
Жизни своей не щадя,
Смелый проносит, как знамя,
Светлое имя вождя.
Смелыми Сталин гордится,
Смелого любит народ,
Смелого пуля боится,
Смелого штых не берёт!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Стелются чёрные тучи, молнии в небе снуют...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8bf4c3f34a110a76'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8bf4c3f34a110a76','Песня смелых','Стелются чёрные тучи,
