INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_dbfbb772e7c05f01','Песня Снеговика','(Песня из фильма «Тайна Снежной королевы»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Вадим Коростылёв, музыка: Марк Минков) | Песни для детей | https://pesni.retroportal.ru/deti/pesnya_snegovika.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из фильма «Тайна Снежной королевы») | merged_versions: 1','Знает каждый снеговик -
Снеговика лепят дети лишь на миг,
Не на века.
Лепят дети лишь на миг,
Лепят дети лишь на миг,
Лепят дети лишь на миг,
Не на века.
Снеговик это значит,
Что он вылеплен из снега,
Это всем давно известно,
Хоть кричи, а хоть молчи.
Снеговик зимой не плачет,
Он заплачет, если с неба,
Если с неба, если с неба
