INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_78c47e3695bdc10a_f56dca5d6ff2b336','rpp_78c47e3695bdc10a','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/06.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9cd3f2de79a289b2','По Ангаре','(«Девчонки танцуют на палубе»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Гребенников и Николай Добронравов, музыка: Александра Пахмутова) | Эстрадные песни | https://pesni.retroportal.ru/estrada/devchonki_tancuyut_na_palube.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Девчонки танцуют на палубе») | merged_versions: 1','Чуть охрипший гудок парохода
Уплывает в таёжную тьму.
Две девчонки танцуют на палубе,
Звёзды с неба летят на корму.
Припев:
А река бежит, зовёт куда-то,
Плывут сибирские девчата
Навстречу утренней заре
По Ангаре,
По Ангаре.
Верят девочки в трудное счастье.
Не спугнёт их ни дождь, ни пурга,
Ведь не зря звёзды под ноги падают
И любуется ими тайга!
Припев
Будут новые плыть пароходы,
Будут годы друг друга сменять,
Но всегда две девчонки на палубе
Под баян будут вальс танцевать.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Девчонки танцуют на палубе»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9cd3f2de79a289b2'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9cd3f2de79a289b2','По Ангаре','Чуть охрипший гудок парохода
Уплывает в таёжную тьму.
