Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_9cd3f2de79a289b2_58aad62c4e826353','rpp_9cd3f2de79a289b2','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/devchonki_tancuyut_na_palube.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bf60dddc6393898e','«По диким степям Забайкалья» («Бродяга»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/29.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вариант I
По диким степям Забайкалья,
Где золото роют в горах,
Бродяга, судьбу проклиная,
Тащился с сумой на плечах.
Бежал из тюрьмы тёмной ночью,
В тюрьме он за правду страдал.
Идти дальше нет уже мочи –
Пред ним расстилался Байкал.
Бродяга к Байкалу подходит,
Рыбацкую лодку берёт
И грустную песню заводит,
Про Родину что-то поёт.
Бродяга Байкал переехал,
Навстречу родимая мать.
&laquo;Ах, здравствуй, ах, здравствуй, родная,
Здоров ли отец мой и брат?&raquo;
&laquo;Отец твой давно уж в могиле,
Землёю засыпан лежит,
А брат твой давно уж в Сибири,
Давно кандалами гремит&raquo;.
Вариант II
По диким степям Забайкалья,
Где золото роют в горах,
Бродяга, судьбу проклиная,
Тащился с сумой на плечах.
На нём рубашонка худая,
И множество разных заплат,
Шапчонка на нём арестанта
И серый тюремный халат.
Бродяга к Байкалу подходит,
Рыбацкую лодку берёт.
И грустную песню заводит -
Про родину что-то поёт:
&laquo;Оставил жену молодую
И малых оставил детей,
Теперь я иду наудачу,
Бог знает, увижусь ли с ней!&raquo;
Бродяга Байкал переехал,
Навстречу - родимая мать.
&laquo;Ах, здравствуй, ах, здравствуй, мамаша,
Здоров ли отец мой да брат?&raquo;
&laquo;Отец твой давно уж в могиле,
Сырою землёю закрыт.
А брат твой давно уж в Сибири,
Давно кандалами гремит.
Пойдём же, пойдём, мой сыночек,
Пойдём же в курень наш родной,
Жена там по мужу скучает,
И плачут детишки гурьбой&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bf60dddc6393898e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bf60dddc6393898e','«По диким степям Забайкалья» («Бродяга»)','Вариант I
