INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_89bbe1775ea1d87c_7505d2385472b2d8','rpp_89bbe1775ea1d87c','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/30.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c7bb0d8755bd6167','По мосткам тесовым','(«По мосткам тесовым, вдоль деревни...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/po_mostkam_tesovym.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («По мосткам тесовым, вдоль деревни...») | merged_versions: 1','По мосткам тесовым, вдоль деревни,
Ты идёшь на модных каблуках,
И к тебе склоняются деревья,
Звёздочки мигают в облаках.
Запоёшь ли песню в час заката&nbsp;–
Умолкают птичьи голоса.
Даже все женатые ребята
Не отводят от тебя глаза.
Только я другой тебя запомнил&nbsp;–
В сапогах, в шинели боевой.
Ты у нас в стрелковом батальоне
Числилась по спискам рядовой.
О тебе кругом гремела слава.
Ты прошла огонь, чтоб вольно жить.
И тебе положено по праву
В самых модных туфельках ходить.
Я иду широкою тропою,
Словно по приказу, за тобой.
Я в боях командовал тобою,
А теперь я вроде рядовой.
Далеко твой звонкий голос слышен.
Вся деревня в лунном серебре.
Две пригоршни цвета белых вишен
Бросил ветер под ноги тебе.
Запоёшь ли песню в час заката&nbsp;–
Умолкают птичьи голоса.
Даже все женатые ребята
Не отводят от тебя глаза.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«По мосткам тесовым, вдоль деревни...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c7bb0d8755bd6167'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c7bb0d8755bd6167','По мосткам тесовым','По мосткам тесовым, вдоль деревни,
