INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_c7bb0d8755bd6167_253c9cdabb7183ca','rpp_c7bb0d8755bd6167','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/po_mostkam_tesovym.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5564915e08a15907','По Муромской дорожке',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/31.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вариант I
По Муромской дорожке
Стояли три сосны.
Со мной прощался милый
До будущей весны.
Он клялся и божился
Со мной одною быть.
На дальней на сторонке
Меня не позабыть.
Наутро он уехал,
Умчался милый вдаль.
На сердце мне оставил
Тоску лишь, да печаль.
А ночью мне приснился
Ужасный страшный сон,
Что милый мой женился,
Нарушил клятву он.
А я над сном смеялась
При ярком свете дня.
Да разве ж это можно,
Чтоб мил забыл меня?
Но сон мой вскоре сбылся.
И раннею весной
Мой милый возвратился
С красавицей женой.
Я у ворот стояла,
Когда он проезжал,
Меня в толпе народа
Он взглядом отыскал.
Увидев мои слёзы,
Глаза он опустил.
И понял, что навеки
Мне сердце погубил.
По Муромской дорожке
Стояли три сосны.
Со мной прощался милый
До будущей весны.
Вариант II
По Муромской дорожке
Стояли три сосны.
Прощался со мной милый
До будущей весны.
Он клялся и божился
Одну меня любить.
На дальней на сторонушке
Меня не позабыть.
Он на коня садился,
Умчался милый вдаль.
Оставил мне на сердце
Тоску лишь, да печаль.
Я долго тосковала,
Все ночи не спала,
Я плакала, рыдала,
Всё милого ждала.
Однажды мне приснился
Тяжёлый страшный сон,
Мой миленький женился,
Нарушил клятву он.
Но я над сном смеялась
При ярком свете дня.
Не может того сбыться,
Чтоб мил забыл меня!
Но скоро сон мой сбылся.
И раннею весной
Мой милый возвратился
С красавицей женой.
Я у ворот стояла,
Когда он проезжал,
Меня в толпе народа
Он взглядом отыскал.
Увидел мои слёзы,
Глаза вниз опустил.
Он понял, что навеки
Он жизнь мою разбил.
По Муромской дорожке
Стояли три сосны.
Прощался парень с девушкой
До будущей весны.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5564915e08a15907'), datetime('now')),datetime('now'));
