INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ed54eb9a98eb3ef6','Победа будет за нами','(«Вперёд - и без останова. Фашизм разгромим навсегда...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Николай Асеев, музыка: Борис Шехтер) | Песни военных лет | https://pesni.retroportal.ru/vov/pobeda_budet_za_nami.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Вперёд - и без останова. Фашизм разгромим навсегда...») | merged_versions: 1','Вперёд&nbsp;- и без останова.
Фашизм разгромим навсегда,
Чтоб это проклятое слово
Исчезло с земли навсегда!
Припев:
Великие сроки настали
Да будет героем&nbsp;- любой!
Веди нашу партию, Сталин
В последний решительный бой!
Об этом и в песнях мы пели
И думали столько годов:
За нами высокие цели,
Чтоб каждый был драться готов!
Припев
Чтоб эти кровавые руки
Детей не пугали в ночах
Чтоб ихней звериной науки
Погас заражённый очаг!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Вперёд - и без останова. Фашизм разгромим навсегда...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ed54eb9a98eb3ef6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ed54eb9a98eb3ef6','Победа будет за нами','Вперёд&nbsp;- и без останова.
