Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_ed54eb9a98eb3ef6_7a8652947f72a1cf','rpp_ed54eb9a98eb3ef6','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/pobeda_budet_za_nami.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1c850a74c94927ac','«Побудь со мной» («Не уходи, побудь со мною»)','(посвящение певице Анастасии Вяльцевой)','ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пойгин, музыка: Николай Зубов) | Старинные романсы | https://pesni.retroportal.ru/sr3/07.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | subtitle: (посвящение певице Анастасии Вяльцевой) | merged_versions: 1','Не уходи, побудь со мною,
Здесь так отрадно, так светло.
Я поцелуями покрою
Уста, и очи, и чело.
Побудь со мной,
Побудь со мной!
Не уходи, побудь со мною,
Я так давно тебя люблю.
Тебя я лаской огневою
И обожгу, и утомлю.
Побудь со мной,
Побудь со мной!
Не уходи, побудь со мною,
Пылает страсть в моей груди.
Восторг любви нас ждёт с тобою,
Не уходи, не уходи.
Побудь со мной,
Побудь со мной!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "retroportal-subtitle:(посвящение певице Анастасии Вяльцевой)", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1c850a74c94927ac'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1c850a74c94927ac','«Побудь со мной» («Не уходи, побудь со мною»)','Не уходи, побудь со мною,
