INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_1c850a74c94927ac_7f13dc235a6057a5','rpp_1c850a74c94927ac','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/07.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bd6ace7e028a9773','Под чарующей лаской твоею',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: А. Маттизен, музыка: Николай Зубов) | Старинные романсы | https://pesni.retroportal.ru/sr3/08.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Под чарующей лаской твоею
Оживаю я сердцем опять,
Грёзы прежние снова лелею,
Вновь хочу и любить, и страдать, ах!
Поцелуем дай забвенье,
Муки сердца исцели,
Пусть умчится прочь сомненье,
В поцелуе жизнь возьми.
Пусть рассудок твердит мне суровый,
Что разлюбишь, изменишь мне ты:
Чар твоих мне не сбросить оковы –
Я во власти твоей красоты, ах!
Припев
И хочу наслажденья я страстно
Кубок выпить, налитый до дна,
Если даже за миг тот прекрасный
Мне могила теперь суждена, ах!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bd6ace7e028a9773'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bd6ace7e028a9773','Под чарующей лаской твоею','Под чарующей лаской твоею
