INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ad2d4b34aea49369','Подарки','(«А мне подарили белку, жука и синицу...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пляцковский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/podarki.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: («А мне подарили белку, жука и синицу...») | merged_versions: 1','Чего не дарят людям в день рождения...
Фантазии гостей предела нет.
Одни приходят с книжками для чтения,
Другие с целым ворохом конфет.
Припев:
А мне подарили, а мне подарили
Белку, жука и синицу.
А мне подарили, а мне подарили
Зайца, ежа и сову.
И может вполне, и может вполне,
Вполне в зоопарк превратится
Квартира моя, квартира моя,
Квартира, в которой живу.
Припев
Кому-то принесли в подарок уточку,
Кому-то мотороллер заводной.
Я так мечтал, что мне подарят дудочку.
Подарков сто, а дудки ни одной.
Припев
Пищат мои подарки и кусаются,
Царапаются все наперебой.
Гостей, конечно, это не касается.
Они уйдут довольные собой.
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(«А мне подарили белку, жука и синицу...»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ad2d4b34aea49369'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ad2d4b34aea49369','Подарки','Чего не дарят людям в день рождения...
