INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_03218e6df38bed2c','Подмосковные вечера','(«Не слышны в саду даже шорохи...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Василий Соловьёв-Седой) | Эстрадные песни | https://pesni.retroportal.ru/estrada/podmoskovnye_vechera.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Не слышны в саду даже шорохи...») | merged_versions: 1','Не слышны в саду даже шорохи,
Всё здесь замерло до утра;
Если б знали вы, как мне дороги
Подмосковные вечера.
Речка движется и не движется,
Вся из лунного серебра,
Песня слышится и не слышится
В эти тихие вечера.
Что ж ты, милая, смотришь искоса,
Низко голову наклоня,
Трудно высказать и не высказать
Всё, что на сердце у меня.
А рассвет уже все заметнее,
Так, пожалуйста, будь добра:
Не забудь и ты эти летние
Подмосковные вечера.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Не слышны в саду даже шорохи...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_03218e6df38bed2c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_03218e6df38bed2c','Подмосковные вечера','Не слышны в саду даже шорохи,
Всё здесь замерло до утра;
