INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e04f844705043240','«Пожалей» («Пожалей же меня»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Николай Бакалейников) | Старинные романсы | https://pesni.retroportal.ru/sr3/09.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','За чарующий взгляд искромётных очей
Не страшусь я ни мук, ни тяжёлых цепей,
За ласкающий звук нежной речи твоей
Я готов на позор от плетей палачей.
Ах, пожалей же меня, дорогая,
Освети мою тёмную жизнь,
Ведь я плачу, от страсти сгорая,
Но напрасно – ведь счастью не быть!
Сжалься ты надо мной, не гони, а прости, -
Для тебя я готов в жертву всё принести,
Ты молчишь... Но твой взгляд мне надежду даёт,
Прикажи, я твой раб, не то жизнь пропадёт.
Ах, пожалей же меня, дорогая,
Освети мою тёмную жизнь,
Ведь я плачу, от страсти сгорая,
Но напрасно – ведь счастью не быть!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e04f844705043240'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e04f844705043240','«Пожалей» («Пожалей же меня»)','За чарующий взгляд искромётных очей
Не страшусь я ни мук, ни тяжёлых цепей,
