INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_e04f844705043240_e7c12d2364434f0b','rpp_e04f844705043240','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/09.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_71d6db6da8afe5ad','Позарастали стёжки‑дорожки',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/32.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Позарастали стёжки-дорожки,
Где проходили милого ножки,
Позарастали мохом-травою,
Где мы гуляли, милый, с тобою.
Мы обнимались, слёзно прощались,
Помнить друг друга мы обещались.
Нет у меня с той поры уж покоя, -
Верно, гуляет милый с другою.
Если забудет, если разлюбит,
Если другую мил приголубит, -
Я отомстить ему поклянуся,
В речке глубокой я утоплюся.
Птички-певуньи, правду скажите,
Весть про милого вы принесите,
Где ж милый скрылся, где пропадает?
Бедное сердце плачет, страдает.
Позарастали стёжки-дорожки,
Где проходили милого ножки,
Позарастали мохом-травою,
Где мы гуляли, милый, с тобою.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_71d6db6da8afe5ad'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_71d6db6da8afe5ad','Позарастали стёжки‑дорожки','Позарастали стёжки-дорожки,
Где проходили милого ножки,
Позарастали мохом-травою,
Где мы гуляли, милый, с тобою.
Мы обнимались, слёзно прощались,
Помнить друг друга мы обещались.
Нет у меня с той поры уж покоя, -
Верно, гуляет милый с другою.
Если забудет, если разлюбит,
Если другую мил приголубит, -
Я отомстить ему поклянуся,
В речке глубокой я утоплюся.
Птички-певуньи, правду скажите,
Весть про милого вы принесите,
