INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_86b07fd7318a6c1a','Пой, моя хорошая','(«Пой, моя хорошая, в поле жито скошено...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Жаров, музыка: Константин Листов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/poj_moya_horoshaya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Пой, моя хорошая, в поле жито скошено...») | merged_versions: 1','Пой, моя хорошая, в поле жито скошено,
Возле дома вечером тишь да благодать.
На земле прохлада, на душе отрада
И слова заветные хочется сказать.
Пой, моя хорошая, мы с тобою дожили
До поры загаданной рано по весне.
И весной и летом помнил я об этом,
Об осеннем свадебном, о счастливом дне.
Все наряды справлены, все столы уставлены
Полными стаканами, доброю едой.
С неба тихо светит, тоже в гости метит
Спутник нашей радости&nbsp;- месяц молодой.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Пой, моя хорошая, в поле жито скошено...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_86b07fd7318a6c1a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_86b07fd7318a6c1a','Пой, моя хорошая','Пой, моя хорошая, в поле жито скошено,
