INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6520e95e073265bb','Пойду ль я, выйду ль я',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/33.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Пойду ль я, выйду ль я, да,
Пойду ль я, выйду ль я, да,
Во дол, во долинушку, да,
Во дол, во широкую.
Сорву ль я, вырву ль я, да,
Сорву ль я, вырву ль я, да,
С винограда ягодку, да,
С винограда винную.
То ли мне не ягодка, да,
То ли мне не винная, да,
Я цветочек сорвала, да,
Я веночек совила.
Кинуся, брошуся, да,
Кинуся, брошуся, да,
Ко молодцу на колени,
Ко молодцу на колени.
Я у молодца сижу, да,
Я на молодца гляжу, да,
Скажи, душа, скажи, свет, да,
Скажи, любишь али нет?
Скажи, душа, скажи, свет, да,
Скажи, любишь али нет? – да,
&laquo;Я любить-то не люблю, да,
Наглядеться не могу!&raquo;','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6520e95e073265bb'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6520e95e073265bb','Пойду ль я, выйду ль я','Пойду ль я, выйду ль я, да,
