INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4147721739088384','Поле чудес','(Песня из кинофильма «Приключения Буратино»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Булат Окуджава, музыка: Алексей Рыбников) | Песни для детей | https://pesni.retroportal.ru/deti/pole_chudes_v_strane_durakov.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из кинофильма «Приключения Буратино») | merged_versions: 1','Не прячьте ваши денежки по банкам и углам,
Несите ваши денежки - иначе быть беде.
И в полночь ваши денежки заройте в землю там,
И в полночь ваши денежки заройте в землю, где?
Заройте в землю, где...
Припев:
Не горы, не овраги и не лес,
Не океан без дна и берегов,
А поле, поле, поле, поле Чудес,
А поле, поле, поле, поле Чудес,
Поле чудес в Стране Дураков.
Крекс-пекс-фекс...
Полейте хорошенечко, советуем мы вам,
И вырастут ветвистые деревья в темноте,
Но вместо листьев денежки засеребрятся там,
Но вместо листьев денежки зазолотятся где?...
Зазолотятся где?
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из кинофильма «Приключения Буратино»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4147721739088384'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4147721739088384','Поле чудес','Не прячьте ваши денежки по банкам и углам,
Несите ваши денежки - иначе быть беде.
И в полночь ваши денежки заройте в землю там,
