INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_4147721739088384_8059fc47d8c199a3','rpp_4147721739088384','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/pole_chudes_v_strane_durakov.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_538842a47c118364','Полоса ль ты моя, полоса',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Всеволод Крестовский, музыка народная) | Народные песни | https://pesni.retroportal.ru/np2/41.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Полоса ль ты моя, полоса!
Не распахана ты, сиротинка,
И тебе не колосья краса,
Не колосья краса, а былинка...
А кругом-то, кругом поглядишь –
Так и зреют могучие нивы!
И стоит благодатная тишь,
И волнуются ржи переливы.
Но горька мне твоя нагота,
Как взгляну я на ниву-то божью:
Отчего ж ты одна, сирота,
Не красуешься матушкой-рожью?
Знать, хозяин-то твой в кабаке
Загулял не одну уж неделю
Иль от горя – в гробовой доске
Отыскал на погосте постелю.
А быть может, и то: в кандалах
По Владимирке пахаря гонят,
За широкий, за вольный размах
Богатырскую силу хоронят.
И шагает он в синюю даль,
Сам шагает да слёзы глотает:
Всё-то ниву свою ему жаль,
Всё полоску свою вспоминает...
Зарастай же, моя полоса,
Частым ельничком ты да берёзкой,
И пускай же ни серп, ни коса
Не сверкают отсель над полоской!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_538842a47c118364'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_538842a47c118364','Полоса ль ты моя, полоса','Полоса ль ты моя, полоса!
Не распахана ты, сиротинка,
И тебе не колосья краса,
Не колосья краса, а былинка...
