INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_a7ea4b9aca1983be_da9f6eea5002ddfc','rpp_a7ea4b9aca1983be','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/34.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_79980fd66a648a7a','Посею лебеду на берегу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/35.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Посею лебеду на берегу,
Мою крупную рассадушку,
Мою крупную зелёную.
Погорела лебеда без дождя,
Моя крупная рассадушка,
Моя крупная зелёная.
Пошлю казака по воду,
Ни воды нет, ни казаченька,
Ни воды нет, ни казаченька.
Кабы мне да, младой, ворона коня,
Я бы вольная казачка была,
Я бы вольная казачка была.
Скакала, плясала б по лугам,
По зелёным по дубравушкам,
По зелёным по дубравушкам.
С донским, с молодым казаком,
Со удалым добрым молодцем,
Со удалым добрым молодцем.
Раздушечка, казак молодой,
Что не ходишь, что не жалуешь ко мне,
Что не ходишь, что не жалуешь ко мне?','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_79980fd66a648a7a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_79980fd66a648a7a','Посею лебеду на берегу','Посею лебеду на берегу,
Мою крупную рассадушку,
Мою крупную зелёную.
Погорела лебеда без дождя,
Моя крупная рассадушка,
Моя крупная зелёная.
Пошлю казака по воду,
Ни воды нет, ни казаченька,
Ни воды нет, ни казаченька.
Кабы мне да, младой, ворона коня,
Я бы вольная казачка была,
Я бы вольная казачка была.
Скакала, плясала б по лугам,
По зелёным по дубравушкам,
По зелёным по дубравушкам.
С донским, с молодым казаком,
Со удалым добрым молодцем,
Со удалым добрым молодцем.
Раздушечка, казак молодой,
Что не ходишь, что не жалуешь ко мне,
Что не ходишь, что не жалуешь ко мне?');
