INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_744224cbad67041e','Посиди хоть минуточку рядом со мной',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Натэлла Горская, музыка: Алексей Животов) | Старинные романсы | https://pesni.retroportal.ru/sr3/11.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Посиди хоть минуточку рядом со мной,
Мы так редко бываем одни,
И улыбкой своей, словно нежной рукой,
Ты морщины мои разгони.
Ты не бойся безмолвной печали моей,
Пусть она не тревожит тебя.
Сядь сюда, мои тяжкие думы развей,
Улыбнись, будто вправду любя.
Подожди уходить, я так редко молю,
Горечь правды в себе сбереги,
Ну, а мне, хоть за то, что так сильно люблю,
На прощанье ещё раз солги.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_744224cbad67041e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_744224cbad67041e','Посиди хоть минуточку рядом со мной','Посиди хоть минуточку рядом со мной,
