INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_188ddeb1d23ef3ae','Последний аккорд',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: В.Л.Л., музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr3/12.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Из окна золотит клавикорды
Умирающий, грустный закат...
Позабытой сонаты аккорды
В потемневшей гостиной звучат...
Вечер тёплый, и синий, и пряный,
И за окнами вянет сирень,
И уходит в ночные туманы
Грустно прожитый, тающий день...
Жизнь ушла... на усталые руки
Глянул луч незаметный, скользя...
Жизнь прошла без любви и без муки,
И прожить её снова нельзя!
Вечер тёплый, и синий, и пряный,
И за окнами вянет сирень,
И уходит в ночные туманы
Грустно прожитый, тающий день...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_188ddeb1d23ef3ae'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_188ddeb1d23ef3ae','Последний аккорд','Из окна золотит клавикорды
