INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_013c0d07a5549411_f64a84e68e77550d','rpp_013c0d07a5549411','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/36.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_099e94c51d24fa82','Поцелуй же меня, моя душечка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Писарев, музыка: Александр Дюбюк) | Старинные романсы | https://pesni.retroportal.ru/sr3/13.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Тебя встретил я, мою милую,
И не надо мне воли прежних дней.
Сердце ожило с новой силою,
Для тебя оно бьётся вновь сильней.
Ты взгляни на меня,
Ты порадуй меня,
Моя милая!
Забыл горе я – долю трудную,
И прошла тоска, забыл всё с тобой.
Снова кажется жизнь мне чудною,
Сердцу весело – счастлив я душой.
Улыбнись же ты мне,
Рвётся сердце к тебе,
Ты – прелестная!
Всё глядел бы я в очи чёрные,
Сердцу много в них наслажденья есть,
В них горит любовь непритворная,
Не понятны им ни обман, ни лесть.
Скажи, друг, мне &laquo;люблю&raquo;,
Утешь душу мою,
Ненаглядная!
Смотришь ласково, улыбаешься, -
Так легко, легко на душе моей!
Скажешь слово ты – как ласкаешься,
Сердце б отдал я тебе вместе с жизнью всей.
Поцелуй же меня,
Подари ты меня,
Моя душечка!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_099e94c51d24fa82'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_099e94c51d24fa82','Поцелуй же меня, моя душечка','Тебя встретил я, мою милую,
И не надо мне воли прежних дней.
Сердце ожило с новой силою,
Для тебя оно бьётся вновь сильней.
Ты взгляни на меня,
Ты порадуй меня,
Моя милая!
Забыл горе я – долю трудную,
И прошла тоска, забыл всё с тобой.
Снова кажется жизнь мне чудною,
Сердцу весело – счастлив я душой.
Улыбнись же ты мне,
Рвётся сердце к тебе,
Ты – прелестная!
Всё глядел бы я в очи чёрные,
Сердцу много в них наслажденья есть,
В них горит любовь непритворная,
Не понятны им ни обман, ни лесть.
Скажи, друг, мне &laquo;люблю&raquo;,
Утешь душу мою,
Ненаглядная!
Смотришь ласково, улыбаешься, -
Так легко, легко на душе моей!
Скажешь слово ты – как ласкаешься,
Сердце б отдал я тебе вместе с жизнью всей.
Поцелуй же меня,
Подари ты меня,
Моя душечка!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_099e94c51d24fa82_f0e82d01ba29978c','rpp_099e94c51d24fa82','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/13.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9cdc46d9ed85a372','Право, маменьке скажу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Берг, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr3/14.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Что такое это значит?
Как одна я с ним сижу,
Всё тоскует он и плачет?
Право, маменьке скажу!
Я ему одна забота,
Но в душе моей лишь лёд,
А глаза мои за что-то
Он кинжалами зовёт,
Он кинжалами зовёт.
Вишь, резва я, непослушна,
Ни на миг не посижу.
Право, мне уж это скушно,
Право, маменьке скажу!
Под окном моим всё бродит,
Сам с собою говорит,
Как одна, он глаз не сводит,
А при людях не глядит,
А при людях не глядит.
Но подчас, как с ним бываю,
И сама я вся дрожу,
И смущаюсь, и пылаю,
Право, маменьке скажу!
Пусть она уж нас рассудит,
Вот ужо я погляжу,
Что-то с ним, бедняжкой, будет...
Нет, уж лучше не скажу!
Нет, уж лучше не скажу!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9cdc46d9ed85a372'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9cdc46d9ed85a372','Право, маменьке скажу','Что такое это значит?
Как одна я с ним сижу,
