INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_39ac2817dbd428c8','Прелестные глазки',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Генрих Гейне, русский текст: Николай Добролюбов, музыка: Пётр Булахов) | Старинные романсы | https://pesni.retroportal.ru/sr3/15.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','У тебя есть алмазы и жемчуг –
Всё, что люди привыкли искать,
Да ещё есть прелестные глазки...
Милый друг, чего больше желать?
Я на эти прелестные глазки
Выслал целую стройную рать
Звучных песен из жаркого сердца,
Милый друг, чего больше желать?
Эти чудные глазки на сердце
Наложили мне страсти печать,
Ими, мой друг, меня ты сгубила,
Милый друг, чего больше желать?','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_39ac2817dbd428c8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_39ac2817dbd428c8','Прелестные глазки','У тебя есть алмазы и жемчуг –
