INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_39ac2817dbd428c8_1a9746915e39dc41','rpp_39ac2817dbd428c8','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/15.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4a7dc762280aa1c0','При народе, в хороводе',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/37.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','При народе, в хороводе
Парень девушку обнял,
А девчонке стыдно стало,
Стала плакать и рыдать.
Дроби, дроби, дроби бей,
Танцуй, ноги не жалей.
Как теперь пойду до дому,
Меня дома забранят.
Поцелуи твои жарка
На губах моих горят.
Припев
Это что же за молодчик,
Развесёленький такой,
Это что же за мальчишка,
Расхорошенький такой.
Припев
При народе, в хороводе
Парень девушку обнял,
А девчонке стыдно стало,
Стала плакать и рыдать.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4a7dc762280aa1c0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4a7dc762280aa1c0','При народе, в хороводе','При народе, в хороводе
Парень девушку обнял,
А девчонке стыдно стало,
Стала плакать и рыдать.
Дроби, дроби, дроби бей,
Танцуй, ноги не жалей.
Как теперь пойду до дому,
Меня дома забранят.
Поцелуи твои жарка
На губах моих горят.
Припев
Это что же за молодчик,
Развесёленький такой,
Это что же за мальчишка,
Расхорошенький такой.
Припев
При народе, в хороводе
Парень девушку обнял,
А девчонке стыдно стало,
Стала плакать и рыдать.
Припев');
