INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_cb868f8753bb3b8b','Притяжение Земли','(«Там горы высокие, там степи просторные...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Роберт Рождественский, музыка: Давид Тухманов) | Патриотические песни | https://pesni.retroportal.ru/rodina/prityazhenie_zemli.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Там горы высокие, там степи просторные...») | merged_versions: 1','Как безмерно оно&nbsp;- притяженье Земли,
Притяженье полей и печальных ракит,
Всех дорог, по которым мы в детстве прошли,
И дорог, по которым пройти предстоит.
Припев:
Там горы высокие,
Там степи просторные,
Там ветры летят, по просёлкам пыля.
Мы дети Галактики,
Но, самое главное,&nbsp;-
Мы дети твои, дорогая Земля!
Притяженье полей, притяженье садов,
И закатов, и сосен в пушистом снегу,
Небольших деревень и больших городов,
И ночного костра на пустом берегу.
Припев
Не изменится этот порядок вещей,
И настигнет меня, и припомнится мне
Притяженье Земли, притяженье друзей,
Притяженье любимой в далёком окне.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Там горы высокие, там степи просторные...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_cb868f8753bb3b8b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_cb868f8753bb3b8b','Притяжение Земли','Как безмерно оно&nbsp;- притяженье Земли,
