INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_44a5ebf7ce4038c2','Про ёлочку','(Детская новогодняя песня)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Максим Рыльский, музыка: Виктор Косенко) | Песни для детей | https://pesni.retroportal.ru/deti/pro_elochku.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Детская новогодняя песня) | merged_versions: 1','Белый снег лежит кругом,
Он сверкает серебром,
Только ёлочка одна
И зимою зелена.
Припев:
Словно ёлка молодая,
Хороша страна родная!
Детвора растёт, резвится,
А потом пойдёт учиться!
Рады ёлочке всегда
Наши сёла, города.
Славно ёлку уберём,
Хором песню заведём.
Припев
Бусы, ёлка, надевай,
Ярко звёздами сверкай.
Чтоб красивой ты была,
Как цветочек, расцвела!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Детская новогодняя песня)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_44a5ebf7ce4038c2'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_44a5ebf7ce4038c2','Про ёлочку','Белый снег лежит кругом,
