INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_141895ba57e40510','Про Суворова','(«В старину гремел Суворов храбрый русский генерал...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Александр Лугин, музыка: Иосиф Фурман) | Песни военных лет | https://pesni.retroportal.ru/vov/suvorov.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («В старину гремел Суворов храбрый русский генерал...») | merged_versions: 1','В старину гремел Суворов
Храбрый русский генерал,
Шёл он в бой без долгих сборов,
Никогда не отступал.
Не любил Суворов споров,
Был солдатом, что отец,
Приговаривал Суворов:
&laquo;Штык, ребята, молодец!&raquo;
Припев:
Штык не промах, не простак,
Колет этак, колет так,
Бьёт и пуля метко:
Если мечен пулей враг,
Не сотрётся метка.
Для страны родной Суворов
Не щадил труда и сил.
Шёл в поход без разговоров,
Вражьи полчища разил.
Побеждал он средь просторов,
Побеждал он и в горах.
Оттого живёт Суворов
И теперь у нас в сердцах.
Припев
Бить врагов учил Суворов -
Чем придётся, хоть дубьём.
Ну а наш известен норов:
Если бьём врага, то бьём!
Под могучий гул моторов,
В бой, какого мир не знал.
Нас ведёт, как вёл Суворов,
Храбрый красный генерал.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«В старину гремел Суворов храбрый русский генерал...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_141895ba57e40510'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_141895ba57e40510','Про Суворова','В старину гремел Суворов
