INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9b012e16ed8d23eb','Провожают гармониста','(«Провожают гармониста в институт...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Юрий Милютин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/provozhayut_garmonista.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Провожают гармониста в институт...») | merged_versions: 1','На деревне расставание поют,&nbsp;-
Провожают гармониста в институт.
Хороводом ходят девушки вокруг:
&laquo;До свиданья, до свиданья, милый друг!
До свиданья, милый друг!
Расскажи-ка, сколько лет тебя нам ждать,
Кем ты станешь, интересно нам узнать&raquo;.
Произносит он с достоинством в ответ:
&laquo;Принят я на инженерный факультет,
На инженерный факультет&raquo;.
Загрустили сразу девушки тогда:
&laquo;Это значит, не вернёшься ты сюда,
Инженером ты поступишь на завод
И забудешь наш весёлый хоровод,
Наш весёлый хоровод&raquo;.
Что он скажет? Все притихли на момент.
&laquo;Не грустите, - отвечает им студент,&nbsp;-
Подождите, я закончу институт,
Инженеру много дела есть и тут,
Много дела есть и тут&raquo;.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Провожают гармониста в институт...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9b012e16ed8d23eb'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9b012e16ed8d23eb','Провожают гармониста','На деревне расставание поют,&nbsp;-
