INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_474861eed1c8f58a','Проходит всё',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Даниил Ратгауз, музыка: Сергей Рахманинов) | Старинные романсы | https://pesni.retroportal.ru/sr3/16.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Проходит всё, и нет к нему возврата.
Жизнь мчится вдаль, мгновения быстрей.
Где звуки слов, звучавших нам когда-то?
Где свет зари нас озарявших дней?
Расцвёл цветок, а завтра он увянет,
Горит огонь, чтоб вскоре отгореть...
Идёт волна, над ней другая встанет...
Я не могу весёлых песен петь!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_474861eed1c8f58a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_474861eed1c8f58a','Проходит всё','Проходит всё, и нет к нему возврата.
