INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8130c0e93ce10fc5','Прощайте скалистые горы','(«Прощайте, скалистые горы, на подвиг Отчизна зовёт!..»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Николай Букин, музыка: Евгений Жарковский) | Песни военных лет | https://pesni.retroportal.ru/vov/proshajte_skalistye_gory.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Прощайте, скалистые горы, на подвиг Отчизна зовёт!..») | merged_versions: 1','Прощайте, скалистые горы,
На подвиг Отчизна зовёт!
Мы вышли в открытое море,
В суровый и дальний поход.
А волны и стонут, и плачут,
И плещут на борт корабля...
Растаял в далёком тумане Рыбачий,
Родимая наша земля.
Корабль мой упрямо качает
Крутая морская волна,
Поднимет и снова бросает
В кипящую бездну она.
Обратно вернусь я не скоро,
Но хватит для битвы огня.
Я знаю, друзья, что не жить мне без моря,
Как море мертво без меня.
Нелёгкой походкой матросской
Иду я навстречу врагам,
А после с победой геройской
К скалистым вернусь берегам.
Хоть волны и стонут, и плачут,
И плещут на борт корабля,
Но радостно встретит героев Рыбачий,
Родимая наша земля.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Прощайте, скалистые горы, на подвиг Отчизна зовёт!..»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8130c0e93ce10fc5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8130c0e93ce10fc5','Прощайте скалистые горы','Прощайте, скалистые горы,
