INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_8130c0e93ce10fc5_b51b0c332cc49e65','rpp_8130c0e93ce10fc5','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/proshajte_skalistye_gory.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_18b09aaac9825e3e','Прощайте, ласковые взоры',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | Старинные романсы | https://pesni.retroportal.ru/sr4/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','(авторы романса неизвестны)
Прощайте, ласковые взоры,
Прощай, мой милый, навсегда,
Разделят нас долины, горы,
Врозь будем жить с тобой, душа.
Я голос твой не буду слышать,
Улыбка скроется из глаз,
Польются слёзы поневоле,
Когда придёт разлуки час.
И в эту горькую минуту
С своей сердечной простотой
Возьму в последний раз я руку,
Скажу: &laquo;Прощай, любезный мой&raquo;.
В полях, лугах, садах прекрасных,
Там, на возвышенном холме,
Где при заре счастливой, ясной
Склонялся ты на грудь ко мне.
Склонялась я, шептала нежно:
- Люблю, люблю, мой друг, тебя;
Я слышу, едешь ты далёко
Прельщать других, а не меня.
А я останусь сиротою,
Век буду по тебе страдать,
Страданье горю не поможет,
Тебя мне больше не видать.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_18b09aaac9825e3e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_18b09aaac9825e3e','Прощайте, ласковые взоры','(авторы романса неизвестны)
Прощайте, ласковые взоры,
Прощай, мой милый, навсегда,
Разделят нас долины, горы,
Врозь будем жить с тобой, душа.
Я голос твой не буду слышать,
Улыбка скроется из глаз,
Польются слёзы поневоле,
Когда придёт разлуки час.
И в эту горькую минуту
С своей сердечной простотой
Возьму в последний раз я руку,
Скажу: &laquo;Прощай, любезный мой&raquo;.
В полях, лугах, садах прекрасных,
Там, на возвышенном холме,
Где при заре счастливой, ясной
Склонялся ты на грудь ко мне.
Склонялась я, шептала нежно:
- Люблю, люблю, мой друг, тебя;
Я слышу, едешь ты далёко
Прельщать других, а не меня.
А я останусь сиротою,
Век буду по тебе страдать,
Страданье горю не поможет,
Тебя мне больше не видать.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_18b09aaac9825e3e_6d2797cdb6114484','rpp_18b09aaac9825e3e','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr4/02.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_87e0c86122d3b4d3','Прощание славянки','(«Прощай, отчий край, ты нас вспоминай...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Владимир Лазарев-Мильдон, музыка: Василий Агапкин) | Песни военных лет | https://pesni.retroportal.ru/vov/proshanie_slavyanki.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Прощай, отчий край, ты нас вспоминай...») | merged_versions: 1','Наступает минута прощания,
Ты глядишь мне тревожно в глаза,
И ловлю я родное дыхание,
А в лицо уже дышит гроза.
Дрогнул воздух туманный и синий,
И тревога коснулась висков,
И зовёт нас на подвиг Россия.
Веет ветром от шага полков.
Прощай, отчий край,
Ты нас вспоминай,
Прощай, милый взгляд,
Прости-прощай,
прости-прощай...
Летят, летят года,
Уходят во мглу поезда,
А в них солдаты.
И в небе тёмном
Горит Сочувствия звезда.
Прощай, отчий край,
Ты нас вспоминай,
Прощай, милый взгляд,
Прости-прощай,
прости-прощай...
Лес да степь, да в степи полустанки.
Повороты родимой земли.
И, как птица, прощанье славянки
Всё летит и рыдает вдали.
Овевает нас Божие Слово,
Мы на этой Земле не одни
И за братьев, за веру Христову
Отдавали мы жизни свои.
Прощай, отчий край,
Ты нас вспоминай,
Прощай, милый взгляд,
Не все из нас придут назад.
Летят, летят года,
А песня, ты с нами всегда:
Тебя мы помним,
И в небе тёмном
Горит Сочувствия звезда.
Прощай, отчий край,
Ты нас вспоминай,
Прощай, милый взгляд,
Дай Бог вернуться нам назад.
Впервые в полном объёме стихи марша  &laquo;Прощание славянки&raquo;  были опубликованы газетой &laquo;Русская Жизнь&raquo; (Сан Франциско, США 20 октября 2012 года).
На сайте &laquo;Retroportal.ru&raquo; размещено эксклюзивное интервью корреспондента газеты &laquo;Русская Жизнь&raquo; Галины Артамоновой с поэтом Владимиром Лазаревым  об истории создания поэтического текста  к музыке легендарного русского марша композитора Василия Агапкина.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Прощай, отчий край, ты нас вспоминай...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_87e0c86122d3b4d3'), datetime('now')),datetime('now'));
