INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_865071a1ef0362f1','«Пряха» («В низенькой светёлке»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np2/38.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','В низенькой светёлке
Огонёк горит,
Молодая пряха
Под окном сидит.
Молода. Красива,
Карие глаза,
По плечам развита
Русая коса.
Русая головка,
Думы без конца...
Ты о чём мечтаешь,
Девица-краса?..
В низенькой светёлке
Огонёк горит,
Молодая пряха
Под окном сидит.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_865071a1ef0362f1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_865071a1ef0362f1','«Пряха» («В низенькой светёлке»)','В низенькой светёлке
