INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fa1d33633c525769','Пусть всегда будет солнце','(«Солнечный круг, небо вокруг...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лев Ошанин, музыка: Аркадий Островский) | Песни для детей | https://pesni.retroportal.ru/deti/pust_vsegda_budet_solnce.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: («Солнечный круг, небо вокруг...») | merged_versions: 1','Солнечный круг, небо вокруг&nbsp;-
Это рисунок мальчишки.
Нарисовал он на листке
И подписал в уголке:
Припев:
Пусть всегда будет солнце,
Пусть всегда будет небо,
Пусть всегда будет мама,
Пусть всегда буду я!
Милый мой друг, верный мой друг,
Людям так хочется мира!
И в тридцать пять сердце опять
Не устаёт повторять:
Припев
Тише солдат, слышишь солдат,
Люди пугаются взрывов.
Тысячи глаз в небо глядят,
Губы упрямо твердят:
Припев
Против беды, против войны
Встанем за наших мальчишек.
Солнце навек, счастье навек,
Так повелел человек!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(«Солнечный круг, небо вокруг...»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fa1d33633c525769'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_fa1d33633c525769','Пусть всегда будет солнце','Солнечный круг, небо вокруг&nbsp;-
