INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_71c3a7e5ffb656ab','Пшеница золотая','(«Мне хорошо, колосья раздвигая, сюда ходить...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Матвей Блантер) | Патриотические песни | https://pesni.retroportal.ru/rodina/pshenica_zolotaya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Мне хорошо, колосья раздвигая, сюда ходить...») | merged_versions: 1','Мне хорошо, колосья раздвигая,
Сюда ходить вечернею порой.
Стеной стоит пшеница золотая
По сторонам тропинки полевой.
Всю ночь поют в пшенице перепёлки
О том, что будет урожайный год,
Ещё о том, что за рекой в посёлке
Моя любовь, моя судьба живёт.
И в час, когда над нашей стороною
Вдали заря вечерняя стоит,
Родное поле говорит со мною,
О самом лучшем в мире говорит.
И хорошо мне здесь остановиться,
И, глядя вдаль, подумать, помолчать.
Шумит, шумит высокая пшеница,
И ей конца и края не видать.','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Мне хорошо, колосья раздвигая, сюда ходить...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_71c3a7e5ffb656ab'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_71c3a7e5ffb656ab','Пшеница золотая','Мне хорошо, колосья раздвигая,
Сюда ходить вечернею порой.
Стеной стоит пшеница золотая
