INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6c8411429ee1d3be','Разлилася Волга широко',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня-страдание) | Народные песни | https://pesni.retroportal.ru/np2/39.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Разлилася Волга широко,
Милый мой теперь далёко.
Ветерочек парус клонит,
От разлуки сердце стонет.
Мне казалось – он смеётся,
А он навек расстаётся.
Ах, поверьте мне, поверьте:
Расставанье хуже смерти.
Зачем было сердце вынуть,
Полюбить, потом покинуть.
А в разлуке, кабы знала,
По тебе я не страдала.
Ах, в прощальный наш денёчек,
Я дарю тебе платочек,
У платочка сини каймы,
А утрёшься – меня вспомни.
До свиданья, - милый скажет,
А на сердце камень ляжет.
До свиданья, до свиданья,
Не забудь моё страданье.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6c8411429ee1d3be'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6c8411429ee1d3be','Разлилася Волга широко','Разлилася Волга широко,
Милый мой теперь далёко.
Ветерочек парус клонит,
От разлуки сердце стонет.
Мне казалось – он смеётся,
А он навек расстаётся.
Ах, поверьте мне, поверьте:
Расставанье хуже смерти.
Зачем было сердце вынуть,
Полюбить, потом покинуть.
А в разлуке, кабы знала,
По тебе я не страдала.
Ах, в прощальный наш денёчек,
Я дарю тебе платочек,
У платочка сини каймы,
А утрёшься – меня вспомни.
До свиданья, - милый скажет,
