INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6c8411429ee1d3be_c63ec40341ef332b','rpp_6c8411429ee1d3be','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/39.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_6eec8b8a5b9449b8','«Разлука» («На заре туманной юности»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Кольцов, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr3/17.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','На заре туманной юности
Всей душой любил я милую.
Был в глазах её небесный свет,
На лице горел любви огонь!
Что пред ней ты, утро майское,
Ты, дуброва-мать зелёная,
Степь, трава-парча шелковая,
Заря, вечер, ночь-волшебница!
Хороши вы, когда нет её,
Когда с вами делишь грусть-тоску!
А при ней – вас хоть бы не было;
С ней зима – весна, ночь – ясный день!
Не забыть мне, как в последний раз
Я сказал ей: &laquo;Прости, милая!
Наш, знать, рок такой, расстанемся,
Но когда-нибудь увидимся...&raquo;
Вмиг огнём лицо всё вспыхнуло,
Белым снегом перекрылося,
И, рыдая, как безумная,
На груди моей повиснула.
&laquo;Не ходи, постой!
Дай время мне
Затушить грусть,
Печаль выплакать
На тебя, на ясна сокола!&raquo;
Занялся дух, словно замерло.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_6eec8b8a5b9449b8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_6eec8b8a5b9449b8','«Разлука» («На заре туманной юности»)','На заре туманной юности
Всей душой любил я милую.
Был в глазах её небесный свет,
На лице горел любви огонь!
Что пред ней ты, утро майское,
Ты, дуброва-мать зелёная,
Степь, трава-парча шелковая,
Заря, вечер, ночь-волшебница!
Хороши вы, когда нет её,
Когда с вами делишь грусть-тоску!
А при ней – вас хоть бы не было;
С ней зима – весна, ночь – ясный день!
Не забыть мне, как в последний раз
Я сказал ей: &laquo;Прости, милая!
Наш, знать, рок такой, расстанемся,
Но когда-нибудь увидимся...&raquo;
Вмиг огнём лицо всё вспыхнуло,
Белым снегом перекрылося,
И, рыдая, как безумная,
На груди моей повиснула.
&laquo;Не ходи, постой!
Дай время мне
Затушить грусть,
Печаль выплакать
На тебя, на ясна сокола!&raquo;
Занялся дух, словно замерло.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6eec8b8a5b9449b8_e55c34c223cb3504','rpp_6eec8b8a5b9449b8','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/17.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b3c9a474c7bc4471','«Разочарование» («Прошедших дней очарованья»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Антон Дельвиг, музыка: Александр Варламов) | Старинные романсы | https://pesni.retroportal.ru/sr4/03.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Прошедших дней очарованья,
Мне вас душе не возвратить!
В любви узнав одни страданья,
Она утратила желанья
И вновь не просится любить.
Она утратила желанья
И вновь не просится любить.
К ней сны младые не забродят,
Опять с надеждой не мирят;
В странах волшебных с ней не ходят,
Весёлых песен не заводят
И сладких слов не говорят.
Весёлых песен не заводят
И сладких слов не говорят.
Её один удел печальный:
Года бесчувственно провесть,
И в край, для горестных не дальный,
Под глас молитвы погребальной
Одни молитвы перенесть.
Под глас молитвы погребальной
Одни молитвы перенесть.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b3c9a474c7bc4471'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b3c9a474c7bc4471','«Разочарование» («Прошедших дней очарованья»)','Прошедших дней очарованья,
Мне вас душе не возвратить!
В любви узнав одни страданья,
Она утратила желанья
И вновь не просится любить.
Она утратила желанья
И вновь не просится любить.
К ней сны младые не забродят,
Опять с надеждой не мирят;
В странах волшебных с ней не ходят,
Весёлых песен не заводят
И сладких слов не говорят.
Весёлых песен не заводят
И сладких слов не говорят.
Её один удел печальный:
Года бесчувственно провесть,
И в край, для горестных не дальный,
Под глас молитвы погребальной
