INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b3c9a474c7bc4471_ea4666c80283fdc1','rpp_b3c9a474c7bc4471','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr4/03.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9474640a09217fbb','Раскинулось море широко',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Георгий Зубарев, музыка: Александр Гурилёв) | Народные песни | https://pesni.retroportal.ru/np2/40.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Раскинулось море широко,
И волны бушуют вдали...
Товарищ, мы едем далёко,
Подальше от нашей земли.
Не слышно на палубе песен,
И Красное море шумит,
А берег суровый и тесен, -
Как вспомнишь, так сердце болит.
&laquo;Товарищ, я вахты не в силах стоять, -
Сказал кочегар кочегару, -
Огни в моих топках совсем прогорят,
В котлах не сдержать мне уж пару.
Пойди, заяви, что я заболел,
И вахту, не кончив, бросаю,
Весь потом истёк, от жары изнемог,
Работать нет сил, умираю!&raquo;
Товарищ ушёл... Лопату схватил,
Собравши последние силы,
Дверь топки привычным толчком отворил,
И пламя его озарило.
Окончив кидать, он напился воды, -
Воды опреснённой, нечистой,
С лица его падал пот, сажи следы,
Услышал он речь машиниста:
&laquo;Ты вахты, не кончив, не смеешь бросать,
Механик тобой недоволен;
Ты к доктору должен пойти и сказать, -
Лекарство он даст, если болен!&raquo;
На палубу вышел... Сознанья уж нет.
В глазах его всё помутилось...
Увидев на миг ослепительный свет...
Упал... Сердце больше не билось.
Проститься с товарищем утром пришли
Матросы, друзья кочегара,
Последний подарок ему поднесли –
Колосник горелый и ржавый.
Напрасно старушка ждёт сына домой, -
Ей скажут, она зарыдает...
А волны бегут от винта за кормой,
И след их вдали пропадает.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9474640a09217fbb'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9474640a09217fbb','Раскинулось море широко','Раскинулось море широко,
