INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_9474640a09217fbb_550b4dfe6940dcee','rpp_9474640a09217fbb','Retroportal — Народные песни','https://pesni.retroportal.ru/np2/40.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e9e9b501dd2ebdcf','Расцвели хризантемы опять',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Лев Дризо) | Старинные романсы | https://pesni.retroportal.ru/sr3/18.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Когда мы расстались с Вами совсем,
Душа исстрадалась глубоко,
Но в сердце больном кто-то радостно пел,
Как счастья предвестник далёкий.
Расцветут хризантемы опять,
Вновь вернётся к тебе твоё счастье,
И исчезнет тоска и ненастье,
Расцветут хризантемы опять.
Расцветут хризантемы опять.
И вот Вы вернулись, опять Вы со мной.
И вновь расцвели в сердце розы,
И веет, как прежде, прекрасной весной.
Вы жизнь, Вы счастье, Вы грёзы.
Расцвели хризантемы опять,
Вновь вернулось ко мне моё счастье,
И исчезли тоска и ненастье!
Расцветут хризантемы опять.
Расцветут хризантемы опять!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e9e9b501dd2ebdcf'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e9e9b501dd2ebdcf','Расцвели хризантемы опять','Когда мы расстались с Вами совсем,
Душа исстрадалась глубоко,
