INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c8834516e159f993','Родина','(«Вижу чудное приволье, вижу нивы и поля...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Феодосий Савинов, музыка неизвестного автора) | Патриотические песни | https://pesni.retroportal.ru/rodina/vizhu_chudnoe_privole.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Вижу чудное приволье, вижу нивы и поля...») | merged_versions: 1','Вижу чудное приволье,
Вижу нивы и поля.
Это русское раздолье,
Это русская земля!
Вижу горы-исполины,
Вижу реки и моря&nbsp;-
Это русские картины,
Это Родина моя.
Слышу песни жаворонка,
Слышу трели соловья.
Это русская сторонка,
Это Родина моя!','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Вижу чудное приволье, вижу нивы и поля...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c8834516e159f993'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c8834516e159f993','Родина','Вижу чудное приволье,
