INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_4c3fa9087260bf78_4a5c784d5298b282','rpp_4c3fa9087260bf78','Retroportal — Патриотические песни','https://pesni.retroportal.ru/rodina/ya_ty_on_ona_vmeste_celaya_strana.html','reference',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_660d50c0b2df84a4','Роспрягайтэ хлопци конэй',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (украинская казачья народная песня) | Народные песни | https://pesni.retroportal.ru/np3/01.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Роспрягайтэ хлопци конэй
Та й лагайтэ спочивать,
А я пиду в сад зэлэный,
В сад крыныченьку копать.
Маруся, раз, два, тры, калына,
Чорнявая дивчина
В саду ягоды рвала.
Копав, копав крыныченьку
У зэленому саду.
Чин э выйдэ дивчинонька
Рано-вранци по воду?
Припев
Выйшла, выйшла дивчинонька
Рано-вранци воду брать,
А за нэю козаченько
Вэдэ коня напувать.
Припев
Просыв, просыв видэрэчко –
Вона його нэ дала,
Дарыв, дарыв з рук колэчко –
Вона його нэ взяла.
Припев
Знаю, знаю дивчинонька,
Чим я тэбэ огорчив:
Що я вчора из вэчора
Краще тэбэ полюбыв.
Припев
Вона ростом нэвэлычка
Ще й годамы молода,
Руса коса до пояса,
В косе лента голуба.
Припев
Роспрягайтэ хлопци конэй
Та й лагайтэ спочивать,
А я пиду в сад зэлэный,
В сад крыныченьку копать.
Припев
Смотрите и слушайте  выступление Государственного академического  Кубанского казачьего хора   с песней &laquo; Распрягайте, хлопцы, коней &raquo; (художественный руководитель музыкального коллектива  Виктор Захарченко ).','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_660d50c0b2df84a4'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_660d50c0b2df84a4','Роспрягайтэ хлопци конэй','Роспрягайтэ хлопци конэй
