INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4ac85fc4a9f55f56','Россия','(«Светит солнышко на небе ясное...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Алымов, музыка: Анатолий Новиков) | Патриотические песни | https://pesni.retroportal.ru/rodina/rossiya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Светит солнышко на небе ясное...») | merged_versions: 1','Где найдёшь страну на свете
Краше Родины моей?
Все края земли моей в расцвете,
Без конца простор полей!
Припев:
Светит солнышко на небе ясное,
Цветут сады, шумят поля.
Россия вольная, страна прекрасная,
Советский край, моя земля!
Нашей силе молодецкой
Нету края и конца.
Богатырь-герой, народ советский
Славит Сталина-отца!
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Светит солнышко на небе ясное...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4ac85fc4a9f55f56'), datetime('now')),datetime('now'));
