INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4d0f00121e73b3e2','Ростов-город','(«Ростов-город, Ростов-Дон! Синий звёздный небосклон...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Сфоронов, музыка: Матвей Блантер) | Патриотические песни | https://pesni.retroportal.ru/rodina/rostov-gorod_rostov-don.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Ростов-город, Ростов-Дон! Синий звёздный небосклон...») | merged_versions: 1','Мы жили в этом городе,
Дружили в этом городе,
Ходили в этом городе гулять.
Как шли мы с разговорами,
С гитарой, с переборами,
Любили мы подружкам напевать.
Припев:
Ростов-город, Ростов-Дон!
Синий звёздный небосклон.
Улица Садовая,
Скамеечка кленовая -
Ростов-город, Ростов-Дон!
Пришла война суровая,
Зажгла огни багровые,
Хлебнули мы свинцового дождя.
И, оставляя город наш,
Любимый, светлый город наш
Мы в сердце уносили, уходя...
Припев
Но вот вернулись снова мы,
Давя врага подковами,
Сметая каски вместе с головой.
Наш город&nbsp;- слава новая,
Наш город&nbsp;- жизнь суровая,
Идём мы вновь знакомой мостовой.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Ростов-город, Ростов-Дон! Синий звёздный небосклон...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4d0f00121e73b3e2'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4d0f00121e73b3e2','Ростов-город','Мы жили в этом городе,
