INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_65fc8fa6dc548a5c','С нами Тимошенко','(«Маршал Тимошенко - наш нарком любимый...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Александр Лугин, музыка: Михаил Бак) | Песни военных лет | https://pesni.retroportal.ru/vov/timoshenko.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Маршал Тимошенко - наш нарком любимый...») | merged_versions: 1','Маршал Тимошенко&nbsp;- наш нарком любимый;
Смелых и умелых готовил он бойцов.
Пусть коварны вьюги, пусть суровы зимы -
Закалённый воин к трудностям готов!
С нами Тимошенко&nbsp;- боевой наш маршал;
Подвиги былые в сердцах живут всегда.
Мы по-богатырски развернёмся маршем,
Дрогнет от удара вражия орда!
Маршал Тимошенко&nbsp;- знает путь к победам;
За героем следом войска вступили в бой.
Родине он предан, Сталину он предан,
С нами Тимошенко&nbsp;- маршал боевой!
Маршал Тимошенко&nbsp;- можешь быть спокоен,
Долг священный помнит в боях любой из нас.
Храбро за Отчизну бьётся красный воин,
Доблестно и точно выполнит приказ!
С нами Тимошенко&nbsp;- боевой наш маршал;
Подвиги былые в сердцах живут всегда.
Мы по-богатырски развернёмся маршем,
Дрогнет от удара вражия орда!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Маршал Тимошенко - наш нарком любимый...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_65fc8fa6dc548a5c'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_65fc8fa6dc548a5c','С нами Тимошенко','Маршал Тимошенко&nbsp;- наш нарком любимый;
