INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_00a231017c994577','С чего начинается Родина?','(песня из кинофильма «Щит и меч»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Вениамин Баснер) | Патриотические песни | https://pesni.retroportal.ru/rodina/s_chego_nachinaetsya_rodina.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: (песня из кинофильма «Щит и меч») | merged_versions: 1','С чего начинается Родина?
С картинки в твоём букваре,
С хороших и верных товарищей,
Живущих в соседнем дворе.
А может, она начинается
С той песни, что пела нам мать.
С того, что в любых испытаниях
У нас никому не отнять.
С чего начинается Родина?
С заветной скамьи у ворот.
С той самой берёзки, что во поле,
Под ветром склоняясь, растёт.
А может, она начинается
С весенней запевки скворца.
И с этой дороги просёлочной,
Которой не видно конца.
С чего начинается Родина?
С окошек, горящих вдали,
Со старой отцовской будёновки,
Что где-то в шкафу мы нашли.
А может, она начинается
Со стука вагонных колёс.
И с клятвы, которую в юности
Ты ей в своём сердце принёс.
С чего начинается Родина?..','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(песня из кинофильма «Щит и меч»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_00a231017c994577'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_00a231017c994577','С чего начинается Родина?','С чего начинается Родина?
