INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b20c585473c1a6ff','Сама садик я садила',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/02.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Сама садик я садила,
Сама буду поливать.
Сама милого любила,
Сама буду забывать.
Ах, что это за садочек,
За зелёненький такой?
Ах, что это за мальчишка,
Разбессовестный такой?
Пустил славушку худую
Все соседи говорят.
За глаза меня ругают,
А в глаза меня хвалят.
При гулянье, при народе
Стал он девку целовать,
А девчонке стыдно стало,
Стала плакать и рыдать.
И мальчишке жалко стало,
Стал её он утешать,
Купил шелковый платочек,
Начал слёзы утирать.
&laquo;Ты не плачь, не плачь, девица,
Не плачь, девица-душа,
Только призыв я отбуду,
Возьму замуж за себя&raquo;.
&laquo;Тебе, мальчик, не жениться,
Меня, девицу, не взять:
Твой папашенька богатый
Не позволит меня взять&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b20c585473c1a6ff'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b20c585473c1a6ff','Сама садик я садила','Сама садик я садила,
Сама буду поливать.
Сама милого любила,
Сама буду забывать.
Ах, что это за садочек,
За зелёненький такой?
Ах, что это за мальчишка,
Разбессовестный такой?
Пустил славушку худую
Все соседи говорят.
За глаза меня ругают,
А в глаза меня хвалят.
При гулянье, при народе
Стал он девку целовать,
А девчонке стыдно стало,
Стала плакать и рыдать.
И мальчишке жалко стало,
Стал её он утешать,
Купил шелковый платочек,
Начал слёзы утирать.
&laquo;Ты не плачь, не плачь, девица,
Не плачь, девица-душа,
Только призыв я отбуду,
Возьму замуж за себя&raquo;.
&laquo;Тебе, мальчик, не жениться,
Меня, девицу, не взять:
Твой папашенька богатый
Не позволит меня взять&raquo;.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b20c585473c1a6ff_d2146481831dc6b9','rpp_b20c585473c1a6ff','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/02.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ed890103ac15e6a6','Светит месяц',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/03.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Светит месяц, светит ясный,
Светит белая заря.
Осветила путь дорожку
Мне до милого двора.
Мне не спится, не лежится,
И сон меня не берёт.
Я сходил бы к милой в гости,
Да не знаю, где живёт.
Попросил бы я товарища,
Мой товарищ доведёт.
Мой товарищ меня краше –
Боюсь Машу отобьёт.
Подхожу я к дому милой,
А у милой нет огня.
Постучал я под окошком,
Моя Маша спать легла.
- Стыдно, стыдно тебе, Маша,
Со вечера рано спать.
- А тебе, мой друг, стыднее,
До полуночи гулять!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ed890103ac15e6a6'), datetime('now')),datetime('now'));
