INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f2b7d2f4083a866c','Священная война','(«Вставай, страна огромная, вставай на смертный бой...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Александр Александров) | Песни военных лет | https://pesni.retroportal.ru/vov/svyashennaya_vojna.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Вставай, страна огромная, вставай на смертный бой...») | merged_versions: 1','Вставай, страна огромная ,
Вставай на смертный бой
С фашистской силой тёмною ,
С проклятою ордой .
Припев:
Пусть ярость благородная
Вскипает, как волна ,&nbsp;-
Идёт война народная ,
Священная война !
Припев
Дадим отпор душителям
Всех пламенных идей,
Насильникам, грабителям,
Мучителям людей!
Припев
Первоначальный текст песни Василия Лебедева-Кумача &laquo;Священная война&raquo;,  опубликованный в газетах  24&nbsp;июня 1941 года, отличается от исполняемого вокальными ансамблями и солистами:
Вставай, страна огромная,
Вставай на смертный бой
С фашистской силой тёмною,
С проклятою ордой.
Припев.
Пусть ярость благородная
Вскипает, как волна,&nbsp;-
Идёт война народная,
Священная война.
Как два различных полюса,
Во всём враждебны мы:
За свет и мир мы боремся,
Они&nbsp;- за царство тьмы.
Припев.
Дадим отпор душителям
Всех пламенных идей,
Насильникам, грабителям,
Мучителям людей!
Припев.
Не смеют крылья чёрные
Над Родиной летать,
Поля её просторные
Не смеет враг топтать!
Припев.
Гнилой фашистской нечисти
Загоним пулю в лоб,
Отребью человечества
Сколотим крепкий гроб!
Припев.
Пойдём ломить всей силою,
Всем сердцем, всей душой
За землю нашу милую,
За наш Союз большой.
Припев.
Встаёт страна огромная,
Встаёт на смертный бой
С фашистской силой темною,
С проклятою ордой.
Припев.
Пусть ярость благородная
Вскипает, как волна,&nbsp;-
Идёт война народная,
Священная война!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Вставай, страна огромная, вставай на смертный бой...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f2b7d2f4083a866c'), datetime('now')),datetime('now'));
