INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bf973f011ef5f913','Сероглазый король',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Анна Ахматова, музыка: Александр Вертинский) | Старинные романсы | https://pesni.retroportal.ru/sr3/19.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Слава тебе, безысходная боль!
Умер вчера сероглазый король.
Вечер осенний был душен и ал,
Муж мой, вернувшись, спокойно сказал:
&laquo;Знаешь, с охоты его принесли,
Тело у старого дуба нашли.
Жаль королеву. Такой молодой!..
За ночь одну она стала вдовой&raquo;.
Трубку свою на камине нашёл
И на ночную работу ушёл.
Дочку свою я сейчас разбужу,
В серые глазки её погляжу.
А за окном шелестят тополя:
&laquo;Нет на земле твоего короля...&raquo;','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bf973f011ef5f913'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bf973f011ef5f913','Сероглазый король','Слава тебе, безысходная боль!
