INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4effea71b73bf5b7','Сибирский вечер','(«Тайга загляделась в окошко...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Грибачёв, музыка: Марк Фрадкин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/sibirskij_vecher.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Тайга загляделась в окошко...») | merged_versions: 1','Тайга загляделась в окошко,
Метель шелестит по стене,
В тайге у Байкала гармошка,
Поёт о степной стороне.
В тайге у Байкала гармошка,
Поёт о степной стороне.
И чудится девушкам в хате,
Ни ночь, ни снега у окна:
Просторная степь на закате
И тихого Дона волна.
Просторная степь на закате
И тихого Дона волна.
И сон гармонист забывает,
Что поздно и время ко сну.
И сам гармонист вспоминает
Москву и казачку одну.
И сам гармонист вспоминает
Москву и казачку одну.
Под сводами светлого зала,
Где встреча героев была,
Казачка два слова сказала
И сердце с собой увезла.
Казачка два слова сказала
И сердце с собой увезла.
Тайга загляделась в окошко,
Метель шелестит по стене,
В тайге у Байкала гармошка,
Поёт о степной стороне.
В тайге у Байкала гармошка,
Поёт о степной стороне.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Тайга загляделась в окошко...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4effea71b73bf5b7'), datetime('now')),datetime('now'));
