INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3048394f9da68999','Сирень-черёмуха','(«Расцвела сирень-черёмуха в саду...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Анатолий Софронов, музыка: Юрий Милютин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/siren-cheremuha.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Расцвела сирень-черёмуха в саду...») | merged_versions: 1','Расцвела сирень-черёмуха в саду
На моё несчастье, на мою беду.
Я в саду хожу, хожу,
Да на цветы гляжу, гляжу,
Но никак в цветах, в цветах
Я милой не найду, я милой не найду,
Ох, не найду.
Чтобы мне её скорее отыскать
Видно все цветы придётся оборвать,
Ой, не прячь, сирень, сирень
Ты милой, милой, в ясный день.
Не мешай мою любовь, ты целовать,
Любовь ты целовать,
Ох, целовать.
Только я к цветку притронулся рукой,
Слышу голос я любимый, дорогой,
Ты сирень оставь, оставь
Да пусть она цветёт в цвету,
Лучше мы в саду, в саду
Да скроемся с тобой, мы скроемся в саду
Вдвоём с тобой.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Расцвела сирень-черёмуха в саду...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3048394f9da68999'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3048394f9da68999','Сирень-черёмуха','Расцвела сирень-черёмуха в саду
На моё несчастье, на мою беду.
