Вдвоём с тобой.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_3048394f9da68999_0ba482c692f9aef1','rpp_3048394f9da68999','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/siren-cheremuha.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9e59a967fa5a10d2','«Сияла ночь» («Тебя любить, обнять и плакать над тобой»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Афанасий Фет, музыка: Николай Ширяев) | Старинные романсы | https://pesni.retroportal.ru/sr3/25.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Сияла ночь. Луной был полон сад.
Сидели мы с тобой в гостиной без огней.
Рояль был весь раскрыт, и струны в нём дрожали,
Как и сердца у нас за песнею твоей.
Ты пела до зари, в слезах изнемогая,
Что ты одна – любовь, что нет любви иной,
И так хотелось жить, чтоб, звука не роняя,
Тебя любить, обнять и плакать над тобой.
Прошли года. Томительно и скучно.
И вот в тиши ночной твой голос вновь,
И веет, как тогда, во вздохах этих звучных,
Что ты одна – вся жизнь, что ты одна – любовь,
Что нет обид судьбы и сердца жгучей муки,
А жизни нет конца, и цели нет иной,
Как только веровать в рыдающие звуки,
Тебя любить, обнять и плакать над тобой!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9e59a967fa5a10d2'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9e59a967fa5a10d2','«Сияла ночь» («Тебя любить, обнять и плакать над тобой»)','Сияла ночь. Луной был полон сад.
Сидели мы с тобой в гостиной без огней.
Рояль был весь раскрыт, и струны в нём дрожали,
Как и сердца у нас за песнею твоей.
