INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_dad02519386732c6','Славное море – священный Байкал',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Дмитрий Давыдов, музыка народная) | Народные песни | https://pesni.retroportal.ru/np3/05.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Славное море – священный Байкал,
Славный корабль – омулевая бочка.
Эй, баргузин, пошевеливай вал,
Молодцу плыть недалечко.
Долго я тяжкие цепи влачил,
Долго бродил я в горах Акатуя.
Старый товарищ бежать пособил,-
Ожил я, волю почуя.
Шилка и Нерчинск не страшны теперь,-
Горная стража меня не поймала,
В дебрях не тронул прожорливый зверь,
Пуля стрелка миновала.
Шёл я и в ночь, и средь белого дня,
Вкруг городов озираяся зорко,
Хлебом кормили крестьянки меня,
Парни снабжали махоркой.
Славное море – священный Байкал,
Славный мой парус – кафтан дыроватый.
Эй, баргузин, пошевеливай вал,
Слышатся бури раскаты.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_dad02519386732c6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_dad02519386732c6','Славное море – священный Байкал','Славное море – священный Байкал,
