INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_5dbdb35df0ee72f9','Славься','(«Славься, славься, ты Русь моя...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Городницкий, музыка: Михаил Глинка) | Патриотические песни | https://pesni.retroportal.ru/rodina/slavsya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Славься, славься, ты Русь моя...») | merged_versions: 1','Славься, славься, ты Русь моя,
Славься, ты русская наша земля!
Да будет во веки веков сильна
Любимая наша родная страна!
Славься, славься из рода в род,
Славься великий наш русский народ!
Врагов посягнувших на край родной
Рази беспощадно могучей рукой!
Слава, слава героям бойцам
Родины нашей отважным сынам!
Кто кровь за Отчизну свою прольёт,
Того никогда не забудет народ.
Славься, славься, ты Русь моя!
Славься, ты русская наша земля!
Вот он, наш Кремль, с ним вся Русь, с ним весь мир...','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Славься, славься, ты Русь моя...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_5dbdb35df0ee72f9'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_5dbdb35df0ee72f9','Славься','Славься, славься, ты Русь моя,
