INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_771b2cc0068dcf64','Слушайте, если хотите',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Денисьев, музыка: Николай Шишкин) | Старинные романсы | https://pesni.retroportal.ru/sr3/20.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Слушайте, если хотите,
Песню я вам спою
И в звуках песни этой
Открою всю душу свою.
Мне так отрадно с вами
Носиться над волнами,
Что в безвозвратную даль
Умчаться мне было б не жаль.
И этой тихой ночью,
Когда кругом всё спит,
Не дремлет моё сердце,
Оно сильней стучит.
В душе же так тревожно,
Боюсь, что невозможно
Ещё когда-нибудь
Мне эту ночь вернуть.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_771b2cc0068dcf64'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_771b2cc0068dcf64','Слушайте, если хотите','Слушайте, если хотите,
