INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8adc59978aa81cb8','Смерть врагам','(«В бой, товарищи, в бой! Нас ведёт за собой знамя...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Виктор Винников, музыка: Александр Цфасман) | Песни военных лет | https://pesni.retroportal.ru/vov/smert_vragam.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («В бой, товарищи, в бой! Нас ведёт за собой знамя...») | merged_versions: 1','В бой, товарищи, в бой!
Нас ведёт за собой
Знамя самой священной войны.
За Отчизну свою
На удар мы в бою
Отвечаем ударом стальным!
Припев:
Наш закон прост и прям&nbsp;-
Смерть врагам! Смерть врагам!
Путь один лишь&nbsp;- вперёд&nbsp;- знает вольный народ
Смерть врагам! Смерть врагам!
Много-много веков
Всяких били врагов
Бонапарта мы били дубьём.
А теперь боевой
Грозной силой стальной
Мы фашистов навеки сметём!
Припев
За знамёна Москвы
Будем драться как львы,
Чтоб Отчизна росла и цвела!
Ради наших детей,
Ради жён, матерей
Мы врага уничтожим дотла!
Припев
Биография композитора, пианиста и дирижёра  Александра Цфасмана  на сайте &laquo;Retroportal.ru&raquo;.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«В бой, товарищи, в бой! Нас ведёт за собой знамя...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8adc59978aa81cb8'), datetime('now')),datetime('now'));
