INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e0dfc6780f62ccf9','Снеги белые, пушисты',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/06.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Снеги белые, пушисты покрывали все поля;
Одного лишь не покрыли горя люта моего.
Есть кусточек среди поля, одинешенёк стоит,
Он не клонит к земле ветки, и листочков на нем нет.
Одна горькая, несчастна, всё горюю по милом,
День горюю, ночь тоскую, понапрасну слёзы лью.
Слеза канет, снег растает, в поле вырастет трава,
Никто травушки не косит, шелковой не обожнёт.
Никто девушки не любит, никто замуж не берёт.
Пойду с горя в чисто поле, сяду я на бугорок.
Пойду с горя в чисто поле, сяду я на бугорок,
Посмотрю я в ту сторонку, где мой миленький живёт.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e0dfc6780f62ccf9'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e0dfc6780f62ccf9','Снеги белые, пушисты','Снеги белые, пушисты покрывали все поля;
