INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_39e3df0c79e9c8bb','Совсем чужие',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Борис Тимофеев, Семён Фруг, музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr3/21.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ты этого хотел, считая всё ошибкой.
Ты первый говорил: &laquo;Нам разойтись пора&raquo;...
Я встретила разрыв спокойною улыбкой,
Но плакала затем все ночи до утра.
И вот мы разошлись. Совсем, совсем чужие;
Нет ожиданья встреч, нет сладости греха.
Осталась карточка, любимых писем связка,
Где проза кажется мелодией стиха.
Остался целый мир, где память отдыхает
И тихо греется чуть тлеющим огнём.
Так книгу старую отрадно взять бывает
И над излюбленным задуматься листом.
И не зови меня, к былому нет возврата,
Разлуки ураган меж нами пролетел.
Любовь не умерла, любовь тобой измята,
Совсем чужие мы, ты этого хотел!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_39e3df0c79e9c8bb'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_39e3df0c79e9c8bb','Совсем чужие','Ты этого хотел, считая всё ошибкой.
