INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_80064120cd126136','Солдатушки, бравы ребятушки',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | Народные песни | https://pesni.retroportal.ru/np3/07.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','(русская народная военная песня)
- Солдатушки, бравы ребятушки,
Где же ваши деды?
- Наши деды – славные победы,
Вот где наши деды!
- Солдатушки, бравы ребятушки,
Где же ваши матки?
- Наши матки – белые палатки,
Вот где наши матки!
- Солдатушки, бравы ребятушки,
А где ваши жёны?
- Наши жёны – ружья заражёны,
Вот где наши жёны!
- Солдатушки, бравы ребятушки,
Где же ваши сёстры?
- Наши сёстры – штыки, сабли остры,
Вот где наши сёстры!
- Солдатушки, бравы ребятушки,
Где же ваши детки?
- Наши детки – пули наши метки,
Вот где наши детки!
- Солдатушки, бравы ребятушки,
Где же ваша хата?
- Наша хата – лагерь супостата,
Вот где наша хата!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_80064120cd126136'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_80064120cd126136','Солдатушки, бравы ребятушки','(русская народная военная песня)
