INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_80064120cd126136_a1c6da6f6e2d9fd7','rpp_80064120cd126136','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/07.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d2d11fa1b9d48f6e','Соловей',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Антон Дельвиг, музыка: Александр Алябьев) | Старинные романсы | https://pesni.retroportal.ru/sr3/22.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вариант I
Соловей мой, соловей,
Голосистый соловей!
Ты куда, куда летишь,
Где всю ночку пропоёшь?
Соловей мой, соловей,
Голосистый соловей!
Кто-то, бедная, как я,
Ночь прослушает тебя,
Не смыкаючи очей,
Утопаючи в слезах?
Соловей мой, соловей,
Голосистый соловей!
Побывай во всех странах,
В деревнях и городах:
Не найти тебе нигде
Горемычнее меня.
Соловей мой, соловей,
Голосистый соловей!
Вариант II
Соловей мой, соловей
Голосистый соловей!
Ты куда, куда летишь,
Где всю ночку пропоёшь?
Кто-то бедная, как я,
Ночь прослушает тебя,
Не смыкаючи очей,
Утопаючи в слезах?
Ты лети, мой соловей,
Хоть за тридевять земель,
Хоть за синие моря,
На чужие берега;
Побывай во всех странах,
В деревнях и в городах:
Не найти тебе нигде
Горемычнее меня.
У меня ли, у младой,
Дорог жемчуг на груди,
У меня ли, у младой,
Жар-колечко на руке,
У меня ли, у младой,
В сердце маленький дружок.
В день осенний на груди
Крупный жемчуг потускнел,
В зимнюю ночку на руке
Распаялось кольцо,
А как нынешней весной
Разлюбил меня милой.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d2d11fa1b9d48f6e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d2d11fa1b9d48f6e','Соловей','Вариант I
