INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d4f750473e348492','Соловьём залётным',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Кольцов, музыка народная) | Народные песни | https://pesni.retroportal.ru/np3/08.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Соловьём залётным юность пролетела.
Волной в непогоду радость прошумела.
Пора золотая была, да сокрылась;
Сила молодая с телом износилась,
Сила молодая с телом износилась.
От кручины-думы в сердце кровь застыла,
Что любил, как душу, - и то изменило.
Как былинку, ветер молодца шатает,
Зима лицо знобит, солнце сожигает,
Зима лицо знобит, солнце сожигает.
До поры, до время всем я весь изжился,
И кафтан мой синий с плеч долой свалился.
Без любви, без счастья по миру скитаюсь:
Разойдусь с бедою – с горем повстречаюсь,
Разойдусь с бедою – с горем повстречаюсь!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d4f750473e348492'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d4f750473e348492','Соловьём залётным','Соловьём залётным юность пролетела.
Волной в непогоду радость прошумела.
