INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d4f750473e348492_13a9f49ef59071f0','rpp_d4f750473e348492','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/08.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_229dce40ef5c8d86','«Сомнение» («Уймитесь, волнения страсти»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Нестор Кукольник, музыка: Михаил Глинка) | Старинные романсы | https://pesni.retroportal.ru/sr3/23.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Уймитесь, волнения страсти,
Засни, безнадёжное сердце,
Я плачу, я стражду, душа истомилась в разлуке!
Я стражду, я плачу, не выплакать горя в слезах.
Напрасно надежда мне счастье гадает, -
Не верю, не верю обетам коварным,
Разлука уносит любовь!
Как сон, неотступный и грозный,
Мне снится соперник счастливый,
И тайно, и злобно кипящая ревность пылает!
И тайно, и злобно оружие ищет рука.
Напрасно измену мне ревность гадает, -
Не верю, не верю коварным наветам,
Я счастлив – ты снова моя!
Минует печальное время,
Мы снова обнимем друг друга,
И страстно, и жарко забьётся воскресшее сердце,
И страстно, и жарко с устами сольются уста.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_229dce40ef5c8d86'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_229dce40ef5c8d86','«Сомнение» («Уймитесь, волнения страсти»)','Уймитесь, волнения страсти,
