INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ced432aa93ce18d5','Сормовская лирическая','(«На Волге широкой, на стрелке далёкой...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/sormovskaya_liricheskaya.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («На Волге широкой, на стрелке далёкой...») | merged_versions: 1','На Волге широкой, на стрелке далёкой
Гудками кого-то зовёт пароход.
Под городом Горьким, где ясные зорьки,
В рабочем посёлке подруга живёт.
В рубашке нарядной к своей ненаглядной
Пришёл объясниться хороший дружок:
Вчера говорила - навек полюбила,
А нынче не вышла в назначенный срок.
Свиданье забыто, над книгой раскрытой
Склонилась подруга в окне золотом.
До утренней смены, до первой сирены
Шуршат осторожно шаги под окном.
Ой, летние ночки, буксиров гудочки.
Волнуется парень и хочет уйти.
Но девушки краше, чем в Сормове нашем,
Ему никогда и нигде не найти.
А утром у входа родного завода
Влюблённому девушка встретится вновь
И скажет: &laquo;Немало я книжек читала,
Но нет ещё книжки про нашу любовь&raquo;.
На Волге широкой, на стрелке далёкой
Гудками кого-то зовёт пароход.
Под городом Горьким, где ясные зорьки,
В рабочем посёлке подруга живёт.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«На Волге широкой, на стрелке далёкой...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ced432aa93ce18d5'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ced432aa93ce18d5','Сормовская лирическая','На Волге широкой, на стрелке далёкой
