INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_e5f447dd3018b33a','Спосеяли девки лён',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/09.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Спосеяли девки лён,
Спосеяли девки лён.
Девки лён, девки лён...
Ходи браво, девки лён.
Спосеявши пололи,
Белы ручки кололи.
Кололи, кололи...
Ходи браво, кололи.
Как во этот во ленок
Повадился паренёк.
Паренёк, паренёк...
Ходи браво, паренёк.
Повадился паренёк –
Иванушка щеголёк.
Щеголёк, щеголёк...
Ходи браво, щеголёк.
Весь леночек притоптал,
Весь леночек притоптал.
Притоптал, притоптал...
Ходи браво, притоптал.
Со льна цветы посрывал,
В быстру речку побросал,
Побросал, побросал...
Ходи браво, побросал.
Спосеяли девки лён,
Спосеяли девки лён.
Девки лён, девки лён...
Ходи браво, девки лён.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_e5f447dd3018b33a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_e5f447dd3018b33a','Спосеяли девки лён','Спосеяли девки лён,
