INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_e5f447dd3018b33a_8dcf503307b56a08','rpp_e5f447dd3018b33a','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/09.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_391671ebb3cbe73f','Спускается солнце за степи',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/10.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Спускается солнце за степи,
Вдали золотится ковыль.
Колодников звонкие цепи
Взметают дорожную пыль.
Динь – бом, динь – бом,
Слышен звон кандальный,
Динь – бом, динь – бом,
Путь сибирский дальний.
Динь - бом, динь – бом,
Слышно там и тут:
Нашего товарища
На каторгу ведут.
Идут они с бритыми лбами,
Шагают вперёд тяжело.
Угрюмые сдвинуты брови,
На сердце раздумье легло.
Припев
&laquo;Что ж, братцы, затянемте песню,
Забудем лихую беду!
Уж, видно, такая невзгода
Написана нам на роду.&raquo;
Припев
Поют про свободные степи,
Про дивную волю поют...
День меркнет всё боле,
А цепи дорогу метут да метут.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_391671ebb3cbe73f'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_391671ebb3cbe73f','Спускается солнце за степи','Спускается солнце за степи,
