INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3643825f9d2b126a','Спустилось солнце за горою',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/11.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Спустилось солнце за горою,
Где чёрный ворон прокричал,
Слеза на грудь его упала,
Последний раз сказал: &laquo;Прощай!&raquo;
&laquo;Прощайте, братцы, мои сёстры,
Прощай, голубушка моя.
Быть может, я не ворочуся,
Быть может, на смерть еду я!
Быть может, саблею-злодейкой
Отрубят голову мою.
Быть может, пуля-лиходейка
Пронзит грудь белую мою.&raquo;
Спустилось солнце за горою,
Где чёрный ворон прокричал,
Слеза на грудь его упала,
Последний раз сказал: &laquo;Прощай!&raquo;','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3643825f9d2b126a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3643825f9d2b126a','Спустилось солнце за горою','Спустилось солнце за горою,
