INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_3643825f9d2b126a_68f193fa90b5d270','rpp_3643825f9d2b126a','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/11.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_32361d8ca9e41492','Спят усталые игрушки','(Колыбельная из телепередачи «Спокойной ночи, малыши!»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Зоя Петрова, музыка: Аркадий Островский) | Песни для детей | https://pesni.retroportal.ru/deti/spyat_ustalye_igrushki.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Колыбельная из телепередачи «Спокойной ночи, малыши!») | merged_versions: 1','Спят усталые игрушки, книжки спят,
Одеяла и подушки ждут ребят.
Даже сказка спать ложится,
Чтобы ночью нам присниться.
Ты ей пожелай: &laquo;Баю-бай!&raquo;
Обязательно по дому в этот час
Тихо-тихо ходит Дрёма возле нас.
За окошком всё темнее,
Утро ночи мудренее,
Глазки закрывай! Баю-бай!
В сказке можно покачаться на луне
И по радуге промчаться на коне.
Со слонёнком подружиться
И поймать перо жар-птицы
Глазки закрывай! Баю-бай!
Баю-бай, должны все люди ночью спать.
Баю-баю, завтра будет день опять.
За день мы устали очень,
Скажем всем: &laquo;Спокойной ночи!&raquo;
Глазки закрывай! Баю-бай!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Колыбельная из телепередачи «Спокойной ночи, малыши!»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_32361d8ca9e41492'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_32361d8ca9e41492','Спят усталые игрушки','Спят усталые игрушки, книжки спят,
Одеяла и подушки ждут ребят.
