INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_32361d8ca9e41492_351489c8a2736668','rpp_32361d8ca9e41492','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/spyat_ustalye_igrushki.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1b0b92885f75371e','Среди долины ровныя',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Мерзляков, музыка народная) | Народные песни | https://pesni.retroportal.ru/np3/12.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Среди долины ровныя,
На гладкой высоте
Цветёт, растёт высокий дуб
В могучей красоте.
Высокий дуб, развесистый,
Один у всех в глазах;
Один, один, бедняжечка,
Как рекрут на часах.
Взойдёт ли красно солнышко, -
Кого под тень принять?
Ударит ли погодушка, -
Кто будет защищать?
Ни сосенки кудрявыя,
Ни ивки вкруг него;
Ни кустики зелёные
Не вьются вкруг него.
Ах, скучно одинокому
И дереву расти!
Ах, горько молодцу
Без милой жизнь вести!
Есть много сребра, золота:
Кому их подарить?
Есть много славы, почестей:
Но с кем их разделить?
Встречаюсь ли с знакомыми:
Поклон – да был таков;
Встречаюсь ли с пригожими:
Поклон – да пара слов.
Одних я сам чуждаюся,
Другой бежит меня.
Все други, все приятели
До чёрного лишь дня!
Где ж сердцем отдохнуть могу,
Когда гроза взойдёт?
Друг нежный спит в сырой земле,
На помощь не придёт.
Ни роду нет, ни племени
В чужой мне стороне;
Не ластится любезная
Подруженька ко мне!
Не плачется от радости
Старик, глядя на нас,
Не вьются вкруг малюточки,
Тихохонько резвясь.
Возьмите же всё золото,
Все почести назад, -
Мне Родину, мне милую,
Мне милой дайте взгляд!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1b0b92885f75371e'), datetime('now')),datetime('now'));
