INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_3168b0010085d0f5_7080ffaa017f6e15','rpp_3168b0010085d0f5','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/14.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b7ab349611107cce','Стоит гора высокая',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Леонид Глибов, музыка народная) | Народные песни | https://pesni.retroportal.ru/np3/15.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Стоить гора высокая
Попид горою гай, гай...
Зэленый гай, густэсенький,
Нэначе справди рай!
Пид гаем вьется риченька,
Як скло вода блешить,
Долыною зэленою
Кудысь вона бижыть.
Край берега, у затышку
Привьязани човны,
А три верби схилилися,
Мов журяться воны.
Шо пройде Красне литечко,
Повиють холода,
Осыплэтся их лыстячко
И понесэ вода...
Журюсь и я над ричкою,
Бижить вона, шумыть,
А в мэне биднэ сердэнько
И млие, и болыть.
Болыть воно та журыться,
Шо вэрнеться весна,
А молодисть не вэрнеться,
Не вэрнеться вона!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b7ab349611107cce'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b7ab349611107cce','Стоит гора высокая','Стоить гора высокая
Попид горою гай, гай...
Зэленый гай, густэсенький,
Нэначе справди рай!
Пид гаем вьется риченька,
