INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c807ed6e2aae59b8','Сторонка родная','(«Сторонка родная, ты солдатскому сердцу мила...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Михалков, музыка: Аркадий Островский) | Патриотические песни | https://pesni.retroportal.ru/rodina/storonka_rodnaya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Сторонка родная, ты солдатскому сердцу мила...») | merged_versions: 1','С неразлучным своим автоматом
Не в одной побывал я стране,
Но повсюду, скажу вам, ребята,
Я скучал по родной стороне.
Припев:
Сторонка, сторонка родная,
Ты солдатскому сердцу мила.
Эх, дорога моя фронтовая,
Далеко ты меня завела.
Батальон наш стоял в Бухаресте,
Бухарест&nbsp;- неплохой городок,
Но признаюсь, ребята, по чести,
Мне дороже родимый Торжок.
Припев
Бил я немцев на улицах Вены,
В ней сады и дворцы хороши.
Только Вена, скажу откровенно,
Хороша не для русской души.
Припев
Дождались мы великой победы,
И теперь, с окончаньем войны,
Я уж как-нибудь, братцы, доеду
До родимой своей стороны.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Сторонка родная, ты солдатскому сердцу мила...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c807ed6e2aae59b8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c807ed6e2aae59b8','Сторонка родная','С неразлучным своим автоматом
