INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8b2be678425fb413','Там, дэ Ятрань круто вьётся',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (украинская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/16.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Там, дэ Ятрань круто вьётся,
З-пид каменья бье вода, -
Там дивчина воду брала,
Чорнобрива, молода.
Ты, дивчино, ты щаслыва,
В тэбэ батько, маты е,
Рид вэлыкий, хата била,
Всё, що в хати, то твое.
А я бидный, безталанный,
Степ широкий – то ж мий сват,
Шабля й люлька – вся родина,
Сивый коник – то ж мий брат.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8b2be678425fb413'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8b2be678425fb413','Там, дэ Ятрань круто вьётся','Там, дэ Ятрань круто вьётся,
З-пид каменья бье вода, -
Там дивчина воду брала,
Чорнобрива, молода.
Ты, дивчино, ты щаслыва,
В тэбэ батько, маты е,
Рид вэлыкий, хата била,
Всё, що в хати, то твое.
А я бидный, безталанный,
Степ широкий – то ж мий сват,
Шабля й люлька – вся родина,
Сивый коник – то ж мий брат.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_8b2be678425fb413_1f2b9b615ce8b8ea','rpp_8b2be678425fb413','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/16.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fc2a6beb5bcc340d','Танец маленьких утят','Детская песенка Томаса Вернера','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (русский текст: Юрий Энтин, музыка: Томас Вернер / Thomas Werner /) | Песни для детей | https://pesni.retroportal.ru/deti/tanec_malenkih_utyat.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: Детская песенка Томаса Вернера | merged_versions: 1','На шагающих утят быть похожими хотят,
Быть похожими хотят не зря, не зря.
Можно хвостик отряхнуть и пуститься в дальний путь
И пуститься в дальний путь, крича &laquo;кря-кря&raquo;.
И природа хороша, и погода хороша,
Нет, не зря поёт душа, не зря, не зря.
Даже толстый бегемот, неуклюжий бегемот
От утят не отстает, кряхтит &laquo;кря-кря&raquo;
Припев:
На мгновенье надо
Детство возвратить.
Мы теперь утята,
И так прекрасно
На свете жить.
На весёлых на утят быть похожими хотят,
Быть похожими хотят не зря, не зря.
Даже бабушка и дед, сбросив восемьдесят лет,
За утятами вослед кричат &laquo;кря-кря&raquo;.
Вместе солнце, речка, дом кружат в танце озорном,
Кружат в танце озорном не зря, не зря.
Неуклюжий бегемот, ничего не разберёт,
Но старательно поёт &laquo;кря-кря-кря-кря&raquo;.
Припев
На танцующих утят быть похожими хотят,
Быть похожими хотят не зря, не зря.
Повторяйте все за мной, все фигуры до одной,
Все фигуры до одной, кря-кря-кря-кря.
Легче танца в мире нет, лучше танца в мире нет,
Вам раскрыт его секрет не зря, не зря.
Посмотрите, бегемот, неуклюжий бегемот,
Вот танцует, вот даёт! кря-кря-кря-кря.
Припев
Слушать песню &laquo;Танец маленьких утят&raquo; композитора Томаса Вернера (перевод со швейцарского Юрия Энтина) в исполнении  Ансамбля фольклорной музыки под управлением Владимира Назарова .','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:Детская песенка Томаса Вернера", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fc2a6beb5bcc340d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_fc2a6beb5bcc340d','Танец маленьких утят','На шагающих утят быть похожими хотят,
Быть похожими хотят не зря, не зря.
