INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_fc2a6beb5bcc340d_bf21bc5b99ad1441','rpp_fc2a6beb5bcc340d','Retroportal — Песни для детей','https://pesni.retroportal.ru/deti/tanec_malenkih_utyat.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_47999f3fca75ba11','Тебя здесь нет, но ты со мною',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Григорий Кушелев-Безбородко) | Старинные романсы | https://pesni.retroportal.ru/sr3/24.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Льётся ливнями дождь, несутся тучи,
Полна ненастья эта ночь,
Но мысль о нём, как свет могучий,
Стоит и не отходит прочь.
Тебя здесь нет, но ты со мною,
Рука моя в твоей руке,
И всё, мой друг, полно тобою
В моём укромном уголке.
Пусть стонет ель, пусть плачет вьюга,
Тоскуя в холоде ночном,
Ты для меня, что солнце юга –
Тепло и свет в тебе одном!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_47999f3fca75ba11'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_47999f3fca75ba11','Тебя здесь нет, но ты со мною','Льётся ливнями дождь, несутся тучи,
Полна ненастья эта ночь,
Но мысль о нём, как свет могучий,
Стоит и не отходит прочь.
Тебя здесь нет, но ты со мною,
Рука моя в твоей руке,
И всё, мой друг, полно тобою
В моём укромном уголке.
Пусть стонет ель, пусть плачет вьюга,
Тоскуя в холоде ночном,
Ты для меня, что солнце юга –
Тепло и свет в тебе одном!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_47999f3fca75ba11_01b2fc3e34c9125c','rpp_47999f3fca75ba11','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/24.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_365a8fe1e49cee9c','Текстильный городок','(«Подмосковный городок, липы жёлтые в рядок...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Танич, музыка: Ян Френкель) | Эстрадные песни | https://pesni.retroportal.ru/estrada/tekstilny_gorodok.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Подмосковный городок, липы жёлтые в рядок...») | merged_versions: 1','Подмосковный городок,
Липы жёлтые в рядок;
Подпевает электричке
Ткацкой фабрики гудок.
Городок наш – ничего,
Населенье таково:
Незамужние ткачихи
Составляют большинство.
В общежитии девчат
Фотографии висят,
Дремлют ленты на гитарах,
И будильники стучат.
Но в хороший вечерок
Заглянул на огонёк
В нашу комнату девичью
Бывший флотский паренёк.
Вышло так оно само:
Написал он мне письмо...
И девчонки к новоселью
Подарили нам трюмо.
Мы на фабрику вдвоём
Утром рядышком идём:
То ли, может, он со мною,
То ли, может, я при нём.
Фотокарточки висят,
И будильники стучат,
Но одной гитарой меньше
Стало в комнате девчат...
Ходят девочки в кино,
Знают девочки одно:
Уносить свои гитары
Им придется всё равно.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Подмосковный городок, липы жёлтые в рядок...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_365a8fe1e49cee9c'), datetime('now')),datetime('now'));
