INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b0b953953de8dd27','Телеграфные куплеты','(из репертуара Владимира Коралли)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Владлен Бахнов и Яков Костюковский, музыка: Модест Табачников) | Эстрадные песни | https://pesni.retroportal.ru/estrada/telegrafnye_kuplety.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (из репертуара Владимира Коралли) | merged_versions: 1','Мой зачин не будет долог:
Я предупреждаю вас,
Что куплеты без глаголов
Буду исполнять сейчас.
Может быть, и странно это,
Но назвал их так поэт:
&laquo;Телеграфные куплеты&raquo;.
Ясно всё? Вопросов нет?
Плут. Палатка. Пиво. Воды.
Кружка. Пена. Ловкость рук.
&laquo;Волга&raquo;. Дача за полгода.
Гобелены. Бронза. Бук.
Разговоры. Дом. Соседи.
Ревизор. Судья. Привет!
Север. Белые медведи.
Ясно всё? Вопросов нет?..','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(из репертуара Владимира Коралли)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b0b953953de8dd27'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b0b953953de8dd27','Телеграфные куплеты','Мой зачин не будет долог:
