INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fad5660f23b14a1d','Тёмно-вишнёвая шаль',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Владимир Бакалейников) | Старинные романсы | https://pesni.retroportal.ru/sr3/26.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я о прошлом теперь не мечтаю,
И мне прошлого больше не жаль.
Только много и много напомнит
Эта тёмно-вишнёвая шаль.
В этой шали я с ним повстречалась,
И любимой меня он называл.
Я стыдливо лицо прикрывала,
А он нежно меня целовал.
Говорил мне: &laquo;Прощай, дорогая,
Расставаться с тобою мне жаль.
Как к лицу тебе, слышишь, родная,
Эта тёмно-вишнёвая шаль!&raquo;
Я о прошлом теперь не мечтаю,
Только сердце затмила печаль.
И я молча к груди прижимаю
Эту тёмно-вишнёвую шаль.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_fad5660f23b14a1d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_fad5660f23b14a1d','Тёмно-вишнёвая шаль','Я о прошлом теперь не мечтаю,
