INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8fec3026074f7aa3','Течёт река Волга','(«Издалека долго течёт река Волга...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лев Ошанин, музыка: Марк Фрадкин) | Патриотические песни | https://pesni.retroportal.ru/rodina/techet_reka_volga.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Издалека долго течёт река Волга...») | merged_versions: 1','Издалека долго
Течёт река Волга,
Течёт река Волга,
Конца и края нет.
Среди хлебов спелых,
Среди снегов белых
Течёт моя Волга,
А мне семнадцать лет.
Сказала мать: &laquo;Бывает всё, сынок.
Быть может, ты устанешь от дорог.
Когда придёшь домой в конце пути,
Свои ладони в Волгу опусти&raquo;.
Издалека долго
Течёт река Волга,
Течёт река Волга,
Конца и края нет.
Среди хлебов спелых,
Среди снегов белых
Течет моя Волга
А мне уж тридцать лет.
Твой первый взгляд и первый плеск весла.
Всё было, только речка унесла.
Я не грущу о той весне былой,
Взамен её&nbsp;- твоя любовь со мной.
Издалека долго
Течёт река Волга,
Течёт река Волга,
Конца и края нет.
Среди хлебов спелых,
Среди снегов белых
Гляжу в тебя, Волга
Седьмой десяток лет.
Здесь мой причал, и здесь мои друзья&nbsp;-
Всё без чего на свете жить нельзя.
С далёких плёсов в звёздной тишине
Другой мальчишка подпевает мне:
&laquo;Издалека долго
Течет река Волга,
Течёт река Волга,
Конца и края нет.
Среди хлебов спелых,
Среди снегов белых
Течёт моя Волга,
А мне семнадцать лет&raquo;...','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Издалека долго течёт река Волга...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8fec3026074f7aa3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8fec3026074f7aa3','Течёт река Волга','Издалека долго
