INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_cc40359034358a24','Тишина за Рогожской заставою','(Песня из фильма «Дом, в котором я живу»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Алексей Фатьянов, музыка: Юрий Бирюков) | Эстрадные песни | https://pesni.retroportal.ru/estrada/tishina_za_rogozhskoj_zastavoyu.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: (Песня из фильма «Дом, в котором я живу») | merged_versions: 1','Тишина за Рогожской заставою.
Спят деревья у сонной реки.
Лишь составы идут за составами,
Да кого-то скликают гудки.
Подскажи, расскажи, утро раннее,
Где с подругой мы счастье найдём?
Может быть, вот на этой окраине
Возле дома, в котором живём?
Не страшны мне ничуть расстояния!
Но, куда ни привёл бы нас путь,
Ты про первое в жизни свидание
И про первый рассвет не забудь.
Как люблю твои светлые волосы,
Как любуюсь улыбкой твоей,
Ты сама догадайся по голосу
Семиструнной гитары моей.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(Песня из фильма «Дом, в котором я живу»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_cc40359034358a24'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_cc40359034358a24','Тишина за Рогожской заставою','Тишина за Рогожской заставою.
