INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_cc40359034358a24_95fc4c3779a7ce16','rpp_cc40359034358a24','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/tishina_za_rogozhskoj_zastavoyu.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b70a68af58fd6e68','«То, что я должен сказать» («Юнкерам»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Александр Вертинский) | Старинные романсы | https://pesni.retroportal.ru/sr3/28.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я не знаю, зачем и кому это нужно,
Кто послал их на смерть недрожащей рукой?
Только так беспощадно, так зло и ненужно
Опустили их в Вечный Покой!
Осторожные зрители молча кутались в шубы,
И какая-то женщина с искажённым лицом
Целовала покойника в посиневшие губы
И швырнула в священника обручальным кольцом.
Закидали их ёлками, замесили их грязью
И пошли по домам под шумок толковать,
Что пора положить бы уж конец безобразию,
Что и так уже скоро, мол, мы начнём голодать.
И никто не додумался просто стать на колени
И сказать этим мальчикам, что в бездарной стране
Даже светлые подвиги – это только ступени
В бесконечные пропасти, к недоступной Весне!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b70a68af58fd6e68'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b70a68af58fd6e68','«То, что я должен сказать» («Юнкерам»)','Я не знаю, зачем и кому это нужно,
Кто послал их на смерть недрожащей рукой?
Только так беспощадно, так зло и ненужно
Опустили их в Вечный Покой!
Осторожные зрители молча кутались в шубы,
И какая-то женщина с искажённым лицом
Целовала покойника в посиневшие губы
И швырнула в священника обручальным кольцом.
Закидали их ёлками, замесили их грязью
И пошли по домам под шумок толковать,
Что пора положить бы уж конец безобразию,
Что и так уже скоро, мол, мы начнём голодать.
И никто не додумался просто стать на колени
И сказать этим мальчикам, что в бездарной стране
Даже светлые подвиги – это только ступени
В бесконечные пропасти, к недоступной Весне!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b70a68af58fd6e68_02402b33804c447b','rpp_b70a68af58fd6e68','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/28.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8b5febcbb9fcb02b','Только раз бывают в жизни встречи',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Павел Герман, музыка: Борис Фомин) | Старинные романсы | https://pesni.retroportal.ru/sr3/27.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','День и ночь роняет сердце ласку,
День и ночь кружится голова,
День и ночь взволнованною сказкой
Мне звучат твои слова.
Только раз бывают в жизни встречи,
Только раз судьбою рвётся нить,
Только раз в холодный зимний вечер
Мне так хочется любить!
Тает луч забытого заката,
Синевой окутаны цветы.
Где же ты, желанная когда-то,
Где, во мне будившая мечты?
Только раз бывают в жизни встречи,
Только раз судьбою рвётся нить,
Только раз в холодный зимний вечер
Мне так хочется любить!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8b5febcbb9fcb02b'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8b5febcbb9fcb02b','Только раз бывают в жизни встречи','День и ночь роняет сердце ласку,
