INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a73c2092b55f9777','Тонкая рябина',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Иван Суриков, музыка народная) | Народные песни | https://pesni.retroportal.ru/np3/18.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','&laquo;Что шумишь, качаясь,
Тонкая рябина,
Головой склоняясь
До самого тына?&raquo;
А через дорогу
За рекой широкой
Так же одиноко
Дуб стоит высокий.
&laquo;Как бы мне, рябине,
К дубу перебраться?
Я б тогда не стала
Гнуться и качаться.
Тонкими ветвями
Я б к нему прижалась
И с его листами
День и ночь шепталась.&raquo;
Но нельзя рябине
К дубу перебраться!
&laquo;Знать, мне, сиротине,
Век одной качаться&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a73c2092b55f9777'), datetime('now')),datetime('now'));
