INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b7e65745d50a7430','Точка, точка, запятая','(Песня из фильма «Точка, точка, запятая»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Юлий Ким, музыка: Геннадий Гладков) | Песни для детей | https://pesni.retroportal.ru/deti/tochka_tochka_zapyataya.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из фильма «Точка, точка, запятая») | merged_versions: 1','Точка, точка, запятая&nbsp;-
Вышла рожица кривая.
Ручки, ножки, огуречик,&nbsp;-
Получился человечек!
Что увидят эти точки,
Что построят эти ручки,
Далеко ли эти ножки
Уведут его,
Как он будет жить на свете&nbsp;-
Мы за это не в ответе:
Мы его нарисовали,
Только и всего!
Что вы, что вы! Очень важно,
Чтобы вырос он отважным,
Сам сумел найти дорогу,
Вычислить разбег.
Это трудно, это сложно,
Но иначе невозможно:
Только так из человечка
Выйдет человек!
Впрочем, знают даже дети,
Как прожить на белом свете;
Легче этого вопроса
Нету ничего!
Просто надо быть правдивым,
Благородным, справедливым,
Умным, честным, сильным, добрым&nbsp;-
Только и всего!
Как всё просто удаётся
На словах и на бумаге,
Как легко на гладкой карте
Стрелку начертить!
Но потом идти придётся
Через горы и овраги...
Так что прежде, человечек,
Выучись ходить!','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из фильма «Точка, точка, запятая»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b7e65745d50a7430'), datetime('now')),datetime('now'));
