INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f992dc7f866b4a36','Три брата','(«Три брата с фашистом дерутся жестоко...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка: Дмитрий Покрасс и Даниил Покрасс) | Песни военных лет | https://pesni.retroportal.ru/vov/tri_brata.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Три брата с фашистом дерутся жестоко...») | merged_versions: 1','Три брата с фашистом дерутся жестоко,
И каждый из братьев силён и плечист:
Один&nbsp;- пехотинец, другой&nbsp;- смелый сокол,
А третий&nbsp;- отважный танкист!
Вот первый у речки ведёт переправу,
Приказ выполняя, торопит бойцов&nbsp;-
И видит, что подлая вражья орава
Забрать его хочет в кольцо.
Враги навалились и справа, и слева,
Их вчетверо больше, чем наших ребят.
Но, полный великой отваги и гнева,
Геройски дерётся отряд.
Фашистские гады кладут все усилья,
Всё жарче и жарче становится бой...
Но вот засверкали знакомые крылья,
И брат появился второй.
Покончивши в небе с фашистскою стервой,
Ударил герой по наземным врагам,
И, братскую помощь почуявши, первый
Дал волю геройским штыкам!
Попятился враг, замешался&nbsp;- и встретил
Конец свой и гибель проклятый фашист...
На помощь двум братьям явился и третий,
Явился отважный танкист.
Так братья дерутся в содружестве смелом,
Геройски воюют за Родину-мать,
Чтоб гадам-фашистам, зверям оголтелым,
По нашей земле не гулять.','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Три брата с фашистом дерутся жестоко...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f992dc7f866b4a36'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f992dc7f866b4a36','Три брата','Три брата с фашистом дерутся жестоко,
