INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_24827344d353ddca','Тридцать три коровы','(Песня из фильма «Мэри Поппинс, до свидания»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Наум Олев, музыка: Максим Дунаевский) | Песни для детей | https://pesni.retroportal.ru/deti/33_korovy.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Песня из фильма «Мэри Поппинс, до свидания») | merged_versions: 1','В центре города большого,
Где травинки не растёт,
Жил поэт - волшебник слова,
Вдохновенный рифмоплёт.
Рифмовал он что попало,
Просто выбился из сил.
И в деревню на поправку,
Где коровы щиплют травку,
Отдыхать отправлен был.
Припев:
Тридцать три коровы,
Тридцать три коровы,
Тридцать три коровы&nbsp;-
Свежая строка.
Тридцать три коровы,
Стих родился новый,
Как стакан парного молока.
Тридцать три коровы,
Стих родился новый,
Как стакан парного молока.
В пять утра вставал он ровно,
Это было нелегко.
Он читал стихи коровам,
Те давали молоко.
День за днём промчалось лето,
Очень вырос наш поэт,
Ведь молочная диета
Благотворна для поэтов
Если им всего шесть лет.
Припев
Интервью композитора  Максима Дунаевского  сайту &laquo;Retroportal.ru&raquo;.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Песня из фильма «Мэри Поппинс, до свидания»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_24827344d353ddca'), datetime('now')),datetime('now'));
