INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_4467c40462fc6413','Тройка мчится, тройка скачет',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Пётр Вяземский, музыка: Павел Булахов) | Народные песни | https://pesni.retroportal.ru/np3/19.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Тройка мчится, тройка скачет,
Вьётся пыль из-под копыт.
Колокольчик то заплачет,
То хохочет, то звенит.
Еду, еду, еду к ней,
Еду к любушке своей.
Кто сей путник и отколе,
И далёк ли путь ему?
По неволе иль по воле
Мчится он в ночную тьму?
Припев
Вот вдали село большое –
Сразу ожил мой ямщик.
Песней звонкой, удалою
Залился он в тот же миг.
Припев
Тпру!.. И тройка вдруг осела
У знакомого крыльца,
В сени девушка влетела
И целует молодца.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_4467c40462fc6413'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_4467c40462fc6413','Тройка мчится, тройка скачет','Тройка мчится, тройка скачет,
