INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_203acaf5decca213','Ты скоро меня позабудешь',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Юлия Жадовская, музыка: Александр Даргомыжский) | Старинные романсы | https://pesni.retroportal.ru/sr3/30.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ты скоро меня позабудешь,
Но я не забуду тебя;
Ты в жизни разлюбишь, полюбишь,
А я – никого, никогда!
Ты новые лица увидишь
И новых друзей изберёшь –
Ты новые чувства узнаешь
И, может быть, счастье найдёшь,
Я – тихо и грустно свершаю
Без радостей жизненный путь;
И как я люблю и страдаю,
Узнает могила одна!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_203acaf5decca213'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_203acaf5decca213','Ты скоро меня позабудешь','Ты скоро меня позабудешь,
