INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c687aac171bf1f60','«Ты, моряк, красивый сам собою» («По морям, по волнам»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/21.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ты, моряк, красивый сам собою,
Тебе от роду двадцать лет.
Полюби меня, моряк, душою,
Что ты скажешь мне в ответ?
По морям, по волнам –
Нынче здесь, завтра там.
По морям, морям, морям, морям.
Эх! Нынче здесь, а завтра там.
Ты, моряк, уедешь в сине море,
Оставляешь меня в горе,
А я буду плакать и рыдать,
Тебя, моряк мой, вспоминать.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c687aac171bf1f60'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c687aac171bf1f60','«Ты, моряк, красивый сам собою» («По морям, по волнам»)','Ты, моряк, красивый сам собою,
