INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_95d8e0f83f24b6a9','Ты, река ли моя реченька',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/22.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Ты, река ли моя реченька,
Ты, река ли моя, быстрая!
Течёшь, речка, не колышешься,
Жёлтым песком не возмутишься!
Ах, ты, умная девица,
Ах ты, Марья, ты, Михайловна!
Что сидишь ты, не улыбнёшься,
Говоришь ты, не усмехнёшься?
Полон двор у нас подвод стоит,
Полна горница гостей сидит.
Уж как все гости сбиралися,
Одного-то гостя нет как нет.
Уж как нету гостя милого,
Моего батюшки родимого.
Снарядить-то меня есть кому,
Благословить-то меня некому.
Что снарядит меня родна мать,
Благословит меня чужой отец.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_95d8e0f83f24b6a9'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_95d8e0f83f24b6a9','Ты, река ли моя реченька','Ты, река ли моя реченька,
