INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ef0757d894add51c','Ты, Россия моя','(«Мать - Россия моя»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Островой, музыка: Серафим Туликов) | Патриотические песни | https://pesni.retroportal.ru/rodina/ty_rossiya_moya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Мать - Россия моя») | merged_versions: 1','Мать&nbsp;- Россия моя,
С чем тебя мне сравнить?
Без тебя мне не петь,
Без тебя мне не жить...
Припев:
Ты, Россия моя,
Золотые края,
Ты, Россия, родная, заветная,
За твою широту,
За твою красоту
Я люблю тебя,
Родина светлая!
Всё, что в сердце моём,
Всё, чем в жизни живу,
Всё, что было и есть,
Я Россией зову!
Припев
Ты мудра и добра,
И народы земли
Славят сердце твоё,
Славят думы твои.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Мать - Россия моя»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ef0757d894add51c'), datetime('now')),datetime('now'));
