INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8a0ea5dc506917d0','«У ворот, ворот» («Ай, Дунай, мой Дунай, ай, весёлый Дунай!»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/23.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','У ворот, ворот, ворот,
Да ворот батюшкиных.
Ай, Дунай, мой Дунай,
Ай, весёлый Дунай!
Разыгралися ребята,
Распотешились.
Припев
Одному-то молодцу
Да худо можется.
Припев
Худо можется,
Да нездоровится.
Припев
Нездоровится ему,
Гулять хочется.
Припев
Я украдусь, я украдусь,
Нагуляюся.
Припев
Я сапоженьки на ножки,
Смур кафтанчик на плечо.
Припев
Я гудок-то под полой,
Под правою стороной.
Припев
Заиграю во струну,
Во серебряную.
Припев
Вы послушайте, ребята,
Что струна-то говорит,
Припев
Что струна-то говорит,
Да мне жениться велит.
Припев
Мне жениться, разориться,
Стару бабу взять,
Припев
Стару бабу взять,
На печи её держать,
Припев
Киселем её кормить,
Молоком её поить, -
Припев
С киселя-то весела,
Да с молока-то молода.
Припев
Вы послушайте, ребята,
Что струна-то говорит,
Припев
Что струна-то говорит,
Да мне жениться велит.
Припев
Мне жениться, разориться,
Красну девицу взять,
Припев
Красну девицу взять,
Да в светлой горенке держать.
Припев
В светлой горенке держать,
Чаем-кофеем поить.
Припев
Чаем-кофеем поить,
И конфетами кормить.
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8a0ea5dc506917d0'), datetime('now')),datetime('now'));
