INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d08a45244999c7d0','У зари-то, у зореньки',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/24.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','У зари-то, у зореньки много ясных звёзд,
А у тёмной-то ноченьки им и счёту нет,
А у тёмной-то ноченьки им и счёту нет.
Горят звёздочки на небе, пламенно горят,
Моему-то сердце бедному что-то говорят,
Моему-то сердце бедному что-то говорят.
Говорят о радостях, о прошедших днях,
Говорят они о горестях, разбивших в прах,
Говорят они о горестях, разбивших в прах.
Звёзды, мои звёздочки, полно вам сиять,
Полно, полно вам прошедшее мне напоминать.
Полно, полно вам прошедшее мне напоминать!
Я бы целу ноченьку, не смыкая глаз,
Все смотрела бы, звёздочки милые, на вас,
Все смотрела бы, звёздочки милые, на вас.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d08a45244999c7d0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d08a45244999c7d0','У зари-то, у зореньки','У зари-то, у зореньки много ясных звёзд,
А у тёмной-то ноченьки им и счёту нет,
А у тёмной-то ноченьки им и счёту нет.
Горят звёздочки на небе, пламенно горят,
Моему-то сердце бедному что-то говорят,
Моему-то сердце бедному что-то говорят.
Говорят о радостях, о прошедших днях,
Говорят они о горестях, разбивших в прах,
Говорят они о горестях, разбивших в прах.
Звёзды, мои звёздочки, полно вам сиять,
Полно, полно вам прошедшее мне напоминать.
Полно, полно вам прошедшее мне напоминать!
Я бы целу ноченьку, не смыкая глаз,
Все смотрела бы, звёздочки милые, на вас,
Все смотрела бы, звёздочки милые, на вас.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d08a45244999c7d0_904fb4eef3f575cb','rpp_d08a45244999c7d0','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/24.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_91c275b2234dba66','У камина',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Пётр Баторин) | Старинные романсы | https://pesni.retroportal.ru/sr3/31.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Ты сидишь одиноко и смотришь с тоской,
Как печально камин догорает
И как пламя то в нём так и вспыхнет порой,
То бессильно опять угасает.
Ты грустишь всё о чём? Не о прошлых ли днях,
Полных неги, любви и привета?
Так чего же ты ищешь в сгоревших углях?
О, тебе не найти в них ответа...
Подожди ещё миг, и не будет огней,
Что тебя так ласкали и грели,
И останется груда лишь чёрных углей,
Что сейчас догореть не успели.
О поверь, ведь любовь – это тот же камин,
Где сгорают все лучшие грёзы...
А погаснет любовь – в сердце холод один,
Впереди же – страданье и слёзы.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_91c275b2234dba66'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_91c275b2234dba66','У камина','Ты сидишь одиноко и смотришь с тоской,
