INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_28f4c3523c575741','У крыльца высокого','(«У крыльца высокого встретила я сокола...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Исаковский, музыка: Матвей Блантер) | Эстрадные песни | https://pesni.retroportal.ru/estrada/u_krylca_vysokogo.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («У крыльца высокого встретила я сокола...») | merged_versions: 1','У крыльца высокого встретила я сокола.
Я весною встретила, на любовь ответила.
Но весна кончается, он со мной прощается.
Да снега повыпали и следы засыпали.
Ой, метели шумные! Ой, снега вы белые!
Что же вы задумали? Что же вы наделали?
У крыльца высокого встретила я сокола.
Я весною встретила, на любовь ответила.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«У крыльца высокого встретила я сокола...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_28f4c3523c575741'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_28f4c3523c575741','У крыльца высокого','У крыльца высокого встретила я сокола.
