INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8c45c2238e24c0eb','«У нас нонче субботея» («Барыня»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/25.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','У нас нонче субботея!
Барыня ты моя, сударыня ты моя, субботея.
А на завтра воскресенье.
Барыня ты моя, сударыня ты моя, воскресенье.
Ко мне нонче друг Ванюша приходил.
Барыня то моя, сударыня то моя, приходил.
Три кармана приносил.
Барыня ты моя, сударыня ты моя, приносил.
Первый карман со орехами,
Второй карман со деньгами.
Барыня ты моя, сударыня ты моя, со деньгами.
Третий карман со изюмом.
Барыня ты моя, сударыня ты моя, со изюмом.
От орехов губы горьки,
Нельзя с милым целоваться.
Барыня ты моя, сударыня ты моя, целоваться.
Только можно обниматься.
Барыня ты моя, сударыня ты моя, обниматься.
От изюма губы сладки,
Можно с милым целоваться.
Барыня ты моя, сударыня ты моя, целоваться.
У нас нонче субботея.
Барыня ты моя, сударыня ты моя, субботея!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8c45c2238e24c0eb'), datetime('now')),datetime('now'));
