INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3ba6137d0a511b6e','Увезу тебя я в тундру','(«Мы поедем, мы помчимся на оленях утром ранним...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пляцковский, музыка: Марк Фрадкин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/uvezu_tebya_ya_v_tundru.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Мы поедем, мы помчимся на оленях утром ранним...») | merged_versions: 1','Увезу тебя я в тундру, увезу к седым снегам,
Белой шкурою медвежьей брошу их к твоим ногам.
По хрустящему морозу поспешим на край земли
И среди сугробов дымных затеряемся в дали.
Припев:
Мы поедем, мы помчимся на оленях утром ранним
И отчаянно ворвёмся прямо в снежную зарю.
Ты узнаешь, что напрасно называют север крайним,
Ты увидишь, он бескрайний, я тебе его дарю.
Увезу тебя я в тундру, увезу тебя одну,
Ярким северным сияньем твои плечи оберну.
Звёздный иней загорится на ресницах серебром,
Сколько хочешь самоцветов, мы с тобою соберём.
Припев
Увезу тебя я в тундру, и тогда поймешь ты вдруг,
Почему к себе так манит и зовет полярный круг.
Ничего, что здесь метели, не беда, что холода,
Если ты полюбишь север, не разлюбишь никогда.
Припев
Слушать песню &laquo;Увезу тебя я в тундру&raquo; композитора Марка Фрадкина на стихи Михаила Пляцковского в исполнении  Колы Бельды .','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Мы поедем, мы помчимся на оленях утром ранним...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3ba6137d0a511b6e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3ba6137d0a511b6e','Увезу тебя я в тундру','Увезу тебя я в тундру, увезу к седым снегам,
Белой шкурою медвежьей брошу их к твоим ногам.
