INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_4e971907a996e36f_53fa687c4e983929','rpp_4e971907a996e36f','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/32.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_872b925e5c635249','Уж ты, поле моё, поле чистое',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/26.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Уж ты, поле моё, поле чистое,
Ты раздольное моё, ты широкое.
Ты раздольное моё, ты широкое.
Ничего ты, поле, не спородило,
Спородило поле част ракитов куст.
Как во этом кусту тело белое,
Тело белое, молодецкое.
Во главах у него сабля вострая,
В ретивом у него пуля быстрая.
Во ногах у него конь вороненькой.
&laquo;Уж ты, конь, ты мой конь, ты товарищ мой.
Ты беги, беги по дорожке вдоль,
По дорожке вдоль, к отцу, к матери.
К отцу, к матери, к молодой жене.
Ты скажи жене, что женился я.
Что женила меня пуля быстрая,
Обвенчала меня сабля вострая.
Обвенчала меня сабля вострая&raquo;.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_872b925e5c635249'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_872b925e5c635249','Уж ты, поле моё, поле чистое','Уж ты, поле моё, поле чистое,
Ты раздольное моё, ты широкое.
Ты раздольное моё, ты широкое.
Ничего ты, поле, не спородило,
Спородило поле част ракитов куст.
Как во этом кусту тело белое,
Тело белое, молодецкое.
Во главах у него сабля вострая,
В ретивом у него пуля быстрая.
Во ногах у него конь вороненькой.
&laquo;Уж ты, конь, ты мой конь, ты товарищ мой.
Ты беги, беги по дорожке вдоль,
По дорожке вдоль, к отцу, к матери.
К отцу, к матери, к молодой жене.
Ты скажи жене, что женился я.
Что женила меня пуля быстрая,
Обвенчала меня сабля вострая.
Обвенчала меня сабля вострая&raquo;.');
