INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c6979b0cc3131619','Уральская рябинушка','(«Вечер тихой песнею над рекой плывёт...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пилипенко, музыка: Евгений Родыгин) | Эстрадные песни | https://pesni.retroportal.ru/estrada/uralskaya_ryabinushka.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Вечер тихой песнею над рекой плывёт...») | merged_versions: 1','Вечер тихой песнею над рекой плывёт,
Дальними зарницами светится завод.
Где-то поезд катится точками огня,
Где-то под рябинушкой парни ждут меня.
Припев:
Ой, рябина кудрявая,
Белые цветы,
Ой, рябина, рябинушка,
Что ж взгрустнула ты?
Лишь гудки певучие смолкнут над водой -
Я иду к рябинушке тропкою крутой.
Треплет под кудрявою ветер без конца
Справа - кудри токаря, слева - кузнеца.
Припев
Там, в цеху, короткие встречи - горячи,
А сойдёмся вечером - сядем и молчим.
Смотрят звёзды летние молча на парней,
Но не скажут ясные, кто из них милей...
Припев
Укрывает инеем землю добела,
Песней журавлиною осень проплыла.
Но тропинкой узкою, там же, между гор,
Мы втроём к рябинушке ходим до сих пор...
Припев
Кто из них желаннее, руку сжать кому -
Сердцем растревоженным так и не пойму.
Оба парня смелые, оба хороши,
Милая рябинушка, сердцу подскажи.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Вечер тихой песнею над рекой плывёт...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c6979b0cc3131619'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c6979b0cc3131619','Уральская рябинушка','Вечер тихой песнею над рекой плывёт,
Дальними зарницами светится завод.
