Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_c6979b0cc3131619_811bae348deb5cc6','rpp_c6979b0cc3131619','Retroportal — Эстрадные песни','https://pesni.retroportal.ru/estrada/uralskaya_ryabinushka.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_03e21808600944e1','Уродилася я',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/28.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Уродилася я, как былинка в поле.
Моя молодость прошла у людей в неволе.
Я с двенадцати лет по людям ходила,
Где качала я детей, где коров доила.
Светлой радости я, ласки не видала,
Износилася моя красота, увяла.
Износили её горе и неволя.
Знать, такая моя уродилася доля!
Уродилася я девицей красивой.
Судьба злая не дала мне доли счастливой.
И у птицы есть гнездо, у волчицы дети,
У меня лишь, молодой, никого на свете.
Птица в тёмном лесу звонко распевает,
И волчица с детьми весело играет.
Хороша я, хороша, да плохо одета.
Никто замуж не берёт девицу за это.
Эх ты, доля моя, доля-сиротинка,
Что полынь ты трава, горькая осинка!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_03e21808600944e1'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_03e21808600944e1','Уродилася я','Уродилася я, как былинка в поле.
Моя молодость прошла у людей в неволе.
Я с двенадцати лет по людям ходила,
Где качала я детей, где коров доила.
Светлой радости я, ласки не видала,
Износилася моя красота, увяла.
Износили её горе и неволя.
Знать, такая моя уродилася доля!
Уродилася я девицей красивой.
Судьба злая не дала мне доли счастливой.
И у птицы есть гнездо, у волчицы дети,
У меня лишь, молодой, никого на свете.
Птица в тёмном лесу звонко распевает,
И волчица с детьми весело играет.
Хороша я, хороша, да плохо одета.
Никто замуж не берёт девицу за это.
Эх ты, доля моя, доля-сиротинка,
Что полынь ты трава, горькая осинка!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_03e21808600944e1_38d172458efaee8a','rpp_03e21808600944e1','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/28.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_146a80470a9dbc61','Утренняя песня','(«Всё гляжу я в окошко вагонное...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Матусовский, музыка: Исаак Дунаевский) | Патриотические песни | https://pesni.retroportal.ru/rodina/utrennyaya_pesnya.html','import_source: https://pesni.retroportal.ru/ | section: Патриотические песни | subtitle: («Всё гляжу я в окошко вагонное...») | merged_versions: 1','Паровозным гудком растревожена
На просторах твоих тишина.
Хороша в это утро погожее
И светла ты, родная страна!
Хороши твои рощи зелёные
И простые цветы на лугу...
Припев:
Всё гляжу, всё гляжу я в окошко вагонное,
Наглядеться никак не могу!
Утро песней своею негромкою
Оглашает поля и леса.
Опоясаны алой каёмкою
Надо мной и землёй небеса.
И, любуясь речными затонами
И вершинами в вечном снегу,
Припев
И вокруг - всё родное и близкое,
Всё добыто в суровом бою.
Никакими словами не высказать,
Как мы любим Отчизну свою!
И поёт моё сердце влюблённое,
И колёса поют на бегу.
Припев','["category-patrioticheskie", "pesni.retroportal.ru", "retroportal-section-patrioticheskie", "retroportal-subtitle:(«Всё гляжу я в окошко вагонное...»)", "Патриотические песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_146a80470a9dbc61'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_146a80470a9dbc61','Утренняя песня','Паровозным гудком растревожена
