INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0157e1ddecc36fca','«Утро туманное» («В дороге»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Иван Тургенев, музыка: Эраст Абаза) | Старинные романсы | https://pesni.retroportal.ru/sr3/33.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Утро туманное, утро седое,
Нивы печальные, снегом покрытые.
Нехотя вспомнишь и время былое,
Вспомнишь и лица, давно позабытые.
Вспомнишь обильные, страстные речи,
Взгляды, так жадно и нежно ловимые,
Первая встреча, последняя встреча,
Тихого голоса звуки любимые.
Вспомнишь разлуку с улыбкою странной,
Многое вспомнишь родное, далёкое,
Слушая говор колёс непрестанный,
Глядя задумчиво в небо широкое.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0157e1ddecc36fca'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_0157e1ddecc36fca','«Утро туманное» («В дороге»)','Утро туманное, утро седое,
Нивы печальные, снегом покрытые.
Нехотя вспомнишь и время былое,
Вспомнишь и лица, давно позабытые.
