INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_ff7d6e73487a11c6','Фронтовая','(«У нас, под раскатами грома, живёт наша песня...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Илья Френкель, музыка: Анатолий Новиков) | Песни военных лет | https://pesni.retroportal.ru/vov/frontovaya.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («У нас, под раскатами грома, живёт наша песня...») | merged_versions: 1','Солнце глянет, день настанет&nbsp;-
День сраженья роковой.
Поле боя дым затянет,
Белый дым пороховой.
Припев:
У нас, под раскатами грома,
Живёт наша песня, как дома.
Мы немцев побьём, опять запоём
И песню домой понесём!
Бомбы воют, землю роют,
Не дают поговорить,
Нас с тобою беспокоят,&nbsp;-
Дай, товарищ, закурить!
Припев
Пули свищут, труса ищут.
Нам, товарищ, не впервой,
Там, километров за тыщу,
Вспоминают нас с тобой.
Припев
Солнце глянет, день настанет&nbsp;-
День победный золотой,
Наша песня громче грянет,
Мы воротимся домой.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«У нас, под раскатами грома, живёт наша песня...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_ff7d6e73487a11c6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_ff7d6e73487a11c6','Фронтовая','Солнце глянет, день настанет&nbsp;-
