INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d20038ed8c1117ac','Хороши весной в саду цветочки','(«Хороши весной в саду цветочки, ещё лучше девушки весной...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Алымов, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/horoshi_vesnoj_v_sadu_cvetochki.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Хороши весной в саду цветочки, ещё лучше девушки весной...») | merged_versions: 1','Хороши весной в саду цветочки,
Ещё лучше девушки весной.
Встретишь вечерочком
Милую в садочке&nbsp;–
Сразу жизнь становится иной.
Моё счастье где-то недалечко,
Подойду, да постучу в окно:
Выйди на крылечко
Ты, мое сердечко,
Без тебя тоскую я давно.
В нашей жизни всякое бывает,
Набегает с тучами гроза.
Туча уплывает,
Ветер утихает,
И опять синеют небеса.
Хороши весной в саду цветочки,
Ещё лучше девушки весной.
Встретишь вечерочком
Милую в садочке&nbsp;–
Сразу жизнь становится иной.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Хороши весной в саду цветочки, ещё лучше девушки весной...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d20038ed8c1117ac'), datetime('now')),datetime('now'));
