INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1b5290dff5a7ce4e','Хорошо дрова рубить',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | Народные песни | https://pesni.retroportal.ru/np3/30.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','(шуточные частушки)
Девушки:  Хорошо дрова рубить,
Которые берёзовы.
Хорошо ребят любить,
Которые тверёзые.
Парни:  Хорошо траву косить,
Которая зелёная.
Хорошо девку любить,
Которая смышлёная.
Девушки:  Хорошо дрова рубить,
Которые осиновы.
Хорошо ребят любить,
Которые красивые.
Парни:  Хорошо траву косить,
Которая росистая.
Хорошо девку любить,
Которая форсистая.
Девушки:  Хорошо дрова рубить
И ложить в поленницы.
Хорошо ребят любить,
Которые не ленятся.
Парни:  Мы кончаем петь припевки,
Идём травушку косить.
Надоели эти девки,
Надо новых заводить.
Девушки:  Полно, полно вам сердиться,
Полно хорохориться.
Не пора ли помириться
И вообще не ссориться.
Вместе:  Хорошо дрова рубить
Да травушку покашивать.
Рядом с дролечками быть,
Про любовь расспрашивать.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1b5290dff5a7ce4e'), datetime('now')),datetime('now'));
