INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_1b5290dff5a7ce4e_94d7708db307cc7f','rpp_1b5290dff5a7ce4e','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/30.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c9a0f12a9ff26615','Хорошо на Волге жить',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | Народные песни | https://pesni.retroportal.ru/np3/31.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','(саратовские припевки)
Хорошо на Волге жить,
Ходят пароходики.
Незаметно пролетают
Молодые годики.
Растяни гармошку шире,
От плеча и до плеча.
Разлилася наша Волга
От Москвы до Калача.
Волгу-речку стала мерить,
В ней глубокая вода.
Кто полюбит Волгу-речку,
Не разлюбит никогда.
Стало близко отовсюду
До родных до Жигулей.
То и дело пароходы
К нам идут с пяти морей.
Что ни сделаю для милого, -
Всё не эдак да не так.
Волга, Дон соединились,
А мы с милым всё никак!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c9a0f12a9ff26615'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c9a0f12a9ff26615','Хорошо на Волге жить','(саратовские припевки)
