INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_c9a0f12a9ff26615_434925b8d59ea9e1','rpp_c9a0f12a9ff26615','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/31.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_002e93d87ff0ca67','Хорошо на московском просторе','(«Песня о Москве» из кинофильма «Свинарка и пастух»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Виктор Гусев, музыка: Тихон Хренников) | Эстрадные песни | https://pesni.retroportal.ru/estrada/horosho_na_moskovskom_prostore.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Песня о Москве» из кинофильма «Свинарка и пастух») | merged_versions: 1','Хорошо на московском просторе,
Светят звёзды Кремля в синеве.
И, как реки встречаются в море,
Так встречаются люди в Москве.
Нас весёлой толпой окружила,
Подсказала простые слова,
Познакомила нас, подружила
В этот радостный вечер Москва.
Припев:
И в какой стороне я ни буду,
По какой ни пройду я траве,
Друга я никогда не забуду,
Если с ним подружился в Москве.
Не забыть мне очей твоих ясных
И простых твоих ласковых слов,
Не забыть мне московских прекрасных
Площадей, переулков, мостов.
Скоро встанет разлука меж нами,
Зазвенит колокольчик&nbsp;- прощай!
За горами, лесами, полями
Ты хоть в песне меня вспоминай.
Припев
Волны радио ночью примчатся
Из Москвы сквозь морозы и дым.
Голос дальней Москвы мне казаться
Будет голосом дальним твоим.
Но я знаю, мы встретимся скоро,
И тогда, дорогая, вдвоём,
На московских широких просторах
Мы опять эту песню споём.
Припев','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Песня о Москве» из кинофильма «Свинарка и пастух»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_002e93d87ff0ca67'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_002e93d87ff0ca67','Хорошо на московском просторе','Хорошо на московском просторе,
Светят звёзды Кремля в синеве.
И, как реки встречаются в море,
