INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_6e74cf671336a2aa_127eab713cff93c7','rpp_6e74cf671336a2aa','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/32.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_1a5746748f0dea37','Чайка',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Елена Буланина, музыка: Евгений Жураковский) | Старинные романсы | https://pesni.retroportal.ru/sr3/34.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Вот вспыхнуло утро, румянятся воды,
Над озером быстрая чайка летит,
Ей много простора, ей много свободы,
Луч солнца у чайки крыло серебрит.
Но что это? Выстрел!.. Нет чайки прелестной –
Она, трепеща, умерла в камышах.
Шутя, её ранил охотник безвестный,
Не глядя на жертву, он скрылся в горах.
И девушка чудная чайкой прелестной
Над озером тихим спокойно жила,
Но в душу вошёл к ней чужой неизвестный,
Ему она сердце и жизнь отдала.
Как чайке охотник, шутя и играя,
Он юное сердце навеки разбил,
Навеки убита вся жизнь молодая,
Нет жизни, нет веры, нет счастья, нет сил.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_1a5746748f0dea37'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_1a5746748f0dea37','Чайка','Вот вспыхнуло утро, румянятся воды,
