INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_fb713689eb1f2e54','Час да по часу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/33.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Час да по часу день проходит,
Солнце зайдёт в этот час.
Куда скрылся мой хороший,
С кем рассталась я вчера?
Куда скрылся мой хороший,
С кем рассталась я вчера?
Колокольчик его звонкий
Бьёт уныло под дугой.
