INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c8659b051aa14a90','Чему учат в школе','(«Буквы разные писать тонким пёрышком в тетрадь...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Михаил Пляцковский, музыка: Владимир Шаинский) | Песни для детей | https://pesni.retroportal.ru/deti/uchat_v_shkole.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: («Буквы разные писать тонким пёрышком в тетрадь...») | merged_versions: 1','Буквы разные писать
Тонким пёрышком в тетрадь
Учат в школе, учат в школе, учат в школе.
Вычитать и умножать,
Малышей не обижать
Учат в школе, учат в школе, учат в школе.
К четырём прибавить два,
По слогам читать слова
Учат в школе, учат в школе, учат в школе.
Книжки добрые любить
И воспитанными быть
Учат в школе, учат в школе, учат в школе.
Рисовать квадрат и круг,
Знать, где север, а где юг -
Учат в школе, учат в школе, учат в школе.
И не путать никогда
Острова и города
Учат в школе, учат в школе, учат в школе.
Про глагол и про тире,
И про дождик во дворе
Учат в школе, учат в школе, учат в школе.
Крепко-накрепко дружить,
С детства дружбой дорожить
Учат в школе, учат в школе, учат в школе.','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(«Буквы разные писать тонким пёрышком в тетрадь...»)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c8659b051aa14a90'), datetime('now')),datetime('now'));
