INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_2ceb67c8f0d13ba6','«Черёмуха» («Под окном черёмуха колышется»)',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/34.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Под окном черёмуха колышется,
Распуская лепестки свои.
За рекой знакомый голос слышится,
И поют всю ночь там соловьи.
Сердце девушки забилось радостно...
Как тепло, как хорошо в саду!..
Жди меня, мой радостный, мой сладостный,
Я в заветный час к тебе приду.
Ой, зачем тобою сердце вынуто?
Для кого теперь твой блещет взгляд?
Мне не жаль, что я тобой покинута, -
Жаль, что люди много говорят.
Прямо к речке тропочка проложена.
Спит мальчонка – он не виноват.
Я не буду плакать и печалиться,
Не вернётся прошлое назад.
Под окном черёмуха колышется,
Осыпая лепестки свои.
За рекой уж голоса не слышатся,
Не поют там больше соловьи...','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_2ceb67c8f0d13ba6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_2ceb67c8f0d13ba6','«Черёмуха» («Под окном черёмуха колышется»)','Под окном черёмуха колышется,
