INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9b10fd5074e3e3c6','Чернобровый, черноокий',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/35.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Чернобровый, черноокий,
Молодец удалой,
Полонил он моё сердце –
Не могу забыти.
Как понять такую радость,
Что мил меня любит?
Побегу ему навстречу,
Крепко обниму я.
Обойму я молодого,
Парня удалого.
Объясню свою любовь я –
Авось умилится.
Не ходить бы красной девке
Вдоль по лугу, лугу,
Не любить бы красной девке
Холостого парня.
Я за то его любила,
Что порой ходит:
Поутру раным-раненько,
Вечером поздненько.
Чтобы люди не сказали,
Ближние не знали, -
Про меня бы молоденьку
Отцу не сказали.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9b10fd5074e3e3c6'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9b10fd5074e3e3c6','Чернобровый, черноокий','Чернобровый, черноокий,
