INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_a8a76a18195bb6e0','Черноморский сокол','(«В небо птицей взмыли самолёты, в облаках мелькнул последний «Ил»...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | Песни военных лет | https://pesni.retroportal.ru/vov/chernomorsky_sokol.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («В небо птицей взмыли самолёты, в облаках мелькнул последний «Ил»...») | merged_versions: 1','(автор музыки и слов:  Евгений&nbsp;Сущенко )
В небо птицей взмыли самолёты,
В облаках мелькнул последний &laquo;Ил&raquo;.
Штурмовать фашистов шли пилоты,
Не щадя врага, огонь косил!
Припев:
Всегда на цель, всегда на штурм
Идём вперёд, идём вперёд!
Героя мимо самолёт,
За ним на &laquo;Илах&raquo; летят орлы,
Врага сметая с родной земли!
На Мысхако держат курс пилоты,
Свой отряд там Куников ведёт.
И летят на воздух вражьи ДОТы,&nbsp;-
Нет, ничто фашистов не спасёт!
Припев
Здесь святая цель зовёт нас к бою,
А сердца отвагою полны.
Не видать фашистам здесь покоя,
Идут в атаку Родины сыны!
Припев
Мы придём в родной наш светлый город,
Будем зори мирные встречать.
Там цветёт сирень и старый тополь,
А пока фашистов будем гнать!
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«В небо птицей взмыли самолёты, в облаках мелькнул последний «Ил»...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_a8a76a18195bb6e0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_a8a76a18195bb6e0','Черноморский сокол','(автор музыки и слов:  Евгений&nbsp;Сущенко )
В небо птицей взмыли самолёты,
В облаках мелькнул последний &laquo;Ил&raquo;.
Штурмовать фашистов шли пилоты,
Не щадя врага, огонь косил!
Припев:
Всегда на цель, всегда на штурм
Идём вперёд, идём вперёд!
Героя мимо самолёт,
За ним на &laquo;Илах&raquo; летят орлы,
Врага сметая с родной земли!
На Мысхако держат курс пилоты,
Свой отряд там Куников ведёт.
И летят на воздух вражьи ДОТы,&nbsp;-
Нет, ничто фашистов не спасёт!
Припев
Здесь святая цель зовёт нас к бою,
А сердца отвагою полны.
Не видать фашистам здесь покоя,
Идут в атаку Родины сыны!
Припев
Мы придём в родной наш светлый город,
Будем зори мирные встречать.
Там цветёт сирень и старый тополь,
А пока фашистов будем гнать!
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_a8a76a18195bb6e0_a3a9e249608962ec','rpp_a8a76a18195bb6e0','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/chernomorsky_sokol.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bea3bed9fb4fb9b0','Чёрный ворон',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/36.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Чёрный ворон, чёрный ворон,
Что ты вьёшься надо мной?
Ты добычи не дождёшься,
Чёрный ворон, я не твой!
Что ты когти распускаешь
Над моею головой?
Иль добычу себе чаешь,
Чёрный ворон, я не твой!
Завяжу смертельну рану
Подарённым мне платком,
А потом с тобой я стану
Говорить всё об одном.
Полети в мою сторонку,
Скажи маменьке моей,
Ты скажи моей любезной,
Что за Родину я пал.
Отнеси платок кровавый
Милой любушке моей.
Ты скажи – она свободна,
Я женился на другой.
Взял невесту тиху-скромну
В чистом поле под кустом,
Обвенчальна была сваха –
Сабля вострая моя.
Калена стрела венчала
Среди битвы роковой.
Вижу смерть моя приходит –
Чёрный ворон, весь я твой!','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bea3bed9fb4fb9b0'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bea3bed9fb4fb9b0','Чёрный ворон','Чёрный ворон, чёрный ворон,
Что ты вьёшься надо мной?
