INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d4dff53b08c84ef8','Что за дерево такое','(Детская новогодняя песенка)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Лидия Некрасова, музыка: Михаил Старокадомский) | Песни для детей | https://pesni.retroportal.ru/deti/chto_za_derevo_takoe.html','import_source: https://pesni.retroportal.ru/ | section: Песни для детей | subtitle: (Детская новогодняя песенка) | merged_versions: 1','Что за дерево такое,&nbsp;-
Вся макушка в серебре,&nbsp;-
Расцвело у нас зимою
В день морозный в декабре?
Припев:
Вот так-так!
Вот так-так!
Это наша ёлка.
Созревают фрукты летом,
Летом яблок полон сад,
А на дереве на этом
В зимний день они висят!
Припев
И орехи, и конфеты,
И шары на нем висят,
Есть на дереве на этом
Всё для радости ребят!
Припев','["category-deti", "pesni.retroportal.ru", "retroportal-section-deti", "retroportal-subtitle:(Детская новогодняя песенка)", "Песни для детей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d4dff53b08c84ef8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d4dff53b08c84ef8','Что за дерево такое','Что за дерево такое,&nbsp;-
