INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_0c12a773afe97a04','Что солдату нужно','(«Над землёю солнце светит, пушки к западу глядят....»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Лев Ошанин, музыка: Валентин Кручинин) | Песни военных лет | https://pesni.retroportal.ru/vov/chto_soldatu_nuzhno.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Над землёю солнце светит, пушки к западу глядят....») | merged_versions: 1','Над землёю солнце светит,
Пушки к западу глядят.
Над землёю ходит ветер,
На ветру стоит солдат.
Припев:
Что солдату нужно?&nbsp;- Родину любить!
Что солдату нужно?&nbsp;- Немца крепче бить!
А придёшь с победой&nbsp;- лаской материнской
Встретит Родина тебя.
Вот команда раздаётся:
-&nbsp;Поднимайся, первый взвод!
Сердце бьётся, в битву рвётся,
Мы опять идём вперёд.
Припев
Злая смерть над нами свищет,
Но солдат в огне крещён.
И покоя он не ищет&nbsp;-
Вражьей смерти ищет он.
Припев
Нет солдату счастья больше,
Чем услышать вражий крик,
Чем вонзить во вражье тело
Беспощадный русский штык!
Припев
Сброшен враг, земля пылает.
Эх, земля&nbsp;- поля, луга!
Возвращённая, родная,
Ты нам вдвое дорога.
Припев','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Над землёю солнце светит, пушки к западу глядят....»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_0c12a773afe97a04'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_0c12a773afe97a04','Что солдату нужно','Над землёю солнце светит,
