INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_8c4cff425dcd7e56','Что ты жадно глядишь на дорогу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Некрасов, музыка народная) | Старинные романсы | https://pesni.retroportal.ru/sr3/35.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Что ты жадно глядишь на дорогу
В стороне от весёлых подруг?
Знать, забило сердечко тревогу –
Всё лицо твое вспыхнуло вдруг.
И зачем ты бежишь торопливо
За промчавшейся тройкой вослед!..
На тебя, подбоченясь, красиво,
Загляделся проезжий корнет.
На тебя заглядеться не диво,
Полюбить тебя всякий непрочь:
Вьётся алая лента игриво
В волосах твоих, тёмных, как ночь...
Не гляди же с тоской на дорогу
И за тройкой вослед не спеши,
И тоскливую в сердце тревогу
Поскорей навсегда заглуши!
Не нагнать тебе бешеной тройки:
Кони крепки и сыты, и бойки,
И ямщик под хмельком, и к другой
Мчится вихрем корнет молодой...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_8c4cff425dcd7e56'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_8c4cff425dcd7e56','Что ты жадно глядишь на дорогу','Что ты жадно глядишь на дорогу
В стороне от весёлых подруг?
Знать, забило сердечко тревогу –
