INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_8c4cff425dcd7e56_7b897e4424218b4a','rpp_8c4cff425dcd7e56','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/35.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_77ea690e3d820383','Что ты, белая берёза',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/37.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Что ты, белая берёза,
Ветра нет, а ты шумишь?
Ретиво моё сердечко,
Горя нет, а ты болишь.
Ты узнай меня, милёнок,
По широкой полосе:
На мне платье голубое,
Лента алая в косе.
Только в доме украшенье,
Когда солнышко взойдёт.
Только сердцу утешенье,
Когда миленький придёт.
Мои щёчки, что листочки,
Глазки, что смородинки...
Давай, милый, погуляем,
Пока мы молоденьки!
Хоть огонь горит и жарко,
Но любовь – ещё жарчей.
Хоть огонь водою тушат,
А любовь – нельзя ничем.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_77ea690e3d820383'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_77ea690e3d820383','Что ты, белая берёза','Что ты, белая берёза,
Ветра нет, а ты шумишь?
Ретиво моё сердечко,
