INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_77ea690e3d820383_b28d0f0aa10026a7','rpp_77ea690e3d820383','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/37.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d2ff673f4ab926d7','Что это сердце',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова неизвестного автора, музыка: Яков Пригожий) | Старинные романсы | https://pesni.retroportal.ru/sr3/36.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Что это сердце сильно так бьётся?
Что за тревога волнует мне грудь?
Чей это голос в душе раздаётся;
Ночь всю томлюсь, не могу я уснуть!
Пусть в чаду любви
Сердце пылкое
Бьётся радостно
В молодой груди!
И дни счастия
Молодой поры
Принимайте вы
Как судьбы дары!
Нет, не скажу я людям об этом,
Нет, не спрошу их, что сталось со мной.
Им не понять, лишь холодным ответом
Все посмеются они надо мной!
Припев
Буду томиться в тиши я ночей,
Скрою я тайну свою от людей.
Голос в душе говорит мне, что вновь
Сердце воскреснет, чувство, любовь!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d2ff673f4ab926d7'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d2ff673f4ab926d7','Что это сердце','Что это сердце сильно так бьётся?
Что за тревога волнует мне грудь?
