INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_32523c0ea310417b','Шире шаг','(«Командир сказал - приказ получен...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Сергей Алымов, музыка: Павел Акуленко) | Песни военных лет | https://pesni.retroportal.ru/vov/shire_shag.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Командир сказал - приказ получен...») | merged_versions: 1','Командир сказал&nbsp;- приказ получен:
Завтра утром выступить в поход.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Днём и ночью, мы всегда готовы
Послужить своей родной стране.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Для побед одной отваги мало,
Нужно знать, что делать на войне.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Мы стрелять без промаха умеем,
Нас не взять атакой штыковой.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Наш нарком, товарищ Тимошенко,
Учит нас науке боевой.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Мы шагаем стройными рядами.
Хороша зелёная трава!
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Нас встречают девушки с цветами,
Говорят весёлые слова.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
Мы Отчизну нашу дорогую
От врагов повсюду отстоим.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!
За вождя, за Сталина родного,
Нашу кровь до капли отдадим.
Эх, шире шаг, веселей, боец, иди,
Во всех боях ждёт победа впереди!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Командир сказал - приказ получен...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_32523c0ea310417b'), datetime('now')),datetime('now'));
