INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_32523c0ea310417b_00f500b4eb24ae29','rpp_32523c0ea310417b','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/shire_shag.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d83b6bcdebfd16a8','Штурвальный с “Марата”','(«Где воздух изранен полётом снаряда...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Алексей Сурков, музыка: Матвей Блантер) | Песни военных лет | https://pesni.retroportal.ru/vov/shturvalny_s_marata.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Где воздух изранен полётом снаряда...») | merged_versions: 1','Где воздух изранен полётом снаряда,
Где бомбами поле изрыто кругом,
За русскую землю, за честь Ленинграда
Морская пехота дерётся с врагом.
Трава на поляне железом примята,
За танком пехота ползёт по земле.
В разбитом окопе штурвальный с &laquo;Марата&raquo;
Остался один на прибрежной скале.
Вскипают барашки в солёном просторе,
Вдоль берега катятся пеной седой...
Шумит краснофлотцу родимое море:
-&nbsp;Стой на смерть, без страха, орёл молодой!
И насмерть дерётся штурвальный с &laquo;Марата&raquo;
Как знамя, подняв бескозырку свою.
Врага поражая последней гранатой,
Он смерть принимает в неравном бою.
Но танкам навстречу торопится рота,
И пушки под пулями катят вперёд
Друзья-комендоры, морская пехота,
Балтийские люди, железный народ!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Где воздух изранен полётом снаряда...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d83b6bcdebfd16a8'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d83b6bcdebfd16a8','Штурвальный с “Марата”','Где воздух изранен полётом снаряда,
Где бомбами поле изрыто кругом,
