INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_d83b6bcdebfd16a8_601e8ca49c7ea1e0','rpp_d83b6bcdebfd16a8','Retroportal — Песни военных лет','https://pesni.retroportal.ru/vov/shturvalny_s_marata.html','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_cac2c39486c13fdb','Шумел камыш, деревья гнулись',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/38.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Вариант I
Шумел камыш, деревья гнулись,
А ночка тёмная была...
Одна возлюбленная пара
Всю ночь гуляла до утра.
А поутру они вставали.
Кругом помятая трава,
Да не одна трава помята, -
Помята молодость моя.
Придёшь домой, а дома спросят:
&laquo;Где ты гуляла, где была?&raquo;.
А ты скажи: &laquo;В саду гуляла,
Домой тропинки не нашла&raquo;.
А если дома ругать будут,
То приходи опять сюда...
Она пришла: его там нету,
Его не будет никогда.
Она глаза платком закрыла
И громко плакать начала:
&laquo;Куда ж краса моя девалась?
Кому ж я счастье отдала?..&raquo;
Шумел камыш, деревья гнулись,
А ночка тёмная была.
Одна возлюбленная пара
Всю ночь гуляла до утра.
Вариант II
Шумел камыш, деревья гнулись,
А ночка тёмная была.
Одна возлюбленная пара
Всю ночь гуляла до утра.
А поутру они проснулись,
Кругом помятая трава.
Ах, не одна трава помята,
Помята девичья краса.
Пойду домой, а дома спросят:
&laquo;Где ты гуляла, где была?&raquo;
А я в ответ скажу: &laquo;Гуляла,
Домой тропинку не нашла&raquo;.
&laquo;А если мама не поверит,
То приходи опять сюда&raquo;.
А я пришла, его уж нету,
Его не будет никогда.
Ах, вот кого я полюбила,
Кому я сердце отдала.
Шумел камыш, деревья гнулись,
А ночка тёмная была.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_cac2c39486c13fdb'), datetime('now')),datetime('now'));
