INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_cac2c39486c13fdb_31ab2803fa99f544','rpp_cac2c39486c13fdb','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/38.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_9f181d3d0fd35b57','Шумел сурово брянский лес','(«Шумел сурово брянский лес, спускались синие туманы...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Анатолий Софронов, музыка: Сигизмунд Кац) | Песни военных лет | https://pesni.retroportal.ru/vov/shumel_surovo_bryansky_les.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Шумел сурово брянский лес, спускались синие туманы...») | merged_versions: 1','Шумел сурово брянский лес,
Спускались синие туманы,
И сосны слышали окрест,
Как шли тропою партизаны...
И грозной ночью на врагов,
На штаб фашистский налетели.
И пули звонко меж стволов
В дубравах брянских засвистели.
В лесах врагам спасенья нет,
Летят советские гранаты,
И командир кричит им вслед:
&laquo;Громи захватчиков, ребята&raquo;!
Шумел сурово брянский лес,
Спускались синие туманы,
И сосны слышали окрест,
Как шли с победой партизаны...','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Шумел сурово брянский лес, спускались синие туманы...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_9f181d3d0fd35b57'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_9f181d3d0fd35b57','Шумел сурово брянский лес','Шумел сурово брянский лес,
