INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_d6680570da67645e','Шумит волна, звенит струна','(«Когда после вахты гитару возьмёшь...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Вадим Малков, музыка: Юрий Слонов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/shumit_volna_zvenit_struna.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Когда после вахты гитару возьмёшь...») | merged_versions: 1','Когда после вахты гитару возьмёшь
И тронешь струну за струной,
Ты словно опять ненадолго зайдёшь
К единственной, самой родной.
Припев:
Шумит волна,
Звенит струна,
Гитара поёт и поёт,&nbsp;-
Поёт о той,
Что вновь с тобой,
Что вновь с тобой.
Звездой голубой чуть мерцает маяк,
Ночная волна шелестит.
И песня тебе помогает, моряк,
Суровую службу нести.
Пусть завтра крутая волна закипит
И ветер хлестнёт штормовой...
Сегодня морская душа говорит
С певучей гитарной струной.','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Когда после вахты гитару возьмёшь...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_d6680570da67645e'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_d6680570da67645e','Шумит волна, звенит струна','Когда после вахты гитару возьмёшь
