INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b7a771057b24d9ce','Эй, седлайте, хлопцы, коней','(Военный вариант украинской песни «Роспрягайте хлопцi коней»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Василий Лебедев-Кумач, музыка народная, обработка: Александр Александров) | Песни военных лет | https://pesni.retroportal.ru/vov/sedlajte_hlopcy_konej.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: (Военный вариант украинской песни «Роспрягайте хлопцi коней») | merged_versions: 1','Эй, седлайте хлопцы коней,
Нам не время почивать.
Полетим на поле брани
Мать-отчизну защищать!
Хочет, хочет враг проклятый
Нашу землю разорить,
Наши семьи, наши хаты,
Наши нивы истребить.
Не позволим, не допустим
Ни зачто и никогда
Чтобы Родину терзала
Ненавистная орда!
Полетим, кавалеристы,
Грозной лавой огневой
И насильникам-фашистам
Снимем головы долой!
Будем драться беззаветно
И штыками и клинком.
С нами весь народ советский,
С нами Сталин наш родной!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(Военный вариант украинской песни «Роспрягайте хлопцi коней»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b7a771057b24d9ce'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b7a771057b24d9ce','Эй, седлайте, хлопцы, коней','Эй, седлайте хлопцы коней,
