INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b2d5be299bcbc9e2','Эй, трубач молоденький','(«Ох, придётся тебе не скоро сына милого обнимать...»)','ru','ussr','ussr_1941_1945',NULL,'pesni.retroportal.ru | (слова: Михаил Светлов, музыка: Георгий Портнов) | Песни военных лет | https://pesni.retroportal.ru/vov/trubach_molodenky.html','import_source: https://pesni.retroportal.ru/ | section: Песни военных лет | subtitle: («Ох, придётся тебе не скоро сына милого обнимать...») | merged_versions: 1','Ох, придётся тебе не скоро
Сына милого обнимать:
В исторические просторы
Ухожу я, родная мать!
Эй, трубач молоденький!
Протруби такое,
Чтобы наша молодость
Потекла рекою!
Нашу молодость боевую
Никогда не согнуть дугой&nbsp;-
Не пойдём мы на мировую
В революции мировой!
Эй, трубач молоденький!
Затруби такое,
Чтоб до счастья нашего
Нам достать рукою!
Мы идём в ураган шрапнели,
Чтоб в далёкие времена,
Словно ласточки, пролетели
Комсомольские имена!
Эй, трубач молоденький!
Протруби такое,
Чтобы наша молодость
Потекла рекою.
Ох, придётся тебе не скоро
Сына милого обнимать:
В исторические просторы
Ухожу я, родная мать!','["category-voennye_gody", "pesni.retroportal.ru", "retroportal-section-voennye_gody", "retroportal-subtitle:(«Ох, придётся тебе не скоро сына милого обнимать...»)", "Песни военных лет"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b2d5be299bcbc9e2'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b2d5be299bcbc9e2','Эй, трубач молоденький','Ох, придётся тебе не скоро
