INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3390dd261628b03a','Эй, ухнем!',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/39.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Эй, ухнем!
Эй, ухнем!
Ещё разик, ещё раз!
Разовьём мы берёзку,
Разовьём мы кудряву!
Ай-да, да ай-да, ай-да, да ай-да,
Разовьём мы кудряву.
Эй, ухнем!
Эй, ухнем!
Ещё разик, ещё раз!
Мы по бережку идём,
Песню солнышку поём.
Ай-да, да ай-да, ай-да, да ай-да,
Песню солнышку поём.
Эй, эй, тяни канат сильней!
Песню солнышку поём.
Эй, ухнем!
