INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3b5abe55e88a2853','Элегия',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай Языков, музыка: Александр Алябьев) | Старинные романсы | https://pesni.retroportal.ru/sr3/37.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Блажен, кто мог на ложе ночи
Тебя руками обогнуть;
Челом в чело, очами в очи,
Уста в уста и грудь на грудь!
Кто соблазнительный твой лепет
Лобзаньем пылким прерывал
И смуглых персей дикий трепет
То усыплял, то пробуждал!..
Но тот блаженней, дева ночи,
Кто в упоении любви
Глядит на огненные очи,
На брови дивные твои,
На свежесть уст твоих пурпурных,
На черноту младых кудрей,
Забыв и жар восторгов бурных,
И силы юности своей!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3b5abe55e88a2853'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3b5abe55e88a2853','Элегия','Блажен, кто мог на ложе ночи
Тебя руками обогнуть;
Челом в чело, очами в очи,
Уста в уста и грудь на грудь!
