Он отыщет покрепче дубину.
Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_c76be7244fe4d8e9_ecc6d7a4d3598883','rpp_c76be7244fe4d8e9','Retroportal — Народные песни','https://pesni.retroportal.ru/np1/28.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_02155167a161c734','Я Вам не говорю',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Дмитрий Михайлов) | Старинные романсы | https://pesni.retroportal.ru/sr3/38.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я Вам не говорю про тайные страданья,
Про муки адские, про жгучую тоску,
Но Вы всё видите, прелестное созданье,
И руку ласково Вы жмёте бедняку.
В Вас нет любви ко мне, но Вы душою нежной,
Душою женственной умеете щадить
Разбитые сердца и дружбой безмятежной
Мятежную любовь хотите усыпить.
Но если б знали Вы, как сильно сердце стонет,
Какая боль в груди, какой огонь в крови,
Когда мой робкий взгляд во взгляде Вашем тонет,
И дружбу ищет он, и тщетно ждёт любви!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_02155167a161c734'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_02155167a161c734','Я Вам не говорю','Я Вам не говорю про тайные страданья,
Про муки адские, про жгучую тоску,
Но Вы всё видите, прелестное созданье,
И руку ласково Вы жмёте бедняку.
В Вас нет любви ко мне, но Вы душою нежной,
Душою женственной умеете щадить
Разбитые сердца и дружбой безмятежной
Мятежную любовь хотите усыпить.
Но если б знали Вы, как сильно сердце стонет,
Какая боль в груди, какой огонь в крови,
Когда мой робкий взгляд во взгляде Вашем тонет,
И дружбу ищет он, и тщетно ждёт любви!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_02155167a161c734_36e93a7f365d28e7','rpp_02155167a161c734','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/38.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_f8a5395774599180','Я Вас любил',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Пушкин, музыка: Борис Шереметев) | Старинные романсы | https://pesni.retroportal.ru/sr3/39.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я Вас любил ; любовь ещё, быть может,
В душе моей угасла не совсем;
Но пусть она Вас больше не тревожит
Я не хочу печалить Вас ничем.
Я вас любил безмолвно, безнадежно,
То робостью, то ревностью томим.
Я вас любил так искренно, так нежно,
Как дай Вам Бог любимой быть другим!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_f8a5395774599180'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_f8a5395774599180','Я Вас любил','Я Вас любил ; любовь ещё, быть может,
В душе моей угасла не совсем;
Но пусть она Вас больше не тревожит
Я не хочу печалить Вас ничем.
Я вас любил безмолвно, безнадежно,
То робостью, то ревностью томим.
Я вас любил так искренно, так нежно,
Как дай Вам Бог любимой быть другим!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_f8a5395774599180_0a6349ce16df9ab2','rpp_f8a5395774599180','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/39.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_c02310e85d450bd3','Я встретил Вас',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Фёдор Тютчев, музыка: Леонид Малашкин) | Старинные романсы | https://pesni.retroportal.ru/sr3/40.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я встретил Вас – и всё былое
В отжившем сердце ожило;
Я вспомнил время золотое –
И сердцу стало так тепло...
Как поздней осени порою
Бывают дни, бывает час,
Когда повеет вдруг весною
И что-то встрепенётся в нас.
Как после вековой разлуки,
Гляжу на Вас как бы во сне,
И вот слышнее стали звуки,
Не умолкавшие во мне...
Тут не одно воспоминанье,
Тут жизнь заговорила вновь, -
И то же в Вас очарованье,
И та ж в душе моей любовь!..','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_c02310e85d450bd3'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_c02310e85d450bd3','Я встретил Вас','Я встретил Вас – и всё былое
В отжившем сердце ожило;
Я вспомнил время золотое –
И сердцу стало так тепло...
Как поздней осени порою
Бывают дни, бывает час,
Когда повеет вдруг весною
И что-то встрепенётся в нас.
Как после вековой разлуки,
Гляжу на Вас как бы во сне,
И вот слышнее стали звуки,
Не умолкавшие во мне...
Тут не одно воспоминанье,
Тут жизнь заговорила вновь, -
И то же в Вас очарованье,
И та ж в душе моей любовь!..');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_c02310e85d450bd3_44fe5aed65964df7','rpp_c02310e85d450bd3','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/40.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bde4f212fd027ccb','Я говорил при расставаньи',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Афанасий Фет, музыка: Александр Гурилёв) | Старинные романсы | https://pesni.retroportal.ru/sr3/41.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я говорил при расставаньи:
&laquo;В далёком и чужом краю
Я сохраню в воспоминанье
Святую молодость твою&raquo;.
Я отгадал душой небрежной
Мою судьбу, - и предо мной
Твой образ милый, образ нежный,
С своей младенческой красой.
И не забыть мне лип старинных
В саду приветливом твоём,
Твоих ресниц и взоров длинных,
И глаз, играющих огнём.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bde4f212fd027ccb'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bde4f212fd027ccb','Я говорил при расставаньи','Я говорил при расставаньи:
