INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_bde4f212fd027ccb_faf7534f7855b2f4','rpp_bde4f212fd027ccb','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/41.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_b7772a7dae491e78','Я думал, сердце позабыло',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Александр Пушкин, музыка: Ольга Донаурова) | Старинные романсы | https://pesni.retroportal.ru/sr3/42.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я думал, сердце позабыло
Способность лёгкую страдать,
Я говорил: &laquo;Тому, что было,
Уж не бывать, уж не бывать&raquo;.
Прошли восторги и печали,
И легковерные мечты...
Но вот опять затрепетали
Пред мощной властью красоты.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_b7772a7dae491e78'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_b7772a7dae491e78','Я думал, сердце позабыло','Я думал, сердце позабыло
