INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_b7772a7dae491e78_1cdc1b2a184e3a1d','rpp_b7772a7dae491e78','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/42.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_109cc42b1748dd89','Я ехала домой',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Мария Пуаре) | Старинные романсы | https://pesni.retroportal.ru/sr3/43.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я ехала домой, душа была полна
Неясным для самой, каким-то новым счастьем.
Казалось мне, что все с таким участьем,
С такою ласкою глядели на меня.
Я ехала домой... Двурогая луна
Смотрела в окна скучного вагона.
Далёкий благовест заутреннего звона
Пел в воздухе, как нежная струна...
Раскинув розовый вуаль,
Красавица заря лениво просыпалась,
И ласточка, стремясь куда-то в даль,
В прозрачном воздухе купалась.
Я ехала домой, я думала о Вас,
Тревожно мысль моя и путалась, и рвалась.
Дремота сладкая моих коснулась глаз.
О, если б никогда я вновь не просыпалась...','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_109cc42b1748dd89'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_109cc42b1748dd89','Я ехала домой','Я ехала домой, душа была полна
Неясным для самой, каким-то новым счастьем.
Казалось мне, что все с таким участьем,
С такою ласкою глядели на меня.
