INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_109cc42b1748dd89_28f0a3343ac79c17','rpp_109cc42b1748dd89','Retroportal — Старинные романсы','https://pesni.retroportal.ru/sr3/43.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_266df6a9c1787d8d','Я на горку шла',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (русская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/40.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Я на горку шла, тяжело несла,
Уморилась, уморилась, уморилася
Тяжело несла в решете овса,
Припев
В решете овса, полтора зерна.
Припев
Я домой пришла, овёс высыпала,
Припев
В нетопленную печь овёс ссыпала.
Припев
Уж я три-то дня сушила и четыре дня толкла,
Припев
На девятый день я блинов напекла.
Припев
Я блинов напекла да к соседушке пошла,
Припев
А соседка недобра, не попотчевала.
Припев
Уж я губушки надула и домой пошла,
Припев
Я домой пришла, мужа выбранила:
Припев
&laquo;Уж ты, куричье дыханье, петушино воздыханье&raquo;.
Припев
Уж и бил меня муж, колотил меня муж.
Припев
Он ко нитке привязал, соломиной наказал.
Припев
Я со этих ли побоев три недели хворала.
Припев
На четвёртую неделю выздоравливала.
Припев
Уж я съела, молода, да блинов стопу,
Припев
Блинов стопу, пирогов сотню,
Припев
Быка-третьяка, тёлку, гуся, порося,
Припев
Тёлку, гуся, порося, ещё уточку,
Припев
Ещё уточку на закусочку.
Припев
А лихая свекровь позавидовала:
Припев
&laquo;Как тебя, моя молодушка, не разорвало?&raquo; -
Припев
&laquo;Разорви того живот, кто неправдою живёт,
Припев
Ещё старых старух, что не любят молодух!&raquo;
Припев','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_266df6a9c1787d8d'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_266df6a9c1787d8d','Я на горку шла','Я на горку шла, тяжело несла,
Уморилась, уморилась, уморилася
