Припев');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('rpl_rpp_266df6a9c1787d8d_96514c77c55654f0','rpp_266df6a9c1787d8d','Retroportal — Народные песни','https://pesni.retroportal.ru/np3/40.shtml','reference',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3a4f1b6049964641','Я не вернусь',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Сергей Касаткин, музыка: Борис Прозоровский) | Старинные романсы | https://pesni.retroportal.ru/sr3/44.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я не вернусь, душа дрожит от боли,
Я страсти призраком, поверь, не обманусь...
Достойным быть мне хватит силы воли,
Ты так и знай, я не вернусь.
В чужом краю, ко всем страстям холодный,
Страдальцем дни скорей влачить решусь.
Оковы прочь, хочу я быть свободным.
О, не зови, я не вернусь.
Не посылай своих мне писем милых,
Я этих строк любви, лукавых строк боюсь.
Не обещай, чего ты дать не в силах,
Да-да, мой друг, я не вернусь.
Ведь я ушёл, тебя не проклиная,
А сделать зла тебе не соглашусь.
Покоя ждёт душа моя больная.
О, пощади... Я не вернусь.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3a4f1b6049964641'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3a4f1b6049964641','Я не вернусь','Я не вернусь, душа дрожит от боли,
