INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bdfcf287ceff08b7','Я очи знал',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Фёдор Тютчев, музыка: Елизавета Кочубей) | Старинные романсы | https://pesni.retroportal.ru/sr3/45.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я очи знал... О, эти очи!
Как я любил их, знает бог!
От их волшебной страстной ночи
Я душу оторвать не мог.
В непостижимом этом взоре,
Жизнь обнажающем до дна,
Такое слышалося горе,
Такая страсти глубина.
Дышал он, грустный, углублённый,
В тени ресниц её густой,
Как наслажденье, утомлённый,
И как страданье, роковой.
И в эти чудные мгновенья
Ни разу мне не довелось
С ним повстречаться без волненья
И любоваться им без слёз.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bdfcf287ceff08b7'), datetime('now')),datetime('now'));
