INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_722a01aceeb99a46','Я помню вальса звук прелестный',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова и музыка: Николай Листов) | Старинные романсы | https://pesni.retroportal.ru/sr3/46.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я помню вальса звук прелестный
Весенней ночью в поздний час,
Его пел голос неизвестный,
И песня чудная лилась.
Да, то был вальс прелестный, томный,
Да, то был дивный вальс!
Теперь зима, и те же ели,
Покрыты сумраком, стоят,
А под окном шумят метели,
И звуки вальса не звучат...
Где ж этот вальс, старинный, томный,
Где ж этот дивный вальс?!','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_722a01aceeb99a46'), datetime('now')),datetime('now'));
