INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_32735af1e930f8a4','Я тебе ничего не скажу',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Афанасий Фет, музыка: Татьяна Котляревская /Татьяна Толстая/) | Старинные романсы | https://pesni.retroportal.ru/sr3/47.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Я тебе ничего не скажу,
Я тебя не встревожу ничуть
И о том, что я молча твержу,
Не решусь ни за что намекнуть!
Целый день спят ночные цветы,
Но лишь солнце за рощей зайдёт,
Открываются тихо мечты,
И я слышу, как сердце цветёт...
И в больную усталую грудь
Веет влагой ночной... Я дрожу,
Я тебя не встревожу ничуть,
Я тебе ничего не скажу.','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_32735af1e930f8a4'), datetime('now')),datetime('now'));
