INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_3c7ac9a293c66f30','Як до мэнэ Якив прыходыв',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (украинская народная песня) | Народные песни | https://pesni.retroportal.ru/np3/41.shtml','import_source: https://pesni.retroportal.ru/ | section: Народные песни | merged_versions: 1','Як до мэнэ Якив прыходыв,
Коробочку ракив прыносив.
А я тии раки забрала,
А Якова с хаты прогнала.
- Иды, иды, Яковэ, с хаты!
Нигдэ тоби, Яковэ, спаты!
Нигдэ тоби, Яковэ, спаты,
Бо на пичи батько и маты.
А на скрыни сын та нэвистка, -
Нэма тоби, Яковэ, миста.
А в люлюки братови диты, -
Нигдэ тэбэ, Яковэ, дитэ.
А у синцах – злые собакы, -
Забьют тоби, Яковэ, бакы!
Избириться, хлопцы, по грошу,
Купить мини ленту хорошу.
А я буду в лентах ходыты,
Будут мэнэ хлопцы любыты.','["category-narodnye", "pesni.retroportal.ru", "retroportal-section-narodnye", "Народные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_3c7ac9a293c66f30'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_3c7ac9a293c66f30','Як до мэнэ Якив прыходыв','Як до мэнэ Якив прыходыв,
