INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_371f8d844e886f3a','Ямщик, не гони лошадей',NULL,'ru','russian_empire_1900_1917',NULL,NULL,'pesni.retroportal.ru | (слова: Николай фон Риттер, музыка: Яков Фельдман) | Старинные романсы | https://pesni.retroportal.ru/sr3/48.shtml','import_source: https://pesni.retroportal.ru/ | section: Старинные романсы | merged_versions: 1','Как грустно, туманно кругом,
Тосклив, безотраден мой путь,
И прошлое кажется сном,
Томит наболевшую грудь!
Ямщик, не гони лошадей!
Мне некуда больше спешить,
Мне некого больше любить,
Ямщик, не гони лошадей!
Как жажду средь мрачных равнин
Измену забыть и любовь, -
Но память, мой злой властелин,
Всё будит минувшее вновь!
Припев
Всё было лишь ложь и обман...
Прощай и мечты, и покой!
А боль незакрывшихся ран
Останется вечно со мной!
Припев','["category-romansy", "pesni.retroportal.ru", "retroportal-section-romansy", "Старинные романсы"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_371f8d844e886f3a'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_371f8d844e886f3a','Ямщик, не гони лошадей','Как грустно, туманно кругом,
