INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('rpp_bb8e1c628fe449fd','Ясной ночкой','(«Ясной ночкой весенней при луне...»)','ru','ussr',NULL,NULL,'pesni.retroportal.ru | (слова: Евгений Долматовский, музыка: Борис Мокроусов) | Эстрадные песни | https://pesni.retroportal.ru/estrada/yasnoj_nochkoj.html','import_source: https://pesni.retroportal.ru/ | section: Эстрадные песни | subtitle: («Ясной ночкой весенней при луне...») | merged_versions: 1','Ясной ночкой весенней при луне
Мой товарищ задавал вопросы мне.
Он спросил меня: я счастлива иль нет?
Только взглядом я дала ему ответ:
Посмотри, милый друг,
На сады, на широкие нивы -
Это счастье моё расцветает вокруг.
Как же не быть мне счастливой?
Цвет сирени - словно пламя под луной.
Мой товарищ до утра ходил со мной.
Он спросил меня: богата я иль нет?
Только взглядом я дала ему ответ:
Посмотри, милый друг,
Как прекрасна земля на рассвете!
Вот богатство моё расцветает вокруг -
Кто ж нас богаче на свете?
И взошло над нами солнце, как венец,
Мой товарищ объяснился наконец.
Он спросил меня: люблю его иль нет?
Только взглядом я дала ему ответ:
Посмотри, милый друг,
На садов золотую отраду -
Это наша любовь расцветает вокруг,
Только спешить с ней не надо...','["category-estrada", "pesni.retroportal.ru", "retroportal-section-estrada", "retroportal-subtitle:(«Ясной ночкой весенней при луне...»)", "Эстрадные песни"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='rpp_bb8e1c628fe449fd'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('rpp_bb8e1c628fe449fd','Ясной ночкой','Ясной ночкой весенней при луне
